CREATE OR REPLACE FUNCTION "public"."_fb_log_event"("p_story_id" "uuid", "p_kind" "text", "p_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_actor_kind" "text" DEFAULT 'user'::"text", "p_routine_run_id" "uuid" DEFAULT NULL::"uuid", "p_retest_run_id" "uuid" DEFAULT NULL::"uuid") RETURNS bigint
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_id bigint;
BEGIN
  INSERT INTO feedback_story_events
    (story_id, kind, payload, actor_id, actor_kind, routine_run_id, retest_run_id)
  VALUES
    (p_story_id, p_kind, COALESCE(p_payload, '{}'::jsonb), auth.uid(),
     COALESCE(p_actor_kind, 'user'), p_routine_run_id, p_retest_run_id)
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."_fb_log_event"("p_story_id" "uuid", "p_kind" "text", "p_payload" "jsonb", "p_actor_kind" "text", "p_routine_run_id" "uuid", "p_retest_run_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."accept_story_suggestion"("p_suggestion_id" "uuid", "p_override_title" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sugg RECORD;
  v_story_id uuid;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  SELECT * INTO v_sugg FROM feedback_story_suggestions
   WHERE id = p_suggestion_id AND dismissed = false;
  IF NOT FOUND THEN RAISE EXCEPTION 'suggestion not found'; END IF;

  v_story_id := create_story(
    COALESCE(p_override_title, v_sugg.proposed_title),
    v_sugg.member_ids,
    NULL,
    'ai_suggested'
  );

  UPDATE feedback_story_suggestions
     SET dismissed = true, dismissed_at = now(), dismissed_by = auth.uid()
   WHERE id = p_suggestion_id;

  RETURN v_story_id;
END;
$$;


ALTER FUNCTION "public"."accept_story_suggestion"("p_suggestion_id" "uuid", "p_override_title" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."add_story_members"("p_story_id" "uuid", "p_submission_ids" "uuid"[]) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor uuid := auth.uid();
  v_count integer;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  INSERT INTO feedback_story_members (story_id, submission_id, added_by)
  SELECT p_story_id, unnest, v_actor
  FROM unnest(p_submission_ids)
  ON CONFLICT DO NOTHING;
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."add_story_members"("p_story_id" "uuid", "p_submission_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."add_tag_to_category"("p_tag_id" "uuid", "p_category_id" "uuid", "p_is_primary" boolean DEFAULT false) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- If setting as primary, unset other primaries for this tag
  IF p_is_primary THEN
    UPDATE tag_category_assignments
    SET is_primary = false
    WHERE tag_id = p_tag_id AND is_primary = true;
    
    -- Also update the legacy category_id and category text columns
    UPDATE unified_tags
    SET category_id = p_category_id,
        category = (SELECT name FROM tag_categories WHERE id = p_category_id)
    WHERE id = p_tag_id;
  END IF;

  -- Insert the assignment
  INSERT INTO tag_category_assignments (tag_id, category_id, is_primary)
  VALUES (p_tag_id, p_category_id, p_is_primary)
  ON CONFLICT (tag_id, category_id) 
  DO UPDATE SET is_primary = EXCLUDED.is_primary;
END;
$$;


ALTER FUNCTION "public"."add_tag_to_category"("p_tag_id" "uuid", "p_category_id" "uuid", "p_is_primary" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_bulk_review_action"("p_action" "text", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_success int := 0;
  v_count int;
  v_cutoff timestamptz;
BEGIN
  IF NOT has_role_jwt('admin'::app_role) THEN
    RETURN jsonb_build_object('success', 0, 'failed', 0, 'error', 'Unauthorized');
  END IF;

  CASE p_action

  WHEN 'approve' THEN
    -- Approve all pending tag suggestions
    WITH updated AS (
      UPDATE tag_suggestions
      SET status = 'approved', reviewed_by = p_user_id, reviewed_at = now()
      WHERE status = 'pending'
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

    -- Publish all CMS content in review
    WITH updated AS (
      UPDATE cms_content_metadata
      SET workflow_state = 'published', published_at = now(), published_by = p_user_id, updated_at = now()
      WHERE workflow_state = 'review'
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

    -- Resolve all open moderation flags
    WITH updated AS (
      UPDATE moderation_flags
      SET status = 'RESOLVED', resolved_by = p_user_id, resolved_at = now(),
          resolution_note = 'Bulk approved via Review & Moderation'
      WHERE status = 'OPEN'
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

  WHEN 'enrich' THEN
    v_success := 0; -- content_flags table does not exist yet

  WHEN 'dedup' THEN
    -- Resolve pending dedupe decisions: mark all as 'skip' (not duplicates / reviewed)
    WITH updated AS (
      UPDATE scraper_dedupe_decisions
      SET decision = 'skip'
      WHERE decision = 'pending'
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

  WHEN 'reject_stale' THEN
    v_cutoff := now() - interval '7 days';

    WITH updated AS (
      UPDATE moderation_flags
      SET status = 'REJECTED', resolved_by = p_user_id, resolved_at = now(),
          resolution_note = 'Auto-rejected: stale (>7 days)'
      WHERE status = 'OPEN' AND created_at < v_cutoff
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

    WITH updated AS (
      UPDATE tag_suggestions
      SET status = 'rejected', reviewed_by = p_user_id, reviewed_at = now()
      WHERE status = 'pending' AND created_at < v_cutoff
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

    WITH updated AS (
      UPDATE ingestion_staging
      SET disposition = 'rejected', review_status = 'rejected', reviewed_at = now()
      WHERE review_status = 'pending_review' AND disposition = 'pending' AND created_at < v_cutoff
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

    -- Also dismiss stale dedupe decisions
    WITH updated AS (
      UPDATE scraper_dedupe_decisions
      SET decision = 'skip'
      WHERE decision = 'pending' AND created_at < v_cutoff
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

  WHEN 'approve_confident' THEN
    WITH updated AS (
      UPDATE tag_suggestions
      SET status = 'approved', reviewed_by = p_user_id, reviewed_at = now()
      WHERE status = 'pending' AND confidence >= 0.8
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

  WHEN 'dismiss_low' THEN
    v_success := 0; -- content_flags table does not exist yet

  WHEN 'reject_all' THEN
    WITH updated AS (
      UPDATE moderation_flags
      SET status = 'REJECTED', resolved_by = p_user_id, resolved_at = now(),
          resolution_note = 'Bulk rejected via Review & Moderation'
      WHERE status = 'OPEN'
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

    WITH updated AS (
      UPDATE tag_suggestions
      SET status = 'rejected', reviewed_by = p_user_id, reviewed_at = now()
      WHERE status = 'pending'
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

    WITH updated AS (
      UPDATE cms_content_metadata
      SET workflow_state = 'draft', updated_at = now()
      WHERE workflow_state = 'review'
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

    WITH updated AS (
      UPDATE ingestion_staging
      SET disposition = 'rejected', review_status = 'rejected', reviewed_at = now()
      WHERE review_status = 'pending_review' AND disposition = 'pending'
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

    -- Also reject all pending dedupe decisions
    WITH updated AS (
      UPDATE scraper_dedupe_decisions
      SET decision = 'skip'
      WHERE decision = 'pending'
      RETURNING id
    )
    SELECT count(*) INTO v_count FROM updated;
    v_success := v_success + v_count;

  ELSE
    RETURN jsonb_build_object('success', 0, 'failed', 0, 'error', 'Unknown action: ' || p_action);
  END CASE;

  RETURN jsonb_build_object('success', v_success, 'failed', 0);
END;
$$;


ALTER FUNCTION "public"."admin_bulk_review_action"("p_action" "text", "p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."anonymize_location_data"("p_days_old" integer DEFAULT 30) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE anonymized_count integer := 0;
BEGIN
  IF NOT public.has_role_jwt('admin'::public.app_role) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE='42501'; END IF;
  PERFORM public.log_security_event('LOCATION_DATA_ANONYMIZED', auth.uid(),
    jsonb_build_object('days_old', p_days_old, 'anonymized_count', anonymized_count), 'medium');
  RETURN anonymized_count;
END;
$$;


ALTER FUNCTION "public"."anonymize_location_data"("p_days_old" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."apply_content_change"("p_change_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_change RECORD;
  v_allowed_tables TEXT[] := ARRAY[
    'venues','events','personalities','news_articles',
    'cities','countries','unified_tags','marketplace_listings',
    'community_groups','hotels','queer_villages'
  ];
  v_sql TEXT;
  v_value TEXT;
  v_col_type TEXT;
BEGIN
  SELECT * INTO v_change FROM public.content_changes
    WHERE id = p_change_id AND status IN ('pending','auto_approved','approved')
    FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Change % not found or not in applicable status', p_change_id;
  END IF;

  IF NOT v_change.content_type = ANY(v_allowed_tables) THEN
    RAISE EXCEPTION 'Invalid content_type: %', v_change.content_type;
  END IF;

  -- Skip flag-only changes (they don't modify data)
  IF v_change.change_type = 'flag' THEN
    UPDATE public.content_changes
    SET status = 'applied', applied_at = now()
    WHERE id = p_change_id;
    RETURN TRUE;
  END IF;

  -- Extract text value from JSONB
  v_value := v_change.new_value #>> '{}';

  -- Look up target column type to handle casting
  SELECT udt_name INTO v_col_type
  FROM information_schema.columns
  WHERE table_schema = 'public'
    AND table_name = v_change.content_type
    AND column_name = v_change.field_name;

  -- Build safe dynamic SQL with appropriate casting
  IF v_col_type = 'uuid' THEN
    v_sql := format(
      'UPDATE %I SET %I = $1::uuid WHERE id = $2',
      v_change.content_type,
      v_change.field_name
    );
  ELSIF v_col_type IN ('int4', 'int8', 'int2') THEN
    v_sql := format(
      'UPDATE %I SET %I = $1::bigint WHERE id = $2',
      v_change.content_type,
      v_change.field_name
    );
  ELSIF v_col_type IN ('float4', 'float8', 'numeric') THEN
    v_sql := format(
      'UPDATE %I SET %I = $1::numeric WHERE id = $2',
      v_change.content_type,
      v_change.field_name
    );
  ELSIF v_col_type = 'bool' THEN
    v_sql := format(
      'UPDATE %I SET %I = $1::boolean WHERE id = $2',
      v_change.content_type,
      v_change.field_name
    );
  ELSE
    v_sql := format(
      'UPDATE %I SET %I = $1 WHERE id = $2',
      v_change.content_type,
      v_change.field_name
    );
  END IF;

  EXECUTE v_sql USING v_value, v_change.content_id;

  UPDATE public.content_changes
  SET status = 'applied', applied_at = now()
  WHERE id = p_change_id;

  RETURN TRUE;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'apply_content_change failed for %: %', p_change_id, SQLERRM;
  RETURN FALSE;
END;
$_$;


ALTER FUNCTION "public"."apply_content_change"("p_change_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."apply_enrichment"("p_staging_id" "uuid", "p_pipeline_run_id" "uuid", "p_stage" "text", "p_new_enriched" "jsonb", "p_actor" "text" DEFAULT 'pipeline-enrich'::"text", "p_status" "text" DEFAULT 'success'::"text", "p_error_message" "text" DEFAULT NULL::"text", "p_duration_ms" integer DEFAULT NULL::integer) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_before jsonb;
  v_changed text[];
  v_audit_id uuid;
BEGIN
  SELECT enriched_data INTO v_before FROM ingestion_staging WHERE id = p_staging_id FOR UPDATE;

  WITH new_keys AS (SELECT key FROM jsonb_each(coalesce(p_new_enriched, '{}'::jsonb))),
       old_keys AS (SELECT key FROM jsonb_each(coalesce(v_before, '{}'::jsonb))),
       added AS (SELECT key FROM new_keys EXCEPT SELECT key FROM old_keys),
       removed AS (SELECT key FROM old_keys EXCEPT SELECT key FROM new_keys),
       changed AS (
         SELECT n.key FROM new_keys n JOIN old_keys o USING (key)
          WHERE coalesce(p_new_enriched,'{}'::jsonb) -> n.key
                IS DISTINCT FROM coalesce(v_before,'{}'::jsonb) -> n.key
       )
  SELECT array_agg(key) INTO v_changed
    FROM (SELECT key FROM added UNION SELECT key FROM removed UNION SELECT key FROM changed) d;

  INSERT INTO enrichment_audit(
    staging_id, pipeline_run_id, stage, status,
    changed_fields, before_data, after_data, error_message, duration_ms, actor
  ) VALUES (
    p_staging_id, p_pipeline_run_id, p_stage, p_status,
    coalesce(v_changed, '{}'::text[]), v_before, p_new_enriched,
    p_error_message, p_duration_ms, p_actor
  ) RETURNING id INTO v_audit_id;

  IF p_status = 'success' THEN
    UPDATE ingestion_staging
       SET enriched_data = coalesce(enriched_data, '{}'::jsonb) || p_new_enriched,
           enrichment_status = 'enriched', updated_at = now()
     WHERE id = p_staging_id;
  ELSIF p_status = 'failed' THEN
    UPDATE ingestion_staging
       SET enrichment_status = 'failed',
           error_message = coalesce(p_error_message, error_message),
           updated_at = now()
     WHERE id = p_staging_id;
  END IF;

  RETURN v_audit_id;
END;
$$;


ALTER FUNCTION "public"."apply_enrichment"("p_staging_id" "uuid", "p_pipeline_run_id" "uuid", "p_stage" "text", "p_new_enriched" "jsonb", "p_actor" "text", "p_status" "text", "p_error_message" "text", "p_duration_ms" integer) OWNER TO "postgres";

