CREATE TABLE IF NOT EXISTS "public"."group_join_requests" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "group_id" "uuid" NOT NULL,
    "user_id" "uuid" NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "message" "text",
    "decided_by" "uuid",
    "decided_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "group_join_requests_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'approved'::"text", 'rejected'::"text", 'cancelled'::"text"])))
);


ALTER TABLE "public"."group_join_requests" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_group_join_request"("request_id" "uuid") RETURNS "public"."group_join_requests"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  req public.group_join_requests;
BEGIN
  SELECT * INTO req FROM public.group_join_requests WHERE id = request_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Join request not found';
  END IF;
  IF req.status <> 'pending' THEN
    RAISE EXCEPTION 'Join request is not pending (status=%)', req.status;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.group_memberships gm
    WHERE gm.group_id = req.group_id
      AND gm.user_id = auth.uid()
      AND gm.role IN ('admin', 'moderator')
  ) THEN
    RAISE EXCEPTION 'Not authorized to approve requests for this group';
  END IF;

  INSERT INTO public.group_memberships (group_id, user_id, role)
  VALUES (req.group_id, req.user_id, 'member')
  ON CONFLICT (group_id, user_id) DO NOTHING;

  UPDATE public.group_join_requests
    SET status = 'approved', decided_by = auth.uid(), decided_at = now()
    WHERE id = request_id
    RETURNING * INTO req;

  RETURN req;
END;
$$;


ALTER FUNCTION "public"."approve_group_join_request"("request_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_story_for_claude"("p_story_id" "uuid", "p_note" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_actor uuid := auth.uid();
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  UPDATE feedback_stories
     SET approved_for_claude_at = COALESCE(approved_for_claude_at, now()),
         approved_by            = COALESCE(approved_by, v_actor),
         needs_followup_reason  = NULL
   WHERE id = p_story_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'story_not_found' USING ERRCODE = 'P0002'; END IF;
  PERFORM _fb_log_event(p_story_id, 'approved_for_claude', jsonb_build_object('note', p_note));
  RETURN p_story_id;
END;
$$;


ALTER FUNCTION "public"."approve_story_for_claude"("p_story_id" "uuid", "p_note" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_tag_suggestions"("p_suggestion_ids" "uuid"[], "p_reviewer_id" "uuid" DEFAULT NULL::"uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  approved_count INTEGER := 0;
  suggestion RECORD;
BEGIN
  IF NOT has_role_jwt('admin'::app_role) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = '42501';
  END IF;
  FOR suggestion IN
    SELECT id, entity_id, entity_type, tag_id
    FROM public.tag_suggestions
    WHERE id = ANY(p_suggestion_ids) AND status = 'pending' AND tag_id IS NOT NULL
  LOOP
    INSERT INTO public.unified_tag_assignments (tag_id, entity_id, entity_type)
    VALUES (suggestion.tag_id, suggestion.entity_id, suggestion.entity_type)
    ON CONFLICT (tag_id, entity_id, entity_type) DO NOTHING;

    UPDATE public.tag_suggestions
    SET status = CASE WHEN p_reviewer_id IS NULL THEN 'auto_approved' ELSE 'approved' END,
        reviewed_by = p_reviewer_id,
        reviewed_at = now()
    WHERE id = suggestion.id;

    UPDATE public.unified_tags SET usage_count = (
      SELECT COUNT(*) FROM public.unified_tag_assignments WHERE tag_id = suggestion.tag_id
    ) WHERE id = suggestion.tag_id;

    approved_count := approved_count + 1;
  END LOOP;
  RETURN approved_count;
END;
$$;


ALTER FUNCTION "public"."approve_tag_suggestions"("p_suggestion_ids" "uuid"[], "p_reviewer_id" "uuid") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."feedback_stories" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "title" "text" NOT NULL,
    "summary" "text",
    "status" "text" DEFAULT 'open'::"text" NOT NULL,
    "priority" smallint DEFAULT 2 NOT NULL,
    "labels" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "assignee_id" "uuid",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "resolved_at" timestamp with time zone,
    "origin" "text" DEFAULT 'manual'::"text" NOT NULL,
    "handoffs" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "brief_title" "text",
    "narrative" "text",
    "narrative_edited" boolean DEFAULT false NOT NULL,
    "approved_for_claude_at" timestamp with time zone,
    "approved_by" "uuid",
    "needs_followup_reason" "text",
    "archived_at" timestamp with time zone,
    "archived_by" "uuid",
    "archive_reason" "text",
    CONSTRAINT "feedback_stories_origin_check" CHECK (("origin" = ANY (ARRAY['manual'::"text", 'ai_suggested'::"text"]))),
    CONSTRAINT "feedback_stories_priority_check" CHECK ((("priority" >= 0) AND ("priority" <= 3))),
    CONSTRAINT "feedback_stories_status_check" CHECK (("status" = ANY (ARRAY['open'::"text", 'planned'::"text", 'in_progress'::"text", 'resolved'::"text", 'archived'::"text"])))
);


