CREATE OR REPLACE FUNCTION "public"."archive_story"("p_story_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "public"."feedback_stories"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_story feedback_stories%ROWTYPE;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  UPDATE feedback_stories
     SET archived_at=now(), archived_by=auth.uid(), archive_reason=p_reason, status='archived'
   WHERE id = p_story_id RETURNING * INTO v_story;
  IF NOT FOUND THEN RAISE EXCEPTION 'story_not_found' USING ERRCODE = 'P0002'; END IF;
  PERFORM _fb_log_event(p_story_id, 'archived', jsonb_build_object('reason', p_reason));
  RETURN v_story;
END;
$$;


