CREATE OR REPLACE FUNCTION "public"."assert_content_metadata_target"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $_$
DECLARE
  allowed text[] := ARRAY[
    'venues','events','personalities','news_articles','cities','countries',
    'unified_tags','marketplace_listings','community_groups','cms_pages',
    'hotels_bnbs','queer_villages','feedback'
  ];
  exists_cnt int;
  q text;
BEGIN
  IF NOT (NEW.content_type = ANY (allowed)) THEN
    RAISE EXCEPTION 'content_metadata: unknown content_type %', NEW.content_type;
  END IF;
  q := format('SELECT 1 FROM public.%I WHERE id = $1 LIMIT 1', NEW.content_type);
  EXECUTE q INTO exists_cnt USING NEW.content_id;
  IF exists_cnt IS NULL THEN
    RAISE EXCEPTION 'content_metadata: % % does not exist', NEW.content_type, NEW.content_id;
  END IF;
  RETURN NEW;
END;
$_$;


ALTER FUNCTION "public"."assert_content_metadata_target"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."assign_user_role"("user_id" "uuid", "role_name" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
#variable_conflict use_column
DECLARE
  _target_user_id uuid := user_id;
  _target_role public.app_role := role_name::public.app_role;
  caller_is_admin boolean;
BEGIN
  SELECT EXISTS (
    SELECT 1 FROM public.user_roles ur
    WHERE ur.user_id = auth.uid() AND ur.role = 'admin'::public.app_role
  ) INTO caller_is_admin;

  IF NOT caller_is_admin THEN
    RAISE EXCEPTION 'Only admins can assign roles';
  END IF;

  INSERT INTO public.user_roles (user_id, role)
  VALUES (_target_user_id, _target_role)
  ON CONFLICT (user_id, role) DO NOTHING;

  RETURN true;
END;
$$;


ALTER FUNCTION "public"."assign_user_role"("user_id" "uuid", "role_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."audit_admin_data_access"("p_admin_id" "uuid", "p_target_user_id" "uuid", "p_data_type" "text", "p_justification" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  is_admin boolean := false;
BEGIN
  -- Verify admin role
  SELECT EXISTS(
    SELECT 1 FROM public.user_roles 
    WHERE user_id = p_admin_id AND role = 'admin'::app_role
  ) INTO is_admin;
  
  IF NOT is_admin THEN
    RETURN false;
  END IF;
  
  -- Log the access
  PERFORM public.log_enhanced_security_event(
    'ADMIN_DATA_ACCESS',
    p_admin_id,
    jsonb_build_object(
      'target_user_id', p_target_user_id,
      'data_type', p_data_type,
      'justification', p_justification,
      'timestamp', NOW()
    ),
    'high'
  );
  
  RETURN true;
END;
$$;


ALTER FUNCTION "public"."audit_admin_data_access"("p_admin_id" "uuid", "p_target_user_id" "uuid", "p_data_type" "text", "p_justification" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."audit_admin_sensitive_access"("p_admin_id" "uuid", "p_target_user_id" "uuid", "p_data_type" "text", "p_justification" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_caller uuid := auth.uid();
  v_is_admin boolean;
  is_emergency boolean := false;
  approval_required boolean := true;
BEGIN
  IF v_caller IS NULL THEN RETURN FALSE; END IF;
  IF p_admin_id IS NOT NULL AND p_admin_id <> v_caller THEN
    PERFORM public.log_security_event('ADMIN_AUDIT_IDENTITY_MISMATCH', v_caller,
      jsonb_build_object('claimed_admin', p_admin_id, 'target_user', p_target_user_id, 'data_type', p_data_type), 'critical');
    RETURN FALSE;
  END IF;
  SELECT EXISTS(SELECT 1 FROM public.user_roles WHERE user_id = v_caller AND role = 'admin'::public.app_role)
  INTO v_is_admin;
  IF NOT v_is_admin THEN RETURN FALSE; END IF;
  is_emergency := (p_justification ILIKE '%emergency%' OR p_justification ILIKE '%urgent%');
  CASE p_data_type
    WHEN 'sexual_orientation', 'gender_identity' THEN approval_required := TRUE;
    WHEN 'financial_data', 'income_range' THEN approval_required := TRUE;
    WHEN 'emergency_contact' THEN approval_required := NOT is_emergency;
    ELSE approval_required := FALSE;
  END CASE;
  PERFORM public.log_security_event('ADMIN_SENSITIVE_DATA_ACCESS', v_caller,
    jsonb_build_object('target_user_id', p_target_user_id, 'data_type', p_data_type,
      'justification', p_justification, 'is_emergency', is_emergency, 'approval_required', approval_required,
      'ip_address', current_setting('request.headers', true)::json->>'x-forwarded-for',
      'user_agent', current_setting('request.headers', true)::json->>'user-agent', 'timestamp', NOW()),
    'critical');
  RETURN NOT approval_required;
END;
$$;


ALTER FUNCTION "public"."audit_admin_sensitive_access"("p_admin_id" "uuid", "p_target_user_id" "uuid", "p_data_type" "text", "p_justification" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."audit_staging_review_change"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
BEGIN
  IF NEW.review_status IS DISTINCT FROM OLD.review_status
     AND NEW.review_status IN ('approved','rejected') THEN
    INSERT INTO public.ingestion_events (staging_id, stage, old_status, new_status, actor, payload)
    VALUES (NEW.id, 'review', OLD.review_status, NEW.review_status,
            coalesce(NEW.reviewed_by::text, 'unknown'),
            jsonb_build_object('notes', NEW.review_notes));
  END IF;
  RETURN NEW;
END $$;


ALTER FUNCTION "public"."audit_staging_review_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_clean_all_duplicates"("p_auto_merge_threshold" numeric DEFAULT 0.9, "p_review_threshold" numeric DEFAULT 0.7, "p_entity_types" "text"[] DEFAULT ARRAY['venues'::"text", 'events'::"text", 'personalities'::"text", 'news_articles'::"text", 'cities'::"text"], "p_limit" integer DEFAULT 200, "p_dry_run" boolean DEFAULT true) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "statement_timeout" TO '300s'
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_type text;
  v_scan_result json;
  v_pair RECORD;
  v_rec_a RECORD;
  v_rec_b RECORD;
  v_keep_id uuid;
  v_remove_id uuid;
  v_merge_result jsonb;
  v_type_scanned int;
  v_type_merged int;
  v_type_flagged int;
  v_type_errors text[];
  v_result jsonb := jsonb_build_object(
    'by_type', '{}'::jsonb,
    'total_scanned', 0,
    'total_auto_merged', 0,
    'total_flagged', 0,
    'errors', '[]'::jsonb,
    'dry_run', p_dry_run
  );
  v_count_a int;
  v_count_b int;
  v_name_field text;
  v_table_name text;
  v_exists_a boolean;
  v_exists_b boolean;
BEGIN
  FOREACH v_type IN ARRAY p_entity_types
  LOOP
    IF v_type = 'tags' THEN
      CONTINUE;
    END IF;

    v_type_scanned := 0;
    v_type_merged := 0;
    v_type_flagged := 0;
    v_type_errors := ARRAY[]::text[];

    -- Step 1: Scan for duplicates
    BEGIN
      v_scan_result := scan_table_duplicates(v_type, p_review_threshold, p_limit);
      v_type_scanned := (v_scan_result->>'scanned')::int;
    EXCEPTION WHEN OTHERS THEN
      v_type_errors := array_append(v_type_errors, 'Scan error: ' || SQLERRM);
      v_result := jsonb_set(v_result, ARRAY['by_type', v_type],
        jsonb_build_object('scanned', 0, 'auto_merged', 0, 'flagged_for_review', 0, 'errors', to_jsonb(v_type_errors))
      );
      CONTINUE;
    END;

    CASE v_type
      WHEN 'venues' THEN v_table_name := 'venues'; v_name_field := 'name';
      WHEN 'events' THEN v_table_name := 'events'; v_name_field := 'title';
      WHEN 'personalities' THEN v_table_name := 'personalities'; v_name_field := 'name';
      WHEN 'news_articles' THEN v_table_name := 'news_articles'; v_name_field := 'title';
      WHEN 'cities' THEN v_table_name := 'cities'; v_name_field := 'name';
      ELSE CONTINUE;
    END CASE;

    -- Step 2: Process pending pairs
    FOR v_pair IN
      SELECT id, entity_a_id, entity_b_id, confidence
      FROM scraper_dedupe_decisions
      WHERE entity_type = v_type AND decision = 'pending'
      ORDER BY confidence DESC
    LOOP
      -- Guard: check both entities still exist
      EXECUTE format('SELECT EXISTS(SELECT 1 FROM %I WHERE id = $1)', v_table_name)
        INTO v_exists_a USING v_pair.entity_a_id;
      EXECUTE format('SELECT EXISTS(SELECT 1 FROM %I WHERE id = $1)', v_table_name)
        INTO v_exists_b USING v_pair.entity_b_id;

      IF NOT v_exists_a OR NOT v_exists_b THEN
        -- Auto-skip stale entries where one entity was already deleted/merged
        UPDATE scraper_dedupe_decisions SET decision = 'skip' WHERE id = v_pair.id;
        CONTINUE;
      END IF;

      IF v_pair.confidence >= p_auto_merge_threshold THEN
        IF NOT p_dry_run THEN
          BEGIN
            EXECUTE format(
              'SELECT count(*) FROM jsonb_each(to_jsonb(r.*)) WHERE value::text NOT IN (''null'', ''""'', ''0'', ''false'')
               FROM %I r WHERE r.id = $1', v_table_name
            ) INTO v_count_a USING v_pair.entity_a_id;
            EXECUTE format(
              'SELECT count(*) FROM jsonb_each(to_jsonb(r.*)) WHERE value::text NOT IN (''null'', ''""'', ''0'', ''false'')
               FROM %I r WHERE r.id = $1', v_table_name
            ) INTO v_count_b USING v_pair.entity_b_id;
          EXCEPTION WHEN OTHERS THEN
            v_count_a := 0; v_count_b := 0;
          END;

          IF v_count_a >= v_count_b THEN
            v_keep_id := v_pair.entity_a_id;
            v_remove_id := v_pair.entity_b_id;
          ELSE
            v_keep_id := v_pair.entity_b_id;
            v_remove_id := v_pair.entity_a_id;
          END IF;

          BEGIN
            v_merge_result := merge_entities(v_type, v_keep_id, v_remove_id, '{}'::jsonb);
            IF (v_merge_result->>'success')::boolean THEN
              v_type_merged := v_type_merged + 1;
              -- Also skip any other pending entries referencing the removed entity
              UPDATE scraper_dedupe_decisions
              SET decision = 'skip'
              WHERE decision = 'pending'
                AND entity_type = v_type
                AND (entity_a_id = v_remove_id OR entity_b_id = v_remove_id)
                AND id != v_pair.id;
            ELSE
              v_type_errors := array_append(v_type_errors, 'Merge failed for ' || v_pair.entity_a_id::text || ' + ' || v_pair.entity_b_id::text);
            END IF;
          EXCEPTION WHEN OTHERS THEN
            v_type_errors := array_append(v_type_errors, 'Merge error: ' || SQLERRM);
          END;
        ELSE
          v_type_merged := v_type_merged + 1;
        END IF;
      ELSE
        v_type_flagged := v_type_flagged + 1;
      END IF;
    END LOOP;

    v_result := jsonb_set(v_result, ARRAY['by_type', v_type],
      jsonb_build_object(
        'scanned', v_type_scanned,
        'auto_merged', v_type_merged,
        'flagged_for_review', v_type_flagged,
        'errors', to_jsonb(v_type_errors)
      )
    );
    v_result := jsonb_set(v_result, '{total_scanned}', to_jsonb((v_result->>'total_scanned')::int + v_type_scanned));
    v_result := jsonb_set(v_result, '{total_auto_merged}', to_jsonb((v_result->>'total_auto_merged')::int + v_type_merged));
    v_result := jsonb_set(v_result, '{total_flagged}', to_jsonb((v_result->>'total_flagged')::int + v_type_flagged));
  END LOOP;

  -- Handle tags separately
  IF 'tags' = ANY(p_entity_types) THEN
    BEGIN
      DECLARE
        v_tag_result jsonb;
      BEGIN
        v_tag_result := auto_clean_merge_duplicates(p_dry_run, p_auto_merge_threshold::real);
        v_result := jsonb_set(v_result, ARRAY['by_type', 'tags'],
          jsonb_build_object(
            'scanned', COALESCE((v_tag_result->>'total_exact_merges')::int, 0) + COALESCE((v_tag_result->>'total_near_merges')::int, 0) + COALESCE((v_tag_result->>'total_skipped')::int, 0),
            'auto_merged', COALESCE((v_tag_result->>'total_exact_merges')::int, 0) + COALESCE((v_tag_result->>'total_near_merges')::int, 0),
            'flagged_for_review', COALESCE((v_tag_result->>'total_skipped')::int, 0),
            'whitespace_fixed', COALESCE((v_tag_result->>'whitespace_fixed')::int, 0),
            'junction_fixed', COALESCE((v_tag_result->>'junction_fixed')::int, 0),
            'errors', '[]'::jsonb,
            'details', v_tag_result
          )
        );
        v_result := jsonb_set(v_result, '{total_auto_merged}',
          to_jsonb((v_result->>'total_auto_merged')::int + COALESCE((v_tag_result->>'total_exact_merges')::int, 0) + COALESCE((v_tag_result->>'total_near_merges')::int, 0))
        );
        v_result := jsonb_set(v_result, '{total_flagged}',
          to_jsonb((v_result->>'total_flagged')::int + COALESCE((v_tag_result->>'total_skipped')::int, 0))
        );
      END;
    EXCEPTION WHEN OTHERS THEN
      v_result := jsonb_set(v_result, ARRAY['by_type', 'tags'],
        jsonb_build_object('scanned', 0, 'auto_merged', 0, 'flagged_for_review', 0, 'errors', jsonb_build_array('Tag dedup error: ' || SQLERRM))
      );
    END;
  END IF;

  RETURN v_result;
END;
$_$;


ALTER FUNCTION "public"."auto_clean_all_duplicates"("p_auto_merge_threshold" numeric, "p_review_threshold" numeric, "p_entity_types" "text"[], "p_limit" integer, "p_dry_run" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_clean_all_duplicates"("p_auto_merge_threshold" numeric DEFAULT 0.9, "p_review_threshold" numeric DEFAULT 0.7, "p_entity_types" "text"[] DEFAULT ARRAY['venues'::"text", 'events'::"text", 'personalities'::"text", 'news_articles'::"text", 'cities'::"text"], "p_limit" integer DEFAULT 500, "p_dry_run" boolean DEFAULT true, "p_offset" integer DEFAULT 0, "p_scan_only" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "statement_timeout" TO '120s'
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_type text;
  v_scan_result json;
  v_pair RECORD;
  v_rec_a RECORD;
  v_rec_b RECORD;
  v_keep_id uuid;
  v_remove_id uuid;
  v_merge_result jsonb;
  v_type_scanned int;
  v_type_merged int;
  v_type_flagged int;
  v_type_errors text[];
  v_type_total int;
  v_type_has_more boolean;
  v_result jsonb := jsonb_build_object(
    'by_type', '{}'::jsonb,
    'total_scanned', 0,
    'total_auto_merged', 0,
    'total_flagged', 0,
    'errors', '[]'::jsonb,
    'dry_run', p_dry_run,
    'scan_only', p_scan_only,
    'offset', p_offset
  );
  v_count_a int;
  v_count_b int;
  v_name_field text;
  v_table_name text;
  v_exists_a boolean;
  v_exists_b boolean;
BEGIN
  -- PHASE 1: Scan for duplicates (per entity type)
  IF p_limit > 0 THEN
    FOREACH v_type IN ARRAY p_entity_types
    LOOP
      IF v_type = 'tags' THEN
        CONTINUE;
      END IF;

      v_type_scanned := 0;
      v_type_merged := 0;
      v_type_flagged := 0;
      v_type_errors := ARRAY[]::text[];
      v_type_total := 0;
      v_type_has_more := false;

      BEGIN
        v_scan_result := scan_table_duplicates(v_type, p_review_threshold, p_limit, p_offset);
        v_type_scanned := (v_scan_result->>'scanned')::int;
        v_type_total := COALESCE((v_scan_result->>'total')::int, 0);
        v_type_has_more := COALESCE((v_scan_result->>'has_more')::boolean, false);
      EXCEPTION WHEN OTHERS THEN
        v_type_errors := array_append(v_type_errors, 'Scan error: ' || SQLERRM);
        v_result := jsonb_set(v_result, ARRAY['by_type', v_type],
          jsonb_build_object('scanned', 0, 'auto_merged', 0, 'flagged_for_review', 0, 'total', 0, 'has_more', false, 'errors', to_jsonb(v_type_errors))
        );
        CONTINUE;
      END;

      -- When scan_only, skip decision processing
      IF NOT p_scan_only THEN
        CASE v_type
          WHEN 'venues' THEN v_table_name := 'venues'; v_name_field := 'name';
          WHEN 'events' THEN v_table_name := 'events'; v_name_field := 'title';
          WHEN 'personalities' THEN v_table_name := 'personalities'; v_name_field := 'name';
          WHEN 'news_articles' THEN v_table_name := 'news_articles'; v_name_field := 'title';
          WHEN 'cities' THEN v_table_name := 'cities'; v_name_field := 'name';
          ELSE CONTINUE;
        END CASE;

        FOR v_pair IN
          SELECT id, entity_a_id, entity_b_id, confidence
          FROM scraper_dedupe_decisions
          WHERE entity_type = v_type AND decision = 'pending'
          ORDER BY confidence DESC
        LOOP
          EXECUTE format('SELECT EXISTS(SELECT 1 FROM %I WHERE id = $1)', v_table_name)
            INTO v_exists_a USING v_pair.entity_a_id;
          EXECUTE format('SELECT EXISTS(SELECT 1 FROM %I WHERE id = $1)', v_table_name)
            INTO v_exists_b USING v_pair.entity_b_id;

          IF NOT v_exists_a OR NOT v_exists_b THEN
            UPDATE scraper_dedupe_decisions SET decision = 'skip' WHERE id = v_pair.id;
            CONTINUE;
          END IF;

          IF v_pair.confidence >= p_auto_merge_threshold THEN
            IF NOT p_dry_run THEN
              BEGIN
                EXECUTE format(
                  'SELECT count(*) FROM jsonb_each(to_jsonb(r.*)) WHERE value::text NOT IN (''null'', ''""'', ''0'', ''false'')
                   FROM %I r WHERE r.id = $1', v_table_name
                ) INTO v_count_a USING v_pair.entity_a_id;
                EXECUTE format(
                  'SELECT count(*) FROM jsonb_each(to_jsonb(r.*)) WHERE value::text NOT IN (''null'', ''""'', ''0'', ''false'')
                   FROM %I r WHERE r.id = $1', v_table_name
                ) INTO v_count_b USING v_pair.entity_b_id;
              EXCEPTION WHEN OTHERS THEN
                v_count_a := 0; v_count_b := 0;
              END;

              IF v_count_a >= v_count_b THEN
                v_keep_id := v_pair.entity_a_id;
                v_remove_id := v_pair.entity_b_id;
              ELSE
                v_keep_id := v_pair.entity_b_id;
                v_remove_id := v_pair.entity_a_id;
              END IF;

              BEGIN
                v_merge_result := merge_entities(v_type, v_keep_id, v_remove_id, '{}'::jsonb);
                IF (v_merge_result->>'success')::boolean THEN
                  v_type_merged := v_type_merged + 1;
                  UPDATE scraper_dedupe_decisions
                  SET decision = 'skip'
                  WHERE decision = 'pending'
                    AND entity_type = v_type
                    AND (entity_a_id = v_remove_id OR entity_b_id = v_remove_id)
                    AND id != v_pair.id;
                ELSE
                  v_type_errors := array_append(v_type_errors, 'Merge failed for ' || v_pair.entity_a_id::text || ' + ' || v_pair.entity_b_id::text);
                END IF;
              EXCEPTION WHEN OTHERS THEN
                v_type_errors := array_append(v_type_errors, 'Merge error: ' || SQLERRM);
              END;
            ELSE
              v_type_merged := v_type_merged + 1;
            END IF;
          ELSE
            v_type_flagged := v_type_flagged + 1;
          END IF;
        END LOOP;
      END IF;  -- end not p_scan_only

      v_result := jsonb_set(v_result, ARRAY['by_type', v_type],
        jsonb_build_object(
          'scanned', v_type_scanned,
          'auto_merged', v_type_merged,
          'flagged_for_review', v_type_flagged,
          'total', v_type_total,
          'has_more', v_type_has_more,
          'errors', to_jsonb(v_type_errors)
        )
      );
      v_result := jsonb_set(v_result, '{total_scanned}', to_jsonb((v_result->>'total_scanned')::int + v_type_scanned));
      v_result := jsonb_set(v_result, '{total_auto_merged}', to_jsonb((v_result->>'total_auto_merged')::int + v_type_merged));
      v_result := jsonb_set(v_result, '{total_flagged}', to_jsonb((v_result->>'total_flagged')::int + v_type_flagged));
    END LOOP;
  END IF;

  -- Tags handled separately (only on offset=0, non-scan-only)
  IF NOT p_scan_only AND p_offset = 0 AND 'tags' = ANY(p_entity_types) THEN
    BEGIN
      DECLARE
        v_tag_result jsonb;
      BEGIN
        v_tag_result := auto_clean_merge_duplicates(p_dry_run, p_auto_merge_threshold::real);
        v_result := jsonb_set(v_result, ARRAY['by_type', 'tags'],
          jsonb_build_object(
            'scanned', COALESCE((v_tag_result->>'total_exact_merges')::int, 0) + COALESCE((v_tag_result->>'total_near_merges')::int, 0) + COALESCE((v_tag_result->>'total_skipped')::int, 0),
            'auto_merged', COALESCE((v_tag_result->>'total_exact_merges')::int, 0) + COALESCE((v_tag_result->>'total_near_merges')::int, 0),
            'flagged_for_review', COALESCE((v_tag_result->>'total_skipped')::int, 0),
            'whitespace_fixed', COALESCE((v_tag_result->>'whitespace_fixed')::int, 0),
            'junction_fixed', COALESCE((v_tag_result->>'junction_fixed')::int, 0),
            'errors', '[]'::jsonb,
            'details', v_tag_result
          )
        );
        v_result := jsonb_set(v_result, '{total_auto_merged}',
          to_jsonb((v_result->>'total_auto_merged')::int + COALESCE((v_tag_result->>'total_exact_merges')::int, 0) + COALESCE((v_tag_result->>'total_near_merges')::int, 0))
        );
        v_result := jsonb_set(v_result, '{total_flagged}',
          to_jsonb((v_result->>'total_flagged')::int + COALESCE((v_tag_result->>'total_skipped')::int, 0))
        );
      END;
    EXCEPTION WHEN OTHERS THEN
      v_result := jsonb_set(v_result, ARRAY['by_type', 'tags'],
        jsonb_build_object('scanned', 0, 'auto_merged', 0, 'flagged_for_review', 0, 'errors', jsonb_build_array('Tag dedup error: ' || SQLERRM))
      );
    END;
  END IF;

  RETURN v_result;
END;
$_$;


ALTER FUNCTION "public"."auto_clean_all_duplicates"("p_auto_merge_threshold" numeric, "p_review_threshold" numeric, "p_entity_types" "text"[], "p_limit" integer, "p_dry_run" boolean, "p_offset" integer, "p_scan_only" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_clean_merge_duplicates"("dry_run" boolean DEFAULT true, "near_dupe_threshold" real DEFAULT 0.85) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    SET "statement_timeout" TO '60s'
    AS $_$
DECLARE
  result jsonb := '{"exact_merges": [], "near_merges": [], "skipped": [], "junction_fixed": 0, "whitespace_fixed": 0}'::jsonb;
  rec record;
  keep_id uuid;
  merge_id uuid;
  merge_count integer := 0;
  junction_count integer := 0;
  ws_count integer := 0;
BEGIN
  -- ============================================================
  -- PHASE 1: Fix whitespace in tag names (double spaces, leading/trailing)
  -- ============================================================
  IF NOT dry_run THEN
    UPDATE unified_tags
    SET name = regexp_replace(trim(name), '\s{2,}', ' ', 'g')
    WHERE status = 'active'
      AND (name ~ '\s{2,}' OR name != trim(name));
    GET DIAGNOSTICS ws_count = ROW_COUNT;
  ELSE
    SELECT count(*) INTO ws_count
    FROM unified_tags
    WHERE status = 'active'
      AND (name ~ '\s{2,}' OR name != trim(name));
  END IF;
  result := jsonb_set(result, '{whitespace_fixed}', to_jsonb(ws_count));

  -- ============================================================
  -- PHASE 2: Exact-name duplicates (case-insensitive, after whitespace normalization)
  -- ============================================================
  FOR rec IN
    SELECT 
      a.id as id_a, a.name as name_a, a.slug as slug_a, a.category_id as cat_a, a.usage_count as use_a,
      b.id as id_b, b.name as name_b, b.slug as slug_b, b.category_id as cat_b, b.usage_count as use_b
    FROM unified_tags a
    JOIN unified_tags b ON lower(regexp_replace(trim(a.name), '\s{2,}', ' ', 'g')) = lower(regexp_replace(trim(b.name), '\s{2,}', ' ', 'g'))
      AND a.id < b.id
    WHERE a.status = 'active' AND b.status = 'active'
    ORDER BY a.name
  LOOP
    -- Prefer cleaner slug (no special chars), then higher usage, then older
    IF rec.slug_a ~ '^[a-z0-9-]+$' AND rec.slug_b ~ '[^a-z0-9-]' THEN
      keep_id := rec.id_a; merge_id := rec.id_b;
    ELSIF rec.slug_b ~ '^[a-z0-9-]+$' AND rec.slug_a ~ '[^a-z0-9-]' THEN
      keep_id := rec.id_b; merge_id := rec.id_a;
    ELSIF rec.use_a >= rec.use_b THEN
      keep_id := rec.id_a; merge_id := rec.id_b;
    ELSE
      keep_id := rec.id_b; merge_id := rec.id_a;
    END IF;

    IF dry_run THEN
      result := jsonb_set(result, '{exact_merges}',
        (result->'exact_merges') || jsonb_build_object(
          'keep', (SELECT name FROM unified_tags WHERE id = keep_id),
          'keep_slug', (SELECT slug FROM unified_tags WHERE id = keep_id),
          'merge', (SELECT name FROM unified_tags WHERE id = merge_id),
          'merge_slug', (SELECT slug FROM unified_tags WHERE id = merge_id)
        )
      );
    ELSE
      IF EXISTS (SELECT 1 FROM unified_tags WHERE id = merge_id AND status = 'active')
         AND EXISTS (SELECT 1 FROM unified_tags WHERE id = keep_id AND status = 'active') THEN
        PERFORM merge_tag(merge_id, keep_id);
        result := jsonb_set(result, '{exact_merges}',
          (result->'exact_merges') || jsonb_build_object(
            'keep', (SELECT name FROM unified_tags WHERE id = keep_id),
            'keep_slug', (SELECT slug FROM unified_tags WHERE id = keep_id),
            'merged', (SELECT name FROM unified_tags WHERE id = merge_id),
            'merged_slug', (SELECT slug FROM unified_tags WHERE id = merge_id)
          )
        );
        merge_count := merge_count + 1;
      END IF;
    END IF;
  END LOOP;

  -- ============================================================
  -- PHASE 3: Near-duplicates — acronym variants, spacing/hyphen variants
  -- ============================================================
  FOR rec IN
    SELECT 
      a.id as id_a, a.name as name_a, a.slug as slug_a, a.usage_count as use_a,
      b.id as id_b, b.name as name_b, b.slug as slug_b, b.usage_count as use_b,
      similarity(lower(a.name), lower(b.name)) as sim
    FROM unified_tags a
    JOIN unified_tags b ON a.id < b.id
    WHERE a.status = 'active' AND b.status = 'active'
      AND similarity(lower(a.name), lower(b.name)) >= near_dupe_threshold
      AND lower(a.name) != lower(b.name)
      AND (
        -- "X" vs "X (ABC)" pattern
        lower(a.name) = regexp_replace(lower(b.name), '\s*\([^)]+\)\s*$', '')
        OR lower(b.name) = regexp_replace(lower(a.name), '\s*\([^)]+\)\s*$', '')
        -- "X-Y" vs "X Y" (hyphen vs space)
        OR lower(replace(a.name, '-', ' ')) = lower(replace(b.name, '-', ' '))
        -- "X- Y" vs "X-Y" (extra space around hyphen)
        OR lower(regexp_replace(a.name, '\s*-\s*', '-', 'g')) = lower(regexp_replace(b.name, '\s*-\s*', '-', 'g'))
      )
    ORDER BY sim DESC
  LOOP
    -- Keep logic:
    -- 1. If one has trailing "(ACRONYM)" → keep that one (more informative)
    -- 2. If one slug is cleaner → keep it
    -- 3. Otherwise prefer shorter name (cleaner variant)
    IF rec.name_a ~ '\([^)]+\)\s*$' AND NOT rec.name_b ~ '\([^)]+\)\s*$' THEN
      keep_id := rec.id_a; merge_id := rec.id_b;
    ELSIF rec.name_b ~ '\([^)]+\)\s*$' AND NOT rec.name_a ~ '\([^)]+\)\s*$' THEN
      keep_id := rec.id_b; merge_id := rec.id_a;
    ELSIF rec.slug_a ~ '^[a-z0-9-]+$' AND rec.slug_b ~ '[^a-z0-9-]' THEN
      keep_id := rec.id_a; merge_id := rec.id_b;
    ELSIF rec.slug_b ~ '^[a-z0-9-]+$' AND rec.slug_a ~ '[^a-z0-9-]' THEN
      keep_id := rec.id_b; merge_id := rec.id_a;
    ELSIF length(rec.name_a) <= length(rec.name_b) THEN
      keep_id := rec.id_a; merge_id := rec.id_b;
    ELSE
      keep_id := rec.id_b; merge_id := rec.id_a;
    END IF;

    IF dry_run THEN
      result := jsonb_set(result, '{near_merges}',
        (result->'near_merges') || jsonb_build_object(
          'keep', (SELECT name FROM unified_tags WHERE id = keep_id),
          'merge', (SELECT name FROM unified_tags WHERE id = merge_id),
          'similarity', rec.sim
        )
      );
    ELSE
      IF EXISTS (SELECT 1 FROM unified_tags WHERE id = merge_id AND status = 'active')
         AND EXISTS (SELECT 1 FROM unified_tags WHERE id = keep_id AND status = 'active') THEN
        PERFORM merge_tag(merge_id, keep_id);
        result := jsonb_set(result, '{near_merges}',
          (result->'near_merges') || jsonb_build_object(
            'keep', (SELECT name FROM unified_tags WHERE id = keep_id),
            'merged', (SELECT name FROM unified_tags WHERE id = merge_id),
            'similarity', rec.sim
          )
        );
        merge_count := merge_count + 1;
      END IF;
    END IF;
  END LOOP;

  -- ============================================================
  -- PHASE 4: Report remaining near-dupes for manual review
  -- ============================================================
  FOR rec IN
    SELECT 
      a.name as name_a, a.slug as slug_a,
      b.name as name_b, b.slug as slug_b,
      similarity(lower(a.name), lower(b.name)) as sim
    FROM unified_tags a
    JOIN unified_tags b ON a.id < b.id
    WHERE a.status = 'active' AND b.status = 'active'
      AND similarity(lower(a.name), lower(b.name)) >= near_dupe_threshold
      AND lower(a.name) != lower(b.name)
      AND NOT (
        lower(a.name) = regexp_replace(lower(b.name), '\s*\([^)]+\)\s*$', '')
        OR lower(b.name) = regexp_replace(lower(a.name), '\s*\([^)]+\)\s*$', '')
        OR lower(replace(a.name, '-', ' ')) = lower(replace(b.name, '-', ' '))
        OR lower(regexp_replace(a.name, '\s*-\s*', '-', 'g')) = lower(regexp_replace(b.name, '\s*-\s*', '-', 'g'))
      )
    ORDER BY sim DESC
    LIMIT 50
  LOOP
    result := jsonb_set(result, '{skipped}',
      (result->'skipped') || jsonb_build_object(
        'tag_a', rec.name_a,
        'tag_b', rec.name_b,
        'similarity', rec.sim,
        'reason', 'needs_manual_review'
      )
    );
  END LOOP;

  -- ============================================================
  -- PHASE 5: Fix missing junction entries
  -- ============================================================
  IF NOT dry_run THEN
    junction_count := fix_missing_junction_entries();
  ELSE
    SELECT count(*) INTO junction_count
    FROM unified_tags ut
    WHERE ut.status = 'active'
      AND ut.category_id IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM tag_category_assignments tca WHERE tca.tag_id = ut.id);
  END IF;
  result := jsonb_set(result, '{junction_fixed}', to_jsonb(junction_count));

  -- Summary
  result := result || jsonb_build_object(
    'dry_run', dry_run,
    'total_exact_merges', jsonb_array_length(result->'exact_merges'),
    'total_near_merges', jsonb_array_length(result->'near_merges'),
    'total_skipped', jsonb_array_length(result->'skipped'),
    'threshold', near_dupe_threshold
  );

  RETURN result;
END;
$_$;


ALTER FUNCTION "public"."auto_clean_merge_duplicates"("dry_run" boolean, "near_dupe_threshold" real) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_escalate_stale_feedback"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_updated integer := 0;
BEGIN
  WITH last_touched AS (
    SELECT submission_id, max(at) AS last_at
    FROM community_submissions_audit
    GROUP BY submission_id
  ),
  eligible AS (
    SELECT cs.id
    FROM community_submissions cs
    LEFT JOIN last_touched lt ON lt.submission_id = cs.id
    WHERE cs.content_type = 'feedback'
      AND cs.is_spam = false
      AND cs.duplicate_of IS NULL
      AND cs.feedback_status <> 'done'
      AND cs.priority > 0
      AND cs.submitted_at < now() - interval '14 days'
      AND coalesce(lt.last_at, cs.submitted_at) < now() - interval '7 days'
  )
  UPDATE community_submissions cs
  SET priority = greatest(0, priority - 1),
      reviewed_at = now()
  FROM eligible e
  WHERE cs.id = e.id;

  GET DIAGNOSTICS v_updated = ROW_COUNT;
  RETURN v_updated;
END;
$$;


ALTER FUNCTION "public"."auto_escalate_stale_feedback"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_remove_broken_link"("link_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  _link content_links%ROWTYPE;
BEGIN
  SELECT * INTO _link FROM content_links WHERE id = link_id;
  IF NOT FOUND THEN RETURN; END IF;

  -- Null-out the URL field on the source content table
  EXECUTE format(
    'UPDATE %I SET %I = NULL WHERE id = $1',
    _link.content_type, _link.field_name
  ) USING _link.content_id;

  -- Mark the content_link as auto-removed
  UPDATE content_links
  SET status = 'AUTO_REMOVED',
      auto_removed_at = NOW(),
      check_count = check_count + 1
  WHERE id = link_id;
END;
$_$;


ALTER FUNCTION "public"."auto_remove_broken_link"("link_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_slug_from_name"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
BEGIN
  IF NEW.slug IS NULL OR NEW.slug = '' THEN
    NEW.slug := public.generate_unique_slug(TG_TABLE_NAME, public.generate_slug(NEW.name), NEW.id);
  END IF;
  RETURN NEW;
END;
$$;


