CREATE OR REPLACE FUNCTION "public"."auto_story_for_submission"("p_submission_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_submission record;
  v_title text;
  v_embedding vector(768);
  v_match_story uuid;
  v_new_story uuid;
BEGIN
  SELECT id, content_type, data, embedding, feedback_status, is_spam, duplicate_of
    INTO v_submission
    FROM community_submissions
   WHERE id = p_submission_id;
  IF NOT FOUND THEN RETURN NULL; END IF;
  IF v_submission.is_spam OR v_submission.duplicate_of IS NOT NULL THEN RETURN NULL; END IF;

  SELECT m.story_id INTO v_match_story
    FROM feedback_story_members m
    JOIN feedback_stories s ON s.id = m.story_id
   WHERE m.submission_id = p_submission_id
     AND s.status NOT IN ('resolved', 'archived')
   LIMIT 1;
  IF v_match_story IS NOT NULL THEN RETURN v_match_story; END IF;

  v_title := COALESCE(
    NULLIF(v_submission.data->>'title', ''),
    NULLIF(v_submission.data->>'message', ''),
    'Untitled'
  );
  v_embedding := v_submission.embedding;

  SELECT s.id INTO v_match_story
    FROM feedback_stories s
    JOIN feedback_story_members m ON m.story_id = s.id
    JOIN community_submissions cs ON cs.id = m.submission_id
   WHERE s.status NOT IN ('resolved', 'archived')
     AND similarity(COALESCE(cs.data->>'title', cs.data->>'message', ''), v_title) >= 0.45
   ORDER BY similarity(COALESCE(cs.data->>'title', cs.data->>'message', ''), v_title) DESC
   LIMIT 1;

  IF v_match_story IS NULL AND v_embedding IS NOT NULL THEN
    SELECT s.id INTO v_match_story
      FROM feedback_stories s
      JOIN feedback_story_members m ON m.story_id = s.id
      JOIN community_submissions cs ON cs.id = m.submission_id
     WHERE s.status NOT IN ('resolved', 'archived')
       AND cs.embedding IS NOT NULL
       AND (1 - (cs.embedding <=> v_embedding)) >= 0.80
     ORDER BY (cs.embedding <=> v_embedding) ASC
     LIMIT 1;
  END IF;

  IF v_match_story IS NOT NULL THEN
    INSERT INTO feedback_story_members (story_id, submission_id)
    VALUES (v_match_story, p_submission_id)
    ON CONFLICT DO NOTHING;
    RETURN v_match_story;
  END IF;

  INSERT INTO feedback_stories (title, origin)
  VALUES (v_title, CASE WHEN v_submission.content_type = 'api_error' THEN 'ai_suggested' ELSE 'manual' END)
  RETURNING id INTO v_new_story;

  INSERT INTO feedback_story_members (story_id, submission_id)
  VALUES (v_new_story, p_submission_id)
  ON CONFLICT DO NOTHING;

  RETURN v_new_story;
END;
$$;


ALTER FUNCTION "public"."auto_story_for_submission"("p_submission_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."basic_rate_limit"("identifier" "text", "max_attempts" integer DEFAULT 10) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  current_attempts INTEGER;
BEGIN
  -- Simple rate limiting without complex cleanup
  SELECT COALESCE(attempt_count, 0) INTO current_attempts
  FROM public.auth_rate_limit_keys
  WHERE key = identifier
  AND last_attempt > NOW() - INTERVAL '1 hour';
  
  IF current_attempts >= max_attempts THEN
    RETURN FALSE;
  END IF;
  
  INSERT INTO public.auth_rate_limit_keys (key, attempt_count, last_attempt)
  VALUES (identifier, 1, now())
  ON CONFLICT (key) 
  DO UPDATE SET 
    attempt_count = auth_rate_limit_keys.attempt_count + 1,
    last_attempt = now();
  
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."basic_rate_limit"("identifier" "text", "max_attempts" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."batch_find_duplicates"("p_target_table" "text" DEFAULT NULL::"text", "p_batch_limit" integer DEFAULT 100) RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_item RECORD; v_match RECORD;
  v_processed INT := 0; v_found_dupes INT := 0; v_found_candidates INT := 0; v_skipped INT := 0;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role,'moderator'::app_role]) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE='42501'; END IF;
  FOR v_item IN
    SELECT id, target_table, normalized_data FROM ingestion_staging
    WHERE (p_target_table IS NULL OR target_table=p_target_table)
      AND dedup_status IN ('unique','pending') AND review_status='pending_review'
      AND disposition='pending' AND normalized_data IS NOT NULL
    ORDER BY created_at ASC LIMIT p_batch_limit
  LOOP
    v_processed := v_processed + 1;
    IF v_item.target_table='venues' THEN
      SELECT INTO v_match venue_id, venue_name, combined_score
      FROM find_venue_duplicates((v_item.normalized_data->>'name')::text,
        COALESCE((v_item.normalized_data->>'latitude')::numeric, 0),
        COALESCE((v_item.normalized_data->>'longitude')::numeric, 0),
        (v_item.normalized_data->>'category')::text, 0.5)
      ORDER BY combined_score DESC LIMIT 1;
      IF v_match.venue_id IS NOT NULL THEN
        IF v_match.combined_score >= 0.85 THEN
          UPDATE ingestion_staging SET dedup_status='duplicate', dedup_match_id=v_match.venue_id,
            dedup_match_table='venues', dedup_match_score=v_match.combined_score,
            dedup_details=jsonb_build_object('matched_name',v_match.venue_name,'score',v_match.combined_score,'method','trigram+geo'),
            updated_at=now() WHERE id=v_item.id;
          v_found_dupes := v_found_dupes+1;
        ELSIF v_match.combined_score >= 0.6 THEN
          UPDATE ingestion_staging SET dedup_status='merge_candidate', dedup_match_id=v_match.venue_id,
            dedup_match_table='venues', dedup_match_score=v_match.combined_score,
            dedup_details=jsonb_build_object('matched_name',v_match.venue_name,'score',v_match.combined_score,'method','trigram+geo'),
            updated_at=now() WHERE id=v_item.id;
          v_found_candidates := v_found_candidates+1;
        END IF;
      END IF;
    ELSIF v_item.target_table='events' THEN
      SELECT INTO v_match event_id, event_title, combined_score
      FROM find_event_duplicates((v_item.normalized_data->>'title')::text,
        COALESCE((v_item.normalized_data->>'start_date')::timestamptz, now()),
        (v_item.normalized_data->>'city')::text)
      ORDER BY combined_score DESC LIMIT 1;
      IF v_match.event_id IS NOT NULL THEN
        IF v_match.combined_score >= 0.85 THEN
          UPDATE ingestion_staging SET dedup_status='duplicate', dedup_match_id=v_match.event_id,
            dedup_match_table='events', dedup_match_score=v_match.combined_score,
            dedup_details=jsonb_build_object('matched_title',v_match.event_title,'score',v_match.combined_score,'method','trigram+date+city'),
            updated_at=now() WHERE id=v_item.id;
          v_found_dupes := v_found_dupes+1;
        ELSIF v_match.combined_score >= 0.6 THEN
          UPDATE ingestion_staging SET dedup_status='merge_candidate', dedup_match_id=v_match.event_id,
            dedup_match_table='events', dedup_match_score=v_match.combined_score,
            dedup_details=jsonb_build_object('matched_title',v_match.event_title,'score',v_match.combined_score,'method','trigram+date+city'),
            updated_at=now() WHERE id=v_item.id;
          v_found_candidates := v_found_candidates+1;
        END IF;
      END IF;
    ELSIF v_item.target_table='personalities' THEN
      SELECT INTO v_match personality_id, personality_name, name_similarity
      FROM find_personality_duplicates((v_item.normalized_data->>'name')::text, 0.6)
      ORDER BY name_similarity DESC LIMIT 1;
      IF v_match.personality_id IS NOT NULL THEN
        IF v_match.name_similarity >= 0.85 THEN
          UPDATE ingestion_staging SET dedup_status='duplicate', dedup_match_id=v_match.personality_id,
            dedup_match_table='personalities', dedup_match_score=v_match.name_similarity,
            dedup_details=jsonb_build_object('matched_name',v_match.personality_name,'score',v_match.name_similarity,'method','trigram_name'),
            updated_at=now() WHERE id=v_item.id;
          v_found_dupes := v_found_dupes+1;
        ELSIF v_match.name_similarity >= 0.6 THEN
          UPDATE ingestion_staging SET dedup_status='merge_candidate', dedup_match_id=v_match.personality_id,
            dedup_match_table='personalities', dedup_match_score=v_match.name_similarity,
            dedup_details=jsonb_build_object('matched_name',v_match.personality_name,'score',v_match.name_similarity,'method','trigram_name'),
            updated_at=now() WHERE id=v_item.id;
          v_found_candidates := v_found_candidates+1;
        END IF;
      END IF;
    ELSE v_skipped := v_skipped+1; END IF;
  END LOOP;
  RETURN json_build_object('processed',v_processed,'duplicates_found',v_found_dupes,
    'merge_candidates_found',v_found_candidates,'skipped',v_skipped);
END;
$$;


