CREATE OR REPLACE FUNCTION "public"."batch_match_tag_embeddings"("p_content_type" "text", "p_content_ids" "uuid"[], "p_match_threshold" double precision DEFAULT 0.7, "p_match_count" integer DEFAULT 8) RETURNS TABLE("content_id" "uuid", "tag_id" "uuid", "tag_name" "text", "similarity" double precision)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ce.content_id,
    sub.tag_id,
    sub.tag_name,
    sub.similarity
  FROM public.content_embeddings ce
  CROSS JOIN LATERAL (
    SELECT
      te.content_id AS tag_id,
      ut.name AS tag_name,
      (1 - (ce.embedding <=> te.embedding))::double precision AS similarity
    FROM public.content_embeddings te
    JOIN public.unified_tags ut ON ut.id = te.content_id AND ut.status = 'active'
    WHERE te.content_type = 'tag'
      AND (1 - (ce.embedding <=> te.embedding)) >= p_match_threshold
    ORDER BY ce.embedding <=> te.embedding
    LIMIT p_match_count
  ) sub
  WHERE ce.content_type = p_content_type
    AND ce.content_id = ANY(p_content_ids);
END;
$$;


ALTER FUNCTION "public"."batch_match_tag_embeddings"("p_content_type" "text", "p_content_ids" "uuid"[], "p_match_threshold" double precision, "p_match_count" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."bulk_apply_batch_changes"("p_batch_id" "text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_applied INT := 0;
  v_id UUID;
BEGIN
  FOR v_id IN
    SELECT id FROM public.content_changes
    WHERE batch_id = p_batch_id AND status = 'auto_approved'
    ORDER BY created_at
  LOOP
    BEGIN
      IF public.apply_content_change(v_id) THEN
        v_applied := v_applied + 1;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'bulk_apply_batch skipped %: %', v_id, SQLERRM;
    END;
  END LOOP;
  RETURN v_applied;
END;
$$;


ALTER FUNCTION "public"."bulk_apply_batch_changes"("p_batch_id" "text") OWNER TO "postgres";


