CREATE OR REPLACE FUNCTION "public"."can_view_sensitive_profile_data"("profile_user_id" "uuid", "requesting_user_id" "uuid", "privacy_field" "text" DEFAULT 'profile_visibility'::"text") RETURNS boolean
    LANGUAGE "sql" STABLE
    SET "search_path" TO ''
    AS $$
  SELECT CASE
    -- Users can always see their own data
    WHEN profile_user_id = requesting_user_id THEN true
    -- Check if specific field is public
    WHEN EXISTS (
      SELECT 1 FROM public.profiles 
      WHERE user_id = profile_user_id 
      AND COALESCE((privacy_settings ->> privacy_field)::boolean, false) = true
    ) THEN true
    -- Admins can view data (this will be controlled by RLS policies)
    WHEN requesting_user_id IN (
      SELECT ur.user_id FROM public.user_roles ur WHERE ur.role = 'admin'
    ) THEN true
    ELSE false
  END;
$$;


