    "runner" "text" NOT NULL,
    "prompt" "text" NOT NULL,
    "prompt_hash" "text" NOT NULL,
    "external_ref" "text",
    "pr_url" "text",
    "commit_sha" "text",
    "files_changed" "text"[],
    "fix_summary" "text",
    "confidence" "text",
    "risks" "text",
    "error" "text",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "finished_at" timestamp with time zone,
    CONSTRAINT "feedback_routine_runs_confidence_check" CHECK ((("confidence" IS NULL) OR ("confidence" = ANY (ARRAY['low'::"text", 'medium'::"text", 'high'::"text"])))),
    CONSTRAINT "feedback_routine_runs_runner_check" CHECK (("runner" = ANY (ARRAY['mock'::"text", 'github_actions'::"text", 'webhook'::"text", 'api'::"text", 'local'::"text"]))),
    CONSTRAINT "feedback_routine_runs_status_check" CHECK (("status" = ANY (ARRAY['queued'::"text", 'dispatched'::"text", 'in_progress'::"text", 'fix_proposed'::"text", 'failed'::"text", 'cancelled'::"text"])))
);


