CREATE OR REPLACE FUNCTION "public"."cancel_routine_run"("p_run_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "public"."feedback_routine_runs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_run feedback_routine_runs%ROWTYPE;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  UPDATE feedback_routine_runs
     SET status='cancelled', finished_at=COALESCE(finished_at, now()),
         error=COALESCE(p_reason, error)
   WHERE id = p_run_id AND status IN ('queued','dispatched','in_progress')
   RETURNING * INTO v_run;
  IF NOT FOUND THEN RAISE EXCEPTION 'run_not_cancellable'; END IF;
  PERFORM _fb_log_event(v_run.story_id, 'routine_cancelled',
    jsonb_build_object('reason', p_reason), 'user', v_run.id);
  RETURN v_run;
END;
$$;


