CREATE OR REPLACE FUNCTION "public"."canonical_profession"("p" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE PARALLEL SAFE
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
  SELECT CASE
    WHEN p IS NULL OR BTRIM(p) = '' THEN NULL
    WHEN lower(BTRIM(p)) ~ '(film|television|stage|voice|movie|theatre|theater) *(actor|actress)'
      OR lower(BTRIM(p)) IN ('actor','actress') THEN 'Actor'
    WHEN lower(BTRIM(p)) IN ('singer','vocalist','pop singer') THEN 'Singer'
    WHEN lower(BTRIM(p)) IN ('singer-songwriter','songwriter') THEN 'Singer-songwriter'
    WHEN lower(BTRIM(p)) ~ '(lgbtq|lgbt|gay|queer|trans|human rights|women''?s rights) rights? activist'
      OR lower(BTRIM(p)) IN ('activist','rights activist') THEN 'Activist'
    WHEN lower(BTRIM(p)) IN ('writer','novelist','author','essayist') THEN 'Writer'
    WHEN lower(BTRIM(p)) IN ('poet') THEN 'Poet'
    WHEN lower(BTRIM(p)) IN ('journalist','columnist','reporter') THEN 'Journalist'
    WHEN lower(BTRIM(p)) IN ('politician','statesman','stateswoman','diplomat') THEN 'Politician'
    WHEN lower(BTRIM(p)) IN ('drag queen','drag king','drag performer') THEN 'Drag queen'
    WHEN lower(BTRIM(p)) IN ('film director','director','movie director') THEN 'Director'
    WHEN lower(BTRIM(p)) IN ('composer','orchestral composer','music composer') THEN 'Composer'
    WHEN lower(BTRIM(p)) IN ('musician','instrumentalist','pianist','guitarist','drummer','bassist') THEN 'Musician'
    WHEN lower(BTRIM(p)) IN ('comedian','stand-up comedian','humorist') THEN 'Comedian'
    WHEN lower(BTRIM(p)) IN ('photographer','photojournalist') THEN 'Photographer'
    WHEN lower(BTRIM(p)) IN ('model','fashion model','supermodel') THEN 'Model'
    WHEN lower(BTRIM(p)) IN ('painter','visual artist','sculptor','artist') THEN 'Artist'
    WHEN lower(BTRIM(p)) IN ('researcher','scientist','biologist','chemist','physicist') THEN 'Researcher'
    WHEN lower(BTRIM(p)) IN ('screenwriter','scenarist') THEN 'Screenwriter'
    WHEN lower(BTRIM(p)) IN ('fashion designer','designer','stylist') THEN 'Fashion designer'
    WHEN lower(BTRIM(p)) IN ('rapper','hip hop artist') THEN 'Rapper'
    ELSE INITCAP(BTRIM(p))
  END;
$$;


ALTER FUNCTION "public"."canonical_profession"("p" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cascade_story_to_members"("p_story_id" "uuid", "p_status" "text" DEFAULT NULL::"text", "p_priority" smallint DEFAULT NULL::smallint, "p_assignee_id" "uuid" DEFAULT NULL::"uuid", "p_resolution" "text" DEFAULT NULL::"text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count integer := 0;
  v_feedback_status text;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  v_feedback_status := CASE p_status
    WHEN 'planned' THEN 'planned'
    WHEN 'in_progress' THEN 'in_progress'
    WHEN 'resolved' THEN 'done'
    WHEN 'archived' THEN 'done'
    ELSE NULL
  END;
  UPDATE community_submissions cs
     SET feedback_status = COALESCE(v_feedback_status, cs.feedback_status),
         priority        = COALESCE(p_priority, cs.priority),
         assignee_id     = COALESCE(p_assignee_id, cs.assignee_id),
         resolution      = COALESCE(p_resolution, cs.resolution),
         resolved_at     = CASE
                             WHEN p_status IN ('resolved', 'archived') AND cs.resolved_at IS NULL
                             THEN now()
                             ELSE cs.resolved_at
                           END
    FROM feedback_story_members m
   WHERE m.story_id = p_story_id
     AND cs.id = m.submission_id
     AND (p_status IS NOT NULL OR p_priority IS NOT NULL OR p_assignee_id IS NOT NULL OR p_resolution IS NOT NULL);
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."cascade_story_to_members"("p_story_id" "uuid", "p_status" "text", "p_priority" smallint, "p_assignee_id" "uuid", "p_resolution" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_financial_data_access"("p_user_id" "uuid", "p_admin_user_id" "uuid", "p_justification" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_caller uuid := auth.uid();
  admin_role_verified boolean := false;
BEGIN
  IF v_caller IS NULL THEN RETURN FALSE; END IF;
  IF p_admin_user_id IS NOT NULL AND p_admin_user_id <> v_caller THEN
    PERFORM public.log_security_event('FINANCIAL_ACCESS_DENIED_IDENTITY_MISMATCH', v_caller,
      jsonb_build_object('claimed_admin', p_admin_user_id, 'target_user', p_user_id), 'critical');
    RETURN FALSE;
  END IF;
  SELECT EXISTS(SELECT 1 FROM public.user_roles WHERE user_id = v_caller AND role = 'admin'::public.app_role)
  INTO admin_role_verified;
  IF NOT admin_role_verified THEN RETURN FALSE; END IF;
  IF p_justification IS NULL OR length(p_justification) < 20 THEN
    PERFORM public.log_security_event('FINANCIAL_ACCESS_DENIED_INSUFFICIENT_JUSTIFICATION', v_caller,
      jsonb_build_object('target_user', p_user_id, 'justification', COALESCE(p_justification, 'none')), 'high');
    RETURN FALSE;
  END IF;
  PERFORM public.log_security_event('FINANCIAL_DATA_ACCESS_REQUEST', v_caller,
    jsonb_build_object('target_user', p_user_id, 'justification', p_justification, 'access_granted', true), 'high');
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."check_financial_data_access"("p_user_id" "uuid", "p_admin_user_id" "uuid", "p_justification" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_mailbox_availability"("p_address" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
BEGIN
  -- Check format
  IF p_address !~ '^[a-z0-9][a-z0-9.\-]{1,28}[a-z0-9]$' THEN
    RETURN jsonb_build_object('available', false, 'reason', 'Invalid format. Use 3-30 lowercase letters, numbers, dots, or hyphens.');
  END IF;
  
  -- Check reserved
  IF EXISTS (SELECT 1 FROM mailbox_reserved_addresses WHERE address = p_address) THEN
    RETURN jsonb_build_object('available', false, 'reason', 'This address is reserved.');
  END IF;
  
  -- Check taken
  IF EXISTS (SELECT 1 FROM profiles WHERE mailbox_address = p_address) THEN
    RETURN jsonb_build_object('available', false, 'reason', 'This address is already taken.');
  END IF;
  
  RETURN jsonb_build_object('available', true, 'reason', null);
END;
$_$;


ALTER FUNCTION "public"."check_mailbox_availability"("p_address" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_pipeline_health"() RETURNS TABLE("opened" integer, "resolved" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_dlq_len INT;
  v_opened INT := 0;
  v_resolved INT := 0;
  v_threshold INT := 500;
BEGIN
  -- dead_letter backlog
  SELECT queue_length INTO v_dlq_len
    FROM public.pgmq_metrics('dead_letter');

  IF v_dlq_len > v_threshold THEN
    INSERT INTO public.pipeline_health_alerts (kind, subject, detail)
    VALUES ('dead_letter_backlog', 'dead_letter',
            jsonb_build_object('queue_length', v_dlq_len, 'threshold', v_threshold))
    ON CONFLICT (kind, subject) WHERE resolved_at IS NULL DO UPDATE
      SET detail = EXCLUDED.detail, last_seen_at = now();
    v_opened := v_opened + 1;
  ELSE
    UPDATE public.pipeline_health_alerts
      SET resolved_at = now()
      WHERE kind = 'dead_letter_backlog' AND subject = 'dead_letter'
        AND resolved_at IS NULL;
    GET DIAGNOSTICS v_resolved = ROW_COUNT;
  END IF;

  -- Consecutive failures per pipeline (last 5 runs, all failed)
  WITH recent AS (
    SELECT pipeline_name,
           array_agg(status ORDER BY created_at DESC) FILTER (WHERE rn <= 5) AS last_5
    FROM (
      SELECT pipeline_name, status, created_at,
             row_number() OVER (PARTITION BY pipeline_name ORDER BY created_at DESC) AS rn
      FROM public.pipeline_runs
      WHERE created_at > now() - INTERVAL '2 days'
    ) s
    WHERE rn <= 5
    GROUP BY pipeline_name
  ),
  bad AS (
    SELECT pipeline_name, last_5 FROM recent
    WHERE array_length(last_5, 1) >= 2
      AND NOT ('completed' = ANY(last_5))
  ),
  ins AS (
    INSERT INTO public.pipeline_health_alerts (kind, subject, detail)
    SELECT 'consecutive_failures', pipeline_name,
           jsonb_build_object('recent_statuses', to_jsonb(last_5))
    FROM bad
    ON CONFLICT (kind, subject) WHERE resolved_at IS NULL DO UPDATE
      SET detail = EXCLUDED.detail, last_seen_at = now()
    RETURNING 1
  )
  SELECT v_opened + count(*) INTO v_opened FROM ins;

  -- Auto-resolve any consecutive_failures alerts whose pipeline
  -- has since completed successfully.
  WITH recovered AS (
    UPDATE public.pipeline_health_alerts a
    SET resolved_at = now()
    FROM public.pipeline_runs r
    WHERE a.kind = 'consecutive_failures'
      AND a.resolved_at IS NULL
      AND r.pipeline_name = a.subject
      AND r.status = 'completed'
      AND r.created_at > a.first_seen_at
    RETURNING 1
  )
  SELECT v_resolved + count(*) INTO v_resolved FROM recovered;

  RETURN QUERY SELECT v_opened, v_resolved;
END;
$$;


ALTER FUNCTION "public"."check_pipeline_health"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_rate_limit_enhanced"("identifier" "text", "max_attempts" integer DEFAULT 10, "time_window_minutes" integer DEFAULT 60, "action_type" "text" DEFAULT 'general'::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  current_attempts integer;
  window_start timestamp;
BEGIN
  window_start := NOW() - (time_window_minutes || ' minutes')::interval;
  
  SELECT COALESCE(attempt_count, 0) INTO current_attempts
  FROM public.auth_rate_limit_keys
  WHERE key = identifier || '_' || action_type
    AND last_attempt > window_start;
  
  IF current_attempts >= max_attempts THEN
    -- Log rate limit exceeded
    PERFORM public.log_enhanced_security_event(
      'RATE_LIMIT_EXCEEDED',
      auth.uid(),
      jsonb_build_object(
        'identifier', identifier,
        'action_type', action_type,
        'attempts', current_attempts,
        'max_attempts', max_attempts
      ),
      'high'
    );
    RETURN FALSE;
  END IF;
  
  INSERT INTO public.auth_rate_limit_keys (key, attempt_count, last_attempt)
  VALUES (identifier || '_' || action_type, 1, NOW())
  ON CONFLICT (key)
  DO UPDATE SET
    attempt_count = public.auth_rate_limit_keys.attempt_count + 1,
    last_attempt = NOW();
  
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."check_rate_limit_enhanced"("identifier" "text", "max_attempts" integer, "time_window_minutes" integer, "action_type" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."circuit_breaker_check"("p_api_name" "text") RETURNS boolean
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE v_state text; v_open_until timestamptz;
BEGIN
  SELECT state, open_until INTO v_state, v_open_until
    FROM api_circuit_breakers WHERE api_name = p_api_name;
  IF v_state IS NULL THEN RETURN true; END IF;
  IF v_state <> 'open' THEN RETURN true; END IF;
  IF v_open_until IS NULL OR v_open_until < now() THEN RETURN true; END IF;
  RETURN false;
END;
$$;


ALTER FUNCTION "public"."circuit_breaker_check"("p_api_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."circuit_breaker_record_failure"("p_api_name" "text", "p_error_msg" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_row api_circuit_breakers;
  v_opened boolean := false;
BEGIN
  UPDATE api_circuit_breakers
  SET failure_count = failure_count + 1,
      last_failure_at = now(),
      updated_at = now()
  WHERE api_name = p_api_name
  RETURNING * INTO v_row;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('circuit_opened', false);
  END IF;

  IF v_row.failure_count >= v_row.threshold AND v_row.state != 'open' THEN
    UPDATE api_circuit_breakers
    SET state = 'open',
        open_until = now() + (v_row.reset_timeout_seconds || ' seconds')::interval,
        updated_at = now()
    WHERE api_name = p_api_name;
    v_opened := true;
  END IF;

  RETURN jsonb_build_object('circuit_opened', v_opened, 'failure_count', v_row.failure_count);
END;
$$;


ALTER FUNCTION "public"."circuit_breaker_record_failure"("p_api_name" "text", "p_error_msg" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."circuit_breaker_record_success"("p_api_name" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  PERFORM register_circuit_breaker(p_api_name);
  UPDATE api_circuit_breakers
     SET success_count = success_count + 1, last_success_at = now(),
         failure_count = 0, state = 'closed', open_until = NULL, updated_at = now()
   WHERE api_name = p_api_name;
END;
$$;


ALTER FUNCTION "public"."circuit_breaker_record_success"("p_api_name" "text") OWNER TO "postgres";


