CREATE OR REPLACE FUNCTION "public"."clean_staging_duplicates"("p_skip_threshold" numeric DEFAULT 0.7, "p_dry_run" boolean DEFAULT true) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "statement_timeout" TO '120s'
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_skipped_duplicates INT := 0;
  v_skipped_merge_candidates INT := 0;
  v_scanned_pending INT := 0;
  v_new_duplicates INT := 0;
  v_new_merge_candidates INT := 0;
  v_new_unique INT := 0;
  v_errors TEXT[] := '{}';
  v_item RECORD;
  v_dupes RECORD;
  v_best_score NUMERIC;
  v_best_match_id UUID;
  v_normalized JSONB;
BEGIN
  -- PHASE 1: Skip items already marked as 'duplicate' but still pending
  IF NOT p_dry_run THEN
    UPDATE ingestion_staging
    SET disposition = 'skipped',
        processed_at = NOW(),
        review_notes = COALESCE(review_notes, '') || ' [Auto-cleaned: duplicate]'
    WHERE dedup_status = 'duplicate'
      AND disposition = 'pending';
    GET DIAGNOSTICS v_skipped_duplicates = ROW_COUNT;
  ELSE
    SELECT COUNT(*) INTO v_skipped_duplicates
    FROM ingestion_staging
    WHERE dedup_status = 'duplicate' AND disposition = 'pending';
  END IF;

  -- PHASE 2: Skip merge_candidates with score >= threshold
  IF NOT p_dry_run THEN
    UPDATE ingestion_staging
    SET disposition = 'skipped',
        dedup_status = 'duplicate',
        processed_at = NOW(),
        review_notes = COALESCE(review_notes, '') || ' [Auto-cleaned: merge_candidate>=' || p_skip_threshold || ']'
    WHERE dedup_status = 'merge_candidate'
      AND disposition = 'pending'
      AND dedup_match_score >= p_skip_threshold;
    GET DIAGNOSTICS v_skipped_merge_candidates = ROW_COUNT;
  ELSE
    SELECT COUNT(*) INTO v_skipped_merge_candidates
    FROM ingestion_staging
    WHERE dedup_status = 'merge_candidate'
      AND disposition = 'pending'
      AND dedup_match_score >= p_skip_threshold;
  END IF;

  -- PHASE 3: Scan pending items (limit 100 per run to stay within timeout)
  FOR v_item IN
    SELECT id, target_table, normalized_data, raw_data
    FROM ingestion_staging
    WHERE dedup_status = 'pending' AND disposition = 'pending'
    LIMIT 100
  LOOP
    v_scanned_pending := v_scanned_pending + 1;
    v_normalized := COALESCE(v_item.normalized_data, v_item.raw_data);
    v_best_score := 0;
    v_best_match_id := NULL;

    BEGIN
      IF v_item.target_table = 'venues' THEN
        SELECT d.venue_id, d.combined_score
        INTO v_best_match_id, v_best_score
        FROM find_venue_duplicates(
          v_normalized->>'name',
          (v_normalized->>'latitude')::NUMERIC,
          (v_normalized->>'longitude')::NUMERIC,
          v_normalized->>'category', 0.4
        ) d ORDER BY d.combined_score DESC LIMIT 1;
      ELSIF v_item.target_table = 'events' THEN
        SELECT d.event_id, d.combined_score
        INTO v_best_match_id, v_best_score
        FROM find_event_duplicates(
          v_normalized->>'title',
          (v_normalized->>'start_date')::TIMESTAMPTZ,
          v_normalized->>'city'
        ) d ORDER BY d.combined_score DESC LIMIT 1;
      ELSIF v_item.target_table = 'personalities' THEN
        SELECT d.personality_id, d.name_similarity
        INTO v_best_match_id, v_best_score
        FROM find_personality_duplicates(v_normalized->>'name', 0.5) d
        ORDER BY d.name_similarity DESC LIMIT 1;
      ELSIF v_item.target_table = 'news_articles' THEN
        SELECT na.id, 1.0::NUMERIC INTO v_best_match_id, v_best_score
        FROM news_articles na
        WHERE na.url = v_normalized->>'url' AND v_normalized->>'url' IS NOT NULL
        LIMIT 1;
      END IF;

      IF v_best_match_id IS NOT NULL THEN
        IF v_best_score >= 0.85 THEN
          v_new_duplicates := v_new_duplicates + 1;
          IF NOT p_dry_run THEN
            UPDATE ingestion_staging
            SET dedup_status = 'duplicate', dedup_match_id = v_best_match_id,
                dedup_match_table = v_item.target_table, dedup_match_score = v_best_score,
                disposition = 'skipped', processed_at = NOW(),
                review_notes = COALESCE(review_notes,'') || ' [Auto-cleaned: scanned duplicate=' || ROUND(v_best_score,3) || ']'
            WHERE id = v_item.id;
          END IF;
        ELSIF v_best_score >= 0.6 THEN
          v_new_merge_candidates := v_new_merge_candidates + 1;
          IF NOT p_dry_run THEN
            UPDATE ingestion_staging
            SET dedup_status = 'merge_candidate', dedup_match_id = v_best_match_id,
                dedup_match_table = v_item.target_table, dedup_match_score = v_best_score
            WHERE id = v_item.id;
          END IF;
        ELSE
          v_new_unique := v_new_unique + 1;
          IF NOT p_dry_run THEN
            UPDATE ingestion_staging SET dedup_status = 'unique' WHERE id = v_item.id;
          END IF;
        END IF;
      ELSE
        v_new_unique := v_new_unique + 1;
        IF NOT p_dry_run THEN
          UPDATE ingestion_staging SET dedup_status = 'unique' WHERE id = v_item.id;
        END IF;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_errors := array_append(v_errors, 'Item ' || v_item.id || ': ' || SQLERRM);
    END;
  END LOOP;

  RETURN jsonb_build_object(
    'phase1_skipped_duplicates', v_skipped_duplicates,
    'phase2_skipped_merge_candidates', v_skipped_merge_candidates,
    'phase3_scanned_pending', v_scanned_pending,
    'phase3_new_duplicates', v_new_duplicates,
    'phase3_new_merge_candidates', v_new_merge_candidates,
    'phase3_new_unique', v_new_unique,
    'total_cleared', v_skipped_duplicates + v_skipped_merge_candidates + v_new_duplicates,
    'dry_run', p_dry_run,
    'errors', to_jsonb(v_errors)
  );
END;
$$;


ALTER FUNCTION "public"."clean_staging_duplicates"("p_skip_threshold" numeric, "p_dry_run" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cms_can_edit"("p_content_type" "text", "p_content_id" "uuid", "p_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  is_admin   boolean;
  is_editor  boolean;
BEGIN
  IF p_user_id IS NULL THEN RETURN false; END IF;
  SELECT EXISTS (
    SELECT 1 FROM public.user_roles
     WHERE user_id = p_user_id AND role IN ('admin','moderator')
  ) INTO is_admin;
  IF is_admin THEN RETURN true; END IF;
  SELECT EXISTS (
    SELECT 1 FROM public.user_roles
     WHERE user_id = p_user_id AND role = 'editor'
  ) INTO is_editor;
  RETURN is_editor;
END;
$$;


ALTER FUNCTION "public"."cms_can_edit"("p_content_type" "text", "p_content_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cms_run_scheduled_publish"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT * FROM public.cms_scheduled_publish
     WHERE status = 'pending' AND scheduled_at <= now()
     ORDER BY scheduled_at ASC LIMIT 200
  LOOP
    BEGIN
      UPDATE public.content_metadata
         SET workflow_state = CASE r.action WHEN 'publish' THEN 'published' ELSE 'draft' END,
             published_at  = CASE r.action WHEN 'publish'   THEN now() ELSE published_at END,
             unpublish_at  = CASE r.action WHEN 'unpublish' THEN now() ELSE unpublish_at END,
             updated_at    = now()
       WHERE content_type = r.content_type AND content_id = r.content_id;
      UPDATE public.cms_scheduled_publish
         SET status = 'executed', executed_at = now()
       WHERE id = r.id;
    EXCEPTION WHEN OTHERS THEN
      UPDATE public.cms_scheduled_publish
         SET status = 'failed', error = SQLERRM, executed_at = now()
       WHERE id = r.id;
    END;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."cms_run_scheduled_publish"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_city_staging_batch"("p_limit" integer DEFAULT 50) RETURNS TABLE("staging_id" "uuid", "city_id" "uuid", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE r RECORD; res RECORD;
BEGIN
  FOR r IN
    SELECT id FROM public.ingestion_staging
    WHERE target_table = 'cities' AND disposition IN ('pending','approved')
      AND ai_validation_status = 'approved'
      AND (dedup_status IN ('unique','duplicate','merge_candidate') OR dedup_status IS NULL)
      AND (review_status IN ('auto','approved') OR review_status IS NULL)
    ORDER BY created_at ASC LIMIT p_limit FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      SELECT * INTO res FROM public.commit_city_staging_item(r.id, 'batch');
      staging_id := r.id; city_id := res.out_city_id; action := res.action; RETURN NEXT;
    EXCEPTION WHEN OTHERS THEN
      UPDATE public.ingestion_staging SET disposition = 'rejected', error_message = 'commit_fn: ' || SQLERRM, updated_at = now() WHERE id = r.id;
      INSERT INTO public.ingestion_events (staging_id, stage, new_status, actor, payload)
      VALUES (r.id, 'commit', 'rejected', 'batch', jsonb_build_object('error', SQLERRM));
    END;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."commit_city_staging_batch"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_city_staging_item"("p_staging_id" "uuid", "p_actor" "text" DEFAULT 'pipeline-commit'::"text") RETURNS TABLE("out_city_id" "uuid", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE
  v_stage RECORD; v_norm JSONB; v_enr JSONB; v_loc JSONB; v_meta JSONB;
  v_name TEXT; v_country_code TEXT; v_country_name TEXT; v_country_id UUID;
  v_lat NUMERIC; v_lng NUMERIC; v_population BIGINT; v_area NUMERIC;
  v_timezone TEXT; v_region TEXT; v_is_capital BOOLEAN;
  v_source_slug TEXT; v_source_eid TEXT; v_existing_id UUID;
  v_lock_key BIGINT; v_action TEXT; v_result_id UUID; v_payload JSONB; v_hash TEXT;
BEGIN
  SELECT * INTO v_stage FROM public.ingestion_staging WHERE id = p_staging_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'staging_item_not_found: %', p_staging_id; END IF;
  IF v_stage.target_table <> 'cities' THEN RAISE EXCEPTION 'not_a_city_staging_item: target=%', v_stage.target_table; END IF;
  IF v_stage.disposition IN ('inserted','updated','committed','rejected') THEN
    RETURN QUERY SELECT v_stage.target_record_id, 'noop'::text; RETURN;
  END IF;
  v_norm := coalesce(v_stage.normalized_data, '{}'::jsonb);
  v_enr  := coalesce(v_stage.enriched_data, '{}'::jsonb);
  v_loc  := coalesce(v_norm->'location', '{}'::jsonb);
  v_meta := coalesce(v_norm->'metadata', v_stage.raw_data, '{}'::jsonb);
  v_name := nullif(btrim(v_norm->>'name'), '');
  v_lat  := nullif(v_loc->>'lat','')::NUMERIC;
  v_lng  := nullif(v_loc->>'lng','')::NUMERIC;
  v_population := nullif(coalesce(v_norm->>'population', v_meta->>'population'), '')::BIGINT;
  v_area := nullif(coalesce(v_norm->>'area_km2', v_meta->>'area'), '')::NUMERIC;
  v_timezone := nullif(btrim(coalesce(v_norm->>'timezone', v_meta->>'timezone')), '');
  v_region := nullif(btrim(coalesce(v_norm->>'region_name', v_meta->>'region_name', v_meta->>'state', v_meta->>'admin1')), '');
  v_is_capital := coalesce((v_meta->>'is_capital')::BOOLEAN, false);
  v_country_code := upper(btrim(coalesce(v_loc->>'country_code', v_meta->>'country_code', v_meta->>'countryCode', v_meta->>'cca2')));
  IF v_country_code = '' THEN v_country_code := NULL; END IF;
  v_country_name := nullif(btrim(coalesce(v_loc->>'country', v_meta->>'country')), '');
  v_source_slug := coalesce(v_stage.source_name, v_stage.source_type, 'unknown');
  v_source_eid := coalesce(v_stage.source_entity_id, v_meta->>'id', v_meta->>'external_id', v_meta->>'geonameid');
  IF v_name IS NULL THEN RAISE EXCEPTION 'city_missing_name: staging=%', p_staging_id; END IF;
  IF v_country_code IS NOT NULL THEN
    SELECT c.id INTO v_country_id FROM public.countries c WHERE c.code = v_country_code AND c.duplicate_of_id IS NULL LIMIT 1;
  END IF;
  IF v_country_id IS NULL AND v_country_name IS NOT NULL THEN
    SELECT c.id INTO v_country_id FROM public.countries c WHERE c.name_normalized = public.normalize_name(v_country_name) AND c.duplicate_of_id IS NULL LIMIT 1;
  END IF;
  IF v_country_id IS NULL THEN
    RAISE EXCEPTION 'city_unresolved_country: staging=% code=% name=%', p_staging_id, v_country_code, v_country_name;
  END IF;
  v_lock_key := hashtextextended(v_country_id::text || '|' || public.normalize_name(v_name), 0);
  PERFORM pg_advisory_xact_lock(v_lock_key);
  IF v_source_eid IS NOT NULL THEN
    SELECT gs.city_id INTO v_existing_id FROM public.geo_sources gs
    WHERE gs.entity_type='city' AND gs.source_slug=v_source_slug AND gs.source_entity_id=v_source_eid LIMIT 1;
  END IF;
  IF v_existing_id IS NULL AND v_stage.dedup_match_id IS NOT NULL
     AND coalesce(v_stage.dedup_match_table,'cities') = 'cities'
     AND v_stage.dedup_status IN ('duplicate','merge_candidate') THEN
    v_existing_id := v_stage.dedup_match_id;
  END IF;
  IF v_existing_id IS NULL THEN
    SELECT c.id INTO v_existing_id FROM public.cities c
    WHERE c.country_id = v_country_id AND c.name_normalized = public.normalize_name(v_name) AND c.duplicate_of_id IS NULL LIMIT 1;
  END IF;
  v_payload := jsonb_build_object('raw', v_stage.raw_data, 'normalized', v_norm, 'enriched', v_enr);
  v_hash := encode(extensions.digest(v_payload::text, 'sha256'), 'hex');
  IF v_existing_id IS NULL THEN
    INSERT INTO public.cities (name, country_id, region_name, population, is_capital, latitude, longitude, timezone, area_km2, data_source, last_synced_at, last_refreshed_at, created_at, updated_at)
    VALUES (v_name, v_country_id, v_region, v_population, v_is_capital, v_lat, v_lng, v_timezone, v_area, v_source_slug, now(), now(), now(), now())
    RETURNING id INTO v_result_id;
    v_action := 'inserted';
  ELSE
    UPDATE public.cities SET
      region_name = coalesce(region_name, v_region), population = coalesce(population, v_population),
      latitude = coalesce(latitude, v_lat), longitude = coalesce(longitude, v_lng),
      timezone = coalesce(timezone, v_timezone), area_km2 = coalesce(area_km2, v_area),
      is_capital = CASE WHEN v_is_capital THEN true ELSE is_capital END,
      last_synced_at = now(), last_refreshed_at = now(), updated_at = now()
    WHERE id = v_existing_id;
    v_result_id := v_existing_id; v_action := 'updated';
  END IF;
  IF v_source_eid IS NOT NULL THEN
    INSERT INTO public.geo_sources (entity_type, city_id, source_slug, source_entity_id, source_url, payload, payload_hash, confidence, is_primary, first_seen_at, last_seen_at)
    VALUES ('city', v_result_id, v_source_slug, v_source_eid, nullif(btrim(v_meta->>'url'),''), v_payload, v_hash, coalesce(v_stage.ai_confidence_score, 1.0), v_action = 'inserted', now(), now())
    ON CONFLICT (source_slug, source_entity_id) DO UPDATE SET payload = EXCLUDED.payload, payload_hash = EXCLUDED.payload_hash, confidence = EXCLUDED.confidence, last_seen_at = now();
  END IF;
  UPDATE public.ingestion_staging SET disposition = v_action, target_record_id = v_result_id, processed_at = now(), updated_at = now() WHERE id = p_staging_id;
  INSERT INTO public.ingestion_events (staging_id, city_id, stage, old_status, new_status, actor, payload)
  VALUES (p_staging_id, v_result_id, 'commit', v_stage.disposition, v_action, p_actor,
          jsonb_build_object('source_slug', v_source_slug, 'source_entity_id', v_source_eid, 'action', v_action));
  RETURN QUERY SELECT v_result_id, v_action;
END;
$$;


ALTER FUNCTION "public"."commit_city_staging_item"("p_staging_id" "uuid", "p_actor" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_country_staging_batch"("p_limit" integer DEFAULT 50) RETURNS TABLE("staging_id" "uuid", "country_id" "uuid", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE r RECORD; res RECORD;
BEGIN
  FOR r IN
    SELECT id FROM public.ingestion_staging
    WHERE target_table = 'countries' AND disposition IN ('pending','approved')
      AND ai_validation_status = 'approved'
      AND (dedup_status IN ('unique','duplicate','merge_candidate') OR dedup_status IS NULL)
      AND (review_status IN ('auto','approved') OR review_status IS NULL)
    ORDER BY created_at ASC LIMIT p_limit FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      SELECT * INTO res FROM public.commit_country_staging_item(r.id, 'batch');
      staging_id := r.id; country_id := res.out_country_id; action := res.action; RETURN NEXT;
    EXCEPTION WHEN OTHERS THEN
      UPDATE public.ingestion_staging SET disposition = 'rejected', error_message = 'commit_fn: ' || SQLERRM, updated_at = now() WHERE id = r.id;
      INSERT INTO public.ingestion_events (staging_id, stage, new_status, actor, payload)
      VALUES (r.id, 'commit', 'rejected', 'batch', jsonb_build_object('error', SQLERRM));
    END;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."commit_country_staging_batch"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_country_staging_item"("p_staging_id" "uuid", "p_actor" "text" DEFAULT 'pipeline-commit'::"text") RETURNS TABLE("out_country_id" "uuid", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE
  v_stage RECORD; v_norm JSONB; v_enr JSONB; v_meta JSONB;
  v_name TEXT; v_code TEXT; v_source_slug TEXT; v_source_eid TEXT;
  v_existing_id UUID; v_lat NUMERIC; v_lng NUMERIC;
  v_capital TEXT; v_population BIGINT; v_area NUMERIC;
  v_currency TEXT; v_languages TEXT[]; v_timezone TEXT;
  v_lock_key BIGINT; v_action TEXT; v_result_id UUID; v_payload JSONB; v_hash TEXT;
BEGIN
  SELECT * INTO v_stage FROM public.ingestion_staging WHERE id = p_staging_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'staging_item_not_found: %', p_staging_id; END IF;
  IF v_stage.target_table <> 'countries' THEN RAISE EXCEPTION 'not_a_country_staging_item: target=%', v_stage.target_table; END IF;
  IF v_stage.disposition IN ('inserted','updated','committed','rejected') THEN
    RETURN QUERY SELECT v_stage.target_record_id, 'noop'::text; RETURN;
  END IF;
  v_norm := coalesce(v_stage.normalized_data, '{}'::jsonb);
  v_enr  := coalesce(v_stage.enriched_data, '{}'::jsonb);
  v_meta := coalesce(v_norm->'metadata', v_stage.raw_data, '{}'::jsonb);
  v_name := nullif(btrim(v_norm->>'name'), '');
  v_code := upper(btrim(coalesce(v_norm->>'code', v_meta->>'code', v_meta->>'cca2', v_meta->>'iso_a2')));
  IF v_code = '' THEN v_code := NULL; END IF;
  v_capital    := nullif(btrim(coalesce(v_norm->>'capital', v_meta->>'capital')), '');
  v_population := nullif(coalesce(v_norm->>'population', v_meta->>'population'), '')::BIGINT;
  v_area       := nullif(coalesce(v_norm->>'area_km2', v_meta->>'area'), '')::NUMERIC;
  v_currency   := nullif(btrim(coalesce(v_norm->>'currency', v_meta->>'currency')), '');
  v_timezone   := nullif(btrim(coalesce(v_norm->>'timezone', v_meta->>'timezone')), '');
  v_lat        := nullif(coalesce(v_norm->'location'->>'lat', v_meta->>'latitude'), '')::NUMERIC;
  v_lng        := nullif(coalesce(v_norm->'location'->>'lng', v_meta->>'longitude'), '')::NUMERIC;
  IF jsonb_typeof(v_norm->'languages') = 'array' THEN
    SELECT array_agg(x::text) INTO v_languages FROM jsonb_array_elements_text(v_norm->'languages') AS x;
  ELSIF jsonb_typeof(v_meta->'languages') = 'array' THEN
    SELECT array_agg(x::text) INTO v_languages FROM jsonb_array_elements_text(v_meta->'languages') AS x;
  END IF;
  v_source_slug := coalesce(v_stage.source_name, v_stage.source_type, 'unknown');
  v_source_eid  := coalesce(v_stage.source_entity_id, v_code, v_meta->>'id', v_meta->>'external_id');
  IF v_name IS NULL THEN RAISE EXCEPTION 'country_missing_name: staging=%', p_staging_id; END IF;
  v_lock_key := hashtextextended(coalesce(v_code, public.normalize_name(v_name)), 0);
  PERFORM pg_advisory_xact_lock(v_lock_key);
  IF v_source_eid IS NOT NULL THEN
    SELECT gs.country_id INTO v_existing_id FROM public.geo_sources gs
    WHERE gs.entity_type='country' AND gs.source_slug=v_source_slug AND gs.source_entity_id=v_source_eid LIMIT 1;
  END IF;
  IF v_existing_id IS NULL AND v_stage.dedup_match_id IS NOT NULL
     AND coalesce(v_stage.dedup_match_table,'countries') = 'countries'
     AND v_stage.dedup_status IN ('duplicate','merge_candidate') THEN
    v_existing_id := v_stage.dedup_match_id;
  END IF;
  IF v_existing_id IS NULL AND v_code IS NOT NULL THEN
    SELECT c.id INTO v_existing_id FROM public.countries c WHERE c.code = v_code AND c.duplicate_of_id IS NULL LIMIT 1;
  END IF;
  v_payload := jsonb_build_object('raw', v_stage.raw_data, 'normalized', v_norm, 'enriched', v_enr);
  v_hash    := encode(extensions.digest(v_payload::text, 'sha256'), 'hex');
  IF v_existing_id IS NULL THEN
    DECLARE v_continent_id UUID; v_continent_code TEXT;
    BEGIN
      v_continent_code := upper(btrim(coalesce(v_meta->>'continent_code', v_meta->>'region', v_meta->'continents'->>0)));
      IF v_continent_code IS NOT NULL AND v_continent_code <> '' THEN
        SELECT cont.id INTO v_continent_id FROM public.continents cont WHERE cont.code = v_continent_code OR upper(cont.name) = v_continent_code LIMIT 1;
      END IF;
      IF v_continent_id IS NULL THEN
        SELECT cont.id INTO v_continent_id FROM public.continents cont ORDER BY cont.code LIMIT 1;
      END IF;
      INSERT INTO public.countries (name, code, continent_id, capital, population, area_km2, currency, languages, timezone, latitude, longitude, data_source, last_synced_at, last_refreshed_at, created_at, updated_at)
      VALUES (v_name, v_code, v_continent_id, v_capital, v_population, v_area, v_currency, v_languages, v_timezone, v_lat, v_lng, v_source_slug, now(), now(), now(), now())
      RETURNING id INTO v_result_id;
      v_action := 'inserted';
    END;
  ELSE
    UPDATE public.countries SET
      capital = coalesce(capital, v_capital), population = coalesce(population, v_population),
      area_km2 = coalesce(area_km2, v_area), currency = coalesce(currency, v_currency),
      languages = coalesce(languages, v_languages), timezone = coalesce(timezone, v_timezone),
      latitude = coalesce(latitude, v_lat), longitude = coalesce(longitude, v_lng),
      code = coalesce(code, v_code), last_synced_at = now(), last_refreshed_at = now(), updated_at = now()
    WHERE id = v_existing_id;
    v_result_id := v_existing_id; v_action := 'updated';
  END IF;
  IF v_source_eid IS NOT NULL THEN
    INSERT INTO public.geo_sources (entity_type, country_id, source_slug, source_entity_id, source_url, payload, payload_hash, confidence, is_primary, first_seen_at, last_seen_at)
    VALUES ('country', v_result_id, v_source_slug, v_source_eid, nullif(btrim(v_meta->>'url'),''), v_payload, v_hash, coalesce(v_stage.ai_confidence_score, 1.0), v_action = 'inserted', now(), now())
    ON CONFLICT (source_slug, source_entity_id) DO UPDATE SET payload = EXCLUDED.payload, payload_hash = EXCLUDED.payload_hash, confidence = EXCLUDED.confidence, last_seen_at = now();
  END IF;
  UPDATE public.ingestion_staging SET disposition = v_action, target_record_id = v_result_id, processed_at = now(), updated_at = now() WHERE id = p_staging_id;
  INSERT INTO public.ingestion_events (staging_id, country_id, stage, old_status, new_status, actor, payload)
  VALUES (p_staging_id, v_result_id, 'commit', v_stage.disposition, v_action, p_actor,
          jsonb_build_object('source_slug', v_source_slug, 'source_entity_id', v_source_eid, 'action', v_action));
  RETURN QUERY SELECT v_result_id, v_action;
END;
$$;


ALTER FUNCTION "public"."commit_country_staging_item"("p_staging_id" "uuid", "p_actor" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_event_staging_batch"("p_limit" integer DEFAULT 50) RETURNS TABLE("staging_id" "uuid", "event_id" "uuid", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE
  r RECORD;
  res RECORD;
BEGIN
  FOR r IN
    SELECT id FROM public.ingestion_staging
    WHERE target_table = 'events'
      AND disposition IN ('pending','approved')
      AND ai_validation_status = 'approved'
      AND (dedup_status IN ('unique','duplicate','merge_candidate') OR dedup_status IS NULL)
      AND (review_status IN ('auto','approved') OR review_status IS NULL)
    ORDER BY created_at ASC
    LIMIT p_limit
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      SELECT * INTO res FROM public.commit_event_staging_item(r.id, 'batch');
      staging_id := r.id; event_id := res.event_id; action := res.action;
      RETURN NEXT;
    EXCEPTION WHEN OTHERS THEN
      UPDATE public.ingestion_staging SET
        disposition = 'rejected',
        error_message = 'commit_fn: ' || SQLERRM,
        updated_at = now()
      WHERE id = r.id;
      INSERT INTO public.ingestion_events (staging_id, stage, new_status, actor, payload)
      VALUES (r.id, 'commit', 'rejected', 'batch',
              jsonb_build_object('error', SQLERRM, 'target_table', 'events'));
    END;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."commit_event_staging_batch"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_event_staging_item"("p_staging_id" "uuid", "p_actor" "text" DEFAULT 'pipeline-commit'::"text") RETURNS TABLE("event_id" "uuid", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE
  v_stage       RECORD;
  v_norm        JSONB;
  v_enr         JSONB;
  v_loc         JSONB;
  v_dates       JSONB;
  v_meta        JSONB;
  v_source_slug TEXT;
  v_source_eid  TEXT;
  v_title       TEXT;
  v_description TEXT;
  v_event_type  TEXT;
  v_start       TIMESTAMPTZ;
  v_end         TIMESTAMPTZ;
  v_venue_id    UUID;
  v_city        TEXT;
  v_country     TEXT;
  v_address     TEXT;
  v_lat         NUMERIC;
  v_lng         NUMERIC;
  v_website     TEXT;
  v_ticket_url  TEXT;
  v_edition     TEXT;
  v_images      TEXT[];
  v_existing_id UUID;
  v_payload     JSONB;
  v_hash        TEXT;
  v_lock_key    BIGINT;
  v_action      TEXT;
  v_result_id   UUID;
  v_valid_event_types CONSTANT TEXT[] := ARRAY[
    'party','festival','pride','fetish','community','meetup','conference',
    'workshop','concert','film','drag','sports','art','theater',
    'fundraiser','protest','social','fair','other'
  ];
BEGIN
  SELECT * INTO v_stage FROM public.ingestion_staging WHERE id = p_staging_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'staging_item_not_found: %', p_staging_id; END IF;
  IF v_stage.target_table <> 'events' THEN RAISE EXCEPTION 'not_an_event_staging_item: target=%', v_stage.target_table; END IF;
  IF v_stage.disposition IN ('inserted','updated','committed','rejected') THEN
    event_id := v_stage.target_record_id; action := 'noop'; RETURN NEXT; RETURN;
  END IF;

  v_norm  := coalesce(v_stage.normalized_data, '{}'::jsonb);
  v_enr   := coalesce(v_stage.enriched_data,   '{}'::jsonb);
  v_loc   := coalesce(v_norm->'location', '{}'::jsonb);
  v_dates := coalesce(v_norm->'dates', '{}'::jsonb);
  v_meta  := coalesce(v_norm->'metadata', v_stage.raw_data, '{}'::jsonb);

  v_title       := nullif(btrim(coalesce(v_norm->>'title', v_norm->>'name')), '');
  v_description := nullif(btrim(coalesce(v_norm->>'description', v_enr->>'description')), '');
  v_event_type  := lower(coalesce(nullif(v_norm->>'event_type',''), nullif(v_norm->>'category',''), 'other'));
  IF NOT (v_event_type = ANY(v_valid_event_types)) THEN v_event_type := 'other'; END IF;

  v_start       := nullif(coalesce(v_norm->>'start_date', v_dates->>'start'),'')::timestamptz;
  v_end         := nullif(coalesce(v_norm->>'end_date',   v_dates->>'end'),'')::timestamptz;
  v_venue_id    := nullif(v_norm->>'venue_id','')::uuid;
  v_city        := nullif(btrim(coalesce(v_loc->>'city', v_norm->>'city')), '');
  v_country     := nullif(btrim(coalesce(v_loc->>'country', v_norm->>'country')), '');
  v_address     := nullif(btrim(coalesce(v_loc->>'address', v_norm->>'address')), '');
  v_lat         := nullif(coalesce(v_loc->>'lat', v_norm->>'latitude'),'')::numeric;
  v_lng         := nullif(coalesce(v_loc->>'lng', v_norm->>'longitude'),'')::numeric;
  v_website     := nullif(btrim(coalesce(v_norm->>'website', v_norm->'contacts'->>'website')), '');
  v_ticket_url  := nullif(btrim(v_norm->>'ticket_url'), '');
  v_edition     := nullif(btrim(v_norm->>'edition'), '');

  IF jsonb_typeof(v_norm->'images') = 'array' THEN
    SELECT array_agg(value::text) INTO v_images FROM jsonb_array_elements_text(v_norm->'images');
  END IF;

  v_source_slug := coalesce(v_stage.source_name, v_stage.source_type, 'unknown');
  v_source_eid  := coalesce(v_stage.source_entity_id, v_meta->>'id', v_meta->>'external_id', v_meta->>'source_id');

  IF v_title IS NULL THEN RAISE EXCEPTION 'event_missing_title: staging=%', p_staging_id; END IF;
  IF v_start IS NULL THEN RAISE EXCEPTION 'event_missing_start_date: staging=%', p_staging_id; END IF;

  v_lock_key := hashtextextended(
    public.normalize_name(v_title) || '|' ||
    coalesce(v_venue_id::text, coalesce(v_city,'')) || '|' ||
    to_char(v_start, 'YYYY-MM-DD HH24'),
    0
  );
  PERFORM pg_advisory_xact_lock(v_lock_key);

  IF v_source_eid IS NOT NULL THEN
    SELECT es.event_id INTO v_existing_id FROM public.event_sources es
    WHERE es.source_slug = v_source_slug AND es.source_entity_id = v_source_eid LIMIT 1;
  END IF;

  IF v_existing_id IS NULL AND v_stage.dedup_match_id IS NOT NULL
     AND coalesce(v_stage.dedup_match_table,'events') = 'events'
     AND v_stage.dedup_status IN ('duplicate','merge_candidate') THEN
    v_existing_id := v_stage.dedup_match_id;
  END IF;

  v_payload := jsonb_build_object('raw', v_stage.raw_data, 'normalized', v_norm, 'enriched', v_enr);
  v_hash := encode(extensions.digest(v_payload::text, 'sha256'), 'hex');

  IF v_existing_id IS NULL THEN
    INSERT INTO public.events (
      title, description, event_type, start_date, end_date,
      venue_id, venue_name, address, city, country,
      latitude, longitude, website, ticket_url, edition,
      images,
      data_source, external_id, last_synced_at, last_refreshed_at,
      status, created_at, updated_at
    ) VALUES (
      v_title, v_description, v_event_type, v_start, v_end,
      v_venue_id, nullif(btrim(v_norm->>'venue_name'),''), v_address,
      coalesce(v_city, ''), coalesce(v_country, 'US'),
      v_lat, v_lng, v_website, v_ticket_url, v_edition,
      v_images,
      v_source_slug, v_source_eid, now(), now(),
      'active', now(), now()
    ) RETURNING id INTO v_result_id;
    v_action := 'inserted';
  ELSE
    UPDATE public.events e SET
      description = coalesce(e.description, v_description),
      address     = coalesce(nullif(e.address,''), v_address, e.address),
      end_date    = coalesce(e.end_date, v_end),
      latitude    = coalesce(e.latitude, v_lat),
      longitude   = coalesce(e.longitude, v_lng),
      website     = coalesce(e.website, v_website),
      ticket_url  = coalesce(e.ticket_url, v_ticket_url),
      edition     = coalesce(e.edition, v_edition),
      images      = CASE WHEN array_length(e.images,1) IS NULL THEN v_images ELSE e.images END,
      last_refreshed_at = now(),
      updated_at  = now()
    WHERE e.id = v_existing_id;
    v_result_id := v_existing_id;
    v_action    := 'updated';
  END IF;

  IF v_source_eid IS NOT NULL THEN
    INSERT INTO public.event_sources AS es (
      event_id, source_slug, source_entity_id, source_url, payload, payload_hash,
      confidence, is_primary, first_seen_at, last_seen_at
    ) VALUES (
      v_result_id, v_source_slug, v_source_eid,
      nullif(btrim(v_meta->>'url'), ''), v_payload, v_hash,
      coalesce(v_stage.ai_confidence_score, 1.0),
      v_action = 'inserted', now(), now()
    )
    ON CONFLICT (source_slug, source_entity_id) DO UPDATE SET
      payload = EXCLUDED.payload, payload_hash = EXCLUDED.payload_hash,
      confidence = EXCLUDED.confidence, last_seen_at = now();
  END IF;

  UPDATE public.ingestion_staging SET
    disposition = v_action, target_record_id = v_result_id,
    processed_at = now(), updated_at = now()
  WHERE id = p_staging_id;

  INSERT INTO public.ingestion_events (staging_id, stage, old_status, new_status, actor, payload)
  VALUES (p_staging_id, 'commit', v_stage.disposition, v_action, p_actor,
          jsonb_build_object('source_slug', v_source_slug, 'source_entity_id', v_source_eid,
                             'action', v_action, 'event_id', v_result_id, 'target_table', 'events'));

  event_id := v_result_id; action := v_action; RETURN NEXT;
END;
$$;


ALTER FUNCTION "public"."commit_event_staging_item"("p_staging_id" "uuid", "p_actor" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_marketplace_staging_batch"("p_limit" integer DEFAULT 50, "p_pipeline_run_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("staging_id" "uuid", "listing_id" "uuid", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_row          RECORD;
  v_norm         JSONB;
  v_enr          JSONB;
  v_meta         JSONB;
  v_title        TEXT;
  v_description  TEXT;
  v_category     TEXT;
  v_category_src TEXT;
  v_category_id  UUID;
  v_subcategory  TEXT;
  v_price        NUMERIC;
  v_price_type   TEXT;
  v_currency     TEXT;
  v_business     TEXT;
  v_biz_type     TEXT;
  v_email        TEXT;
  v_phone        TEXT;
  v_website      TEXT;
  v_location     TEXT;
  v_images       TEXT[];
  v_brand        TEXT;
  v_external_url TEXT;
  v_affiliate_url TEXT;
  v_merchant_dom TEXT;
  v_merchant_id  UUID;
  v_availability TEXT;
  v_in_stock     BOOLEAN;
  v_slug         TEXT;
  v_src_slug     TEXT;
  v_src_eid      TEXT;
  v_source_url   TEXT;
  v_payload      JSONB;
  v_hash         TEXT;
  v_existing_id  UUID;
  v_prev_price   NUMERIC;
  v_lock_key     BIGINT;
  v_action       TEXT;
  v_result_id    UUID;
  v_class        JSONB;
  v_relev        NUMERIC;
  v_sens         JSONB;
  v_qscore       INT;
  v_biz_type_ok  TEXT;
BEGIN
  FOR v_row IN
    SELECT s.*
      FROM public.ingestion_staging s
     WHERE s.target_table = 'marketplace_listings'
       AND s.disposition = 'pending'
       AND s.ai_validation_status = 'approved'
       AND (s.dedup_status IN ('unique','duplicate') OR s.dedup_status IS NULL)
       AND s.review_status IN ('auto','approved')
       AND (p_pipeline_run_id IS NULL OR s.pipeline_run_id = p_pipeline_run_id)
     ORDER BY s.created_at ASC
     LIMIT p_limit
     FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      v_norm := coalesce(v_row.normalized_data, '{}'::jsonb);
      v_enr  := coalesce(v_row.enriched_data,   '{}'::jsonb);
      v_meta := coalesce(v_norm->'metadata', v_row.raw_data, '{}'::jsonb);
      v_class:= coalesce(v_row.classification_result, '{}'::jsonb);

      v_title        := nullif(btrim(coalesce(v_norm->>'name', v_norm->>'title', v_meta->>'product_name', v_meta->>'title')), '');
      v_description  := nullif(btrim(coalesce(v_norm->>'description', v_enr->>'description', v_meta->>'description')), '');

      -- Source-level category (e.g. "Bags") stored as subcategory; high-level bucket fits check constraint
      v_category_src := nullif(btrim(coalesce(v_norm->>'category', v_meta->>'category', v_meta->>'category_name')), '');
      v_subcategory  := nullif(btrim(coalesce(v_norm->>'subcategory', v_meta->>'subcategory', v_category_src)), '');
      v_biz_type     := nullif(btrim(coalesce(v_norm->>'business_type', v_meta->>'business_type')), '');
      -- Decide products vs services — default products; services only if business_type or source clearly indicates
      IF v_biz_type IS NOT NULL AND v_biz_type ILIKE '%service%' THEN
        v_category := 'services';
      ELSE
        v_category := 'products';
      END IF;

      -- Resolve category_id from marketplace_categories (case-insensitive name or slug match)
      IF v_category_src IS NOT NULL THEN
        SELECT id INTO v_category_id
          FROM public.marketplace_categories
         WHERE is_active = true
           AND (lower(name) = lower(v_category_src) OR lower(slug) = lower(regexp_replace(v_category_src, '[^a-zA-Z0-9]+', '-', 'g')))
         LIMIT 1;
      END IF;

      v_price        := nullif(coalesce(v_meta->>'price', v_norm->>'price', v_meta->>'search_price'), '')::numeric;
      v_price_type   := coalesce(nullif(btrim(coalesce(v_norm->>'price_type', v_meta->>'price_type')), ''), 'fixed');
      v_currency     := coalesce(upper(nullif(btrim(coalesce(v_norm->>'currency', v_meta->>'currency')), '')), 'USD');
      v_business     := nullif(btrim(coalesce(v_norm->>'business_name', v_meta->>'merchant_name', v_meta->>'business_name', v_meta->>'brand_name')), '');
      v_email        := nullif(btrim(coalesce((v_norm->'contacts'->>'email'), v_meta->>'contact_email', v_meta->>'email')), '');
      v_phone        := nullif(btrim(coalesce((v_norm->'contacts'->>'phone'), v_meta->>'contact_phone', v_meta->>'phone')), '');
      v_website      := nullif(btrim(coalesce((v_norm->'contacts'->>'website'), v_meta->>'merchant_url', v_meta->>'website', (v_norm->'urls'->>0))), '');
      v_location     := nullif(btrim(coalesce(v_norm->>'location', v_meta->>'location', (v_norm->'location'->>'address'))), '');
      v_brand        := nullif(btrim(coalesce(v_norm->>'brand', v_meta->>'brand', v_meta->>'brand_name')), '');
      v_external_url := nullif(btrim(coalesce(v_meta->>'merchant_deep_link', v_meta->>'product_url', (v_norm->'urls'->>0), v_website)), '');
      v_affiliate_url:= nullif(btrim(coalesce(v_meta->>'aw_deep_link', v_meta->>'affiliate_url', v_norm->>'affiliate_url')), '');
      v_in_stock     := CASE WHEN v_meta ? 'in_stock' THEN (v_meta->>'in_stock')::boolean
                             WHEN v_norm ? 'in_stock' THEN (v_norm->>'in_stock')::boolean
                             ELSE NULL END;
      v_availability := CASE WHEN v_in_stock IS TRUE THEN 'in_stock'
                             WHEN v_in_stock IS FALSE THEN 'out_of_stock'
                             ELSE coalesce(v_norm->>'availability', 'unknown') END;

      v_images := ARRAY(
        SELECT value::text
          FROM jsonb_array_elements_text(coalesce(v_norm->'images', v_enr->'images', '[]'::jsonb))
         WHERE value::text IS NOT NULL AND value::text <> ''
      );

      v_relev := nullif(v_class->>'lgbti_relevance_score', '')::numeric;
      v_sens  := coalesce(v_class->'sensitivity_flags', '[]'::jsonb);
      v_qscore:= nullif(v_row.ai_validation_result->>'quality', '')::int;

      v_src_slug := coalesce(v_row.source_name, v_row.source_type, 'unknown');
      v_src_eid  := coalesce(v_row.source_entity_id,
                             v_meta->>'aw_product_id',
                             v_meta->>'product_id',
                             v_meta->>'id',
                             v_meta->>'external_id');
      v_source_url := v_external_url;

      IF v_external_url IS NOT NULL THEN
        v_merchant_dom := lower(substring(v_external_url FROM 'https?://(?:www\.)?([^/:?#]+)'));
      ELSIF v_website IS NOT NULL THEN
        v_merchant_dom := lower(substring(v_website FROM 'https?://(?:www\.)?([^/:?#]+)'));
      END IF;

      IF v_merchant_dom IS NOT NULL THEN
        SELECT id INTO v_merchant_id
          FROM public.affiliate_partners
         WHERE v_merchant_dom = ANY(domains) AND enabled = true
         LIMIT 1;
      END IF;

      IF v_title IS NULL OR length(v_title) < 2 THEN
        UPDATE public.ingestion_staging SET disposition='rejected', error_message='missing_title', updated_at=now() WHERE id = v_row.id;
        staging_id := v_row.id; listing_id := NULL; action := 'rejected'; RETURN NEXT;
        CONTINUE;
      END IF;
      IF v_business IS NULL THEN v_business := coalesce(v_brand, v_merchant_dom, 'unknown'); END IF;

      v_slug := regexp_replace(lower(extensions.unaccent(v_title)), '[^a-z0-9]+', '-', 'g');
      v_slug := trim(both '-' from substring(v_slug FROM 1 FOR 80));
      IF coalesce(v_src_eid,'') <> '' THEN
        v_slug := v_slug || '-' || substring(md5(v_src_slug || ':' || v_src_eid) FOR 8);
      END IF;

      v_payload := jsonb_strip_nulls(jsonb_build_object(
        'title', v_title, 'price', v_price, 'business', v_business,
        'external_url', v_external_url, 'availability', v_availability
      ));
      v_hash := md5(v_payload::text);

      IF v_row.payload_hash = v_hash AND v_row.disposition = 'committed' THEN
        staging_id := v_row.id; listing_id := v_row.target_record_id; action := 'noop'; RETURN NEXT;
        CONTINUE;
      END IF;

      v_lock_key := hashtextextended(coalesce(v_src_slug || ':' || v_src_eid, v_title), 42);
      PERFORM pg_advisory_xact_lock(v_lock_key);

      v_existing_id := v_row.dedup_match_id;
      IF v_existing_id IS NULL AND v_src_eid IS NOT NULL THEN
        SELECT id INTO v_existing_id
          FROM public.marketplace_listings
         WHERE source_type = v_src_slug AND source_entity_id = v_src_eid
         LIMIT 1;
      END IF;

      IF v_existing_id IS NULL THEN
        INSERT INTO public.marketplace_listings (
          title, description, category, subcategory, category_id,
          price, price_type, currency,
          business_name, business_type, contact_email, contact_phone, website,
          location, images, status, slug,
          source_type, source_entity_id, external_url, affiliate_url,
          merchant_domain, merchant_id, brand,
          availability, in_stock, last_verified_at, last_seen_at,
          link_health, quality_score, lgbti_relevance_score, sensitivity_flags,
          classified_at, review_status, payload_hash
        ) VALUES (
          v_title, v_description, v_category, v_subcategory, v_category_id,
          v_price, v_price_type, v_currency,
          v_business, v_biz_type, v_email, v_phone, v_website,
          v_location, v_images, 'active', v_slug,
          v_src_slug, v_src_eid, v_external_url, v_affiliate_url,
          v_merchant_dom, v_merchant_id, v_brand,
          v_availability, v_in_stock, now(), now(),
          'unchecked', v_qscore, v_relev, v_sens,
          CASE WHEN v_relev IS NOT NULL THEN now() ELSE NULL END,
          coalesce(v_row.review_status,'auto'), v_hash
        )
        RETURNING id INTO v_result_id;
        v_action := 'inserted';
      ELSE
        SELECT price INTO v_prev_price FROM public.marketplace_listings WHERE id = v_existing_id;
        UPDATE public.marketplace_listings SET
          title          = coalesce(v_title, title),
          description    = coalesce(v_description, description),
          category       = v_category,
          subcategory    = coalesce(v_subcategory, subcategory),
          category_id    = coalesce(v_category_id, category_id),
          price          = coalesce(v_price, price),
          currency       = coalesce(v_currency, currency),
          business_name  = coalesce(v_business, business_name),
          website        = coalesce(v_website, website),
          images         = CASE WHEN array_length(v_images,1) > 0 THEN v_images ELSE images END,
          external_url   = coalesce(v_external_url, external_url),
          affiliate_url  = coalesce(v_affiliate_url, affiliate_url),
          merchant_domain= coalesce(v_merchant_dom, merchant_domain),
          merchant_id    = coalesce(v_merchant_id, merchant_id),
          brand          = coalesce(v_brand, brand),
          availability   = v_availability,
          in_stock       = coalesce(v_in_stock, in_stock),
          last_verified_at = now(),
          last_seen_at     = now(),
          quality_score    = coalesce(v_qscore, quality_score),
          lgbti_relevance_score = coalesce(v_relev, lgbti_relevance_score),
          sensitivity_flags     = CASE WHEN v_sens <> '[]'::jsonb THEN v_sens ELSE sensitivity_flags END,
          classified_at    = CASE WHEN v_relev IS NOT NULL THEN now() ELSE classified_at END,
          payload_hash     = v_hash,
          updated_at       = now()
        WHERE id = v_existing_id
        RETURNING id INTO v_result_id;
        v_action := 'updated';

        IF v_price IS NOT NULL AND (v_prev_price IS NULL OR v_prev_price <> v_price) THEN
          INSERT INTO public.marketplace_price_history (listing_id, price, currency, source_slug, availability)
          VALUES (v_result_id, v_price, v_currency, v_src_slug, v_availability);
        END IF;
      END IF;

      INSERT INTO public.marketplace_listing_sources (listing_id, source_slug, source_entity_id, source_url, raw, payload_hash, confidence, is_primary)
      VALUES (v_result_id, v_src_slug, v_src_eid, v_source_url, v_row.raw_data, v_hash, 1.0, v_action = 'inserted')
      ON CONFLICT (source_slug, source_entity_id) WHERE source_entity_id IS NOT NULL
      DO UPDATE SET listing_id = EXCLUDED.listing_id, raw = EXCLUDED.raw, payload_hash = EXCLUDED.payload_hash, last_seen_at = now();

      IF v_action = 'inserted' AND v_price IS NOT NULL THEN
        INSERT INTO public.marketplace_price_history (listing_id, price, currency, source_slug, availability)
        VALUES (v_result_id, v_price, v_currency, v_src_slug, v_availability);
      END IF;

      UPDATE public.ingestion_staging SET
        disposition      = 'committed',
        target_record_id = v_result_id,
        payload_hash     = v_hash,
        processed_at     = now(),
        updated_at       = now()
      WHERE id = v_row.id;

      INSERT INTO public.ingestion_events (staging_id, stage, new_status, actor, payload)
      VALUES (v_row.id, 'commit', 'committed', 'commit_marketplace_staging_batch',
              jsonb_build_object('listing_id', v_result_id, 'action', v_action, 'price', v_price));

      staging_id := v_row.id;
      listing_id := v_result_id;
      action     := v_action;
      RETURN NEXT;
    EXCEPTION WHEN OTHERS THEN
      UPDATE public.ingestion_staging SET
        disposition   = 'rejected',
        error_message = 'commit_err: ' || SQLERRM,
        updated_at    = now()
      WHERE id = v_row.id;
      INSERT INTO public.ingestion_events (staging_id, stage, new_status, actor, payload)
      VALUES (v_row.id, 'commit', 'rejected', 'commit_marketplace_staging_batch',
              jsonb_build_object('error', SQLERRM));
      staging_id := v_row.id;
      listing_id := NULL;
      action     := 'error';
      RETURN NEXT;
    END;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."commit_marketplace_staging_batch"("p_limit" integer, "p_pipeline_run_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_marketplace_staging_item"("p_staging_id" "uuid", "p_actor" "text" DEFAULT 'review:individual'::"text") RETURNS TABLE("listing_id" "uuid", "action" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_row          RECORD;
  v_norm         JSONB;
  v_enr          JSONB;
  v_meta         JSONB;
  v_class        JSONB;
  v_title        TEXT;
  v_description  TEXT;
  v_category     TEXT;
  v_category_src TEXT;
  v_category_id  UUID;
  v_subcategory  TEXT;
  v_price        NUMERIC;
  v_price_type   TEXT;
  v_currency     TEXT;
  v_business     TEXT;
  v_biz_type     TEXT;
  v_email        TEXT;
  v_phone        TEXT;
  v_website      TEXT;
  v_location     TEXT;
  v_images       TEXT[];
  v_brand        TEXT;
  v_external_url TEXT;
  v_affiliate_url TEXT;
  v_merchant_dom TEXT;
  v_merchant_id  UUID;
  v_availability TEXT;
  v_in_stock     BOOLEAN;
  v_slug         TEXT;
  v_src_slug     TEXT;
  v_src_eid      TEXT;
  v_payload      JSONB;
  v_hash         TEXT;
  v_existing_id  UUID;
  v_prev_price   NUMERIC;
  v_lock_key     BIGINT;
  v_action       TEXT;
  v_result_id    UUID;
  v_relev        NUMERIC;
  v_sens         JSONB;
  v_qscore       INT;
BEGIN
  SELECT * INTO v_row FROM public.ingestion_staging WHERE id = p_staging_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'staging_item_not_found: %', p_staging_id; END IF;
  IF v_row.target_table <> 'marketplace_listings' THEN
    RAISE EXCEPTION 'not_a_marketplace_staging_item: target=%', v_row.target_table;
  END IF;
  IF v_row.disposition IN ('inserted','updated','committed','rejected') THEN
    listing_id := v_row.target_record_id; action := 'noop'; RETURN NEXT; RETURN;
  END IF;

  v_norm := coalesce(v_row.normalized_data, '{}'::jsonb);
  v_enr  := coalesce(v_row.enriched_data,   '{}'::jsonb);
  v_meta := coalesce(v_norm->'metadata', v_row.raw_data, '{}'::jsonb);
  v_class:= coalesce(v_row.classification_result, '{}'::jsonb);

  v_title        := nullif(btrim(coalesce(v_norm->>'name', v_norm->>'title', v_meta->>'product_name', v_meta->>'title')), '');
  v_description  := nullif(btrim(coalesce(v_norm->>'description', v_enr->>'description', v_meta->>'description')), '');
  v_category_src := nullif(btrim(coalesce(v_norm->>'category', v_meta->>'category', v_meta->>'category_name')), '');
  v_subcategory  := nullif(btrim(coalesce(v_norm->>'subcategory', v_meta->>'subcategory', v_category_src)), '');
  v_biz_type     := nullif(btrim(coalesce(v_norm->>'business_type', v_meta->>'business_type')), '');
  v_category     := CASE WHEN v_biz_type ILIKE '%service%' THEN 'services' ELSE 'products' END;

  IF v_category_src IS NOT NULL THEN
    SELECT id INTO v_category_id FROM public.marketplace_categories
     WHERE is_active = true
       AND (lower(name) = lower(v_category_src)
            OR lower(slug) = lower(regexp_replace(v_category_src, '[^a-zA-Z0-9]+', '-', 'g')))
     LIMIT 1;
  END IF;

  v_price       := nullif(coalesce(v_meta->>'price', v_norm->>'price', v_meta->>'search_price'), '')::numeric;
  v_price_type  := coalesce(nullif(btrim(coalesce(v_norm->>'price_type', v_meta->>'price_type')), ''), 'fixed');
  v_currency    := coalesce(upper(nullif(btrim(coalesce(v_norm->>'currency', v_meta->>'currency')), '')), 'USD');
  v_business    := nullif(btrim(coalesce(v_norm->>'business_name', v_meta->>'merchant_name', v_meta->>'business_name', v_meta->>'brand_name')), '');
  v_email       := nullif(btrim(coalesce((v_norm->'contacts'->>'email'), v_meta->>'contact_email', v_meta->>'email')), '');
  v_phone       := nullif(btrim(coalesce((v_norm->'contacts'->>'phone'), v_meta->>'contact_phone', v_meta->>'phone')), '');
  v_website     := nullif(btrim(coalesce((v_norm->'contacts'->>'website'), v_meta->>'merchant_url', v_meta->>'website', (v_norm->'urls'->>0))), '');
  v_location    := nullif(btrim(coalesce(v_norm->>'location', v_meta->>'location', (v_norm->'location'->>'address'))), '');
  v_brand       := nullif(btrim(coalesce(v_norm->>'brand', v_meta->>'brand', v_meta->>'brand_name')), '');
  v_external_url := nullif(btrim(coalesce(v_meta->>'merchant_deep_link', v_meta->>'product_url', (v_norm->'urls'->>0), v_website)), '');
  v_affiliate_url:= nullif(btrim(coalesce(v_meta->>'aw_deep_link', v_meta->>'affiliate_url', v_norm->>'affiliate_url')), '');
  v_in_stock    := CASE WHEN v_meta ? 'in_stock' THEN (v_meta->>'in_stock')::boolean
                        WHEN v_norm ? 'in_stock' THEN (v_norm->>'in_stock')::boolean
                        ELSE NULL END;
  v_availability:= CASE WHEN v_in_stock IS TRUE THEN 'in_stock'
                        WHEN v_in_stock IS FALSE THEN 'out_of_stock'
                        ELSE coalesce(v_norm->>'availability', 'unknown') END;

  v_images := ARRAY(
    SELECT value::text FROM jsonb_array_elements_text(coalesce(v_norm->'images', v_enr->'images', '[]'::jsonb))
     WHERE value::text IS NOT NULL AND value::text <> ''
  );

  v_relev := nullif(v_class->>'lgbti_relevance_score', '')::numeric;
  v_sens  := coalesce(v_class->'sensitivity_flags', '[]'::jsonb);
  v_qscore:= nullif(v_row.ai_validation_result->>'quality', '')::int;

  v_src_slug := coalesce(v_row.source_name, v_row.source_type, 'unknown');
  v_src_eid  := coalesce(v_row.source_entity_id, v_meta->>'aw_product_id', v_meta->>'product_id', v_meta->>'id', v_meta->>'external_id');

  IF v_external_url IS NOT NULL THEN
    v_merchant_dom := lower(substring(v_external_url FROM 'https?://(?:www\.)?([^/:?#]+)'));
  ELSIF v_website IS NOT NULL THEN
    v_merchant_dom := lower(substring(v_website FROM 'https?://(?:www\.)?([^/:?#]+)'));
  END IF;

  IF v_merchant_dom IS NOT NULL THEN
    SELECT id INTO v_merchant_id FROM public.affiliate_partners
     WHERE v_merchant_dom = ANY(domains) AND enabled = true LIMIT 1;
  END IF;

  IF v_title IS NULL OR length(v_title) < 2 THEN
    UPDATE public.ingestion_staging SET disposition='rejected', error_message='missing_title', updated_at=now() WHERE id = v_row.id;
    listing_id := NULL; action := 'rejected'; RETURN NEXT; RETURN;
  END IF;
  IF v_business IS NULL THEN v_business := coalesce(v_brand, v_merchant_dom, 'unknown'); END IF;

  v_slug := regexp_replace(lower(extensions.unaccent(v_title)), '[^a-z0-9]+', '-', 'g');
  v_slug := trim(both '-' from substring(v_slug FROM 1 FOR 80));
  IF coalesce(v_src_eid,'') <> '' THEN
    v_slug := v_slug || '-' || substring(md5(v_src_slug || ':' || v_src_eid) FOR 8);
  END IF;

  v_payload := jsonb_strip_nulls(jsonb_build_object(
    'title', v_title, 'price', v_price, 'business', v_business,
    'external_url', v_external_url, 'availability', v_availability));
  v_hash := md5(v_payload::text);

  v_lock_key := hashtextextended(coalesce(v_src_slug || ':' || v_src_eid, v_title), 42);
  PERFORM pg_advisory_xact_lock(v_lock_key);

  v_existing_id := v_row.dedup_match_id;
  IF v_existing_id IS NULL AND v_src_eid IS NOT NULL THEN
    SELECT id INTO v_existing_id FROM public.marketplace_listings
     WHERE source_type = v_src_slug AND source_entity_id = v_src_eid LIMIT 1;
  END IF;

  IF v_existing_id IS NULL THEN
    INSERT INTO public.marketplace_listings (
      title, description, category, subcategory, category_id,
      price, price_type, currency,
      business_name, business_type, contact_email, contact_phone, website,
      location, images, status, slug,
      source_type, source_entity_id, external_url, affiliate_url,
      merchant_domain, merchant_id, brand,
      availability, in_stock, last_verified_at, last_seen_at,
      link_health, quality_score, lgbti_relevance_score, sensitivity_flags,
      classified_at, review_status, payload_hash
    ) VALUES (
      v_title, v_description, v_category, v_subcategory, v_category_id,
      v_price, v_price_type, v_currency,
      v_business, v_biz_type, v_email, v_phone, v_website,
      v_location, v_images, 'active', v_slug,
      v_src_slug, v_src_eid, v_external_url, v_affiliate_url,
      v_merchant_dom, v_merchant_id, v_brand,
      v_availability, v_in_stock, now(), now(),
      'unchecked', v_qscore, v_relev, v_sens,
      CASE WHEN v_relev IS NOT NULL THEN now() ELSE NULL END,
      coalesce(v_row.review_status,'auto'), v_hash
    ) RETURNING id INTO v_result_id;
    v_action := 'inserted';
  ELSE
    SELECT price INTO v_prev_price FROM public.marketplace_listings WHERE id = v_existing_id;
    UPDATE public.marketplace_listings SET
      title = coalesce(v_title, title),
      description = coalesce(v_description, description),
      category = v_category,
      subcategory = coalesce(v_subcategory, subcategory),
      category_id = coalesce(v_category_id, category_id),
      price = coalesce(v_price, price),
      currency = coalesce(v_currency, currency),
      business_name = coalesce(v_business, business_name),
      website = coalesce(v_website, website),
      images = CASE WHEN array_length(v_images,1) > 0 THEN v_images ELSE images END,
      external_url = coalesce(v_external_url, external_url),
      affiliate_url = coalesce(v_affiliate_url, affiliate_url),
      merchant_domain = coalesce(v_merchant_dom, merchant_domain),
      merchant_id = coalesce(v_merchant_id, merchant_id),
      brand = coalesce(v_brand, brand),
      availability = v_availability,
      in_stock = coalesce(v_in_stock, in_stock),
      last_verified_at = now(),
      last_seen_at = now(),
      quality_score = coalesce(v_qscore, quality_score),
      lgbti_relevance_score = coalesce(v_relev, lgbti_relevance_score),
      sensitivity_flags = CASE WHEN v_sens <> '[]'::jsonb THEN v_sens ELSE sensitivity_flags END,
      classified_at = CASE WHEN v_relev IS NOT NULL THEN now() ELSE classified_at END,
      payload_hash = v_hash,
      updated_at = now()
    WHERE id = v_existing_id RETURNING id INTO v_result_id;
    v_action := 'updated';

    IF v_price IS NOT NULL AND (v_prev_price IS NULL OR v_prev_price <> v_price) THEN
      INSERT INTO public.marketplace_price_history (listing_id, price, currency, source_slug, availability)
      VALUES (v_result_id, v_price, v_currency, v_src_slug, v_availability);
    END IF;
  END IF;

  INSERT INTO public.marketplace_listing_sources (listing_id, source_slug, source_entity_id, source_url, raw, payload_hash, confidence, is_primary)
  VALUES (v_result_id, v_src_slug, v_src_eid, v_external_url, v_row.raw_data, v_hash, 1.0, v_action = 'inserted')
  ON CONFLICT (source_slug, source_entity_id) WHERE source_entity_id IS NOT NULL
  DO UPDATE SET listing_id = EXCLUDED.listing_id, raw = EXCLUDED.raw, payload_hash = EXCLUDED.payload_hash, last_seen_at = now();

  IF v_action = 'inserted' AND v_price IS NOT NULL THEN
    INSERT INTO public.marketplace_price_history (listing_id, price, currency, source_slug, availability)
    VALUES (v_result_id, v_price, v_currency, v_src_slug, v_availability);
  END IF;

  UPDATE public.ingestion_staging SET
    disposition = 'committed',
    target_record_id = v_result_id,
    payload_hash = v_hash,
    processed_at = now(),
    updated_at = now()
  WHERE id = v_row.id;

  INSERT INTO public.ingestion_events (staging_id, stage, new_status, actor, payload)
  VALUES (v_row.id, 'commit', 'committed', p_actor,
          jsonb_build_object('listing_id', v_result_id, 'action', v_action, 'price', v_price));

  listing_id := v_result_id;
  action := v_action;
  RETURN NEXT;
END;
$$;


ALTER FUNCTION "public"."commit_marketplace_staging_item"("p_staging_id" "uuid", "p_actor" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_news_staging_item"("p_staging_id" "uuid", "p_actor" "text" DEFAULT 'review:individual'::"text") RETURNS TABLE("article_id" "uuid", "action" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_row RECORD; v_norm JSONB; v_enr JSONB; v_meta JSONB; v_dates JSONB; v_urls JSONB; v_images JSONB;
  v_fp TEXT; v_existing_id UUID;
  v_published TIMESTAMPTZ; v_source_id UUID; v_title TEXT; v_url TEXT;
  v_content TEXT; v_image TEXT; v_image_attribution TEXT; v_image_hash TEXT; v_excerpt TEXT;
  v_target_id UUID; v_action TEXT;
  v_quality_status TEXT; v_relevance NUMERIC; v_quality_after NUMERIC;
  v_quality_before NUMERIC; v_sentiment TEXT; v_blocked_reasons TEXT[];
  v_pipeline_ver TEXT;
  v_country_ids UUID[]; v_city_ids UUID[];
  v_review_items JSONB;
BEGIN
  SELECT * INTO v_row FROM public.ingestion_staging WHERE id = p_staging_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'staging_item_not_found: %', p_staging_id; END IF;
  IF v_row.target_table <> 'news_articles' THEN
    RAISE EXCEPTION 'not_a_news_staging_item: target=%', v_row.target_table;
  END IF;
  IF v_row.disposition IN ('inserted','updated','committed','rejected') THEN
    article_id := v_row.target_record_id; action := 'noop'; RETURN NEXT; RETURN;
  END IF;

  v_norm := coalesce(v_row.normalized_data, v_row.raw_data, '{}'::JSONB);
  v_enr  := coalesce(v_row.enriched_data, '{}'::JSONB);
  v_meta := coalesce(v_norm->'metadata', '{}'::JSONB);
  v_dates := coalesce(v_norm->'dates', '{}'::JSONB);
  v_urls := coalesce(v_norm->'urls', '[]'::JSONB);
  v_images := coalesce(v_norm->'images', '[]'::JSONB);

  v_title := nullif(trim(coalesce(v_norm->>'title', v_norm->>'name', '')), '');
  v_url := nullif(trim(coalesce(v_norm->>'url',
    CASE WHEN jsonb_array_length(v_urls) > 0 THEN v_urls->>0 ELSE NULL END,
    v_meta->>'url')), '');
  v_content := coalesce(v_norm->>'content', v_norm->>'description', '');
  v_image := coalesce(nullif(v_enr->>'image_url', ''), v_norm->>'image_url',
    CASE WHEN jsonb_array_length(v_images) > 0 THEN v_images->>0 ELSE NULL END,
    v_meta->>'image_url');
  v_image_attribution := nullif(v_enr->>'image_attribution', '');
  v_image_hash := nullif(v_enr->>'image_hash', '');
  v_excerpt := coalesce(v_norm->>'excerpt', v_meta->>'excerpt');
  v_published := coalesce(
    nullif(v_norm->>'published_at','')::TIMESTAMPTZ,
    nullif(v_dates->>'start','')::TIMESTAMPTZ,
    nullif(v_meta->>'published_at','')::TIMESTAMPTZ, now());
  v_source_id := coalesce(nullif(v_norm->>'source_id','')::UUID, nullif(v_meta->>'source_id','')::UUID);
  v_quality_status := nullif(v_enr->>'quality_status', '');
  v_relevance := nullif(v_enr->>'relevance_score', '')::NUMERIC;
  v_quality_after := nullif(v_enr->>'quality_score_after', '')::NUMERIC;
  v_quality_before := nullif(v_enr->>'quality_score_before', '')::NUMERIC;
  v_sentiment := nullif(v_enr->>'sentiment', '');
  v_pipeline_ver := nullif(v_enr->>'quality_pipeline_version', '');
  v_blocked_reasons := CASE WHEN jsonb_typeof(v_enr->'auto_publish_blocked_reasons') = 'array'
    THEN ARRAY(SELECT jsonb_array_elements_text(v_enr->'auto_publish_blocked_reasons')) ELSE NULL END;
  v_country_ids := coalesce(
    CASE WHEN jsonb_typeof(v_enr->'country_ids') = 'array'
      THEN ARRAY(SELECT (jsonb_array_elements_text(v_enr->'country_ids'))::UUID) END,
    CASE WHEN jsonb_typeof(v_norm->'country_ids') = 'array'
      THEN ARRAY(SELECT (jsonb_array_elements_text(v_norm->'country_ids'))::UUID) END,
    '{}'::UUID[]);
  v_city_ids := coalesce(
    CASE WHEN jsonb_typeof(v_enr->'city_ids') = 'array'
      THEN ARRAY(SELECT (jsonb_array_elements_text(v_enr->'city_ids'))::UUID) END,
    CASE WHEN jsonb_typeof(v_norm->'city_ids') = 'array'
      THEN ARRAY(SELECT (jsonb_array_elements_text(v_norm->'city_ids'))::UUID) END,
    '{}'::UUID[]);
  v_review_items := v_enr->'quality_resolved_links'->'review';

  IF v_title IS NULL OR v_source_id IS NULL THEN
    UPDATE public.ingestion_staging SET disposition = 'rejected',
      error_message = 'missing title or source_id', processed_at = now() WHERE id = v_row.id;
    article_id := NULL; action := 'rejected'; RETURN NEXT; RETURN;
  END IF;

  v_fp := public.news_compute_fingerprint(v_title, v_published, v_source_id, v_url);
  v_existing_id := NULL;
  IF v_fp IS NOT NULL THEN
    SELECT id INTO v_existing_id FROM public.news_articles WHERE fingerprint = v_fp LIMIT 1;
  END IF;
  IF v_existing_id IS NULL AND v_url IS NOT NULL THEN
    SELECT id INTO v_existing_id FROM public.news_articles WHERE url = v_url LIMIT 1;
  END IF;

  IF v_existing_id IS NULL THEN
    INSERT INTO public.news_articles (
      source_id, title, content, excerpt, url, image_url, image_attribution, image_hash, author,
      published_at, category, tags, country_ids, city_ids,
      fingerprint, content_hash, ingestion_staging_id,
      slug, publisher_name, first_seen_at, last_seen_at, seen_count,
      quality_status, relevance_score, quality_score, quality_score_before,
      sentiment, quality_decision, quality_pipeline_version,
      last_quality_run_at, auto_publish_blocked_reasons
    ) VALUES (
      v_source_id, v_title, v_content,
      left(coalesce(v_excerpt, v_content), 500),
      coalesce(v_url, 'staging://' || v_row.id::TEXT), v_image, v_image_attribution, v_image_hash,
      coalesce(v_norm->>'author', v_meta->>'author'), v_published,
      coalesce(nullif(v_norm->>'category',''), 'general'),
      coalesce(ARRAY(SELECT jsonb_array_elements_text(v_norm->'tags')), '{}'::TEXT[]),
      v_country_ids, v_city_ids, v_fp,
      encode(extensions.digest(convert_to(coalesce(v_content, v_title, ''), 'UTF8'), 'sha256'), 'hex'),
      v_row.id,
      coalesce(nullif(v_norm->>'slug',''),
        trim(both '-' from substr(regexp_replace(lower(v_title), '[^a-z0-9]+', '-', 'g'), 1, 240))
          || '-' || substr(coalesce(v_fp, gen_random_uuid()::TEXT), 1, 8)),
      coalesce(nullif(v_norm->>'publisher_name',''), v_row.source_name),
      now(), now(), 1,
      v_quality_status, v_relevance, v_quality_after, v_quality_before,
      v_sentiment, v_enr->'quality_decision', v_pipeline_ver,
      CASE WHEN v_quality_status IS NOT NULL THEN now() ELSE NULL END,
      v_blocked_reasons
    ) RETURNING id INTO v_target_id;
    v_action := 'inserted';
  ELSE
    UPDATE public.news_articles SET
      title = coalesce(v_title, title),
      content = coalesce(nullif(v_content,''), content),
      excerpt = coalesce(nullif(v_excerpt,''), excerpt),
      image_url = coalesce(v_image, image_url),
      image_attribution = coalesce(v_image_attribution, image_attribution),
      image_hash = coalesce(v_image_hash, image_hash),
      author = coalesce(v_norm->>'author', v_meta->>'author', author),
      published_at = LEAST(published_at, v_published),
      last_seen_at = now(), seen_count = coalesce(seen_count,1) + 1,
      fingerprint = coalesce(fingerprint, v_fp),
      content_hash = coalesce(content_hash, encode(extensions.digest(convert_to(coalesce(v_content, v_title, ''), 'UTF8'), 'sha256'), 'hex')),
      country_ids = ARRAY(SELECT DISTINCT unnest(coalesce(country_ids,'{}'::UUID[]) || v_country_ids)),
      city_ids    = ARRAY(SELECT DISTINCT unnest(coalesce(city_ids,'{}'::UUID[])    || v_city_ids)),
      quality_status = coalesce(v_quality_status, quality_status),
      relevance_score = coalesce(v_relevance, relevance_score),
      quality_score = coalesce(v_quality_after, quality_score),
      quality_score_before = coalesce(v_quality_before, quality_score_before),
      sentiment = coalesce(v_sentiment, sentiment),
      quality_decision = coalesce(v_enr->'quality_decision', quality_decision),
      quality_pipeline_version = coalesce(v_pipeline_ver, quality_pipeline_version),
      last_quality_run_at = CASE WHEN v_quality_status IS NOT NULL THEN now() ELSE last_quality_run_at END,
      auto_publish_blocked_reasons = coalesce(v_blocked_reasons, auto_publish_blocked_reasons),
      updated_at = now()
    WHERE id = v_existing_id RETURNING id INTO v_target_id;
    v_action := 'updated';
  END IF;

  IF array_length(v_country_ids, 1) > 0 THEN
    INSERT INTO public.news_article_countries (article_id, country_id)
    SELECT v_target_id, cid FROM unnest(v_country_ids) AS cid
    ON CONFLICT (article_id, country_id) DO NOTHING;
  END IF;
  IF array_length(v_city_ids, 1) > 0 THEN
    INSERT INTO public.news_article_cities (article_id, city_id)
    SELECT v_target_id, cid FROM unnest(v_city_ids) AS cid
    ON CONFLICT (article_id, city_id) DO NOTHING;
  END IF;

  IF jsonb_typeof(v_review_items) = 'array' AND jsonb_array_length(v_review_items) > 0 THEN
    INSERT INTO public.entity_link_review (article_id, entity_type, candidate_name, score, context_snippet)
    SELECT v_target_id, COALESCE(item->>'type', 'country'),
           item->>'name', (item->>'score')::NUMERIC, item->>'reason'
      FROM jsonb_array_elements(v_review_items) AS item
     WHERE item->>'name' IS NOT NULL;
  END IF;

  UPDATE public.ingestion_staging
    SET disposition = v_action, target_record_id = v_target_id, processed_at = now()
   WHERE id = v_row.id;

  INSERT INTO public.ingestion_events (staging_id, stage, new_status, actor, payload)
  VALUES (v_row.id, 'commit', v_action, p_actor,
          jsonb_build_object('article_id', v_target_id, 'action', v_action, 'fingerprint', v_fp));

  article_id := v_target_id;
  action := v_action;
  RETURN NEXT;
END;
$$;


ALTER FUNCTION "public"."commit_news_staging_item"("p_staging_id" "uuid", "p_actor" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_personality_staging_batch"("p_limit" integer DEFAULT 50) RETURNS TABLE("staging_id" "uuid", "personality_id" "uuid", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE
  r   RECORD;
  res RECORD;
BEGIN
  FOR r IN
    SELECT id FROM public.ingestion_staging
    WHERE target_table = 'personalities'
      AND disposition IN ('pending','approved')
      AND ai_validation_status = 'approved'
      AND (dedup_status IN ('unique','duplicate','merge_candidate') OR dedup_status IS NULL)
      AND (review_status IN ('auto','approved') OR review_status IS NULL)
    ORDER BY created_at ASC
    LIMIT p_limit
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      SELECT * INTO res FROM public.commit_personality_staging_item(r.id, 'batch');
      staging_id := r.id; personality_id := res.personality_id; action := res.action;
      RETURN NEXT;
    EXCEPTION WHEN OTHERS THEN
      UPDATE public.ingestion_staging SET
        disposition   = 'rejected',
        error_message = 'commit_fn: ' || SQLERRM,
        updated_at    = now()
      WHERE id = r.id;
      INSERT INTO public.ingestion_events (staging_id, stage, new_status, actor, payload)
      VALUES (r.id, 'commit', 'rejected', 'batch',
              jsonb_build_object('error', SQLERRM, 'target_table', 'personalities'));
    END;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."commit_personality_staging_batch"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_personality_staging_item"("p_staging_id" "uuid", "p_actor" "text" DEFAULT 'pipeline-commit'::"text") RETURNS TABLE("personality_id" "uuid", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_stage       RECORD;
  v_norm        JSONB;
  v_enr         JSONB;
  v_meta        JSONB;
  v_name        TEXT;
  v_qid         TEXT;
  v_external    JSONB;
  v_description TEXT;
  v_bio         TEXT;
  v_profession  TEXT;
  v_nationality TEXT;
  v_birth_date  DATE;
  v_death_date  DATE;
  v_birth_place TEXT;
  v_image_url   TEXT;
  v_website     TEXT;
  v_pronouns    TEXT;
  v_is_living   BOOLEAN;
  v_fields      JSONB;
  v_social      JSONB;
  v_achievements JSONB;
  v_lgbti_conn  TEXT;
  v_lgbti_det   TEXT;
  v_top_book    TEXT;
  v_concerts    JSONB;
  v_sensit      JSONB;
  v_source_slug TEXT;
  v_source_eid  TEXT;
  v_source_url  TEXT;
  v_existing_id UUID;
  v_payload     JSONB;
  v_hash        TEXT;
  v_lock_key    BIGINT;
  v_action      TEXT;
  v_result_id   UUID;
  v_visibility  TEXT;
  v_verif       TEXT;
BEGIN
  SELECT * INTO v_stage FROM public.ingestion_staging WHERE id = p_staging_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'staging_item_not_found: %', p_staging_id; END IF;
  IF v_stage.target_table <> 'personalities' THEN
    RAISE EXCEPTION 'not_a_personality_staging_item: target=%', v_stage.target_table;
  END IF;
  IF v_stage.disposition IN ('inserted','updated','committed','rejected') THEN
    RETURN QUERY SELECT v_stage.target_record_id, 'noop'::text;
    RETURN;
  END IF;

  v_norm := coalesce(v_stage.normalized_data, '{}'::jsonb);
  v_enr  := coalesce(v_stage.enriched_data,   '{}'::jsonb);
  v_meta := coalesce(v_norm->'metadata', v_stage.raw_data, '{}'::jsonb);

  v_name        := nullif(btrim(v_norm->>'name'), '');
  v_qid         := nullif(btrim(coalesce(v_norm->>'wikidata_qid', v_meta->>'wikidata_qid', v_enr->>'wikidata_qid')), '');
  v_external    := coalesce(v_norm->'external_ids', v_enr->'external_ids', '{}'::jsonb);
  v_description := nullif(btrim(coalesce(v_norm->>'description', v_enr->>'description', v_meta->>'description')), '');
  v_bio         := nullif(btrim(coalesce(v_norm->>'bio', v_enr->>'bio')), '');
  v_profession  := nullif(btrim(coalesce(v_norm->>'profession', v_meta->>'profession')), '');
  v_nationality := nullif(btrim(coalesce(v_norm->>'nationality', v_meta->>'nationality')), '');
  v_birth_date  := nullif(v_norm->>'birth_date','')::date;
  v_death_date  := nullif(v_norm->>'death_date','')::date;
  v_birth_place := nullif(btrim(coalesce(v_norm->>'birth_place', v_meta->>'birth_place')), '');
  v_image_url   := nullif(btrim(coalesce(v_norm->>'image_url', v_enr->>'image_url')), '');
  v_website     := nullif(btrim(coalesce(v_norm->>'website_url', v_meta->>'website_url')), '');
  v_pronouns    := nullif(btrim(coalesce(v_norm->>'pronouns', v_meta->>'pronouns')), '');
  v_lgbti_conn  := nullif(btrim(coalesce(v_norm->>'lgbti_connection', v_enr->>'lgbti_connection')), '');
  v_lgbti_det   := nullif(btrim(coalesce(v_norm->>'lgbti_details',    v_enr->>'lgbti_details')), '');
  v_top_book    := nullif(btrim(coalesce(v_norm->>'top_book', v_enr->>'top_book')), '');
  v_is_living   := CASE WHEN v_death_date IS NOT NULL THEN false
                        WHEN v_norm ? 'is_living' THEN (v_norm->>'is_living')::boolean
                        ELSE true END;
  v_fields      := coalesce(v_norm->'fields',       '[]'::jsonb);
  v_social      := coalesce(v_norm->'social_links', v_enr->'social_links', '{}'::jsonb);
  v_achievements:= coalesce(v_norm->'achievements', v_enr->'achievements', '[]'::jsonb);
  v_concerts    := coalesce(v_norm->'next_concerts', v_enr->'next_concerts', '[]'::jsonb);
  v_sensit      := coalesce(v_norm->'sensitivity_flags', v_enr->'sensitivity_flags', '{}'::jsonb);

  v_source_slug := coalesce(v_stage.source_name, v_stage.source_type, 'unknown');
  v_source_eid  := coalesce(v_stage.source_entity_id, v_qid, v_meta->>'id', v_meta->>'external_id');
  v_source_url  := nullif(btrim(coalesce(v_meta->>'url', v_norm->>'profile_url')), '');

  IF v_name IS NULL THEN RAISE EXCEPTION 'personality_missing_name: staging=%', p_staging_id; END IF;

  v_payload := jsonb_strip_nulls(jsonb_build_object(
    'name', v_name, 'wikidata_qid', v_qid, 'birth_date', v_birth_date, 'profession', v_profession
  ));
  v_hash     := encode(extensions.digest(v_payload::text, 'sha256'), 'hex');
  v_lock_key := ('x'||substr(md5(coalesce(v_qid, lower(v_name))), 1, 15))::bit(60)::bigint;
  PERFORM pg_advisory_xact_lock(v_lock_key);

  v_existing_id := v_stage.dedup_match_id;
  IF v_existing_id IS NULL AND v_qid IS NOT NULL THEN
    SELECT id INTO v_existing_id FROM public.personalities WHERE wikidata_qid = v_qid LIMIT 1;
  END IF;

  v_visibility := coalesce(nullif(v_norm->>'visibility',''), 'draft');
  v_verif      := coalesce(nullif(v_norm->>'verification_status',''), 'pending');

  IF v_existing_id IS NULL THEN
    INSERT INTO public.personalities (
      name, pronouns, description, bio, birth_date, death_date, is_living,
      profession, nationality, birth_place, image_url, website_url,
      fields, social_links, achievements, next_concerts, top_book,
      lgbti_connection, lgbti_details, sensitivity_flags,
      wikidata_qid, external_ids,
      verification_status, visibility, is_featured,
      payload_hash, last_refreshed_at, created_at, updated_at
    ) VALUES (
      v_name, v_pronouns, v_description, v_bio, v_birth_date, v_death_date, v_is_living,
      v_profession, v_nationality, v_birth_place, v_image_url, v_website,
      v_fields, v_social, v_achievements, v_concerts, v_top_book,
      v_lgbti_conn, v_lgbti_det, v_sensit,
      v_qid, v_external,
      v_verif, v_visibility, false,
      v_hash, now(), now(), now()
    ) RETURNING id INTO v_result_id;
    v_action := 'inserted';
  ELSE
    UPDATE public.personalities SET
      description       = coalesce(description,       v_description),
      bio               = coalesce(bio,               v_bio),
      birth_date        = coalesce(birth_date,        v_birth_date),
      death_date        = coalesce(death_date,        v_death_date),
      is_living         = coalesce(is_living,         v_is_living),
      profession        = coalesce(profession,        v_profession),
      nationality       = coalesce(nationality,       v_nationality),
      birth_place       = coalesce(birth_place,       v_birth_place),
      image_url         = coalesce(image_url,         v_image_url),
      website_url       = coalesce(website_url,       v_website),
      pronouns          = coalesce(pronouns,          v_pronouns),
      lgbti_connection  = coalesce(lgbti_connection,  v_lgbti_conn),
      lgbti_details     = coalesce(lgbti_details,     v_lgbti_det),
      top_book          = coalesce(top_book,          v_top_book),
      wikidata_qid      = coalesce(wikidata_qid,      v_qid),
      external_ids      = coalesce(external_ids,'{}'::jsonb) || v_external,
      social_links      = coalesce(social_links,'{}'::jsonb) || v_social,
      fields            = CASE WHEN jsonb_array_length(coalesce(fields,'[]'::jsonb)) = 0 THEN v_fields ELSE fields END,
      achievements      = CASE WHEN jsonb_array_length(coalesce(achievements,'[]'::jsonb)) = 0 THEN v_achievements ELSE achievements END,
      next_concerts     = CASE WHEN jsonb_array_length(coalesce(next_concerts,'[]'::jsonb)) = 0 THEN v_concerts ELSE next_concerts END,
      sensitivity_flags = coalesce(sensitivity_flags,'{}'::jsonb) || v_sensit,
      payload_hash      = v_hash,
      last_refreshed_at = now(),
      updated_at        = now()
    WHERE id = v_existing_id;
    v_result_id := v_existing_id;
    v_action    := 'updated';
  END IF;

  IF v_source_eid IS NOT NULL THEN
    INSERT INTO public.personality_sources (
      personality_id, source_slug, source_entity_id, source_url,
      raw, payload_hash, confidence, is_primary, first_seen_at, last_seen_at
    ) VALUES (
      v_result_id, v_source_slug, v_source_eid, v_source_url,
      v_stage.raw_data, v_hash, coalesce(v_stage.ai_confidence_score, 1.0),
      v_action = 'inserted', now(), now()
    )
    ON CONFLICT (source_slug, source_entity_id) DO UPDATE SET
      personality_id = EXCLUDED.personality_id,
      raw            = EXCLUDED.raw,
      payload_hash   = EXCLUDED.payload_hash,
      confidence     = EXCLUDED.confidence,
      last_seen_at   = now();
  END IF;

  UPDATE public.ingestion_staging SET
    disposition      = v_action,
    target_record_id = v_result_id,
    processed_at     = now(),
    updated_at       = now()
  WHERE id = p_staging_id;

  INSERT INTO public.ingestion_events (staging_id, stage, old_status, new_status, actor, payload)
  VALUES (p_staging_id, 'commit', v_stage.disposition, v_action, p_actor,
          jsonb_build_object('source_slug', v_source_slug, 'source_entity_id', v_source_eid,
                             'action', v_action, 'personality_id', v_result_id,
                             'target_table', 'personalities', 'wikidata_qid', v_qid));

  RETURN QUERY SELECT v_result_id, v_action;
END;
$$;


ALTER FUNCTION "public"."commit_personality_staging_item"("p_staging_id" "uuid", "p_actor" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."commit_personality_staging_item"("p_staging_id" "uuid", "p_actor" "text") IS 'Atomic commit: upsert personality + personality_sources + audit + advisory lock';



CREATE OR REPLACE FUNCTION "public"."commit_venue_staging_batch"("p_limit" integer DEFAULT 50) RETURNS TABLE("staging_id" "uuid", "venue_id" "uuid", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE
  r RECORD;
  res RECORD;
BEGIN
  FOR r IN
    SELECT id FROM public.ingestion_staging
    WHERE target_table = 'venues'
      AND disposition IN ('pending','approved')
      AND ai_validation_status = 'approved'
      AND (dedup_status IN ('unique','duplicate','merge_candidate') OR dedup_status IS NULL)
      AND (review_status IN ('auto','approved') OR review_status IS NULL)
    ORDER BY created_at ASC
    LIMIT p_limit
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      SELECT * INTO res FROM public.commit_venue_staging_item(r.id, 'batch');
      staging_id := r.id; venue_id := res.venue_id; action := res.action;
      RETURN NEXT;
    EXCEPTION WHEN OTHERS THEN
      UPDATE public.ingestion_staging SET
        disposition = 'rejected',
        error_message = 'commit_fn: ' || SQLERRM,
        updated_at = now()
      WHERE id = r.id;
      INSERT INTO public.ingestion_events (staging_id, stage, new_status, actor, payload)
      VALUES (r.id, 'commit', 'rejected', 'batch', jsonb_build_object('error', SQLERRM));
    END;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."commit_venue_staging_batch"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_venue_staging_item"("p_staging_id" "uuid", "p_actor" "text" DEFAULT 'pipeline'::"text") RETURNS TABLE("venue_id" "uuid", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog', 'extensions'
    AS $$
DECLARE
  v_stage RECORD; v_norm JSONB; v_enr JSONB; v_loc JSONB; v_contacts JSONB; v_meta JSONB;
  v_source_slug TEXT; v_source_eid TEXT;
  v_phone TEXT; v_email TEXT; v_website TEXT; v_phone_n TEXT; v_email_n TEXT; v_domain TEXT;
  v_name TEXT; v_existing_id UUID; v_city_id UUID; v_lat NUMERIC; v_lng NUMERIC;
  v_address TEXT; v_category TEXT; v_description TEXT;
  v_payload JSONB; v_hash TEXT; v_lock_key BIGINT; v_action TEXT; v_result_id UUID;
  v_acc_type TEXT; v_booking_url TEXT; v_stars NUMERIC;
  v_amenities TEXT[]; v_platform JSONB; v_lgbtq_tags TEXT[]; v_existing_tags TEXT[];
  v_valid_categories CONSTANT TEXT[] := ARRAY['bar','club','restaurant','hotel','sauna','theater','community_center','organization','event-venue','gallery','other'];
  -- Shadow-mode: snapshot of existing venue for conflict logging
  v_old_desc TEXT; v_old_addr TEXT; v_old_phone TEXT; v_old_email TEXT; v_old_site TEXT;
  v_old_src TEXT; v_old_age NUMERIC;
BEGIN
  SELECT * INTO v_stage FROM public.ingestion_staging WHERE id = p_staging_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'staging_item_not_found: %', p_staging_id; END IF;
  IF v_stage.target_table <> 'venues' THEN RAISE EXCEPTION 'not_a_venue_staging_item: target=%', v_stage.target_table; END IF;
  IF v_stage.disposition IN ('inserted','updated','committed','rejected') THEN
    RETURN QUERY SELECT v_stage.target_record_id, 'noop'::text; RETURN;
  END IF;
  v_norm := coalesce(v_stage.normalized_data, '{}'::jsonb);
  v_enr := coalesce(v_stage.enriched_data, '{}'::jsonb);
  v_loc := coalesce(v_norm->'location', '{}'::jsonb);
  v_contacts := coalesce(v_norm->'contacts', '{}'::jsonb);
  v_meta := coalesce(v_norm->'metadata', v_stage.raw_data, '{}'::jsonb);
  v_name := nullif(btrim(v_norm->>'name'), '');
  v_description := nullif(btrim(coalesce(v_norm->>'description', v_enr->>'description')), '');
  v_address := nullif(btrim(v_loc->>'address'), '');
  v_lat := nullif(v_loc->>'lat','')::numeric;
  v_lng := nullif(v_loc->>'lng','')::numeric;
  v_category := lower(coalesce(nullif(v_norm->>'category',''), ''));
  IF NOT (v_category = ANY(v_valid_categories)) THEN v_category := 'other'; END IF;
  v_phone := nullif(btrim(v_contacts->>'phone'), '');
  v_email := nullif(btrim(v_contacts->>'email'), '');
  v_website := nullif(btrim(v_contacts->>'website'), '');
  v_phone_n := public.normalize_phone(v_phone);
  v_email_n := lower(v_email);
  v_domain := public.extract_website_domain(v_website);
  v_source_slug := coalesce(v_stage.source_name, v_stage.source_type, 'unknown');
  v_source_eid := coalesce(v_stage.source_entity_id, v_meta->>'id', v_meta->>'external_id', v_meta->>'source_id');
  v_acc_type := nullif(btrim(v_norm->>'accommodation_type'), '');
  v_booking_url := nullif(btrim(coalesce(v_norm->>'booking_url', v_enr->>'booking_url')), '');
  v_stars := nullif(v_norm->>'star_rating','')::numeric;
  v_platform := coalesce(v_norm->'platform_ids', '{}'::jsonb);
  IF jsonb_typeof(v_norm->'amenities') = 'array' THEN
    SELECT array_agg(value) INTO v_amenities FROM jsonb_array_elements_text(v_norm->'amenities');
  END IF;
  IF jsonb_typeof(v_norm->'lgbtq_markers') = 'array' THEN
    SELECT array_agg(value) INTO v_lgbtq_tags FROM jsonb_array_elements_text(v_norm->'lgbtq_markers');
  END IF;
  IF v_name IS NULL THEN RAISE EXCEPTION 'venue_missing_name: staging=%', p_staging_id; END IF;
  v_lock_key := hashtextextended(coalesce(v_phone_n, v_email_n, v_domain, public.normalize_name(v_name)), 0);
  PERFORM pg_advisory_xact_lock(v_lock_key);
  IF v_source_eid IS NOT NULL THEN
    SELECT vs.venue_id INTO v_existing_id FROM public.venue_sources vs
    WHERE vs.source_slug = v_source_slug AND vs.source_entity_id = v_source_eid LIMIT 1;
  END IF;
  IF v_existing_id IS NULL AND v_stage.dedup_match_id IS NOT NULL
     AND coalesce(v_stage.dedup_match_table,'venues') = 'venues'
     AND v_stage.dedup_status IN ('duplicate','merge_candidate') THEN
    v_existing_id := v_stage.dedup_match_id;
  END IF;
  IF v_loc->>'city' IS NOT NULL AND length(btrim(v_loc->>'city')) > 0 THEN
    SELECT c.id INTO v_city_id FROM public.cities c WHERE lower(c.name) = lower(btrim(v_loc->>'city')) LIMIT 1;
  END IF;
  v_payload := jsonb_build_object('raw', v_stage.raw_data, 'normalized', v_norm, 'enriched', v_enr);
  v_hash := encode(extensions.digest(v_payload::text, 'sha256'), 'hex');
  IF v_existing_id IS NULL THEN
    INSERT INTO public.venues (
      name, description, address, city, country, latitude, longitude,
      phone, email, website, category, city_id,
      accommodation_type, booking_url, star_rating, amenities, platform_ids,
      data_source, external_id, last_synced_at, last_refreshed_at, created_at, updated_at
    ) VALUES (
      v_name, v_description, coalesce(v_address, v_name),
      coalesce(nullif(v_loc->>'city',''), ''), coalesce(nullif(v_loc->>'country',''), ''),
      v_lat, v_lng, v_phone, v_email, v_website, v_category, v_city_id,
      v_acc_type, v_booking_url, v_stars,
      coalesce(v_amenities, ARRAY[]::text[]), v_platform,
      v_source_slug, v_source_eid, now(), now(), now(), now()
    ) RETURNING venues.id INTO v_result_id;
    v_action := 'inserted';
  ELSE
    -- Snapshot existing values for shadow-mode conflict logging
    SELECT description, address, phone, email, website,
           data_source, EXTRACT(EPOCH FROM (now() - updated_at))/86400.0
      INTO v_old_desc, v_old_addr, v_old_phone, v_old_email, v_old_site,
           v_old_src, v_old_age
    FROM public.venues WHERE venues.id = v_existing_id;

    PERFORM public.log_venue_field_conflict(v_existing_id, p_staging_id,
      'description', v_old_desc, v_old_src, v_old_age, v_description, v_source_slug);
    PERFORM public.log_venue_field_conflict(v_existing_id, p_staging_id,
      'address',     v_old_addr, v_old_src, v_old_age, v_address,     v_source_slug);
    PERFORM public.log_venue_field_conflict(v_existing_id, p_staging_id,
      'phone',       v_old_phone, v_old_src, v_old_age, v_phone,      v_source_slug);
    PERFORM public.log_venue_field_conflict(v_existing_id, p_staging_id,
      'email',       v_old_email, v_old_src, v_old_age, v_email,      v_source_slug);
    PERFORM public.log_venue_field_conflict(v_existing_id, p_staging_id,
      'website',     v_old_site,  v_old_src, v_old_age, v_website,    v_source_slug);

    UPDATE public.venues SET
      description = coalesce(description, v_description),
      address = coalesce(nullif(address,''), v_address, address),
      phone = coalesce(phone, v_phone),
      email = coalesce(email, v_email),
      website = coalesce(website, v_website),
      latitude = coalesce(latitude, v_lat),
      longitude = coalesce(longitude, v_lng),
      city_id = coalesce(city_id, v_city_id),
      accommodation_type = coalesce(accommodation_type, v_acc_type),
      booking_url = coalesce(booking_url, v_booking_url),
      star_rating = coalesce(star_rating, v_stars),
      amenities = CASE WHEN v_amenities IS NOT NULL AND array_length(v_amenities,1) > 0
                       THEN ARRAY(SELECT DISTINCT unnest(coalesce(amenities, ARRAY[]::text[]) || v_amenities))
                       ELSE amenities END,
      platform_ids = coalesce(platform_ids, '{}'::jsonb) || v_platform,
      last_refreshed_at = now(), updated_at = now()
    WHERE venues.id = v_existing_id;
    v_result_id := v_existing_id; v_action := 'updated';
  END IF;
  IF v_lgbtq_tags IS NOT NULL AND array_length(v_lgbtq_tags,1) > 0 THEN
    SELECT v.tags INTO v_existing_tags FROM public.venues v WHERE v.id = v_result_id;
    UPDATE public.venues
    SET tags = ARRAY(SELECT DISTINCT unnest(coalesce(v_existing_tags, ARRAY[]::text[]) || v_lgbtq_tags))
    WHERE venues.id = v_result_id;
  END IF;
  IF v_source_eid IS NOT NULL THEN
    INSERT INTO public.venue_sources (
      venue_id, source_slug, source_entity_id, source_url, payload, payload_hash,
      confidence, is_primary, first_seen_at, last_seen_at
    ) VALUES (
      v_result_id, v_source_slug, v_source_eid, nullif(btrim(v_meta->>'url'), ''),
      v_payload, v_hash, coalesce(v_stage.ai_confidence_score, 1.0),
      v_action = 'inserted', now(), now()
    ) ON CONFLICT (source_slug, source_entity_id) DO UPDATE SET
      payload = EXCLUDED.payload, payload_hash = EXCLUDED.payload_hash,
      confidence = EXCLUDED.confidence, last_seen_at = now();
  END IF;
  UPDATE public.ingestion_staging SET
    disposition = v_action, target_record_id = v_result_id,
    processed_at = now(), updated_at = now()
  WHERE ingestion_staging.id = p_staging_id;
  INSERT INTO public.ingestion_events (staging_id, venue_id, stage, old_status, new_status, actor, payload)
  VALUES (p_staging_id, v_result_id, 'commit', v_stage.disposition, v_action, p_actor,
          jsonb_build_object('source_slug', v_source_slug, 'source_entity_id', v_source_eid,
                             'action', v_action, 'accommodation_type', v_acc_type));
  RETURN QUERY SELECT v_result_id, v_action;
END;
$$;


ALTER FUNCTION "public"."commit_venue_staging_item"("p_staging_id" "uuid", "p_actor" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."commit_village_staging_batch"("p_limit" integer DEFAULT 50) RETURNS TABLE("staging_id" "uuid", "village_id" "uuid", "action" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_catalog', 'extensions'
    AS $$
DECLARE
  r   RECORD;
  v_id uuid;
  v_action text;
  v_slug text;
  v_name text;
  v_desc text;
  v_lat  double precision;
  v_lon  double precision;
  v_tags text[];
  v_website text;
  v_image_url text;
  v_db_id uuid;
  v_meta jsonb;
BEGIN
  FOR r IN
    SELECT s.id, s.normalized_data, s.enriched_data, s.source_entity_id
    FROM ingestion_staging s
    WHERE s.target_table = 'queer_villages'
      AND s.disposition   = 'pending'
      AND s.dedup_status  IN ('unique','pending')
    ORDER BY s.created_at
    LIMIT p_limit
  LOOP
    v_action := 'skipped';

    BEGIN
      v_name    := r.normalized_data->>'name';
      v_desc    := COALESCE(r.normalized_data->>'description', r.enriched_data->>'wikipedia_extract', '');
      v_lat     := (r.normalized_data->'location'->>'lat')::double precision;
      v_lon     := (r.normalized_data->'location'->>'lng')::double precision;
      v_tags    := ARRAY(SELECT jsonb_array_elements_text(COALESCE(r.normalized_data->'tags','[]'::jsonb)));
      v_website := r.normalized_data->>'website';
      v_image_url := COALESCE(r.enriched_data->>'image_url', r.normalized_data->>'image_url');
      v_meta    := COALESCE(r.normalized_data->'metadata', '{}'::jsonb);
      v_db_id   := (v_meta->>'db_id')::uuid;

      IF v_name IS NULL OR v_name = '' THEN
        UPDATE ingestion_staging SET disposition='rejected', error_message='missing name', updated_at=now() WHERE id=r.id;
        CONTINUE;
      END IF;

      v_slug := lower(regexp_replace(v_name, '[^a-zA-Z0-9]+', '-', 'g'));
      v_slug := trim(both '-' from v_slug);

      IF v_db_id IS NOT NULL THEN
        UPDATE queer_villages SET
          description = CASE WHEN (description IS NULL OR description='') AND v_desc <> '' THEN v_desc ELSE description END,
          latitude    = COALESCE(latitude, v_lat),
          longitude   = COALESCE(longitude, v_lon),
          image_url   = COALESCE(image_url, v_image_url),
          tags        = CASE WHEN tags IS NULL OR array_length(tags,1) IS NULL THEN v_tags ELSE tags END,
          updated_at  = now()
        WHERE id = v_db_id
        RETURNING id INTO v_id;
        v_action := 'updated';
      ELSE
        INSERT INTO queer_villages (name, slug, description, latitude, longitude, tags, website, image_url, created_at, updated_at)
        VALUES (v_name, v_slug, v_desc, v_lat, v_lon, v_tags, v_website, v_image_url, now(), now())
        ON CONFLICT (slug) DO UPDATE SET
          description = CASE WHEN (queer_villages.description IS NULL OR queer_villages.description='') AND v_desc<>'' THEN v_desc ELSE queer_villages.description END,
          updated_at  = now()
        RETURNING id INTO v_id;
        v_action := 'inserted';
      END IF;

      UPDATE ingestion_staging SET
        disposition      = 'committed',
        target_record_id = v_id,
        processed_at     = now(),
        updated_at       = now()
      WHERE id = r.id;

    EXCEPTION WHEN OTHERS THEN
      v_action := 'error';
      UPDATE ingestion_staging SET
        disposition   = 'rejected',
        error_message = SQLERRM,
        updated_at    = now()
      WHERE id = r.id;
    END;

    staging_id := r.id;
    village_id := v_id;
    action     := v_action;
    RETURN NEXT;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."commit_village_staging_batch"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."compute_quality_score"("p_entity_type" "text", "p_entity_id" "uuid") RETURNS smallint
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  score SMALLINT := 0;
  has_embedding BOOLEAN := false;
BEGIN
  SELECT EXISTS(
    SELECT 1 FROM content_embeddings 
    WHERE content_type = p_entity_type AND content_id = p_entity_id
  ) INTO has_embedding;

  IF p_entity_type = 'venues' THEN
    SELECT
      CASE WHEN v.name IS NOT NULL AND v.name != '' THEN 15 ELSE 0 END +
      CASE WHEN v.latitude IS NOT NULL AND v.longitude IS NOT NULL THEN 15 ELSE 0 END +
      CASE WHEN v.city_id IS NOT NULL THEN 10 ELSE 0 END +
      CASE WHEN v.country_id IS NOT NULL THEN 5 ELSE 0 END +
      CASE WHEN v.category IS NOT NULL AND v.category != '' THEN 10 ELSE 0 END +
      CASE WHEN v.website IS NOT NULL AND v.website != '' THEN 10 ELSE 0 END +
      CASE WHEN v.images IS NOT NULL AND array_length(v.images, 1) > 0 THEN 10 ELSE 0 END +
      CASE WHEN v.description IS NOT NULL AND length(v.description) > 50 THEN 10 ELSE 0 END +
      CASE WHEN has_embedding THEN 5 ELSE 0 END +
      CASE WHEN v.duplicate_of_id IS NULL THEN 10 ELSE 0 END
    INTO score
    FROM venues v WHERE v.id = p_entity_id;

  ELSIF p_entity_type = 'events' THEN
    SELECT
      CASE WHEN e.title IS NOT NULL AND e.title != '' THEN 15 ELSE 0 END +
      CASE WHEN e.start_date IS NOT NULL THEN 15 ELSE 0 END +
      CASE WHEN e.city_id IS NOT NULL THEN 10 ELSE 0 END +
      CASE WHEN e.country_id IS NOT NULL THEN 5 ELSE 0 END +
      CASE WHEN e.venue_id IS NOT NULL THEN 10 ELSE 0 END +
      CASE WHEN e.description IS NOT NULL AND length(e.description) > 0 THEN 10 ELSE 0 END +
      CASE WHEN e.website IS NOT NULL AND e.website != '' THEN 10 ELSE 0 END +
      CASE WHEN has_embedding THEN 5 ELSE 0 END +
      CASE WHEN e.event_type IS NOT NULL AND e.event_type != '' THEN 10 ELSE 0 END +
      CASE WHEN e.duplicate_of_id IS NULL THEN 10 ELSE 0 END
    INTO score
    FROM events e WHERE e.id = p_entity_id;

  ELSIF p_entity_type = 'personalities' THEN
    SELECT
      CASE WHEN p.name IS NOT NULL AND p.name != '' THEN 15 ELSE 0 END +
      CASE WHEN p.birth_date IS NOT NULL THEN 10 ELSE 0 END +
      CASE WHEN p.city_id IS NOT NULL THEN 10 ELSE 0 END +
      CASE WHEN p.country_id IS NOT NULL THEN 10 ELSE 0 END +
      CASE WHEN p.profession IS NOT NULL AND p.profession != '' THEN 10 ELSE 0 END +
      CASE WHEN p.lgbti_connection IS NOT NULL AND length(p.lgbti_connection) > 0 THEN 15 ELSE 0 END +
      CASE WHEN p.image_url IS NOT NULL AND p.image_url != '' THEN 10 ELSE 0 END +
      CASE WHEN has_embedding THEN 10 ELSE 0 END +
      CASE WHEN p.duplicate_of_id IS NULL THEN 10 ELSE 0 END
    INTO score
    FROM personalities p WHERE p.id = p_entity_id;

  ELSIF p_entity_type = 'news_articles' THEN
    SELECT
      CASE WHEN n.title IS NOT NULL AND n.title != '' THEN 15 ELSE 0 END +
      CASE WHEN n.content IS NOT NULL AND length(n.content) > 100 THEN 15 ELSE 0 END +
      CASE WHEN n.source_id IS NOT NULL THEN 10 ELSE 0 END +
      CASE WHEN (n.city_ids IS NOT NULL AND array_length(n.city_ids, 1) > 0)
            OR (n.country_ids IS NOT NULL AND array_length(n.country_ids, 1) > 0) THEN 15 ELSE 0 END +
      CASE WHEN n.image_url IS NOT NULL AND n.image_url != '' THEN 10 ELSE 0 END +
      CASE WHEN n.url IS NOT NULL AND n.url != '' THEN 10 ELSE 0 END +
      CASE WHEN has_embedding THEN 10 ELSE 0 END +
      CASE WHEN n.duplicate_of_id IS NULL THEN 15 ELSE 0 END
    INTO score
    FROM news_articles n WHERE n.id = p_entity_id;
  END IF;

  RETURN COALESCE(score, 0);
END;
$$;


ALTER FUNCTION "public"."compute_quality_score"("p_entity_type" "text", "p_entity_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."compute_staging_idempotency_key"("p_source_name" "text", "p_source_entity_id" "text", "p_payload_hash" "text", "p_fallback" "uuid") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'public', 'extensions', 'pg_catalog'
    AS $$
  SELECT encode(digest(
    coalesce(p_source_name, 'unknown') || ':' ||
    coalesce(nullif(p_source_entity_id, ''), p_payload_hash, p_fallback::text),
    'sha1'), 'hex');
$$;


