CREATE OR REPLACE FUNCTION "public"."compute_tag_similarities"() RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    SET "statement_timeout" TO '600s'
    AS $$
DECLARE
  embedding_count INT := 0;
  cooccurrence_count INT := 0;
  total_count INT;
  batch_count INT;
  tag_ids uuid[];
  batch_start INT;
  batch_size INT := 200;
  num_tags INT;
BEGIN
  IF NOT has_role_jwt('admin'::app_role) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE='42501'; END IF;
  TRUNCATE tag_relationships;
  SELECT array_agg(content_id ORDER BY content_id) INTO tag_ids FROM content_embeddings WHERE content_type = 'tag';
  num_tags := coalesce(array_length(tag_ids, 1), 0);
  IF num_tags = 0 THEN
    RETURN json_build_object('success', true, 'embedding_relationships', 0, 'cooccurrence_relationships', 0, 'total_relationships', 0);
  END IF;
  batch_start := 1;
  WHILE batch_start <= num_tags LOOP
    INSERT INTO tag_relationships (id, tag1_id, tag2_id, similarity_score, relationship_type)
    SELECT gen_random_uuid(), e1.content_id, e2.content_id,
      ROUND((1 - (e1.embedding <=> e2.embedding))::numeric, 4), 'embedding'
    FROM content_embeddings e1 JOIN content_embeddings e2
      ON e1.content_id < e2.content_id AND e2.content_type = 'tag'
    WHERE e1.content_type = 'tag'
      AND e1.content_id = ANY(tag_ids[batch_start : LEAST(batch_start + batch_size - 1, num_tags)])
      AND 1 - (e1.embedding <=> e2.embedding) >= 0.7;
    GET DIAGNOSTICS batch_count = ROW_COUNT;
    embedding_count := embedding_count + batch_count;
    batch_start := batch_start + batch_size;
  END LOOP;
  WITH venue_tag_ids AS (
    SELECT v.id AS venue_id, ut.id AS tag_id
    FROM venues v CROSS JOIN LATERAL unnest(v.tags) AS tag_name
    JOIN unified_tags ut ON lower(ut.name) = lower(tag_name)
    WHERE v.tags IS NOT NULL),
  tag_venue_counts AS (SELECT tag_id, COUNT(DISTINCT venue_id) AS venue_count FROM venue_tag_ids GROUP BY tag_id),
  co_pairs AS (SELECT LEAST(a.tag_id, b.tag_id) AS tag1_id, GREATEST(a.tag_id, b.tag_id) AS tag2_id,
    COUNT(DISTINCT a.venue_id) AS co_count
    FROM venue_tag_ids a JOIN venue_tag_ids b ON a.venue_id = b.venue_id AND a.tag_id < b.tag_id
    GROUP BY 1, 2),
  scored AS (SELECT cp.tag1_id, cp.tag2_id,
    ROUND((cp.co_count::numeric / GREATEST(tc1.venue_count + tc2.venue_count - cp.co_count, 1))::numeric, 4) AS score
    FROM co_pairs cp
    JOIN tag_venue_counts tc1 ON tc1.tag_id = cp.tag1_id
    JOIN tag_venue_counts tc2 ON tc2.tag_id = cp.tag2_id
    WHERE cp.co_count >= 3)
  INSERT INTO tag_relationships (id, tag1_id, tag2_id, similarity_score, relationship_type)
  SELECT gen_random_uuid(), s.tag1_id, s.tag2_id, s.score, 'co_occurrence' FROM scored s
  WHERE s.score >= 0.15
    AND NOT EXISTS (SELECT 1 FROM tag_relationships tr WHERE tr.tag1_id = s.tag1_id AND tr.tag2_id = s.tag2_id);
  GET DIAGNOSTICS cooccurrence_count = ROW_COUNT;
  SELECT COUNT(*) INTO total_count FROM tag_relationships;
  RETURN json_build_object('success', true, 'embedding_relationships', embedding_count,
    'cooccurrence_relationships', cooccurrence_count, 'total_relationships', total_count, 'tags_processed', num_tags);
END;
$$;


ALTER FUNCTION "public"."compute_tag_similarities"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."compute_workflow_duration"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.status IN ('completed', 'failed', 'dead_letter', 'cancelled')
     AND NEW.started_at IS NOT NULL AND NEW.completed_at IS NOT NULL THEN
    NEW.duration_ms = EXTRACT(EPOCH FROM (NEW.completed_at - NEW.started_at)) * 1000;
  END IF;
  RETURN NEW;
END;
$$;


