CREATE OR REPLACE FUNCTION "public"."detect_feedback_clusters"("p_trigram_threshold" real DEFAULT 0.35, "p_embedding_threshold" real DEFAULT 0.78, "p_days_window" integer DEFAULT 90, "p_min_cluster_size" integer DEFAULT 3) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_inserted integer := 0;
  v_row RECORD;
  v_parent jsonb := '{}'::jsonb;
  v_key_a text;
  v_key_b text;
  v_root_a text;
  v_root_b text;
BEGIN
  CREATE TEMP TABLE IF NOT EXISTS _fb_pairs(
    a_id uuid, b_id uuid, score real
  ) ON COMMIT DROP;
  TRUNCATE _fb_pairs;

  INSERT INTO _fb_pairs(a_id, b_id, score)
  WITH eligible AS (
    SELECT id, data->>'title' AS title, embedding
      FROM community_submissions
     WHERE content_type IN ('feedback','api_error')
       AND duplicate_of IS NULL
       AND is_spam = false
       AND submitted_at > now() - make_interval(days => p_days_window)
       AND feedback_status <> 'done'
       AND NOT EXISTS (
         SELECT 1 FROM feedback_story_members m
          JOIN feedback_stories s ON s.id = m.story_id
         WHERE m.submission_id = community_submissions.id
           AND s.status NOT IN ('resolved','archived')
       )
  )
  SELECT LEAST(a.id, b.id),
         GREATEST(a.id, b.id),
         GREATEST(
           0.4 * COALESCE(similarity(a.title, b.title), 0)
           + 0.6 * COALESCE(1 - (a.embedding <=> b.embedding), 0),
           0.0
         )::real AS score
    FROM eligible a
    JOIN eligible b
      ON a.id < b.id
     AND (
       similarity(a.title, b.title) >= p_trigram_threshold
       OR (a.embedding IS NOT NULL
           AND b.embedding IS NOT NULL
           AND (1 - (a.embedding <=> b.embedding)) >= p_embedding_threshold)
     );

  DELETE FROM _fb_pairs WHERE score < 0.45;

  FOR v_row IN SELECT a_id, b_id FROM _fb_pairs LOOP
    v_key_a := v_row.a_id::text;
    v_key_b := v_row.b_id::text;
    v_root_a := COALESCE(v_parent->>v_key_a, v_key_a);
    WHILE v_root_a <> COALESCE(v_parent->>v_root_a, v_root_a) LOOP
      v_root_a := v_parent->>v_root_a;
    END LOOP;
    v_root_b := COALESCE(v_parent->>v_key_b, v_key_b);
    WHILE v_root_b <> COALESCE(v_parent->>v_root_b, v_root_b) LOOP
      v_root_b := v_parent->>v_root_b;
    END LOOP;
    IF v_root_a <> v_root_b THEN
      v_parent := jsonb_set(v_parent, ARRAY[v_root_a], to_jsonb(v_root_b));
    END IF;
    v_parent := jsonb_set(v_parent, ARRAY[v_key_a], to_jsonb(v_root_b));
    v_parent := jsonb_set(v_parent, ARRAY[v_key_b], to_jsonb(v_root_b));
  END LOOP;

  INSERT INTO feedback_story_suggestions (
    proposed_title, member_ids, avg_similarity, method
  )
  WITH roots AS (
    SELECT key::uuid AS member_id, value #>> '{}' AS root
      FROM jsonb_each(v_parent)
  ),
  clusters AS (
    SELECT root, array_agg(member_id ORDER BY member_id) AS ids
      FROM roots
     GROUP BY root
    HAVING count(*) >= p_min_cluster_size
  ),
  scored AS (
    SELECT c.ids,
           (SELECT avg(score) FROM _fb_pairs p
             WHERE p.a_id = ANY(c.ids) AND p.b_id = ANY(c.ids))::real AS avg_score,
           (SELECT cs.data->>'title' FROM community_submissions cs
             WHERE cs.id = c.ids[1] LIMIT 1) AS seed_title
      FROM clusters c
  )
  SELECT
    COALESCE(seed_title, 'Related feedback cluster') AS proposed_title,
    ids,
    COALESCE(avg_score, 0.5),
    'hybrid'
  FROM scored
  WHERE NOT EXISTS (
    SELECT 1 FROM feedback_story_suggestions existing
     WHERE existing.dismissed = false
       AND existing.member_ids @> scored.ids
       AND scored.ids @> existing.member_ids
  );

  GET DIAGNOSTICS v_inserted = ROW_COUNT;
  RETURN v_inserted;
END;
$$;


ALTER FUNCTION "public"."detect_feedback_clusters"("p_trigram_threshold" real, "p_embedding_threshold" real, "p_days_window" integer, "p_min_cluster_size" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."detect_feedback_duplicates"("p_threshold" real DEFAULT 0.45, "p_days_window" integer DEFAULT 90) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_inserted integer := 0;
BEGIN
  WITH pairs AS (
    SELECT
      LEAST(a.id, b.id)   AS a_id,
      GREATEST(a.id, b.id) AS b_id,
      similarity(a.data->>'title', b.data->>'title') AS sim
    FROM community_submissions a
    JOIN community_submissions b
      ON a.id < b.id
      AND b.content_type = 'feedback'
      AND b.duplicate_of IS NULL
      AND b.is_spam = false
      AND b.submitted_at > now() - make_interval(days => p_days_window)
      AND (b.data->>'title') %> (a.data->>'title')
    WHERE a.content_type = 'feedback'
      AND a.duplicate_of IS NULL
      AND a.is_spam = false
      AND a.submitted_at > now() - make_interval(days => p_days_window)
  )
  INSERT INTO feedback_duplicate_suggestions (a_id, b_id, similarity)
  SELECT a_id, b_id, sim FROM pairs WHERE sim >= p_threshold
  ON CONFLICT (a_id, b_id) DO UPDATE
    SET similarity = EXCLUDED.similarity
    WHERE feedback_duplicate_suggestions.dismissed = false;

  GET DIAGNOSTICS v_inserted = ROW_COUNT;
  RETURN v_inserted;
END;
$$;


ALTER FUNCTION "public"."detect_feedback_duplicates"("p_threshold" real, "p_days_window" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."detect_near_duplicate_tags"("min_sim" real DEFAULT 0.7) RETURNS TABLE("tag_a_name" "text", "tag_a_category" "text", "tag_b_name" "text", "tag_b_category" "text", "sim" real)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN QUERY
  SELECT a.name, a.category, b.name, b.category, 
    extensions.similarity(LOWER(a.name), LOWER(b.name))
  FROM unified_tags a
  JOIN unified_tags b ON a.id < b.id
  WHERE a.status = 'active' AND b.status = 'active'
    AND extensions.similarity(LOWER(a.name), LOWER(b.name)) > min_sim
  ORDER BY extensions.similarity(LOWER(a.name), LOWER(b.name)) DESC
  LIMIT 100;
END;
$$;


ALTER FUNCTION "public"."detect_near_duplicate_tags"("min_sim" real) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."detect_stale_venues"("p_stale_after_days" integer DEFAULT 60, "p_dry_run" boolean DEFAULT false) RETURNS TABLE("venue_id" "uuid", "last_seen_at" timestamp with time zone)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_record RECORD;
BEGIN
  FOR v_record IN
    WITH last_sources AS (
      SELECT venue_id, MAX(last_seen_at) AS max_seen
      FROM public.venue_sources
      GROUP BY venue_id
    )
    SELECT v.id AS vid, ls.max_seen
    FROM public.venues v
    LEFT JOIN last_sources ls ON ls.venue_id = v.id
    WHERE v.closed_at IS NULL
      AND coalesce(ls.max_seen, v.created_at) < now() - (p_stale_after_days || ' days')::interval
  LOOP
    IF NOT p_dry_run THEN
      UPDATE public.venues SET closed_at = now()
        WHERE id = v_record.vid AND closed_at IS NULL;
      INSERT INTO public.venue_closed_audit(venue_id, closed_at, reason, detail)
      VALUES (v_record.vid, now(), 'stale_no_recent_source_sighting',
        jsonb_build_object(
          'last_seen_at', v_record.max_seen,
          'threshold_days', p_stale_after_days,
          'detected_by', 'detect_stale_venues_cron'));
    END IF;
    venue_id := v_record.vid;
    last_seen_at := v_record.max_seen;
    RETURN NEXT;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."detect_stale_venues"("p_stale_after_days" integer, "p_dry_run" boolean) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."detect_stale_venues"("p_stale_after_days" integer, "p_dry_run" boolean) IS 'Marks venues.closed_at when no source has listed the venue for p_stale_after_days. Audit in venue_closed_audit.';



CREATE OR REPLACE FUNCTION "public"."dispatch_claude_routine"("p_story_id" "uuid", "p_runner" "text", "p_prompt" "text", "p_prompt_hash" "text") RETURNS "public"."feedback_routine_runs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor uuid := auth.uid();
  v_story feedback_stories%ROWTYPE;
  v_run feedback_routine_runs%ROWTYPE;
  v_minute timestamptz := date_trunc('minute', now());
  v_day date := (now() AT TIME ZONE 'UTC')::date;
  v_minute_ct integer;
  v_day_ct integer;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  IF p_runner NOT IN ('mock','github_actions','webhook','api','local') THEN
    RAISE EXCEPTION 'invalid_runner: %', p_runner;
  END IF;
  IF coalesce(trim(p_prompt), '') = '' THEN RAISE EXCEPTION 'prompt_required'; END IF;
  IF coalesce(trim(p_prompt_hash), '') = '' THEN RAISE EXCEPTION 'prompt_hash_required'; END IF;

  SELECT * INTO v_story FROM feedback_stories WHERE id = p_story_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'story_not_found' USING ERRCODE = 'P0002'; END IF;
  IF v_story.archived_at IS NOT NULL THEN RAISE EXCEPTION 'story_archived'; END IF;
  IF v_story.approved_for_claude_at IS NULL THEN RAISE EXCEPTION 'not_approved'; END IF;

  INSERT INTO feedback_dispatch_counters (actor_id, bucket_minute, bucket_day, minute_count, day_count)
  VALUES (v_actor, v_minute, v_day, 1, 1)
  ON CONFLICT (actor_id, bucket_day) DO UPDATE
    SET minute_count = CASE
          WHEN feedback_dispatch_counters.bucket_minute = EXCLUDED.bucket_minute
            THEN feedback_dispatch_counters.minute_count + 1
          ELSE 1 END,
        bucket_minute = EXCLUDED.bucket_minute,
        day_count = feedback_dispatch_counters.day_count + 1
  RETURNING minute_count, day_count INTO v_minute_ct, v_day_ct;

  IF v_minute_ct > 5 THEN RAISE EXCEPTION 'rate_limit_minute'; END IF;
  IF v_day_ct > 50 THEN RAISE EXCEPTION 'rate_limit_day'; END IF;

  SELECT * INTO v_run FROM feedback_routine_runs
   WHERE story_id = p_story_id AND prompt_hash = p_prompt_hash
     AND status NOT IN ('failed','cancelled')
   ORDER BY created_at DESC LIMIT 1;
  IF FOUND THEN RETURN v_run; END IF;

  INSERT INTO feedback_routine_runs (story_id, status, runner, prompt, prompt_hash, created_by)
  VALUES (p_story_id, 'queued', p_runner, p_prompt, p_prompt_hash, v_actor)
  RETURNING * INTO v_run;

  PERFORM _fb_log_event(p_story_id, 'routine_dispatched',
    jsonb_build_object('runner', p_runner, 'run_id', v_run.id), 'user', v_run.id);
  RETURN v_run;
END;
$$;


ALTER FUNCTION "public"."dispatch_claude_routine"("p_story_id" "uuid", "p_runner" "text", "p_prompt" "text", "p_prompt_hash" "text") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."ingestion_dlq" (
    "id" bigint NOT NULL,
    "staging_id" "uuid",
    "pipeline_run_id" "uuid",
    "source_slug" "text",
    "stage" "text" NOT NULL,
    "error_code" "text",
    "error_message" "text",
    "payload" "jsonb",
    "attempts" integer DEFAULT 0 NOT NULL,
    "max_attempts" integer DEFAULT 5 NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "next_retry_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "locked_until" timestamp with time zone,
    "locked_by" "text",
    "last_attempt_at" timestamp with time zone,
    "resolved_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "ingestion_dlq_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'retrying'::"text", 'permanent_failed'::"text", 'resolved'::"text"])))
);


ALTER TABLE "public"."ingestion_dlq" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dlq_claim_batch"("p_limit" integer DEFAULT 25, "p_worker" "text" DEFAULT 'dlq-consumer'::"text") RETURNS SETOF "public"."ingestion_dlq"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  UPDATE public.ingestion_dlq d
  SET status='retrying', locked_until=now() + interval '5 minutes', locked_by=p_worker,
      attempts=attempts+1, last_attempt_at=now()
  WHERE d.id IN (
    SELECT id FROM public.ingestion_dlq
    WHERE status='pending' AND next_retry_at <= now()
      AND (locked_until IS NULL OR locked_until < now())
    ORDER BY next_retry_at LIMIT p_limit FOR UPDATE SKIP LOCKED
  ) RETURNING d.*;
END; $$;


ALTER FUNCTION "public"."dlq_claim_batch"("p_limit" integer, "p_worker" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dlq_enqueue"("p_staging_id" "uuid", "p_stage" "text", "p_error_code" "text", "p_error" "text", "p_payload" "jsonb" DEFAULT NULL::"jsonb", "p_source" "text" DEFAULT NULL::"text") RETURNS bigint
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE v_id BIGINT;
BEGIN
  INSERT INTO public.ingestion_dlq(staging_id, stage, error_code, error_message, payload, source_slug)
  VALUES (p_staging_id, p_stage, p_error_code, p_error, p_payload, p_source) RETURNING id INTO v_id;
  RETURN v_id;
END; $$;


ALTER FUNCTION "public"."dlq_enqueue"("p_staging_id" "uuid", "p_stage" "text", "p_error_code" "text", "p_error" "text", "p_payload" "jsonb", "p_source" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dlq_fail"("p_id" bigint, "p_err" "text") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE r RECORD;
BEGIN
  SELECT attempts, max_attempts INTO r FROM public.ingestion_dlq WHERE id=p_id;
  IF r.attempts >= r.max_attempts THEN
    UPDATE public.ingestion_dlq SET status='permanent_failed', error_message=p_err, locked_until=NULL WHERE id=p_id;
  ELSE
    UPDATE public.ingestion_dlq
      SET status='pending', error_message=p_err, locked_until=NULL,
          next_retry_at = now() + (CASE attempts
            WHEN 1 THEN interval '1 minute' WHEN 2 THEN interval '5 minutes'
            WHEN 3 THEN interval '30 minutes' WHEN 4 THEN interval '2 hours'
            ELSE interval '12 hours' END)
      WHERE id=p_id;
  END IF;
END; $$;


ALTER FUNCTION "public"."dlq_fail"("p_id" bigint, "p_err" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dlq_resolve"("p_id" bigint) RETURNS "void"
    LANGUAGE "sql"
    SET "search_path" TO 'public'
    AS $$
  UPDATE public.ingestion_dlq SET status='resolved', resolved_at=now(), locked_until=NULL WHERE id=p_id;
$$;


ALTER FUNCTION "public"."dlq_resolve"("p_id" bigint) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."enqueue_content_enrichment_on_insert"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pgmq'
    AS $$
DECLARE
  v_entity_type TEXT;
BEGIN
  -- Map table to entity type for populate-embeddings
  v_entity_type := CASE TG_TABLE_NAME
    WHEN 'venues'        THEN 'venue'
    WHEN 'events'        THEN 'event'
    WHEN 'personalities' THEN 'personality'
    WHEN 'news_articles' THEN 'news'
  END;

  -- Enqueue geo-linking (uses TG_TABLE_NAME directly as content_type)
  PERFORM public.pgmq_send(
    'content_processing',
    jsonb_build_object(
      'workflow',      'geo-link-content',
      'content_type',  TG_TABLE_NAME,
      'content_id',    NEW.id::text,
      'triggered_by',  'db_trigger'
    ),
    0
  );

  -- Enqueue embedding generation
  PERFORM public.pgmq_send(
    'content_processing',
    jsonb_build_object(
      'workflow',     'populate-embeddings',
      'entity_type',  v_entity_type,
      'entity_id',    NEW.id::text,
      'triggered_by', 'db_trigger'
    ),
    5  -- 5-second delay so the row is fully committed first
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- Never block an INSERT due to enrichment queue failure
  RAISE WARNING 'enqueue_content_enrichment_on_insert failed for %.%: %', TG_TABLE_NAME, NEW.id, SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."enqueue_content_enrichment_on_insert"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."enqueue_workflow"("p_workflow_name" "text", "p_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_triggered_by" "text" DEFAULT 'cron'::"text") RETURNS bigint
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_queue_name text;
  v_msg_id bigint;
BEGIN
  -- Look up the queue for this workflow
  SELECT queue_name INTO v_queue_name
  FROM workflow_definitions
  WHERE name = p_workflow_name AND is_enabled = true;

  IF v_queue_name IS NULL THEN
    RAISE EXCEPTION 'Workflow "%" not found or disabled', p_workflow_name;
  END IF;

  -- Enqueue the message
  SELECT public.pgmq_send(
    v_queue_name,
    jsonb_build_object(
      'workflow', p_workflow_name,
      'triggered_by', p_triggered_by,
      'idempotency_key', p_workflow_name || '-' || to_char(now(), 'YYYYMMDDHH24MI')
    ) || p_payload
  ) INTO v_msg_id;

  RETURN v_msg_id;
END;
$$;


ALTER FUNCTION "public"."enqueue_workflow"("p_workflow_name" "text", "p_payload" "jsonb", "p_triggered_by" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ensure_content_links"("p_entity_type" "text", "p_entity_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  urls_added INTEGER := 0;
  rec RECORD;
BEGIN
  IF p_entity_type = 'venues' THEN
    FOR rec IN
      SELECT 'website' as field, website as url FROM venues WHERE id = p_entity_id AND website IS NOT NULL AND website != ''
    LOOP
      INSERT INTO content_links (content_type, content_id, field_name, original_url, status)
      VALUES (p_entity_type, p_entity_id, rec.field, rec.url, 'PENDING')
      ON CONFLICT DO NOTHING;
      IF FOUND THEN urls_added := urls_added + 1; END IF;
    END LOOP;

  ELSIF p_entity_type = 'events' THEN
    FOR rec IN
      SELECT 'website' as field, website as url FROM events WHERE id = p_entity_id AND website IS NOT NULL AND website != ''
      UNION ALL
      SELECT 'ticket_url', ticket_url FROM events WHERE id = p_entity_id AND ticket_url IS NOT NULL AND ticket_url != ''
    LOOP
      INSERT INTO content_links (content_type, content_id, field_name, original_url, status)
      VALUES (p_entity_type, p_entity_id, rec.field, rec.url, 'PENDING')
      ON CONFLICT DO NOTHING;
      IF FOUND THEN urls_added := urls_added + 1; END IF;
    END LOOP;

  ELSIF p_entity_type = 'news_articles' THEN
    FOR rec IN
      SELECT 'url' as field, url FROM news_articles WHERE id = p_entity_id AND url IS NOT NULL AND url != ''
    LOOP
      INSERT INTO content_links (content_type, content_id, field_name, original_url, status)
      VALUES (p_entity_type, p_entity_id, rec.field, rec.url, 'PENDING')
      ON CONFLICT DO NOTHING;
      IF FOUND THEN urls_added := urls_added + 1; END IF;
    END LOOP;

  ELSIF p_entity_type = 'personalities' THEN
    FOR rec IN
      SELECT 'website_url' as field, website_url as url FROM personalities WHERE id = p_entity_id AND website_url IS NOT NULL AND website_url != ''
    LOOP
      INSERT INTO content_links (content_type, content_id, field_name, original_url, status)
      VALUES (p_entity_type, p_entity_id, rec.field, rec.url, 'PENDING')
      ON CONFLICT DO NOTHING;
      IF FOUND THEN urls_added := urls_added + 1; END IF;
    END LOOP;
  END IF;

  RETURN urls_added;
END;
$$;


ALTER FUNCTION "public"."ensure_content_links"("p_entity_type" "text", "p_entity_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."escalate_pipeline_alerts_to_feedback"() RETURNS TABLE("escalated" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_count INT := 0;
  v_alert RECORD;
  v_fingerprint TEXT;
  v_submission_id UUID;
BEGIN
  FOR v_alert IN
    SELECT id, kind, subject, detail, first_seen_at, last_seen_at
    FROM public.pipeline_health_alerts
    WHERE resolved_at IS NULL
      AND escalated_submission_id IS NULL
      AND first_seen_at < now() - INTERVAL '24 hours'
  LOOP
    v_fingerprint := encode(
      extensions.digest('pipeline:' || v_alert.kind || ':' || v_alert.subject, 'sha256'),
      'hex'
    );

    INSERT INTO public.community_submissions (
      content_type, data, fingerprint, occurrence_count, last_seen_at, feedback_status
    ) VALUES (
      'pipeline_failure',
      jsonb_build_object(
        'title', 'Pipeline down: ' || v_alert.subject,
        'description',
          'Pipeline health alert "' || v_alert.kind || '" for "' || v_alert.subject ||
          '" has been open since ' || to_char(v_alert.first_seen_at, 'YYYY-MM-DD HH24:MI') || ' UTC.',
        'category', 'bug',
        'source', 'pipeline_health',
        'alert_kind', v_alert.kind,
        'alert_subject', v_alert.subject,
        'alert_detail', v_alert.detail,
        'alert_first_seen_at', v_alert.first_seen_at,
        'pipeline_health_alert_id', v_alert.id
      ),
      v_fingerprint, 1, now(), 'new'
    )
    ON CONFLICT (fingerprint) WHERE content_type = 'pipeline_failure' AND fingerprint IS NOT NULL
    DO UPDATE
      SET occurrence_count = public.community_submissions.occurrence_count + 1,
          last_seen_at = now(),
          data = EXCLUDED.data
    RETURNING id INTO v_submission_id;

    UPDATE public.pipeline_health_alerts
      SET escalated_submission_id = v_submission_id
      WHERE id = v_alert.id;

    v_count := v_count + 1;
  END LOOP;

  RETURN QUERY SELECT v_count;
END;
$$;


ALTER FUNCTION "public"."escalate_pipeline_alerts_to_feedback"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."escalate_pipeline_alerts_to_feedback"() IS 'Escalates pipeline_health_alerts open > 24h into community_submissions (category=bug, content_type=pipeline_failure). Runs hourly via pg_cron. Auto-closes the feedback ticket when the alert is resolved.';



