CREATE OR REPLACE FUNCTION "public"."extract_city_from_text"("input_text" "text") RETURNS TABLE("id" "uuid", "name" "text", "country_id" "uuid")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
  SELECT c.id, c.name, c.country_id
  FROM cities c
  WHERE input_text ILIKE '%' || c.name || '%'
    AND length(c.name) >= 3
  ORDER BY length(c.name) DESC, c.population DESC NULLS LAST
  LIMIT 1;
$$;


