CREATE OR REPLACE FUNCTION "public"."feedback_sla_stats"("p_days_window" integer DEFAULT 90) RETURNS TABLE("category" "text", "priority" smallint, "resolved_n" integer, "median_seconds" double precision, "p95_seconds" double precision)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
  SELECT
    coalesce(data->>'category', 'other')                               AS category,
    priority,
    count(*)::int                                                      AS resolved_n,
    percentile_cont(0.5) WITHIN GROUP (ORDER BY extract(epoch FROM (resolved_at - submitted_at))) AS median_seconds,
    percentile_cont(0.95) WITHIN GROUP (ORDER BY extract(epoch FROM (resolved_at - submitted_at))) AS p95_seconds
  FROM community_submissions
  WHERE content_type = 'feedback'
    AND is_spam = false
    AND resolved_at IS NOT NULL
    AND submitted_at >= now() - make_interval(days => p_days_window)
  GROUP BY 1, 2
  ORDER BY 1, 2;
$$;


ALTER FUNCTION "public"."feedback_sla_stats"("p_days_window" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_city_duplicate_candidates"("p_name" "text", "p_country_id" "uuid" DEFAULT NULL::"uuid", "p_lat" numeric DEFAULT NULL::numeric, "p_lng" numeric DEFAULT NULL::numeric, "p_limit" integer DEFAULT 10) RETURNS TABLE("city_id" "uuid", "match_type" "text", "score" numeric, "distance_m" double precision)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'extensions', 'pg_catalog'
    AS $$
  WITH candidates AS (
    SELECT c.id AS cid, 'name_exact_country'::text AS mt, 0.99::numeric AS sc,
           public.haversine_m(p_lat, p_lng, c.latitude, c.longitude) AS dm
    FROM public.cities c
    WHERE p_country_id IS NOT NULL AND c.country_id = p_country_id
      AND public.normalize_name(c.name) = public.normalize_name(p_name) AND c.duplicate_of_id IS NULL
    UNION ALL
    SELECT c.id, 'name_proximity_country',
           extensions.similarity(c.name_normalized, public.normalize_name(p_name))::numeric,
           public.haversine_m(p_lat, p_lng, c.latitude, c.longitude)
    FROM public.cities c
    WHERE p_country_id IS NOT NULL AND c.country_id = p_country_id
      AND extensions.similarity(c.name_normalized, public.normalize_name(p_name)) > 0.3
      AND c.duplicate_of_id IS NULL
    UNION ALL
    SELECT c.id, 'name_geo_proximity',
           extensions.similarity(c.name_normalized, public.normalize_name(p_name))::numeric,
           public.haversine_m(p_lat, p_lng, c.latitude, c.longitude)
    FROM public.cities c
    WHERE extensions.similarity(c.name_normalized, public.normalize_name(p_name)) > 0.3
      AND c.duplicate_of_id IS NULL
      AND p_lat IS NOT NULL AND c.latitude IS NOT NULL
      AND public.haversine_m(p_lat, p_lng, c.latitude, c.longitude) < 25000
  ),
  best AS (SELECT DISTINCT ON (cid) cid, mt, sc, dm FROM candidates ORDER BY cid, sc DESC, dm ASC NULLS LAST)
  SELECT cid, mt, sc, dm FROM best ORDER BY sc DESC, dm ASC NULLS LAST LIMIT p_limit;
$$;


ALTER FUNCTION "public"."find_city_duplicate_candidates"("p_name" "text", "p_country_id" "uuid", "p_lat" numeric, "p_lng" numeric, "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_city_duplicates"("p_name" "text", "p_country_id" "uuid" DEFAULT NULL::"uuid", "p_latitude" numeric DEFAULT NULL::numeric, "p_longitude" numeric DEFAULT NULL::numeric, "p_threshold" numeric DEFAULT 0.7) RETURNS TABLE("city_id" "uuid", "city_name" "text", "name_similarity" numeric, "same_country" boolean, "geo_distance_km" numeric, "combined_score" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    SET "statement_timeout" TO '120s'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.id AS city_id,
    c.name AS city_name,
    extensions.similarity(lower(extensions.unaccent(c.name)), lower(extensions.unaccent(p_name)))::numeric AS name_similarity,
    CASE WHEN p_country_id IS NOT NULL AND c.country_id = p_country_id THEN true ELSE false END AS same_country,
    CASE WHEN p_latitude IS NOT NULL AND p_longitude IS NOT NULL AND c.latitude IS NOT NULL AND c.longitude IS NOT NULL
      THEN (6371 * acos(
        LEAST(1.0, cos(radians(c.latitude::float8)) * cos(radians(p_latitude::float8)) *
        cos(radians(p_longitude::float8) - radians(c.longitude::float8)) +
        sin(radians(c.latitude::float8)) * sin(radians(p_latitude::float8)))
      ))::numeric
      ELSE NULL END AS geo_distance_km,
    (
      extensions.similarity(lower(extensions.unaccent(c.name)), lower(extensions.unaccent(p_name)))::numeric * 0.5 +
      CASE WHEN p_country_id IS NOT NULL AND c.country_id = p_country_id THEN 0.3::numeric ELSE 0.0::numeric END +
      CASE WHEN p_latitude IS NOT NULL AND p_longitude IS NOT NULL AND c.latitude IS NOT NULL AND c.longitude IS NOT NULL
        THEN GREATEST(0.0::numeric, (1.0 - (6371 * acos(
          LEAST(1.0, cos(radians(c.latitude::float8)) * cos(radians(p_latitude::float8)) *
          cos(radians(p_longitude::float8) - radians(c.longitude::float8)) +
          sin(radians(c.latitude::float8)) * sin(radians(p_latitude::float8)))
        )) / 50.0)::numeric) * 0.2
        ELSE 0.0::numeric END
    ) AS combined_score
  FROM public.cities c
  WHERE 
    extensions.similarity(lower(extensions.unaccent(c.name)), lower(extensions.unaccent(p_name))) > p_threshold
  ORDER BY combined_score DESC
  LIMIT 5;
END;
$$;


ALTER FUNCTION "public"."find_city_duplicates"("p_name" "text", "p_country_id" "uuid", "p_latitude" numeric, "p_longitude" numeric, "p_threshold" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_country_duplicate_candidates"("p_name" "text", "p_code" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 10) RETURNS TABLE("country_id" "uuid", "match_type" "text", "score" numeric)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'extensions', 'pg_catalog'
    AS $$
  WITH candidates AS (
    SELECT c.id AS cid, 'code_exact'::text AS mt, 1.00::numeric AS sc
    FROM public.countries c
    WHERE p_code IS NOT NULL AND c.code = upper(btrim(p_code)) AND c.duplicate_of_id IS NULL
    UNION ALL
    SELECT c.id, 'name_exact', 0.98 FROM public.countries c
    WHERE public.normalize_name(c.name) = public.normalize_name(p_name) AND c.duplicate_of_id IS NULL
    UNION ALL
    SELECT c.id, 'name_proximity', extensions.similarity(c.name_normalized, public.normalize_name(p_name))::numeric
    FROM public.countries c
    WHERE extensions.similarity(c.name_normalized, public.normalize_name(p_name)) > 0.3
      AND c.duplicate_of_id IS NULL
  ),
  best AS (SELECT DISTINCT ON (cid) cid, mt, sc FROM candidates ORDER BY cid, sc DESC)
  SELECT cid, mt, sc FROM best ORDER BY sc DESC LIMIT p_limit;
$$;


ALTER FUNCTION "public"."find_country_duplicate_candidates"("p_name" "text", "p_code" "text", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_duplicate_candidates"("p_entity_type" "text", "p_entity_id" "uuid", "p_threshold" real DEFAULT 0.7) RETURNS TABLE("candidate_id" "uuid", "candidate_name" "text", "similarity_score" real, "same_city" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
BEGIN
  IF p_entity_type = 'venues' THEN
    RETURN QUERY
    SELECT v2.id, v2.name,
      similarity(v1.name, v2.name)::REAL,
      (v1.city_id IS NOT NULL AND v1.city_id = v2.city_id)
    FROM venues v1, venues v2
    WHERE v1.id = p_entity_id
      AND v2.id != v1.id
      AND v2.duplicate_of_id IS NULL
      AND similarity(v1.name, v2.name) >= p_threshold
    ORDER BY similarity(v1.name, v2.name) DESC
    LIMIT 5;

  ELSIF p_entity_type = 'events' THEN
    RETURN QUERY
    SELECT e2.id, e2.title,
      similarity(e1.title, e2.title)::REAL,
      (e1.city_id IS NOT NULL AND e1.city_id = e2.city_id)
    FROM events e1, events e2
    WHERE e1.id = p_entity_id
      AND e2.id != e1.id
      AND e2.duplicate_of_id IS NULL
      AND similarity(e1.title, e2.title) >= p_threshold
    ORDER BY similarity(e1.title, e2.title) DESC
    LIMIT 5;

  ELSIF p_entity_type = 'personalities' THEN
    RETURN QUERY
    SELECT p2.id, p2.name,
      similarity(p1.name, p2.name)::REAL,
      (p1.country_id IS NOT NULL AND p1.country_id = p2.country_id)
    FROM personalities p1, personalities p2
    WHERE p1.id = p_entity_id
      AND p2.id != p1.id
      AND p2.duplicate_of_id IS NULL
      AND similarity(p1.name, p2.name) >= p_threshold
    ORDER BY similarity(p1.name, p2.name) DESC
    LIMIT 5;

  ELSIF p_entity_type = 'news_articles' THEN
    RETURN QUERY
    SELECT n2.id, n2.title,
      similarity(n1.title, n2.title)::REAL,
      false
    FROM news_articles n1, news_articles n2
    WHERE n1.id = p_entity_id
      AND n2.id != n1.id
      AND n2.duplicate_of_id IS NULL
      AND similarity(n1.title, n2.title) >= p_threshold
    ORDER BY similarity(n1.title, n2.title) DESC
    LIMIT 5;
  END IF;
END;
$$;


ALTER FUNCTION "public"."find_duplicate_candidates"("p_entity_type" "text", "p_entity_id" "uuid", "p_threshold" real) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_event_duplicate_candidates"("p_title" "text", "p_start_date" timestamp with time zone, "p_venue_id" "uuid" DEFAULT NULL::"uuid", "p_city" "text" DEFAULT NULL::"text", "p_lat" numeric DEFAULT NULL::numeric, "p_lng" numeric DEFAULT NULL::numeric, "p_edition" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 20) RETURNS TABLE("event_id" "uuid", "match_type" "text", "score" numeric, "distance_m" double precision, "time_diff_hours" double precision)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'extensions', 'pg_catalog'
    AS $$
  WITH candidates AS (
    SELECT e.id AS eid, 'venue_date_exact'::text AS mt, 0.98::numeric AS sc,
           public.haversine_m(p_lat, p_lng, e.latitude, e.longitude) AS dm,
           extract(epoch FROM (e.start_date - p_start_date))/3600.0 AS th
    FROM public.events e
    WHERE p_venue_id IS NOT NULL
      AND e.venue_id = p_venue_id
      AND e.duplicate_of_id IS NULL
      AND e.start_date BETWEEN p_start_date - interval '48 hours' AND p_start_date + interval '48 hours'
      AND extensions.similarity(e.title_normalized, public.normalize_name(p_title)) > 0.35
    UNION ALL
    SELECT e.id, 'title_city_time',
           extensions.similarity(e.title_normalized, public.normalize_name(p_title))::numeric * 0.95,
           public.haversine_m(p_lat, p_lng, e.latitude, e.longitude),
           extract(epoch FROM (e.start_date - p_start_date))/3600.0
    FROM public.events e
    WHERE p_city IS NOT NULL
      AND lower(e.city) = lower(btrim(p_city))
      AND e.duplicate_of_id IS NULL
      AND extensions.similarity(e.title_normalized, public.normalize_name(p_title)) > 0.3
      AND e.start_date BETWEEN p_start_date - interval '48 hours' AND p_start_date + interval '48 hours'
    UNION ALL
    SELECT e.id, 'title_geo_time',
           extensions.similarity(e.title_normalized, public.normalize_name(p_title))::numeric * 0.93,
           public.haversine_m(p_lat, p_lng, e.latitude, e.longitude),
           extract(epoch FROM (e.start_date - p_start_date))/3600.0
    FROM public.events e
    WHERE p_lat IS NOT NULL AND e.latitude IS NOT NULL
      AND e.duplicate_of_id IS NULL
      AND extensions.similarity(e.title_normalized, public.normalize_name(p_title)) > 0.3
      AND e.start_date BETWEEN p_start_date - interval '48 hours' AND p_start_date + interval '48 hours'
      AND public.haversine_m(p_lat, p_lng, e.latitude, e.longitude) < 2000
    UNION ALL
    SELECT e.id, 'recurring_series', 0.75::numeric,
           public.haversine_m(p_lat, p_lng, e.latitude, e.longitude),
           extract(epoch FROM (e.start_date - p_start_date))/3600.0
    FROM public.events e
    WHERE p_edition IS NOT NULL
      AND e.venue_id = p_venue_id
      AND e.duplicate_of_id IS NULL
      AND extensions.similarity(e.title_normalized, public.normalize_name(p_title)) > 0.75
      AND abs(extract(epoch FROM (e.start_date - p_start_date))/86400.0) > 7
  ),
  best AS (
    SELECT DISTINCT ON (eid) eid, mt, sc, dm, th
    FROM candidates
    ORDER BY eid, sc DESC, abs(th) ASC, dm ASC NULLS LAST
  )
  SELECT eid, mt, sc, dm, th FROM best
  ORDER BY sc DESC, abs(th) ASC, dm ASC NULLS LAST
  LIMIT p_limit;
$$;


ALTER FUNCTION "public"."find_event_duplicate_candidates"("p_title" "text", "p_start_date" timestamp with time zone, "p_venue_id" "uuid", "p_city" "text", "p_lat" numeric, "p_lng" numeric, "p_edition" "text", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_event_duplicates"("p_title" "text", "p_start_date" timestamp with time zone, "p_city" "text" DEFAULT NULL::"text") RETURNS TABLE("event_id" "uuid", "event_title" "text", "title_similarity" numeric, "date_diff_hours" numeric, "city_match" boolean, "combined_score" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    e.id as event_id,
    e.title as event_title,
    similarity(lower(unaccent(e.title)), lower(unaccent(p_title)))::numeric as title_similarity,
    (EXTRACT(EPOCH FROM (e.start_date - p_start_date)) / 3600.0)::numeric as date_diff_hours,
    CASE WHEN p_city IS NOT NULL AND lower(e.city) = lower(p_city) THEN true ELSE false END as city_match,
    (
      similarity(lower(unaccent(e.title)), lower(unaccent(p_title)))::numeric * 0.5 +
      GREATEST(0.0, 1.0 - ABS(EXTRACT(EPOCH FROM (e.start_date - p_start_date)) / 86400.0))::numeric * 0.3 +
      CASE WHEN p_city IS NOT NULL AND lower(e.city) = lower(p_city) THEN 0.2::numeric ELSE 0.0::numeric END
    ) as combined_score
  FROM public.events e
  WHERE 
    similarity(lower(unaccent(e.title)), lower(unaccent(p_title))) > 0.5
    AND e.start_date BETWEEN p_start_date - interval '7 days' AND p_start_date + interval '7 days'
  ORDER BY combined_score DESC
  LIMIT 5;
END;
$$;


ALTER FUNCTION "public"."find_event_duplicates"("p_title" "text", "p_start_date" timestamp with time zone, "p_city" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_existing_by_url"("p_url" "text") RETURNS TABLE("source" "text", "id" "uuid", "slug" "text", "title" "text")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  WITH host AS (
    SELECT regexp_replace(
      coalesce(substring(p_url from '^[a-z]+://([^/]+)'), ''),
      '^www\.', ''
    ) AS h
  )
  (
    SELECT 'venues'::text, v.id, v.slug, v.name
      FROM public.venues v, host
      WHERE v.website_domain = host.h AND host.h <> ''
      LIMIT 1
  )
  UNION ALL
  (
    SELECT 'events'::text, e.id, e.slug, e.title
      FROM public.events e
      WHERE e.website = p_url
      LIMIT 1
  )
  UNION ALL
  (
    SELECT 'news_articles'::text, n.id, n.slug, n.title
      FROM public.news_articles n
      WHERE n.url = p_url
      LIMIT 1
  )
  LIMIT 1;
$$;


ALTER FUNCTION "public"."find_existing_by_url"("p_url" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."find_existing_by_url"("p_url" "text") IS 'Extension reverse-lookup: returns the first canonical entity matching the URL or its host. Used by extension/src/shared/api.ts findExisting().';



CREATE OR REPLACE FUNCTION "public"."find_hotel_duplicate_candidates"("p_name" "text", "p_phone_e164" "text" DEFAULT NULL::"text", "p_email" "text" DEFAULT NULL::"text", "p_website_domain" "text" DEFAULT NULL::"text", "p_lat" numeric DEFAULT NULL::numeric, "p_lng" numeric DEFAULT NULL::numeric, "p_city_id" "uuid" DEFAULT NULL::"uuid", "p_platform_ids" "jsonb" DEFAULT '{}'::"jsonb", "p_booking_url" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 20, "p_address" "text" DEFAULT NULL::"text") RETURNS TABLE("venue_id" "uuid", "match_type" "text", "score" numeric, "distance_m" double precision)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'extensions'
    AS $$
  WITH platform_keys AS (
    SELECT key, value::text AS pid FROM jsonb_each_text(coalesce(p_platform_ids, '{}'::jsonb))
    WHERE value IS NOT NULL AND value::text <> ''
  ),
  candidates AS (
    SELECT v.id, ('platform_' || pk.key)::text AS mt, 1.00::numeric AS sc,
           public.haversine_m(p_lat, p_lng, v.latitude, v.longitude) AS dm
    FROM public.venues v JOIN platform_keys pk ON v.platform_ids ->> pk.key = pk.pid
    WHERE v.duplicate_of_id IS NULL
    UNION ALL
    SELECT v.id, 'booking_url_exact', 0.99, public.haversine_m(p_lat, p_lng, v.latitude, v.longitude)
    FROM public.venues v
    WHERE p_booking_url IS NOT NULL AND lower(btrim(v.booking_url)) = lower(btrim(p_booking_url))
      AND v.duplicate_of_id IS NULL
    UNION ALL
    SELECT c.venue_id, c.match_type, c.score, c.distance_m
    FROM public.find_venue_duplicate_candidates(p_name, p_phone_e164, p_email, p_website_domain, p_lat, p_lng, p_city_id, p_limit, p_address) c
  )
  SELECT DISTINCT ON (id) id, mt, sc, dm FROM candidates
  ORDER BY id, sc DESC, dm ASC NULLS LAST LIMIT p_limit;
$$;


ALTER FUNCTION "public"."find_hotel_duplicate_candidates"("p_name" "text", "p_phone_e164" "text", "p_email" "text", "p_website_domain" "text", "p_lat" numeric, "p_lng" numeric, "p_city_id" "uuid", "p_platform_ids" "jsonb", "p_booking_url" "text", "p_limit" integer, "p_address" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_marketplace_duplicate_candidates"("p_title" "text", "p_source_slug" "text" DEFAULT NULL::"text", "p_source_entity_id" "text" DEFAULT NULL::"text", "p_merchant_domain" "text" DEFAULT NULL::"text", "p_external_url" "text" DEFAULT NULL::"text", "p_brand" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 10) RETURNS TABLE("listing_id" "uuid", "matched_title" "text", "match_type" "text", "score" numeric, "distance_m" numeric, "time_diff_hours" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_title_norm TEXT := lower(extensions.unaccent(regexp_replace(coalesce(p_title,''), '\s+', ' ', 'g')));
BEGIN
  IF v_title_norm = '' AND p_source_entity_id IS NULL AND p_external_url IS NULL THEN
    RETURN;
  END IF;

  IF p_source_slug IS NOT NULL AND p_source_entity_id IS NOT NULL THEN
    RETURN QUERY
      SELECT m.id, m.title, 'source_entity_id'::text, 1.00::numeric, NULL::numeric, NULL::numeric
      FROM public.marketplace_listings m
      WHERE m.source_type = p_source_slug
        AND m.source_entity_id = p_source_entity_id
      LIMIT p_limit;
    IF FOUND THEN RETURN; END IF;
  END IF;

  IF p_external_url IS NOT NULL AND length(p_external_url) > 10 THEN
    RETURN QUERY
      SELECT m.id, m.title, 'external_url'::text, 0.97::numeric, NULL::numeric, NULL::numeric
      FROM public.marketplace_listings m
      WHERE m.external_url = p_external_url
      LIMIT p_limit;
    IF FOUND THEN RETURN; END IF;
  END IF;

  IF p_merchant_domain IS NOT NULL THEN
    RETURN QUERY
      SELECT m.id, m.title, 'domain_title'::text,
             (0.6 + extensions.similarity(m.title_normalized, v_title_norm) * 0.4)::numeric,
             NULL::numeric, NULL::numeric
      FROM public.marketplace_listings m
      WHERE m.merchant_domain = p_merchant_domain
        AND extensions.similarity(m.title_normalized, v_title_norm) >= 0.70
      ORDER BY extensions.similarity(m.title_normalized, v_title_norm) DESC
      LIMIT p_limit;
    IF FOUND THEN RETURN; END IF;
  END IF;

  IF p_brand IS NOT NULL THEN
    RETURN QUERY
      SELECT m.id, m.title, 'brand_title'::text,
             (extensions.similarity(m.title_normalized, v_title_norm) * 0.85)::numeric,
             NULL::numeric, NULL::numeric
      FROM public.marketplace_listings m
      WHERE m.brand ILIKE p_brand
        AND extensions.similarity(m.title_normalized, v_title_norm) >= 0.85
      ORDER BY extensions.similarity(m.title_normalized, v_title_norm) DESC
      LIMIT p_limit;
    IF FOUND THEN RETURN; END IF;
  END IF;

  RETURN QUERY
    SELECT m.id, m.title, 'title_trigram'::text,
           (extensions.similarity(m.title_normalized, v_title_norm) * 0.75)::numeric,
           NULL::numeric, NULL::numeric
    FROM public.marketplace_listings m
    WHERE extensions.similarity(m.title_normalized, v_title_norm) >= 0.80
    ORDER BY extensions.similarity(m.title_normalized, v_title_norm) DESC
    LIMIT p_limit;
END;
$$;


ALTER FUNCTION "public"."find_marketplace_duplicate_candidates"("p_title" "text", "p_source_slug" "text", "p_source_entity_id" "text", "p_merchant_domain" "text", "p_external_url" "text", "p_brand" "text", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_nearest_airport"("visitor_lat" numeric, "visitor_lng" numeric) RETURNS TABLE("iata_code" "text", "city_name" "text", "country_code" "text", "distance_km" numeric)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  -- Prefer commercial airports (name contains Airport/International/etc.) within 200km.
  -- Falls back to absolute nearest if no commercial airport found nearby.
  WITH distances AS (
    SELECT a.iata_code, a.city_name, a.country_code,
      a.name AS airport_name,
      (6371 * acos(LEAST(1.0, cos(radians(visitor_lat)) * cos(radians(a.latitude)) *
      cos(radians(a.longitude) - radians(visitor_lng)) +
      sin(radians(visitor_lat)) * sin(radians(a.latitude)))))::NUMERIC AS distance_km
    FROM airports a
    WHERE a.latitude IS NOT NULL AND a.longitude IS NOT NULL
  ),
  commercial AS (
    SELECT d.iata_code, d.city_name, d.country_code, d.distance_km
    FROM distances d
    WHERE d.distance_km < 200
      AND (d.airport_name ILIKE '%airport%' 
        OR d.airport_name ILIKE '%international%'
        OR d.airport_name ILIKE '%aeroport%'
        OR d.airport_name ILIKE '%aeropuerto%'
        OR d.airport_name ILIKE '%aeroporto%'
        OR d.airport_name ILIKE '%flughafen%')
    ORDER BY d.distance_km
    LIMIT 1
  ),
  fallback AS (
    SELECT d.iata_code, d.city_name, d.country_code, d.distance_km
    FROM distances d
    ORDER BY d.distance_km
    LIMIT 1
  )
  SELECT * FROM commercial
  UNION ALL
  SELECT * FROM fallback
  WHERE NOT EXISTS (SELECT 1 FROM commercial)
  LIMIT 1;
$$;


ALTER FUNCTION "public"."find_nearest_airport"("visitor_lat" numeric, "visitor_lng" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_news_duplicates"("p_title" "text", "p_source_id" "uuid" DEFAULT NULL::"uuid", "p_published_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_threshold" numeric DEFAULT 0.7) RETURNS TABLE("article_id" "uuid", "article_title" "text", "title_similarity" numeric, "same_source" boolean, "date_diff_hours" numeric, "combined_score" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    SET "statement_timeout" TO '120s'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    n.id AS article_id,
    n.title AS article_title,
    extensions.similarity(lower(extensions.unaccent(n.title)), lower(extensions.unaccent(p_title)))::numeric AS title_similarity,
    CASE WHEN p_source_id IS NOT NULL AND n.source_id = p_source_id THEN true ELSE false END AS same_source,
    CASE WHEN p_published_at IS NOT NULL AND n.published_at IS NOT NULL
      THEN ABS(EXTRACT(EPOCH FROM (n.published_at - p_published_at)) / 3600.0)::numeric
      ELSE NULL END AS date_diff_hours,
    (
      extensions.similarity(lower(extensions.unaccent(n.title)), lower(extensions.unaccent(p_title)))::numeric * 0.7 +
      CASE WHEN p_source_id IS NOT NULL AND n.source_id = p_source_id THEN 0.15::numeric ELSE 0.0::numeric END +
      CASE WHEN p_published_at IS NOT NULL AND n.published_at IS NOT NULL
        THEN GREATEST(0.0::numeric, (1.0 - ABS(EXTRACT(EPOCH FROM (n.published_at - p_published_at)) / 86400.0))::numeric) * 0.15
        ELSE 0.0::numeric END
    ) AS combined_score
  FROM public.news_articles n
  WHERE 
    extensions.similarity(lower(extensions.unaccent(n.title)), lower(extensions.unaccent(p_title))) > p_threshold
    AND (p_published_at IS NULL OR n.published_at BETWEEN p_published_at - interval '7 days' AND p_published_at + interval '7 days')
  ORDER BY combined_score DESC
  LIMIT 5;
END;
$$;


ALTER FUNCTION "public"."find_news_duplicates"("p_title" "text", "p_source_id" "uuid", "p_published_at" timestamp with time zone, "p_threshold" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_personality_duplicate_candidates"("p_name" "text", "p_wikidata_qid" "text" DEFAULT NULL::"text", "p_birth_date" "date" DEFAULT NULL::"date", "p_external_ids" "jsonb" DEFAULT '{}'::"jsonb", "p_profession" "text" DEFAULT NULL::"text", "p_nationality" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 10) RETURNS TABLE("personality_id" "uuid", "matched_name" "text", "match_type" "text", "score" numeric, "distance_m" numeric, "time_diff_hours" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_name_norm TEXT := public.normalize_name(coalesce(p_name,''));
BEGIN
  IF v_name_norm = '' AND p_wikidata_qid IS NULL AND (p_external_ids = '{}'::jsonb OR p_external_ids IS NULL) THEN
    RETURN;
  END IF;

  IF p_wikidata_qid IS NOT NULL THEN
    RETURN QUERY
      SELECT p.id, p.name, 'wikidata_qid'::text, 1.00::numeric, NULL::numeric, NULL::numeric
      FROM public.personalities p
      WHERE p.wikidata_qid = p_wikidata_qid
      LIMIT p_limit;
    IF FOUND THEN RETURN; END IF;
  END IF;

  IF p_external_ids IS NOT NULL AND p_external_ids <> '{}'::jsonb THEN
    RETURN QUERY
      SELECT p.id, p.name, 'external_id'::text, 0.95::numeric, NULL::numeric, NULL::numeric
      FROM public.personalities p
      WHERE p.external_ids ?| (SELECT array_agg(k) FROM jsonb_object_keys(p_external_ids) k)
        AND EXISTS (
          SELECT 1 FROM jsonb_each_text(p_external_ids) e
          WHERE p.external_ids->>e.key = e.value
        )
      LIMIT p_limit;
    IF FOUND THEN RETURN; END IF;
  END IF;

  IF p_birth_date IS NOT NULL THEN
    RETURN QUERY
      SELECT p.id, p.name, 'name_dob'::text,
             GREATEST(0.95, extensions.similarity(p.name_normalized, v_name_norm))::numeric,
             NULL::numeric, NULL::numeric
      FROM public.personalities p
      WHERE p.birth_date = p_birth_date
        AND extensions.similarity(p.name_normalized, v_name_norm) >= 0.85
      ORDER BY extensions.similarity(p.name_normalized, v_name_norm) DESC
      LIMIT p_limit;
    IF FOUND THEN RETURN; END IF;
  END IF;

  IF p_profession IS NOT NULL OR p_nationality IS NOT NULL THEN
    RETURN QUERY
      SELECT p.id, p.name, 'name_context'::text,
             (extensions.similarity(p.name_normalized, v_name_norm) * 0.9)::numeric,
             NULL::numeric, NULL::numeric
      FROM public.personalities p
      WHERE extensions.similarity(p.name_normalized, v_name_norm) >= 0.88
        AND (
          (p_profession  IS NOT NULL AND p.profession  ILIKE '%' || p_profession  || '%') OR
          (p_nationality IS NOT NULL AND p.nationality ILIKE '%' || p_nationality || '%')
        )
      ORDER BY extensions.similarity(p.name_normalized, v_name_norm) DESC
      LIMIT p_limit;
    IF FOUND THEN RETURN; END IF;
  END IF;

  RETURN QUERY
    SELECT p.id, p.name, 'name_trigram'::text,
           (extensions.similarity(p.name_normalized, v_name_norm) * 0.8)::numeric,
           NULL::numeric, NULL::numeric
    FROM public.personalities p
    WHERE extensions.similarity(p.name_normalized, v_name_norm) >= 0.75
    ORDER BY extensions.similarity(p.name_normalized, v_name_norm) DESC
    LIMIT p_limit;
END;
$$;


ALTER FUNCTION "public"."find_personality_duplicate_candidates"("p_name" "text", "p_wikidata_qid" "text", "p_birth_date" "date", "p_external_ids" "jsonb", "p_profession" "text", "p_nationality" "text", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."find_personality_duplicate_candidates"("p_name" "text", "p_wikidata_qid" "text", "p_birth_date" "date", "p_external_ids" "jsonb", "p_profession" "text", "p_nationality" "text", "p_limit" integer) IS 'Multi-signal personality dedup: Wikidata QID > external IDs > name+DOB > name+profession > trigram';



CREATE OR REPLACE FUNCTION "public"."find_personality_duplicates"("p_name" "text", "p_threshold" numeric DEFAULT 0.7) RETURNS TABLE("personality_id" "uuid", "personality_name" "text", "name_similarity" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    p.id as personality_id,
    p.name as personality_name,
    similarity(lower(unaccent(p.name)), lower(unaccent(p_name)))::numeric as name_similarity
  FROM public.personalities p
  WHERE similarity(lower(unaccent(p.name)), lower(unaccent(p_name))) > p_threshold
  ORDER BY name_similarity DESC
  LIMIT 5;
END;
$$;


ALTER FUNCTION "public"."find_personality_duplicates"("p_name" "text", "p_threshold" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_queer_village"("p_lat" double precision, "p_lng" double precision, "p_city_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("village_id" "uuid", "village_name" "text", "match_type" "text")
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Strategy 1: Same city, nearest within 1km (was 5km)
  IF p_city_id IS NOT NULL THEN
    RETURN QUERY
    SELECT qv.id, qv.name, 'city_nearest'::TEXT
    FROM queer_villages qv
    WHERE qv.city_id = p_city_id
      AND qv.latitude IS NOT NULL
      AND qv.longitude IS NOT NULL
      AND (
        6371 * acos(
          LEAST(1.0, GREATEST(-1.0,
            cos(radians(p_lat)) * cos(radians(qv.latitude))
            * cos(radians(qv.longitude) - radians(p_lng))
            + sin(radians(p_lat)) * sin(radians(qv.latitude))
          ))
        )
      ) <= 1
    ORDER BY (
      6371 * acos(
        LEAST(1.0, GREATEST(-1.0,
          cos(radians(p_lat)) * cos(radians(qv.latitude))
          * cos(radians(qv.longitude) - radians(p_lng))
          + sin(radians(p_lat)) * sin(radians(qv.latitude))
        ))
      )
    )
    LIMIT 1;

    IF FOUND THEN RETURN; END IF;
  END IF;

  -- Strategy 2: Any village within 500m globally (was 3km)
  RETURN QUERY
  SELECT qv.id, qv.name, 'nearest'::TEXT
  FROM queer_villages qv
  WHERE qv.latitude IS NOT NULL
    AND qv.longitude IS NOT NULL
    AND (
      6371 * acos(
        LEAST(1.0, GREATEST(-1.0,
          cos(radians(p_lat)) * cos(radians(qv.latitude))
          * cos(radians(qv.longitude) - radians(p_lng))
          + sin(radians(p_lat)) * sin(radians(qv.latitude))
        ))
      )
    ) <= 0.5
  ORDER BY (
    6371 * acos(
      LEAST(1.0, GREATEST(-1.0,
        cos(radians(p_lat)) * cos(radians(qv.latitude))
        * cos(radians(qv.longitude) - radians(p_lng))
        + sin(radians(p_lat)) * sin(radians(qv.latitude))
      ))
    )
  )
  LIMIT 1;
END;
$$;


ALTER FUNCTION "public"."find_queer_village"("p_lat" double precision, "p_lng" double precision, "p_city_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_unified_tag_duplicates"("p_threshold" real DEFAULT 0.6, "p_limit" integer DEFAULT 100) RETURNS TABLE("tag_a_id" "uuid", "tag_a_slug" "text", "tag_b_id" "uuid", "tag_b_slug" "text", "similarity" real)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
  SELECT a.id, a.slug, b.id, b.slug, similarity(a.slug, b.slug)
    FROM v_active_tags a
    JOIN v_active_tags b ON a.id < b.id AND a.slug % b.slug
   WHERE similarity(a.slug, b.slug) >= p_threshold
   ORDER BY similarity(a.slug, b.slug) DESC LIMIT p_limit;
$$;


ALTER FUNCTION "public"."find_unified_tag_duplicates"("p_threshold" real, "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_venue_duplicate_candidates"("p_name" "text", "p_phone_e164" "text" DEFAULT NULL::"text", "p_email" "text" DEFAULT NULL::"text", "p_website_domain" "text" DEFAULT NULL::"text", "p_lat" numeric DEFAULT NULL::numeric, "p_lng" numeric DEFAULT NULL::numeric, "p_city_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 20, "p_address" "text" DEFAULT NULL::"text") RETURNS TABLE("venue_id" "uuid", "match_type" "text", "score" numeric, "distance_m" double precision)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'extensions'
    AS $$
  WITH candidates AS (
    SELECT v.id AS vid, 'phone_exact'::text AS mt, 1.00::numeric AS sc,
           public.haversine_m(p_lat, p_lng, v.latitude, v.longitude) AS dm
    FROM public.venues v
    WHERE p_phone_e164 IS NOT NULL AND v.phone_e164 = p_phone_e164 AND v.duplicate_of_id IS NULL
    UNION ALL
    SELECT v.id, 'email_exact', 0.98, public.haversine_m(p_lat, p_lng, v.latitude, v.longitude)
    FROM public.venues v
    WHERE p_email IS NOT NULL AND v.email_lower = lower(btrim(p_email)) AND v.duplicate_of_id IS NULL
    UNION ALL
    SELECT v.id, 'domain_proximity', 0.95, public.haversine_m(p_lat, p_lng, v.latitude, v.longitude)
    FROM public.venues v
    WHERE p_website_domain IS NOT NULL AND v.website_domain = p_website_domain AND v.duplicate_of_id IS NULL
      AND (p_lat IS NULL OR v.latitude IS NULL OR public.haversine_m(p_lat, p_lng, v.latitude, v.longitude) < 500)
    UNION ALL
    SELECT v.id, 'name_proximity',
           extensions.similarity(v.name_normalized, public.normalize_name(p_name))::numeric,
           public.haversine_m(p_lat, p_lng, v.latitude, v.longitude)
    FROM public.venues v
    WHERE v.name_normalized % public.normalize_name(p_name) AND v.duplicate_of_id IS NULL
      AND (p_city_id IS NULL OR v.city_id = p_city_id)
      AND (p_lat IS NULL OR v.latitude IS NULL OR public.haversine_m(p_lat, p_lng, v.latitude, v.longitude) < 1500)
    UNION ALL
    SELECT v.id, 'address_name_proximity',
           ((extensions.similarity(v.address_normalized, public.normalize_address(p_address)) +
             extensions.similarity(v.name_normalized,     public.normalize_name(p_name))) / 2)::numeric,
           public.haversine_m(p_lat, p_lng, v.latitude, v.longitude)
    FROM public.venues v
    WHERE p_address IS NOT NULL
      AND v.address_normalized IS NOT NULL
      AND v.address_normalized % public.normalize_address(p_address)
      AND v.name_normalized    % public.normalize_name(p_name)
      AND v.duplicate_of_id IS NULL
      AND (p_city_id IS NULL OR v.city_id = p_city_id)
  ),
  best AS (
    SELECT DISTINCT ON (vid) vid, mt, sc, dm
    FROM candidates ORDER BY vid, sc DESC, dm ASC NULLS LAST
  )
  SELECT vid, mt, sc, dm FROM best
  ORDER BY sc DESC, dm ASC NULLS LAST
  LIMIT p_limit;
$$;


ALTER FUNCTION "public"."find_venue_duplicate_candidates"("p_name" "text", "p_phone_e164" "text", "p_email" "text", "p_website_domain" "text", "p_lat" numeric, "p_lng" numeric, "p_city_id" "uuid", "p_limit" integer, "p_address" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_venue_duplicates"("p_name" "text", "p_latitude" numeric, "p_longitude" numeric, "p_category" "text" DEFAULT NULL::"text", "p_threshold" numeric DEFAULT 0.5) RETURNS TABLE("venue_id" "uuid", "venue_name" "text", "name_similarity" numeric, "geo_distance_m" numeric, "category_match" boolean, "combined_score" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    v.id as venue_id,
    v.name as venue_name,
    similarity(lower(unaccent(v.name)), lower(unaccent(p_name)))::numeric as name_similarity,
    (6371000 * acos(
      LEAST(1.0, cos(radians(v.latitude::float8)) * cos(radians(p_latitude::float8)) *
      cos(radians(p_longitude::float8) - radians(v.longitude::float8)) +
      sin(radians(v.latitude::float8)) * sin(radians(p_latitude::float8)))
    ))::numeric as geo_distance_m,
    CASE WHEN p_category IS NOT NULL AND lower(v.category) = lower(p_category) THEN true ELSE false END as category_match,
    (
      similarity(lower(unaccent(v.name)), lower(unaccent(p_name)))::numeric * 0.6 +
      GREATEST(0.0, 1.0 - (6371000 * acos(
        LEAST(1.0, cos(radians(v.latitude::float8)) * cos(radians(p_latitude::float8)) *
        cos(radians(p_longitude::float8) - radians(v.longitude::float8)) +
        sin(radians(v.latitude::float8)) * sin(radians(p_latitude::float8)))
      )) / 100.0)::numeric * 0.3 +
      CASE WHEN p_category IS NOT NULL AND lower(v.category) = lower(p_category) THEN 0.1::numeric ELSE 0.0::numeric END
    ) as combined_score
  FROM public.venues v
  WHERE 
    similarity(lower(unaccent(v.name)), lower(unaccent(p_name))) > p_threshold
    AND v.latitude IS NOT NULL AND v.longitude IS NOT NULL
    AND v.latitude BETWEEN p_latitude - 0.09 AND p_latitude + 0.09
    AND v.longitude BETWEEN p_longitude - 0.09 AND p_longitude + 0.09
  ORDER BY combined_score DESC
  LIMIT 5;
END;
$$;


ALTER FUNCTION "public"."find_venue_duplicates"("p_name" "text", "p_latitude" numeric, "p_longitude" numeric, "p_category" "text", "p_threshold" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fix_missing_junction_entries"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  fixed_count integer;
BEGIN
  -- Insert junction entries for active tags that have category_id but no junction row
  INSERT INTO tag_category_assignments (tag_id, category_id, is_primary)
  SELECT ut.id, ut.category_id, true
  FROM unified_tags ut
  WHERE ut.status = 'active'
    AND ut.category_id IS NOT NULL
    AND NOT EXISTS (
      SELECT 1 FROM tag_category_assignments tca WHERE tca.tag_id = ut.id
    )
  ON CONFLICT (tag_id, category_id) DO NOTHING;

  GET DIAGNOSTICS fixed_count = ROW_COUNT;

  -- Also sync the text category column where it's NULL but category_id is set
  UPDATE unified_tags ut SET category = tc.name
  FROM tag_categories tc
  WHERE ut.category_id = tc.id
    AND ut.status = 'active'
    AND (ut.category IS NULL OR ut.category = '');

  RETURN fixed_count;
END;
$$;


ALTER FUNCTION "public"."fix_missing_junction_entries"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."flag_near_duplicate_on_insert"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  similar_tag RECORD;
BEGIN
  FOR similar_tag IN
    SELECT id, name, similarity(LOWER(NEW.name), LOWER(name)) as sim
    FROM unified_tags
    WHERE id != NEW.id
      AND status = 'active'
      AND similarity(LOWER(NEW.name), LOWER(name)) > 0.7
    ORDER BY similarity(LOWER(NEW.name), LOWER(name)) DESC
    LIMIT 3
  LOOP
    INSERT INTO tag_suggestions (
      entity_id, entity_type, tag_id, suggested_tag_name,
      source, confidence, status, created_at
    ) VALUES (
      NEW.id, 'tag', similar_tag.id,
      'Near-duplicate of "' || similar_tag.name || '" (similarity: ' || ROUND(similar_tag.sim::numeric, 2) || ')',
      'duplicate_warning', similar_tag.sim, 'pending', now()
    )
    ON CONFLICT DO NOTHING;
  END LOOP;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."flag_near_duplicate_on_insert"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_pipeline_run_failure_handler"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE
  v_pipeline_name text;
  v_error_msg     text;
  v_consecutive   int;
  v_alert_id      uuid;
  v_first_seen    timestamptz;
  v_sub_id        uuid;
BEGIN
  IF NEW.status <> 'failed' OR OLD.status = 'failed' THEN
    RETURN NEW;
  END IF;

  v_pipeline_name := NEW.pipeline_name;
  v_error_msg     := COALESCE(NEW.error_message, 'Pipeline failed');

  INSERT INTO pipeline_errors (function_name, severity, message, context, pipeline_run_id)
  VALUES (
    v_pipeline_name, 'error', v_error_msg,
    jsonb_build_object('pipeline_id', NEW.pipeline_id, 'run_id', NEW.id, 'items_failed', NEW.items_failed),
    NEW.id
  );

  SELECT count(*) INTO v_consecutive
  FROM pipeline_runs
  WHERE pipeline_name = v_pipeline_name
    AND status = 'failed'
    AND created_at > now() - interval '24 hours';

  INSERT INTO pipeline_health_alerts (kind, subject, detail, first_seen_at, last_seen_at)
  VALUES (
    'consecutive_failures', v_pipeline_name,
    jsonb_build_object('consecutive_failures', v_consecutive, 'last_error', v_error_msg, 'run_id', NEW.id),
    now(), now()
  )
  ON CONFLICT (kind, subject) WHERE resolved_at IS NULL
  DO UPDATE SET
    last_seen_at = now(),
    detail = pipeline_health_alerts.detail || jsonb_build_object(
      'consecutive_failures', v_consecutive,
      'last_error', v_error_msg,
      'run_id', NEW.id
    );

  SELECT id, first_seen_at INTO v_alert_id, v_first_seen
  FROM pipeline_health_alerts
  WHERE kind = 'consecutive_failures' AND subject = v_pipeline_name AND resolved_at IS NULL;

  IF v_consecutive >= 3
     AND v_first_seen < now() - interval '24 hours'
     AND v_alert_id IS NOT NULL
     AND NOT EXISTS (
       SELECT 1 FROM community_submissions
       WHERE content_type = 'pipeline_failure'
         AND (data->>'pipeline_name') = v_pipeline_name
         AND feedback_status <> 'done'
     )
  THEN
    INSERT INTO community_submissions (content_type, status, feedback_status, data)
    VALUES (
      'pipeline_failure', 'pending', 'new',
      jsonb_build_object(
        'category',       'bug',
        'title',          'Pipeline ' || v_pipeline_name || ' failing',
        'body',           'Pipeline has failed ' || v_consecutive || '+ times in 24h. Last error: ' || v_error_msg,
        'source',         'pipeline-monitor',
        'pipeline_name',  v_pipeline_name,
        'alert_id',       v_alert_id,
        'auto_github_sync', true
      )
    )
    RETURNING id INTO v_sub_id;

    UPDATE pipeline_health_alerts
    SET escalated_submission_id = v_sub_id
    WHERE id = v_alert_id AND escalated_submission_id IS NULL;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_pipeline_run_failure_handler"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_pipeline_run_success_handler"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
BEGIN
  IF NEW.status <> 'completed' OR OLD.status = 'completed' THEN
    RETURN NEW;
  END IF;

  UPDATE pipeline_health_alerts
  SET resolved_at = now()
  WHERE kind = 'consecutive_failures'
    AND subject = NEW.pipeline_name
    AND resolved_at IS NULL;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_pipeline_run_success_handler"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fx_to_usd"("p_amount" numeric, "p_currency" "text") RETURNS numeric
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  SELECT CASE
    WHEN p_amount IS NULL THEN NULL
    WHEN p_currency IS NULL THEN p_amount
    ELSE round(p_amount * coalesce((SELECT rate_to_usd FROM public.fx_rates WHERE currency = upper(p_currency)), 1.0), 2)
  END;
$$;


ALTER FUNCTION "public"."fx_to_usd"("p_amount" numeric, "p_currency" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_data_ops_alerts"() RETURNS TABLE("alert_kind" "text", "fingerprint" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE r RECORD;
BEGIN
  -- Coverage gaps: any source/city with success_ratio < 0.4
  FOR r IN
    SELECT source_slug, city, accommodation_type, expected_count, actual_count, success_ratio, gap_kind
    FROM public.coverage_gaps
    WHERE gap_kind IN ('under_target','never_run')
  LOOP
    INSERT INTO public.data_ops_alerts(alert_kind, severity, source_slug, detail, fingerprint)
    VALUES ('coverage_gap', 'warn', r.source_slug,
      jsonb_build_object('city', r.city, 'acc_type', r.accommodation_type,
        'expected', r.expected_count, 'actual', r.actual_count, 'ratio', r.success_ratio, 'kind', r.gap_kind),
      'cov:' || r.source_slug || ':' || coalesce(r.city,'-') || ':' || coalesce(r.accommodation_type,'-'))
    ON CONFLICT (fingerprint) WHERE acked_at IS NULL DO NOTHING;
    alert_kind := 'coverage_gap'; fingerprint := 'cov:' || r.source_slug; RETURN NEXT;
  END LOOP;

  -- Dedup precision drift: precision < 0.7 with >= 10 decisions
  FOR r IN
    SELECT rpc_match_type, decisions, precision FROM public.dedup_precision
    WHERE decisions >= 10 AND precision IS NOT NULL AND precision < 0.7
  LOOP
    INSERT INTO public.data_ops_alerts(alert_kind, severity, detail, fingerprint)
    VALUES ('dedup_precision_drift', 'error',
      jsonb_build_object('match_type', r.rpc_match_type, 'precision', r.precision, 'decisions', r.decisions),
      'dedup:' || r.rpc_match_type)
    ON CONFLICT (fingerprint) WHERE acked_at IS NULL DO NOTHING;
    alert_kind := 'dedup_precision_drift'; fingerprint := 'dedup:' || r.rpc_match_type; RETURN NEXT;
  END LOOP;

  -- DLQ backlog: >50 items in pending or any permanent_failed
  FOR r IN
    SELECT source_slug, stage, status, items FROM public.dlq_summary
    WHERE (status='pending' AND items > 50) OR status='permanent_failed'
  LOOP
    INSERT INTO public.data_ops_alerts(alert_kind, severity, source_slug, detail, fingerprint)
    VALUES ('dlq_backlog',
      CASE WHEN r.status='permanent_failed' THEN 'error' ELSE 'warn' END,
      r.source_slug,
      jsonb_build_object('stage', r.stage, 'status', r.status, 'items', r.items),
      'dlq:' || coalesce(r.source_slug,'-') || ':' || r.stage || ':' || r.status)
    ON CONFLICT (fingerprint) WHERE acked_at IS NULL DO NOTHING;
    alert_kind := 'dlq_backlog'; fingerprint := 'dlq:' || coalesce(r.source_slug,'-'); RETURN NEXT;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."generate_data_ops_alerts"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_email_token"() RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  alphabet text := '0123456789ABCDEFGHJKMNPQRSTVWXYZ';
  result text := '';
  i int;
  rand_byte int;
BEGIN
  FOR i IN 1..12 LOOP
    rand_byte := (random() * 32)::int;
    IF rand_byte > 31 THEN rand_byte := 31; END IF;
    result := result || substr(alphabet, rand_byte + 1, 1);
  END LOOP;
  RETURN lower(result);
END;
$$;


ALTER FUNCTION "public"."generate_email_token"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_slug"("input_text" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE
  slug text;
BEGIN
  slug := lower(trim(input_text));
  slug := replace(slug, 'ä', 'ae');
  slug := replace(slug, 'ö', 'oe');
  slug := replace(slug, 'ü', 'ue');
  slug := replace(slug, 'ß', 'ss');
  slug := replace(slug, 'é', 'e');
  slug := replace(slug, 'è', 'e');
  slug := replace(slug, 'ê', 'e');
  slug := replace(slug, 'ë', 'e');
  slug := replace(slug, 'à', 'a');
  slug := replace(slug, 'â', 'a');
  slug := replace(slug, 'á', 'a');
  slug := replace(slug, 'ô', 'o');
  slug := replace(slug, 'ó', 'o');
  slug := replace(slug, 'ò', 'o');
  slug := replace(slug, 'ù', 'u');
  slug := replace(slug, 'ú', 'u');
  slug := replace(slug, 'û', 'u');
  slug := replace(slug, 'ñ', 'n');
  slug := replace(slug, 'ç', 'c');
  slug := replace(slug, 'ø', 'o');
  slug := replace(slug, 'å', 'a');
  slug := replace(slug, 'æ', 'ae');
  slug := replace(slug, '&', 'and');
  slug := replace(slug, '@', 'at');
  slug := regexp_replace(slug, '[^a-z0-9-]', '-', 'g');
  slug := regexp_replace(slug, '-+', '-', 'g');
  slug := trim(both '-' from slug);
  IF slug = '' THEN
    slug := 'untitled';
  END IF;
  RETURN slug;
END;
$$;


ALTER FUNCTION "public"."generate_slug"("input_text" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_source_quality_alerts"() RETURNS integer
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count INT := 0;
  r RECORD;
BEGIN
  FOR r IN
    WITH recent AS (
      SELECT entity_type, source_name,
             percentile_cont(0.50) WITHIN GROUP (ORDER BY score_p50) AS p50_recent,
             SUM(n)::int AS n_recent
      FROM public.pipeline_quality_daily
      WHERE day >= (CURRENT_DATE - INTERVAL '7 days')
      GROUP BY entity_type, source_name
      HAVING SUM(n) >= 50
    ),
    baseline AS (
      SELECT entity_type, source_name,
             percentile_cont(0.50) WITHIN GROUP (ORDER BY score_p50) AS p50_baseline,
             SUM(n)::int AS n_baseline
      FROM public.pipeline_quality_daily
      WHERE day >= (CURRENT_DATE - INTERVAL '30 days')
        AND day <  (CURRENT_DATE - INTERVAL '8 days')
      GROUP BY entity_type, source_name
      HAVING SUM(n) >= 50
    )
    SELECT r.entity_type, r.source_name, r.p50_recent, b.p50_baseline,
           (b.p50_baseline - r.p50_recent) AS drop_points,
           r.n_recent, b.n_baseline
    FROM recent r
    JOIN baseline b USING (entity_type, source_name)
    WHERE (b.p50_baseline - r.p50_recent) >= 15
  LOOP
    INSERT INTO public.data_ops_alerts(alert_kind, severity, source_slug, detail, fingerprint)
    VALUES (
      'source_quality_drop',
      CASE WHEN r.drop_points >= 25 THEN 'error' ELSE 'warn' END,
      r.source_name,
      jsonb_build_object(
        'entity_type', r.entity_type,
        'p50_recent', r.p50_recent,
        'p50_baseline', r.p50_baseline,
        'drop_points', r.drop_points,
        'n_recent', r.n_recent,
        'n_baseline', r.n_baseline
      ),
      'qdrop:' || r.source_name || ':' || r.entity_type
        || ':' || to_char(date_trunc('week', now()), 'IYYY-IW')
    )
    ON CONFLICT (fingerprint) WHERE acked_at IS NULL DO NOTHING;
    v_count := v_count + 1;
  END LOOP;
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."generate_source_quality_alerts"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_unique_slug"("p_table_name" "text", "p_base_slug" "text", "p_exclude_id" "uuid" DEFAULT NULL::"uuid") RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $_$
DECLARE
  candidate text;
  counter int := 0;
  exists_already boolean;
BEGIN
  candidate := p_base_slug;
  LOOP
    EXECUTE format(
      'SELECT EXISTS(SELECT 1 FROM %I WHERE slug = $1 AND ($2 IS NULL OR id != $2))',
      p_table_name
    ) INTO exists_already USING candidate, p_exclude_id;
    EXIT WHEN NOT exists_already;
    counter := counter + 1;
    candidate := p_base_slug || '-' || counter;
  END LOOP;
  RETURN candidate;
END;
$_$;


