CREATE OR REPLACE FUNCTION "public"."get_admin_counts"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result jsonb;
  estimates jsonb;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role,'moderator'::app_role]) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE='42501';
  END IF;

  -- Approximate counts from planner stats (instant, ~5% imprecision)
  SELECT jsonb_object_agg(relname, reltuples::bigint)
  INTO estimates
  FROM pg_class
  WHERE relnamespace = 'public'::regnamespace
    AND relname = ANY (ARRAY[
      'venues','events','news_articles','personalities','cities','countries',
      'hotels','queer_villages','marketplace_listings','community_groups',
      'unified_tags','cms_pages','email_ingestions','workflow_runs',
      'scrape_sources','content_links','community_submissions','redirects'
    ]);

  -- Exact counts where filtering is needed (these hit indexes or are tiny)
  SELECT estimates || jsonb_build_object(
    'review_staging', (SELECT count(*) FROM ingestion_staging WHERE review_status='pending_review' AND disposition='pending'),
    'review_cms',     (SELECT count(*) FROM cms_content_metadata WHERE workflow_state='review'),
    'review_moderation', (SELECT count(*) FROM moderation_flags WHERE status='OPEN'),
    'review_tags',    (SELECT count(*) FROM tag_suggestions WHERE status='pending'),
    'review_duplicates', (SELECT count(*) FROM scraper_dedupe_decisions WHERE decision='pending'),
    'review_feedback', (SELECT count(*) FROM community_submissions WHERE content_type='feedback' AND feedback_status IN ('new','under_review'))
  )
  INTO result;

  RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_admin_counts"() OWNER TO "postgres";


