CREATE OR REPLACE FUNCTION "public"."get_bias_signal"("p_user_id" "uuid" DEFAULT NULL::"uuid", "p_session_id" "text" DEFAULT NULL::"text", "p_window" integer DEFAULT 30) RETURNS TABLE("entity_type" "text", "entity_id" "text", "event_type" "text", "age_days" real, "embedding" "extensions"."vector")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
  WITH ev AS (
    SELECT ue.entity_type, ue.entity_id, ue.event_type, ue.created_at
    FROM user_events ue
    WHERE (p_user_id IS NOT NULL AND ue.user_id = p_user_id)
       OR (p_user_id IS NULL AND ue.session_id = p_session_id)
    ORDER BY ue.created_at DESC LIMIT p_window
  )
  SELECT ev.entity_type, ev.entity_id, ev.event_type,
         EXTRACT(EPOCH FROM (now() - ev.created_at))::real / 86400.0,
         ce.embedding
  FROM ev
  JOIN content_embeddings ce
    ON ce.content_type = ev.entity_type AND ce.content_id::text = ev.entity_id
  WHERE ce.embedding IS NOT NULL;
$$;


