CREATE OR REPLACE FUNCTION "public"."get_category_ancestors"("p_category_id" "uuid") RETURNS TABLE("id" "uuid", "name" "text", "slug" "text", "level" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH RECURSIVE ancestors AS (
    -- Start with the given category
    SELECT tc.id, tc.name, tc.slug, tc.level, tc.parent_id
    FROM tag_categories tc
    WHERE tc.id = p_category_id
    
    UNION ALL
    
    -- Walk up the tree
    SELECT tc.id, tc.name, tc.slug, tc.level, tc.parent_id
    FROM tag_categories tc
    JOIN ancestors a ON a.parent_id = tc.id
  )
  SELECT ancestors.id, ancestors.name, ancestors.slug, ancestors.level
  FROM ancestors
  ORDER BY ancestors.level ASC;
END;
$$;


ALTER FUNCTION "public"."get_category_ancestors"("p_category_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_category_tree"("p_parent_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result JSONB;
BEGIN
  WITH cat_tag_counts AS (
    SELECT tca.category_id, count(DISTINCT tca.tag_id) AS cnt
    FROM tag_category_assignments tca
    JOIN unified_tags ut ON ut.id = tca.tag_id AND ut.status = 'active'
    GROUP BY tca.category_id
  ),
  parent_total_counts AS (
    -- count active tags assigned to a top-level cat OR any of its children
    SELECT pc.id AS parent_id,
           count(DISTINCT ut.id) AS total_cnt
    FROM tag_categories pc
    LEFT JOIN tag_categories cc ON cc.parent_id = pc.id
    LEFT JOIN tag_category_assignments tca
      ON tca.category_id = pc.id OR tca.category_id = cc.id
    LEFT JOIN unified_tags ut
      ON ut.id = tca.tag_id AND ut.status = 'active'
    WHERE pc.level = 0
    GROUP BY pc.id
  ),
  children_json AS (
    SELECT cc.parent_id,
           jsonb_agg(
             jsonb_build_object(
               'id', cc.id,
               'name', cc.name,
               'slug', cc.slug,
               'level', cc.level,
               'sort_order', cc.sort_order,
               'description', cc.description,
               'color', cc.color,
               'parent_id', cc.parent_id,
               'tag_count', COALESCE(ctc.cnt, 0)
             ) ORDER BY cc.sort_order
           ) AS kids
    FROM tag_categories cc
    LEFT JOIN cat_tag_counts ctc ON ctc.category_id = cc.id
    WHERE cc.parent_id IS NOT NULL
    GROUP BY cc.parent_id
  )
  SELECT jsonb_agg(
    jsonb_build_object(
      'id', pc.id,
      'name', pc.name,
      'slug', pc.slug,
      'level', pc.level,
      'sort_order', pc.sort_order,
      'description', pc.description,
      'color', pc.color,
      'tag_count', COALESCE(ctc.cnt, 0),
      'total_tag_count', COALESCE(ptc.total_cnt, 0),
      'children', COALESCE(cj.kids, '[]'::jsonb)
    ) ORDER BY pc.sort_order
  )
  INTO result
  FROM tag_categories pc
  LEFT JOIN cat_tag_counts ctc ON ctc.category_id = pc.id
  LEFT JOIN parent_total_counts ptc ON ptc.parent_id = pc.id
  LEFT JOIN children_json cj ON cj.parent_id = pc.id
  WHERE pc.level = 0
    AND (p_parent_id IS NULL OR pc.id = p_parent_id);

  RETURN COALESCE(result, '[]'::jsonb);
END;
$$;


ALTER FUNCTION "public"."get_category_tree"("p_parent_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_eligible_wolfram_tags"("p_limit" integer DEFAULT 20) RETURNS TABLE("id" "uuid", "name" "text", "description" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
