    AS $$
  SELECT t.id, t.name, t.description
  FROM unified_tags t
  WHERE t.wolfram_enriched_at IS NULL
    AND EXISTS (
      SELECT 1 FROM tag_category_assignments tca
      JOIN tag_categories tc ON tc.id = tca.category_id
      WHERE tca.tag_id = t.id
        AND tc.slug IN ('health-wellness','mental-health','physical-wellness','reproductive-health','sexual-health','intersex','substances-harm-reduction')
    )
    AND NOT EXISTS (
      SELECT 1 FROM tag_category_assignments tca2
      JOIN tag_categories tc2 ON tc2.id = tca2.category_id
      WHERE tca2.tag_id = t.id
        AND tc2.slug IN ('gender-identity','sexual-orientation','expression-presentation','culture-slang','slang-terminology','community-events','kink-fetish','bdsm','fetish-practices','leather-gear','rights-activism','political-activism','history-heritage','historical-movements','art-literature','media-entertainment','relationships','roles-dynamics','relationship-roles','sexual-roles','power-exchange','safety-practices','venue-travel','news-topics','miscellaneous','support-resources','workplace-education','legal-rights','body-modification')
    )
  LIMIT p_limit;
$$;


