CREATE OR REPLACE FUNCTION "public"."get_enrichment_failures"("p_entity_type" "text" DEFAULT NULL::"text", "p_since" interval DEFAULT '24:00:00'::interval, "p_limit" integer DEFAULT 50) RETURNS TABLE("entity_type" "text", "entity_id" "uuid", "enrichment_status" "jsonb", "quality_score" smallint, "needs_attention" boolean, "failed_steps" "text"[], "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role,'moderator'::app_role]) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE='42501'; END IF;
  RETURN QUERY
  WITH failures AS (
    SELECT 'venues'::TEXT AS et, v.id, v.enrichment_status AS es, v.quality_score AS qs, v.needs_attention AS na, v.updated_at AS ua
    FROM venues v WHERE v.enrichment_status IS NOT NULL AND v.enrichment_status::TEXT LIKE '%failed%'
      AND v.updated_at >= now() - p_since AND (p_entity_type IS NULL OR p_entity_type='venues')
    UNION ALL
    SELECT 'events'::TEXT, e.id, e.enrichment_status, e.quality_score, e.needs_attention, e.updated_at
    FROM events e WHERE e.enrichment_status IS NOT NULL AND e.enrichment_status::TEXT LIKE '%failed%'
      AND e.updated_at >= now() - p_since AND (p_entity_type IS NULL OR p_entity_type='events')
    UNION ALL
    SELECT 'personalities'::TEXT, p.id, p.enrichment_status, p.quality_score, p.needs_attention, p.updated_at
    FROM personalities p WHERE p.enrichment_status IS NOT NULL AND p.enrichment_status::TEXT LIKE '%failed%'
      AND p.updated_at >= now() - p_since AND (p_entity_type IS NULL OR p_entity_type='personalities')
    UNION ALL
    SELECT 'news_articles'::TEXT, n.id, n.enrichment_status, n.quality_score, n.needs_attention, n.updated_at
    FROM news_articles n WHERE n.enrichment_status IS NOT NULL AND n.enrichment_status::TEXT LIKE '%failed%'
      AND n.updated_at >= now() - p_since AND (p_entity_type IS NULL OR p_entity_type='news_articles')
  )
  SELECT f.et, f.id, f.es, f.qs, f.na,
    (SELECT array_agg(key) FROM jsonb_each_text(f.es) WHERE value='failed'), f.ua
  FROM failures f ORDER BY f.ua DESC LIMIT p_limit;
END;
$$;


ALTER FUNCTION "public"."get_enrichment_failures"("p_entity_type" "text", "p_since" interval, "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_entity_attributes"("entity_id_param" "uuid", "entity_type_param" "text") RETURNS TABLE("attribute_id" "uuid", "attribute_name" "text", "attribute_description" "text", "attribute_icon" "text", "attribute_category" "text")
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO ''
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    a.id as attribute_id,
    a.name as attribute_name,
    a.description as attribute_description,
    a.icon as attribute_icon,
    a.category as attribute_category
  FROM public.attributes a
  JOIN public.entity_attribute_assignments eaa ON eaa.attribute_id = a.id
  WHERE eaa.entity_id = entity_id_param 
    AND eaa.entity_type = entity_type_param
    AND a.is_active = true
  ORDER BY a.sort_order, a.name;
END;
$$;


