CREATE OR REPLACE FUNCTION "public"."get_homepage_stats"() RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  estimates jsonb;
BEGIN
  -- Approximate counts from planner stats (instant)
  SELECT jsonb_object_agg(
    CASE relname
      WHEN 'community_posts' THEN 'posts'
      WHEN 'community_groups' THEN 'groups'
      WHEN 'unified_tags' THEN 'tags'
      WHEN 'marketplace_listings' THEN 'marketplace'
      WHEN 'news_articles' THEN 'news'
      ELSE relname
    END,
    reltuples::bigint
  )
  INTO estimates
  FROM pg_class
  WHERE relnamespace = 'public'::regnamespace
    AND relname = ANY (ARRAY[
      'venues','profiles','cities','countries','events','community_posts',
      'personalities','community_groups','unified_tags','marketplace_listings','news_articles'
    ]);

  RETURN estimates || jsonb_build_object(
    'cms',          (SELECT count(*) FROM cms_content WHERE deleted_at IS NULL),
    'generated_at', now()
  );
END;
$$;


