CREATE OR REPLACE FUNCTION "public"."get_import_statistics"() RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE result json;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role,'moderator'::app_role]) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE='42501'; END IF;
  SELECT json_build_object(
    'total_imports',COUNT(*),'successful_imports',COUNT(*) FILTER (WHERE status='completed'),
    'failed_imports',COUNT(*) FILTER (WHERE status='failed'),
    'pending_imports',COUNT(*) FILTER (WHERE status IN ('pending','processing')),
    'total_records_processed',COALESCE(SUM(processed_records),0),
    'total_successful_records',COALESCE(SUM(successful_records),0),
    'total_failed_records',COALESCE(SUM(failed_records),0),
    'total_duplicate_records',COALESCE(SUM(duplicate_records),0),
    'total_items_fetched',COALESCE(SUM(items_fetched),0),
    'total_items_ai_approved',COALESCE(SUM(items_ai_approved),0),
    'total_items_committed',COALESCE(SUM(items_committed),0),
    'total_ai_cost_usd',COALESCE(SUM(ai_cost_usd),0),
    'items_pending_review',(SELECT COUNT(*) FROM ingestion_staging WHERE review_status='pending_review'),
    'last_import_date',MAX(created_at)
  ) INTO result FROM import_jobs_enhanced;
  RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_import_statistics"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_inbox_counts"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT jsonb_build_object(
    'unread_dms', (
      SELECT COUNT(*) FROM conversation_participants cp
      JOIN conversations c ON c.id = cp.conversation_id
      JOIN messages m ON m.conversation_id = c.id 
        AND m.created_at > COALESCE(cp.last_read_at, '1970-01-01'::timestamptz)
        AND m.sender_id != p_user_id
      WHERE cp.user_id = p_user_id AND cp.is_muted = false
    ),
    'unread_emails', (
      SELECT COUNT(*) FROM mailbox_emails
      WHERE owner_id = p_user_id 
        AND is_read = false 
        AND folder = 'inbox'
        AND deleted_at IS NULL
    ),
    'unread_notifications', (
      SELECT COUNT(*) FROM notifications
      WHERE user_id = p_user_id AND read = false
    )
  );
$$;


