    'dismissed', count(*) FILTER (WHERE status = 'DISMISSED'),
    'auto_removed', count(*) FILTER (WHERE status = 'AUTO_REMOVED'),
    'malicious', count(*) FILTER (WHERE scan_verdict = 'malicious'),
