CREATE OR REPLACE FUNCTION "public"."get_links_due_for_recheck"("batch_limit" integer DEFAULT 50) RETURNS SETOF "public"."content_links"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  SELECT *
  FROM content_links
  WHERE status = 'BROKEN'
    AND check_count BETWEEN 1 AND 3
    AND last_checked_at IS NOT NULL
    AND (
      (check_count = 1 AND last_checked_at < NOW() - INTERVAL '1 day')
      OR (check_count = 2 AND last_checked_at < NOW() - INTERVAL '1 week')
      OR (check_count = 3 AND last_checked_at < NOW() - INTERVAL '1 month')
    )
  ORDER BY last_checked_at ASC
  LIMIT batch_limit;
$$;


