CREATE OR REPLACE FUNCTION "public"."get_or_create_email_token"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  existing text;
  candidate text;
  attempts int := 0;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'auth required';
  END IF;

  SELECT token INTO existing
  FROM public.user_email_tokens
  WHERE user_id = auth.uid() AND revoked_at IS NULL;

  IF existing IS NOT NULL THEN
    RETURN existing;
  END IF;

  WHILE attempts < 3 LOOP
    candidate := public.generate_email_token();
    BEGIN
      INSERT INTO public.user_email_tokens (user_id, token)
      VALUES (auth.uid(), candidate);
      RETURN candidate;
    EXCEPTION WHEN unique_violation THEN
      attempts := attempts + 1;
    END;
  END LOOP;

  RAISE EXCEPTION 'could not allocate email token after % attempts', attempts;
END;
$$;


ALTER FUNCTION "public"."get_or_create_email_token"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_personality_profession_facets"("lim" integer DEFAULT 20) RETURNS TABLE("profession" "text", "cnt" bigint)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  WITH base AS (
    SELECT public.canonical_profession(
      split_part(p.profession, ',', 1)
    ) AS profession
    FROM public.personalities p
    WHERE p.visibility = 'public'
      AND p.profession IS NOT NULL
      AND p.profession <> ''
      AND p.profession NOT ILIKE '%adult performer%'
      AND p.profession NOT ILIKE '%adult model%'
      AND p.profession NOT ILIKE '%adult film%'
      AND p.profession NOT ILIKE '%porn%'
  )
  SELECT profession, COUNT(*)::bigint AS cnt
  FROM base
  WHERE profession IS NOT NULL
  GROUP BY profession
  ORDER BY COUNT(*) DESC, profession ASC
  LIMIT GREATEST(lim, 1);
$$;


ALTER FUNCTION "public"."get_personality_profession_facets"("lim" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_public_profile_safe"("target_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  profile_record record;
  safe_data jsonb;
  privacy_settings jsonb;
BEGIN
  -- Get the profile record
  SELECT * INTO profile_record 
  FROM public.profiles 
  WHERE user_id = target_user_id;
  
  IF NOT FOUND THEN
    RETURN null;
  END IF;
  
  -- Parse privacy settings
  privacy_settings := COALESCE(profile_record.privacy_settings, '{}'::jsonb);
  
  -- Always include basic display information
  safe_data := jsonb_build_object(
    'id', profile_record.id,
    'user_id', profile_record.user_id,
    'display_name', profile_record.display_name,
    'bio', profile_record.bio,
    'avatar_url', profile_record.avatar_url,
    'created_at', profile_record.created_at,
    'is_business', profile_record.is_business
  );
  
  -- Add location only if location_public is true
  IF COALESCE((privacy_settings ->> 'location_public')::boolean, false) = true THEN
    safe_data := safe_data || jsonb_build_object('location', profile_record.location);
  END IF;
  
  -- Add pronouns only if pronouns_public is true  
  IF COALESCE((privacy_settings ->> 'pronouns_public')::boolean, false) = true THEN
    safe_data := safe_data || jsonb_build_object('pronouns', profile_record.pronouns);
  END IF;
  
  -- Add website and social links only if contact_public is true
  IF COALESCE((privacy_settings ->> 'contact_public')::boolean, false) = true THEN
    safe_data := safe_data || jsonb_build_object(
      'website', profile_record.website,
      'social_links', profile_record.social_links
    );
  END IF;
  
  -- Add basic interests only if interests_public is true
  IF COALESCE((privacy_settings ->> 'interests_public')::boolean, false) = true THEN
    safe_data := safe_data || jsonb_build_object(
      'interests', profile_record.interests,
      'occupation', profile_record.occupation,
      'education', profile_record.education
    );
  END IF;
  
  -- NEVER expose sensitive fields publicly:
  -- phone, date_of_birth, gender_identity, sexual_orientation, 
  -- relationship_status, income_range, emergency_contact_*,
  -- physical characteristics, lifestyle preferences, etc.
  
  RETURN safe_data;
END;
$$;


ALTER FUNCTION "public"."get_public_profile_safe"("target_user_id" "uuid") OWNER TO "postgres";


