CREATE OR REPLACE FUNCTION "public"."get_similar_personalities"("personality_uuid" "uuid", "result_limit" integer DEFAULT 6, "min_similarity" double precision DEFAULT 0.3) RETURNS TABLE("id" "uuid", "name" "text", "profession" "text", "nationality" "text", "image_url" "text", "is_living" boolean, "birth_date" "date", "death_date" "date", "description" "text", "similarity" double precision)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  source_embedding vector(768);
BEGIN
  SELECT ce.embedding INTO source_embedding
  FROM content_embeddings ce
  WHERE ce.content_id = personality_uuid
    AND ce.content_type = 'personality'
  LIMIT 1;

  IF source_embedding IS NULL THEN
    RETURN QUERY
    SELECT 
      p.id, p.name, p.profession, p.nationality, p.image_url,
      p.is_living, p.birth_date, p.death_date, p.description,
      0.0::FLOAT AS similarity
    FROM personalities p
    WHERE p.id != personality_uuid
      AND p.visibility = 'public'
      AND p.profession IS NOT NULL
      AND p.profession = (SELECT p2.profession FROM personalities p2 WHERE p2.id = personality_uuid)
    ORDER BY p.view_count DESC NULLS LAST
    LIMIT result_limit;
    RETURN;
  END IF;

  RETURN QUERY
  SELECT 
    p.id, p.name, p.profession, p.nationality, p.image_url,
    p.is_living, p.birth_date, p.death_date, p.description,
    (1 - (ce.embedding <=> source_embedding))::FLOAT AS similarity
  FROM content_embeddings ce
  JOIN personalities p ON p.id = ce.content_id
  WHERE ce.content_type = 'personality'
    AND ce.content_id != personality_uuid
    AND p.visibility = 'public'
    AND (1 - (ce.embedding <=> source_embedding)) > min_similarity
  ORDER BY ce.embedding <=> source_embedding
  LIMIT result_limit;
END;
$$;


ALTER FUNCTION "public"."get_similar_personalities"("personality_uuid" "uuid", "result_limit" integer, "min_similarity" double precision) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_similar_tags"("p_tag_id" "uuid", "p_limit" integer DEFAULT 10, "p_min_score" double precision DEFAULT 0.7) RETURNS TABLE("tag_id" "uuid", "tag_name" "text", "tag_slug" "text", "category_name" "text", "category_color" "text", "similarity_score" double precision, "relationship_type" "text", "usage_count" integer)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH related AS (
    SELECT
      CASE WHEN tr.tag1_id = p_tag_id THEN tr.tag2_id ELSE tr.tag1_id END AS related_tag_id,
      tr.similarity_score::float,
      tr.relationship_type
    FROM tag_relationships tr
    WHERE (tr.tag1_id = p_tag_id OR tr.tag2_id = p_tag_id)
      AND tr.similarity_score >= p_min_score
    ORDER BY tr.similarity_score DESC
    LIMIT p_limit
  )
  SELECT
    ut.id,
    ut.name,
    ut.slug,
    tc.name,
    tc.color,
    r.similarity_score,
    r.relationship_type,
    COALESCE(ut.usage_count, 0)::int
  FROM related r
  JOIN unified_tags ut ON ut.id = r.related_tag_id
  LEFT JOIN tag_categories tc ON tc.id = ut.category_id
  WHERE ut.status = 'active';

  -- Fallback: if no embedding relationships, return same-category tags
  IF NOT FOUND THEN
    RETURN QUERY
    SELECT
      ut.id,
      ut.name,
      ut.slug,
      tc.name,
      tc.color,
      0.0::float AS similarity_score,
      'same_category'::text AS relationship_type,
      COALESCE(ut.usage_count, 0)::int
    FROM unified_tags ut
    LEFT JOIN tag_categories tc ON tc.id = ut.category_id
    WHERE ut.category_id = (SELECT category_id FROM unified_tags WHERE id = p_tag_id)
      AND ut.id != p_tag_id
      AND ut.status = 'active'
    ORDER BY ut.usage_count DESC NULLS LAST
    LIMIT p_limit;
  END IF;
END;
$$;


ALTER FUNCTION "public"."get_similar_tags"("p_tag_id" "uuid", "p_limit" integer, "p_min_score" double precision) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_staging_ids"("p_target_table" "text" DEFAULT NULL::"text", "p_dedup_status" "text" DEFAULT NULL::"text", "p_search" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 50000) RETURNS json
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT COALESCE(json_agg(sub.id), '[]'::json)
  FROM (
    SELECT s.id FROM ingestion_staging s
    WHERE s.review_status = 'pending_review'
      AND s.disposition = 'pending'
      AND (p_target_table IS NULL OR s.target_table = p_target_table)
      AND (p_dedup_status IS NULL OR s.dedup_status = p_dedup_status)
      AND (p_search IS NULL OR s.normalized_data::text ILIKE '%' || p_search || '%')
    LIMIT p_limit
  ) sub;
$$;


ALTER FUNCTION "public"."get_staging_ids"("p_target_table" "text", "p_dedup_status" "text", "p_search" "text", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_staging_ids"("p_target_table" "text" DEFAULT NULL::"text", "p_dedup_status" "text" DEFAULT NULL::"text", "p_search" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 50000, "p_review_status" "text" DEFAULT NULL::"text") RETURNS json
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT COALESCE(json_agg(sub.id), '[]'::json)
  FROM (
    SELECT s.id FROM ingestion_staging s
    WHERE 1=1
      AND (p_target_table IS NULL OR s.target_table = p_target_table)
      AND (p_dedup_status IS NULL OR s.dedup_status = p_dedup_status)
      AND (p_review_status IS NULL OR s.review_status = p_review_status)
      AND (p_search IS NULL OR s.normalized_data::text ILIKE '%' || p_search || '%')
    LIMIT p_limit
  ) sub;
$$;


ALTER FUNCTION "public"."get_staging_ids"("p_target_table" "text", "p_dedup_status" "text", "p_search" "text", "p_limit" integer, "p_review_status" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_staging_page"("p_target_table" "text" DEFAULT NULL::"text", "p_review_status" "text" DEFAULT NULL::"text", "p_dedup_status" "text" DEFAULT NULL::"text", "p_search" "text" DEFAULT NULL::"text", "p_page" integer DEFAULT 1, "p_per_page" integer DEFAULT 50, "p_sort_field" "text" DEFAULT 'created_at'::"text", "p_sort_dir" "text" DEFAULT 'desc'::"text") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_offset INT; v_total INT; v_items JSON; v_query TEXT; v_count_query TEXT; v_where TEXT := 'WHERE 1=1';
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role,'moderator'::app_role]) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE='42501'; END IF;
  v_offset := (GREATEST(p_page,1)-1) * p_per_page;
  IF p_target_table IS NOT NULL THEN v_where := v_where || ' AND s.target_table = ' || quote_literal(p_target_table); END IF;
  IF p_review_status IS NOT NULL THEN v_where := v_where || ' AND s.review_status = ' || quote_literal(p_review_status); END IF;
  IF p_dedup_status IS NOT NULL THEN v_where := v_where || ' AND s.dedup_status = ' || quote_literal(p_dedup_status); END IF;
  IF p_search IS NOT NULL AND p_search != '' THEN
    v_where := v_where || ' AND (s.normalized_data::text ILIKE ' || quote_literal('%' || p_search || '%') || ')'; END IF;
  v_count_query := 'SELECT count(*) FROM ingestion_staging s ' || v_where;
  EXECUTE v_count_query INTO v_total;
  IF p_sort_field NOT IN ('created_at','updated_at','dedup_match_score','ai_confidence_score','target_table') THEN
    p_sort_field := 'created_at'; END IF;
  IF p_sort_dir NOT IN ('asc','desc') THEN p_sort_dir := 'desc'; END IF;
  v_query := format(
    'SELECT json_agg(row_to_json(t)) FROM (SELECT s.id, s.job_id, s.source_type, s.target_table, s.normalized_data, s.raw_data, s.ai_validation_status, s.ai_confidence_score, s.ai_validation_result, s.dedup_status, s.dedup_match_id, s.dedup_match_table, s.dedup_match_score, s.dedup_details, s.review_status, s.reviewed_by, s.reviewed_at, s.review_notes, s.disposition, s.error_message, s.created_at, s.updated_at FROM ingestion_staging s %s ORDER BY s.%I %s NULLS LAST LIMIT %s OFFSET %s) t',
    v_where, p_sort_field, p_sort_dir, p_per_page, v_offset);
  EXECUTE v_query INTO v_items;
  RETURN json_build_object('items', COALESCE(v_items,'[]'::json), 'total', v_total,
    'page', p_page, 'per_page', p_per_page, 'total_pages', CEIL(v_total::numeric / p_per_page));
END;
$$;


ALTER FUNCTION "public"."get_staging_page"("p_target_table" "text", "p_review_status" "text", "p_dedup_status" "text", "p_search" "text", "p_page" integer, "p_per_page" integer, "p_sort_field" "text", "p_sort_dir" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_stale_embeddings"("p_limit" integer DEFAULT 200) RETURNS TABLE("table_name" "text", "id" "text", "updated_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
  WITH candidates AS (
    SELECT 'venues'::text AS table_name, v.id::text AS id, v.updated_at, 'venue'::text AS content_type
    FROM venues v
    UNION ALL
    SELECT 'events',            e.id::text, e.updated_at, 'event'        FROM events e
    UNION ALL
    SELECT 'cities',            c.id::text, c.updated_at, 'city'         FROM cities c
    UNION ALL
    SELECT 'countries',         co.id::text, co.updated_at, 'country'    FROM countries co
    UNION ALL
    SELECT 'personalities',     p.id::text, p.updated_at, 'personality'  FROM personalities p
    UNION ALL
    SELECT 'news_articles',     n.id::text, n.updated_at, 'news'         FROM news_articles n
    UNION ALL
    SELECT 'marketplace_listings', m.id::text, m.updated_at, 'marketplace' FROM marketplace_listings m
    UNION ALL
    SELECT 'queer_villages',    q.id::text, q.updated_at, 'queer_village' FROM queer_villages q
    UNION ALL
    SELECT 'unified_tags',      t.id::text, t.updated_at, 'tag'          FROM unified_tags t
  )
  SELECT cand.table_name, cand.id, cand.updated_at
  FROM candidates cand
  LEFT JOIN content_embeddings ce
    ON ce.content_type = cand.content_type
   AND ce.content_id::text = cand.id
  WHERE ce.embedding IS NULL OR ce.updated_at < cand.updated_at
  ORDER BY cand.updated_at DESC NULLS LAST
  LIMIT p_limit;
$$;


ALTER FUNCTION "public"."get_stale_embeddings"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_subcategories"("p_parent_id" "uuid") RETURNS TABLE("id" "uuid", "name" "text", "slug" "text", "sort_order" integer, "description" "text", "color" "text", "tag_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    tc.id,
    tc.name,
    tc.slug,
    tc.sort_order,
    tc.description,
    tc.color,
    COUNT(DISTINCT tca.tag_id) as tag_count
  FROM tag_categories tc
  LEFT JOIN tag_category_assignments tca ON tca.category_id = tc.id
  LEFT JOIN unified_tags ut ON ut.id = tca.tag_id AND ut.status = 'active'
  WHERE tc.parent_id = p_parent_id
  GROUP BY tc.id, tc.name, tc.slug, tc.sort_order, tc.description, tc.color
  ORDER BY tc.sort_order;
END;
$$;


ALTER FUNCTION "public"."get_subcategories"("p_parent_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_table_policies"("table_name_param" "text") RETURNS TABLE("policy_name" "text", "role_name" "text", "command" "text", "using_expr" "text", "with_check_expr" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    p.polname::text,
    r.rolname::text,
    CASE 
      WHEN p.polcmd = 'r' THEN 'SELECT'
      WHEN p.polcmd = 'a' THEN 'INSERT'
      WHEN p.polcmd = 'w' THEN 'UPDATE'
      WHEN p.polcmd = 'd' THEN 'DELETE'
      ELSE p.polcmd::text
    END,
    pg_get_expr(p.polqual, p.polrelid)::text,
    pg_get_expr(p.polwithcheck, p.polrelid)::text
  FROM 
    pg_catalog.pg_policy p
  JOIN 
    pg_catalog.pg_class c ON p.polrelid = c.oid
  JOIN 
    pg_catalog.pg_namespace n ON c.relnamespace = n.oid
  CROSS JOIN LATERAL unnest(p.polroles) AS role_oid
  JOIN 
    pg_catalog.pg_roles r ON r.oid = role_oid
  WHERE 
    n.nspname = 'public' AND
    c.relname = table_name_param
  ORDER BY 
    p.polname;
END;
$$;


ALTER FUNCTION "public"."get_table_policies"("table_name_param" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_table_policies"("p_schema_name" "text", "p_table_name" "text") RETURNS TABLE("policy_name" "text", "policy_roles" "text"[], "policy_cmd" "text", "policy_qual" "text", "policy_with_check" "text")
    LANGUAGE "sql"
    SET "search_path" TO ''
    AS $$
    SELECT
        polname::text AS policy_name,
        polroles::text[] AS policy_roles,
        CASE polcmd
            WHEN 'r' THEN 'SELECT'
            WHEN 'a' THEN 'INSERT'
            WHEN 'w' THEN 'UPDATE'
            WHEN 'd' THEN 'DELETE'
            WHEN '*' THEN 'ALL'
        END AS policy_cmd,
        pg_get_expr(polqual, polrelid, true) AS policy_qual,
        pg_get_expr(polwithcheck, polrelid, true) AS policy_with_check
    FROM
        pg_policy
        JOIN pg_class ON pg_policy.polrelid = pg_class.oid
        JOIN pg_namespace ON pg_class.relnamespace = pg_namespace.oid
    WHERE
        pg_namespace.nspname = p_schema_name
        AND pg_class.relname = p_table_name
    ORDER BY
        policy_name;
$$;


ALTER FUNCTION "public"."get_table_policies"("p_schema_name" "text", "p_table_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_tag_categories"("p_tag_id" "uuid") RETURNS TABLE("category_id" "uuid", "category_name" "text", "is_primary" boolean)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT tca.category_id, tc.name, tca.is_primary
  FROM tag_category_assignments tca
  JOIN tag_categories tc ON tc.id = tca.category_id
  WHERE tca.tag_id = p_tag_id
  ORDER BY tca.is_primary DESC, tc.sort_order;
$$;


