CREATE OR REPLACE FUNCTION "public"."get_tag_graph_data"("p_min_score" double precision DEFAULT 0.7, "p_category_filter" "uuid" DEFAULT NULL::"uuid") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result json;
BEGIN
  SELECT json_build_object(
    'nodes', COALESCE((
      SELECT json_agg(json_build_object(
        'id', ut.id,
        'name', ut.name,
        'slug', ut.slug,
        'category_id', ut.category_id,
        'category_name', tc.name,
        'category_color', tc.color,
        'usage_count', COALESCE(ut.usage_count, 0)
      ))
      FROM unified_tags ut
      LEFT JOIN tag_categories tc ON tc.id = ut.category_id
      WHERE ut.status = 'active'
        AND ut.id IN (
          SELECT tag1_id FROM tag_relationships WHERE similarity_score >= p_min_score
          UNION
          SELECT tag2_id FROM tag_relationships WHERE similarity_score >= p_min_score
        )
        AND (p_category_filter IS NULL OR ut.category_id = p_category_filter)
    ), '[]'::json),
    'edges', COALESCE((
      SELECT json_agg(json_build_object(
        'source', tr.tag1_id,
        'target', tr.tag2_id,
        'score', tr.similarity_score,
        'type', tr.relationship_type
      ))
      FROM tag_relationships tr
      WHERE tr.similarity_score >= p_min_score
        AND (p_category_filter IS NULL OR (
          EXISTS (SELECT 1 FROM unified_tags WHERE id = tr.tag1_id AND category_id = p_category_filter)
          AND EXISTS (SELECT 1 FROM unified_tags WHERE id = tr.tag2_id AND category_id = p_category_filter)
        ))
    ), '[]'::json)
  ) INTO result;

  RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_tag_graph_data"("p_min_score" double precision, "p_category_filter" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_tag_linked_content"("p_tag_id" "uuid", "p_tag_name" "text", "p_tag_slug" "text", "p_limit" integer DEFAULT 20) RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result JSONB;
BEGIN
  SELECT jsonb_build_object(
    'venues', COALESCE((
      SELECT jsonb_agg(row_to_json(v_row))
      FROM (
        SELECT v.id, v.name, v.city, v.country, v.category,
               v.images[1] AS image_url, v.foursquare_rating, v.address, v.slug
        FROM unified_tag_assignments uta
        JOIN venues v ON v.id = uta.entity_id
        WHERE uta.tag_id = p_tag_id
          AND uta.entity_type IN ('venue', 'venues')
        ORDER BY v.featured DESC NULLS LAST, v.foursquare_rating DESC NULLS LAST
        LIMIT p_limit
      ) v_row
    ), '[]'::jsonb),

    'events', COALESCE((
      SELECT jsonb_agg(row_to_json(e_row))
      FROM (
        SELECT e.id, e.title, e.start_date, e.end_date, e.city,
               e.country, e.images[1] AS image_url, e.event_type, e.slug,
               ev.name AS venue_name
        FROM unified_tag_assignments uta
        JOIN events e ON e.id = uta.entity_id
        LEFT JOIN venues ev ON ev.id = e.venue_id
        WHERE uta.tag_id = p_tag_id
          AND uta.entity_type IN ('event', 'events')
          AND e.status = 'active'
        ORDER BY e.featured DESC NULLS LAST, e.start_date DESC NULLS LAST
        LIMIT p_limit
      ) e_row
    ), '[]'::jsonb),

    'news', COALESCE((
      SELECT jsonb_agg(row_to_json(n_row))
      FROM (
        SELECT na.id, na.title, na.published_at, na.image_url,
               na.excerpt, na.url,
               CASE WHEN ns.name IS NOT NULL
                 THEN jsonb_build_object('name', ns.name)
                 ELSE NULL
               END AS news_sources
        FROM unified_tag_assignments uta
        JOIN news_articles na ON na.id = uta.entity_id
        LEFT JOIN news_sources ns ON ns.id = na.source_id
        WHERE uta.tag_id = p_tag_id
          AND uta.entity_type IN ('news_article', 'news')
        ORDER BY na.is_featured DESC NULLS LAST, na.published_at DESC NULLS LAST
        LIMIT p_limit
      ) n_row
    ), '[]'::jsonb),

    'personalities', COALESCE((
      SELECT jsonb_agg(row_to_json(p_row))
      FROM (
        SELECT p.id, p.name, p.profession, p.nationality,
               p.image_url, p.birth_date, p.death_date, p.slug
        FROM personalities p
        WHERE p.visibility = 'public'
          AND (
            p_tag_name = ANY(p.tags)
            OR p_tag_slug = ANY(p.tags)
            OR lower(p_tag_name) = ANY(
              SELECT lower(unnest(p.tags))
            )
          )
        ORDER BY p.is_featured DESC NULLS LAST, p.view_count DESC NULLS LAST
        LIMIT p_limit
      ) p_row
    ), '[]'::jsonb),

    'groups', COALESCE((
      SELECT jsonb_agg(row_to_json(g_row))
      FROM (
        SELECT cg.id, cg.name, cg.description, cg.image_url AS avatar_url,
               cg.member_count,
               CASE WHEN cg.is_private THEN 'private' ELSE 'public' END AS privacy
        FROM unified_tag_assignments uta
        JOIN community_groups cg ON cg.id = uta.entity_id
        WHERE uta.tag_id = p_tag_id
          AND uta.entity_type IN ('community_group', 'group')
        ORDER BY cg.member_count DESC NULLS LAST
        LIMIT p_limit
      ) g_row
    ), '[]'::jsonb)
  ) INTO result;

  RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_tag_linked_content"("p_tag_id" "uuid", "p_tag_name" "text", "p_tag_slug" "text", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_translated_content"("p_table" "text", "p_id" "uuid", "p_lang" "text", "p_fields" "text"[] DEFAULT '{}'::"text"[]) RETURNS "jsonb"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
  select coalesce(
    jsonb_object_agg(field_name, value),
    '{}'::jsonb
  )
  from public.content_translations
  where table_name = p_table
    and record_id = p_id
    and language = p_lang
    and status = 'published'
    and (array_length(p_fields, 1) is null or field_name = any(p_fields));
$$;


