CREATE OR REPLACE FUNCTION "public"."get_user_signal"("p_user_id" "uuid" DEFAULT NULL::"uuid", "p_session_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE result jsonb;
BEGIN
  WITH prof AS (
    SELECT p.interests, p.hobbies, p.languages, p.location, p.hobbies AS h2
    FROM profiles p WHERE p.user_id = p_user_id LIMIT 1
  ),
  recent_cities AS (
    SELECT jsonb_agg(DISTINCT (metadata->>'city')) AS cities
    FROM user_events
    WHERE created_at > now() - interval '30 days'
      AND ((p_user_id IS NOT NULL AND user_id = p_user_id)
        OR (p_user_id IS NULL AND session_id = p_session_id))
      AND metadata->>'city' IS NOT NULL
  ),
  recent_tags AS (
    SELECT jsonb_agg(DISTINCT tag) AS tags
    FROM (
      SELECT jsonb_array_elements_text(metadata->'tags') AS tag
      FROM user_events
      WHERE created_at > now() - interval '30 days'
        AND ((p_user_id IS NOT NULL AND user_id = p_user_id)
          OR (p_user_id IS NULL AND session_id = p_session_id))
    ) t
  )
  SELECT jsonb_build_object(
    'interests', COALESCE((SELECT interests FROM prof), '[]'::jsonb),
    'languages', COALESCE((SELECT languages FROM prof), '[]'::jsonb),
    'home_city', (SELECT location FROM prof),
    'recent_cities', COALESCE((SELECT cities FROM recent_cities), '[]'::jsonb),
    'recent_tags', COALESCE((SELECT tags FROM recent_tags), '[]'::jsonb)
  ) INTO result;
  RETURN result;
END $$;


