    "tripadvisor_id" "text",
    "tripadvisor_rating" numeric(3,2),
    "tripadvisor_review_count" integer,
    "tomtom_id" "text",
    "tomtom_rating" numeric(3,1),
    "tomtom_data" "jsonb" DEFAULT '{}'::"jsonb",
    "data_source" "text",
    "external_id" "text",
    "last_synced_at" timestamp with time zone,
    "sync_status" "text" DEFAULT 'manual'::"text",
    "city_id" "uuid",
    "country_id" "uuid",
    "geo_linked_at" timestamp with time zone,
    "queer_village_id" "uuid",
    "lgbti_relevance_score" numeric(3,2),
    "sensitivity_flags" "jsonb",
    "classified_at" timestamp with time zone,
    "quality_score" smallint DEFAULT 0,
    "needs_attention" boolean DEFAULT false,
    "duplicate_of_id" "uuid",
    "enrichment_status" "jsonb" DEFAULT '{}'::"jsonb",
    "logo_url" "text",
    "logo_fetched_at" timestamp with time zone,
    "slug" "text" NOT NULL,
    "phone_e164" "text",
    "website_domain" "text",
    "email_lower" "text",
    "name_normalized" "text",
    "last_refreshed_at" timestamp with time zone,
    "verification_status" "text" DEFAULT 'unverified'::"text" NOT NULL,
    "booking_url" "text",
    "star_rating" numeric(2,1),
    "platform_ids" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "amenities_verified" boolean DEFAULT false NOT NULL,
    "accommodation_type" "text",
    "address_normalized" "text",
    "venue_subtype" "text",
    "url_status" character varying(20) DEFAULT NULL::character varying,
    "url_checked_at" timestamp with time zone,
    "content_language" "text",
    "closed_at" timestamp with time zone,
    "is_organizer" boolean DEFAULT false NOT NULL,
    "organizer_handles" "jsonb",
    CONSTRAINT "venues_accommodation_type_check" CHECK ((("accommodation_type" IS NULL) OR ("accommodation_type" = ANY (ARRAY['hotel'::"text", 'bnb'::"text", 'hostel'::"text", 'resort'::"text", 'guesthouse'::"text", 'apartment'::"text", 'villa'::"text", 'campground'::"text"])))),
    CONSTRAINT "venues_category_check" CHECK (("category" = ANY (ARRAY['bar'::"text", 'club'::"text", 'restaurant'::"text", 'hotel'::"text", 'sauna'::"text", 'theater'::"text", 'community_center'::"text", 'organization'::"text", 'event-venue'::"text", 'gallery'::"text", 'other'::"text"]))),
    CONSTRAINT "venues_price_range_check" CHECK ((("price_range" >= 1) AND ("price_range" <= 4))),
    CONSTRAINT "venues_slug_format_chk" CHECK ((("slug" IS NULL) OR ("slug" ~ '^[a-z0-9][a-z0-9-]*[a-z0-9]$'::"text") OR ("slug" ~ '^[a-z0-9]$'::"text"))),
    CONSTRAINT "venues_star_rating_check" CHECK ((("star_rating" IS NULL) OR (("star_rating" >= (0)::numeric) AND ("star_rating" <= (5)::numeric))))
);


