CREATE OR REPLACE FUNCTION "public"."has_any_role_jwt"("required_roles" "public"."app_role"[]) RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    COALESCE(((SELECT auth.jwt()) ->> 'user_role')::app_role = ANY(required_roles), false)
    OR EXISTS (
      SELECT 1 FROM public.user_roles
      WHERE user_id = (SELECT auth.uid()) AND role = ANY(required_roles)
    );
$$;


