CREATE OR REPLACE FUNCTION "public"."log_security_event"("p_event_type" "text", "p_user_id" "uuid" DEFAULT NULL::"uuid", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb", "p_severity" "text" DEFAULT 'medium'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_caller uuid := auth.uid();
  v_is_admin boolean := false;
  v_effective_user uuid;
  event_id uuid := gen_random_uuid();
BEGIN
  IF v_caller IS NOT NULL THEN
    SELECT EXISTS(SELECT 1 FROM public.user_roles WHERE user_id = v_caller AND role = 'admin'::public.app_role)
    INTO v_is_admin;
  END IF;
  IF v_is_admin OR v_caller IS NULL THEN
    v_effective_user := COALESCE(p_user_id, v_caller);
  ELSE
    v_effective_user := v_caller;
  END IF;
  INSERT INTO public.security_events (id, event_type, user_id, metadata, created_at)
  VALUES (event_id, p_event_type, v_effective_user,
    p_metadata || jsonb_build_object('severity', p_severity, 'timestamp', NOW(),
      'ip_address', current_setting('request.headers', true)::json->>'x-forwarded-for',
      'logged_by', v_caller),
    NOW());
  IF p_severity = 'critical' THEN
    INSERT INTO public.security_monitoring (id, event_type, severity, metadata)
    VALUES (gen_random_uuid(), 'SECURITY_INCIDENT_' || p_event_type, p_severity,
      p_metadata || jsonb_build_object('incident_id', event_id, 'requires_immediate_action', true, 'logged_by', v_caller));
  END IF;
  RETURN event_id;
END;
$$;


ALTER FUNCTION "public"."log_security_event"("p_event_type" "text", "p_user_id" "uuid", "p_metadata" "jsonb", "p_severity" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_sensitive_data_access"("p_user_id" "uuid", "p_target_user_id" "uuid", "p_data_type" "text", "p_access_method" "text" DEFAULT 'direct'::"text") RETURNS "void"
