      'data_type', p_data_type, 'access_method', p_access_method,
      'ip_address', current_setting('request.headers', true)::json->>'x-forwarded-for',
      'user_agent', current_setting('request.headers', true)::json->>'user-agent', 'timestamp', NOW()),
    'high');
END;
$$;


