CREATE OR REPLACE FUNCTION "public"."log_unified_tag_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor TEXT := COALESCE(current_setting('app.actor', true), 'system:trigger');
BEGIN
  IF TG_OP = 'UPDATE' THEN
    IF OLD.human_reviewed = TRUE AND v_actor LIKE 'system:%' THEN
      RAISE EXCEPTION 'human_reviewed tag % cannot be modified by %', OLD.id, v_actor;
    END IF;
    INSERT INTO tag_change_log(tag_id, action_type, before_data, after_data, actor)
      VALUES (OLD.id, 'update', to_jsonb(OLD), to_jsonb(NEW), v_actor);
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    INSERT INTO tag_change_log(tag_id, action_type, before_data, actor)
      VALUES (OLD.id, 'delete', to_jsonb(OLD), v_actor);
    RETURN OLD;
  ELSIF TG_OP = 'INSERT' THEN
    INSERT INTO tag_change_log(tag_id, action_type, after_data, actor)
      VALUES (NEW.id, 'create', to_jsonb(NEW), v_actor);
    RETURN NEW;
  END IF;
  RETURN NULL;
END $$;


ALTER FUNCTION "public"."log_unified_tag_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_unified_tag_slug_redirect"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'UPDATE' AND NEW.slug IS DISTINCT FROM OLD.slug
     AND OLD.slug IS NOT NULL AND NEW.slug IS NOT NULL THEN
    INSERT INTO public.tag_slug_redirects (old_slug, new_slug, tag_id)
    VALUES (OLD.slug, NEW.slug, NEW.id)
    ON CONFLICT (old_slug) DO UPDATE
      SET new_slug = EXCLUDED.new_slug, tag_id = EXCLUDED.tag_id;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."log_unified_tag_slug_redirect"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_venue_field_conflict"("p_venue_id" "uuid", "p_staging_id" "uuid", "p_field_name" "text", "p_existing_val" "text", "p_existing_src" "text", "p_existing_age_days" numeric, "p_incoming_val" "text", "p_incoming_src" "text") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_existing JSONB := to_jsonb(p_existing_val);
  v_incoming JSONB := to_jsonb(p_incoming_val);
  v_variants JSONB;
  v_resolved JSONB;
BEGIN
  -- Skip when nothing to compare: either side null/empty, or values match
  IF p_incoming_val IS NULL OR length(btrim(p_incoming_val)) = 0 THEN RETURN; END IF;
  IF p_existing_val IS NULL OR length(btrim(p_existing_val)) = 0 THEN RETURN; END IF;
  IF p_existing_val = p_incoming_val THEN RETURN; END IF;

  v_variants := jsonb_build_array(
    jsonb_build_object('source', p_existing_src, 'value', v_existing, 'recency_days', p_existing_age_days),
    jsonb_build_object('source', p_incoming_src, 'value', v_incoming, 'recency_days', 0)
  );
  v_resolved := public.resolve_field_conflict(v_variants, 'venue');

  INSERT INTO public.venue_field_conflicts (
    venue_id, staging_id, field_name,
    existing_value, resolved_value, resolved_source,
    variants, would_overwrite, shadow_mode, resolved_at
  ) VALUES (
    p_venue_id, p_staging_id, p_field_name,
    v_existing,
    v_resolved->'resolved_value',
    v_resolved->>'resolved_source',
    v_variants,
    -- Would overwrite if resolver picks something other than the existing value
    coalesce((v_resolved->>'resolved_source') <> p_existing_src, false),
    TRUE,
    now()
  );
END;
$$;


ALTER FUNCTION "public"."log_venue_field_conflict"("p_venue_id" "uuid", "p_staging_id" "uuid", "p_field_name" "text", "p_existing_val" "text", "p_existing_src" "text", "p_existing_age_days" numeric, "p_incoming_val" "text", "p_incoming_src" "text") OWNER TO "postgres";


