CREATE OR REPLACE FUNCTION "public"."mark_story_needs_followup"("p_story_id" "uuid", "p_reason" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  IF coalesce(trim(p_reason), '') = '' THEN RAISE EXCEPTION 'reason_required'; END IF;
  UPDATE feedback_stories
     SET needs_followup_reason = p_reason,
         approved_for_claude_at = NULL, approved_by = NULL
   WHERE id = p_story_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'story_not_found' USING ERRCODE = 'P0002'; END IF;
  PERFORM _fb_log_event(p_story_id, 'needs_followup', jsonb_build_object('reason', p_reason));
  RETURN p_story_id;
END;
$$;


