CREATE OR REPLACE FUNCTION "public"."match_content_embeddings"("query_embedding" "extensions"."vector", "similarity_threshold" double precision DEFAULT 0.1, "match_count" integer DEFAULT 5) RETURNS TABLE("content_id" "uuid", "content_type" "text", "content_text" "text", "metadata" "jsonb", "similarity" double precision)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ce.content_id,
    ce.content_type,
    ce.content_text,
    ce.metadata,
    (1 - (ce.embedding <=> query_embedding))::float AS similarity
  FROM public.content_embeddings ce
  WHERE (1 - (ce.embedding <=> query_embedding))::float > similarity_threshold
  ORDER BY ce.embedding <=> query_embedding
  LIMIT match_count;
END;
$$;


ALTER FUNCTION "public"."match_content_embeddings"("query_embedding" "extensions"."vector", "similarity_threshold" double precision, "match_count" integer) OWNER TO "postgres";


