CREATE OR REPLACE FUNCTION "public"."merge_entities"("p_entity_type" "text", "p_keep_id" "uuid", "p_remove_id" "uuid", "p_merged_data" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    SET "statement_timeout" TO '30s'
    AS $_$
DECLARE
  v_table_name text;
  v_name_field text;
  v_keep_name text;
  v_remove_name text;
  v_fk_updates int := 0;
  v_tmp int;
  v_key text;
  v_val jsonb;
BEGIN
  IF NOT has_role_jwt('admin'::app_role) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = '42501';
  END IF;
  CASE p_entity_type
    WHEN 'venues' THEN v_table_name := 'venues'; v_name_field := 'name';
    WHEN 'events' THEN v_table_name := 'events'; v_name_field := 'title';
    WHEN 'personalities' THEN v_table_name := 'personalities'; v_name_field := 'name';
    WHEN 'news_articles' THEN v_table_name := 'news_articles'; v_name_field := 'title';
    WHEN 'cities' THEN v_table_name := 'cities'; v_name_field := 'name';
    ELSE RAISE EXCEPTION 'Unsupported entity type: %', p_entity_type;
  END CASE;

  EXECUTE format('SELECT %I FROM %I WHERE id = $1', v_name_field, v_table_name)
    INTO v_keep_name USING p_keep_id;
  EXECUTE format('SELECT %I FROM %I WHERE id = $1', v_name_field, v_table_name)
    INTO v_remove_name USING p_remove_id;

  IF v_keep_name IS NULL THEN
    RAISE EXCEPTION 'Keep entity % not found in %', p_keep_id, v_table_name;
  END IF;
  IF v_remove_name IS NULL THEN
    RAISE EXCEPTION 'Remove entity % not found in %', p_remove_id, v_table_name;
  END IF;

  IF p_merged_data IS NOT NULL AND p_merged_data != '{}'::jsonb THEN
    FOR v_key, v_val IN SELECT * FROM jsonb_each(p_merged_data)
    LOOP
      BEGIN
        EXECUTE format('UPDATE %I SET %I = $1 WHERE id = $2', v_table_name, v_key)
        USING v_val #>> '{}', p_keep_id;
      EXCEPTION WHEN OTHERS THEN
        NULL;
      END;
    END LOOP;
  END IF;

  IF p_entity_type = 'venues' THEN
    UPDATE events SET venue_id = p_keep_id WHERE venue_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    UPDATE venue_checkins SET venue_id = p_keep_id WHERE venue_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    UPDATE venue_reviews SET venue_id = p_keep_id WHERE venue_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    UPDATE venue_tag_assignments SET venue_id = p_keep_id
    WHERE venue_id = p_remove_id
    AND NOT EXISTS (SELECT 1 FROM venue_tag_assignments vta2
      WHERE vta2.venue_id = p_keep_id AND vta2.tag_id = venue_tag_assignments.tag_id);
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    DELETE FROM venue_tag_assignments WHERE venue_id = p_remove_id;
    UPDATE festivals SET venue_id = p_keep_id WHERE venue_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    UPDATE marketplace_listings SET venue_id = p_keep_id WHERE venue_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
  ELSIF p_entity_type = 'events' THEN
    UPDATE event_attendees SET event_id = p_keep_id WHERE event_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
  ELSIF p_entity_type = 'personalities' THEN
    NULL;
  ELSIF p_entity_type = 'news_articles' THEN
    UPDATE news_article_cities SET article_id = p_keep_id
    WHERE article_id = p_remove_id
    AND NOT EXISTS (SELECT 1 FROM news_article_cities nac2
      WHERE nac2.article_id = p_keep_id AND nac2.city_id = news_article_cities.city_id);
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    DELETE FROM news_article_cities WHERE article_id = p_remove_id;
    UPDATE news_article_countries SET article_id = p_keep_id
    WHERE article_id = p_remove_id
    AND NOT EXISTS (SELECT 1 FROM news_article_countries naco2
      WHERE naco2.article_id = p_keep_id AND naco2.country_id = news_article_countries.country_id);
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    DELETE FROM news_article_countries WHERE article_id = p_remove_id;
  ELSIF p_entity_type = 'cities' THEN
    UPDATE city_aliases SET city_id = p_keep_id WHERE city_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    UPDATE events SET city_id = p_keep_id WHERE city_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    UPDATE festivals SET city_id = p_keep_id WHERE city_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    UPDATE hotels SET city_id = p_keep_id WHERE city_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    UPDATE news_article_cities SET city_id = p_keep_id
    WHERE city_id = p_remove_id
    AND NOT EXISTS (SELECT 1 FROM news_article_cities nac2
      WHERE nac2.city_id = p_keep_id AND nac2.article_id = news_article_cities.article_id);
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    DELETE FROM news_article_cities WHERE city_id = p_remove_id;
    UPDATE personalities SET city_id = p_keep_id WHERE city_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    UPDATE queer_villages SET city_id = p_keep_id WHERE city_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
    UPDATE venues SET city_id = p_keep_id WHERE city_id = p_remove_id;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_fk_updates := v_fk_updates + v_tmp;
  END IF;

  EXECUTE format('DELETE FROM %I WHERE id = $1', v_table_name) USING p_remove_id;

  INSERT INTO import_audit_log (import_job_id, user_id, action, details)
  VALUES (NULL, COALESCE(auth.uid(), '00000000-0000-0000-0000-000000000000'::uuid),
    'entity_merged',
    jsonb_build_object('entity_type', p_entity_type, 'keep_id', p_keep_id,
      'keep_name', v_keep_name, 'remove_id', p_remove_id, 'remove_name', v_remove_name,
      'fk_updates', v_fk_updates, 'merged_fields', COALESCE(p_merged_data, '{}'::jsonb)));

  UPDATE scraper_dedupe_decisions SET decision = 'merged'
  WHERE ((entity_a_id = p_keep_id AND entity_b_id = p_remove_id) OR
         (entity_a_id = p_remove_id AND entity_b_id = p_keep_id)) AND decision = 'pending';

  RETURN jsonb_build_object('success', true, 'entity_type', p_entity_type,
    'keep_id', p_keep_id, 'keep_name', v_keep_name,
    'remove_id', p_remove_id, 'remove_name', v_remove_name, 'fk_updates', v_fk_updates);
END;
$_$;


ALTER FUNCTION "public"."merge_entities"("p_entity_type" "text", "p_keep_id" "uuid", "p_remove_id" "uuid", "p_merged_data" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."merge_pipeline_node_states"("p_run_id" "uuid", "p_patch" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE pipeline_runs
  SET node_states = node_states || p_patch
  WHERE id = p_run_id;
END;
$$;


ALTER FUNCTION "public"."merge_pipeline_node_states"("p_run_id" "uuid", "p_patch" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."merge_tag"("source_tag_id" "uuid", "canonical_tag_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  source_name TEXT;
  source_slug TEXT;
  canonical_name TEXT;
BEGIN
  SELECT name, slug INTO source_name, source_slug
  FROM unified_tags WHERE id = source_tag_id AND status = 'active';
  
  IF source_name IS NULL THEN
    RAISE EXCEPTION 'Source tag % not found or not active', source_tag_id;
  END IF;

  SELECT name INTO canonical_name
  FROM unified_tags WHERE id = canonical_tag_id AND status = 'active';

  IF canonical_name IS NULL THEN
    RAISE EXCEPTION 'Canonical tag % not found or not active', canonical_tag_id;
  END IF;

  -- Create alias
  INSERT INTO tag_aliases (canonical_tag_id, alias_name, alias_slug, alias_type)
  VALUES (canonical_tag_id, source_name, source_slug, 'synonym')
  ON CONFLICT (alias_slug) DO NOTHING;

  -- Move unified_tag_assignments (skip if would create duplicate)
  UPDATE unified_tag_assignments
  SET tag_id = canonical_tag_id
  WHERE tag_id = source_tag_id
    AND NOT EXISTS (
      SELECT 1 FROM unified_tag_assignments uta2
      WHERE uta2.tag_id = canonical_tag_id
        AND uta2.entity_id = unified_tag_assignments.entity_id
        AND uta2.entity_type = unified_tag_assignments.entity_type
    );
  DELETE FROM unified_tag_assignments WHERE tag_id = source_tag_id;

  -- Merge category assignments: add source's categories to canonical (non-primary)
  INSERT INTO tag_category_assignments (tag_id, category_id, is_primary)
  SELECT canonical_tag_id, tca.category_id, false
  FROM tag_category_assignments tca
  WHERE tca.tag_id = source_tag_id
  ON CONFLICT (tag_id, category_id) DO NOTHING;
  DELETE FROM tag_category_assignments WHERE tag_id = source_tag_id;

  -- Delete tag_relationships involving source
  DELETE FROM tag_relationships WHERE tag1_id = source_tag_id OR tag2_id = source_tag_id;

  -- Delete tag_favorites involving source
  DELETE FROM tag_favorites WHERE tag_id = source_tag_id;

  -- Update denormalized tags text arrays: replace source name with canonical name
  -- Only update tables that actually contain tag data
  UPDATE venues SET tags = array_replace(tags, source_name, canonical_name)
  WHERE tags @> ARRAY[source_name];

  UPDATE news_articles SET tags = array_replace(tags, source_name, canonical_name)
  WHERE tags @> ARRAY[source_name];

  UPDATE personalities SET tags = array_replace(tags, source_name, canonical_name)
  WHERE tags @> ARRAY[source_name];

  UPDATE community_groups SET tags = array_replace(tags, source_name, canonical_name)
  WHERE tags @> ARRAY[source_name];

  UPDATE community_posts SET tags = array_replace(tags, source_name, canonical_name)
  WHERE tags @> ARRAY[source_name];

  UPDATE festivals SET tags = array_replace(tags, source_name, canonical_name)
  WHERE tags @> ARRAY[source_name];

  UPDATE hotels SET tags = array_replace(tags, source_name, canonical_name)
  WHERE tags @> ARRAY[source_name];

  -- Clean up tag_suggestions referencing the source tag
  DELETE FROM tag_suggestions WHERE tag_id = source_tag_id;

  -- Mark source as merged
  UPDATE unified_tags SET
    status = 'merged',
    merged_into_id = canonical_tag_id,
    deprecated_at = now(),
    deprecation_reason = 'Merged into ' || canonical_name
  WHERE id = source_tag_id;
END;
$$;


ALTER FUNCTION "public"."merge_tag"("source_tag_id" "uuid", "canonical_tag_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."merge_unified_tag"("p_canonical_id" "uuid", "p_duplicate_id" "uuid", "p_actor" "text" DEFAULT 'system'::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_canon_slug text; v_dup_slug text;
BEGIN
  IF NOT has_role_jwt('admin'::app_role) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE = '42501';
  END IF;
  IF p_canonical_id = p_duplicate_id THEN
    RAISE EXCEPTION 'merge_unified_tag: canonical and duplicate are the same';
  END IF;
  SELECT slug INTO v_canon_slug FROM unified_tags WHERE id = p_canonical_id;
  SELECT slug INTO v_dup_slug   FROM unified_tags WHERE id = p_duplicate_id;
  IF v_canon_slug IS NULL OR v_dup_slug IS NULL THEN
    RAISE EXCEPTION 'merge_unified_tag: tag(s) not found';
  END IF;
  UPDATE venues SET tags = array_replace(tags, v_dup_slug, v_canon_slug), updated_at = now()
   WHERE v_dup_slug = ANY(tags);
  UPDATE news_articles SET tags = array_replace(tags, v_dup_slug, v_canon_slug), updated_at = now()
   WHERE v_dup_slug = ANY(tags);
  UPDATE personalities SET tags = array_replace(tags, v_dup_slug, v_canon_slug), updated_at = now()
   WHERE v_dup_slug = ANY(tags);
  UPDATE venues SET tags = (SELECT array_agg(DISTINCT t) FROM unnest(tags) t WHERE t IS NOT NULL)
   WHERE v_canon_slug = ANY(tags);
  UPDATE news_articles SET tags = (SELECT array_agg(DISTINCT t) FROM unnest(tags) t WHERE t IS NOT NULL)
   WHERE v_canon_slug = ANY(tags);
  UPDATE personalities SET tags = (SELECT array_agg(DISTINCT t) FROM unnest(tags) t WHERE t IS NOT NULL)
   WHERE v_canon_slug = ANY(tags);
  UPDATE unified_tags
     SET status = 'merged', merged_into_id = p_canonical_id,
         deprecated_at = now(),
         deprecation_reason = format('merged into %s by %s', v_canon_slug, p_actor),
         updated_at = now()
   WHERE id = p_duplicate_id;
  PERFORM recount_unified_tag_usage();
END;
$$;


ALTER FUNCTION "public"."merge_unified_tag"("p_canonical_id" "uuid", "p_duplicate_id" "uuid", "p_actor" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."news_commit_staging_batch"("p_job_id" "uuid", "p_pipeline_run_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 500) RETURNS TABLE("inserted" integer, "updated" integer, "skipped" integer, "errors" integer, "details" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_inserted INT := 0; v_updated INT := 0; v_skipped INT := 0; v_errors INT := 0;
  v_row RECORD; v_norm JSONB; v_enr JSONB; v_meta JSONB; v_dates JSONB; v_urls JSONB; v_images JSONB;
  v_fp TEXT; v_existing_id UUID;
  v_published TIMESTAMPTZ; v_source_id UUID; v_title TEXT; v_url TEXT;
  v_content TEXT; v_image TEXT; v_image_attribution TEXT; v_image_hash TEXT; v_excerpt TEXT;
  v_target_id UUID; v_action TEXT; v_details JSONB := '[]'::JSONB;
  v_quality_status TEXT; v_relevance NUMERIC; v_quality_after NUMERIC;
  v_quality_before NUMERIC; v_sentiment TEXT; v_blocked_reasons TEXT[];
  v_pipeline_ver TEXT;
  v_country_ids UUID[]; v_city_ids UUID[];
  v_review_items JSONB;
BEGIN
  FOR v_row IN
    SELECT id, normalized_data, enriched_data, raw_data, source_name
      FROM public.ingestion_staging
     WHERE job_id = p_job_id AND target_table = 'news_articles' AND disposition = 'pending'
       AND coalesce(dedup_status, 'pending') IN ('pending','unique','merge_candidate','duplicate')
       AND coalesce(ai_validation_status,'pending') IN ('pending','approved','needs_review')
     ORDER BY created_at LIMIT p_limit
  LOOP
    BEGIN
      v_norm := coalesce(v_row.normalized_data, v_row.raw_data, '{}'::JSONB);
      v_enr  := coalesce(v_row.enriched_data, '{}'::JSONB);
      v_meta := coalesce(v_norm->'metadata', '{}'::JSONB);
      v_dates := coalesce(v_norm->'dates', '{}'::JSONB);
      v_urls := coalesce(v_norm->'urls', '[]'::JSONB);
      v_images := coalesce(v_norm->'images', '[]'::JSONB);
      v_title := nullif(trim(coalesce(v_norm->>'title', v_norm->>'name', '')), '');
      v_url := nullif(trim(coalesce(v_norm->>'url',
        CASE WHEN jsonb_array_length(v_urls) > 0 THEN v_urls->>0 ELSE NULL END,
        v_meta->>'url')), '');
      v_content := coalesce(v_norm->>'content', v_norm->>'description', '');
      v_image := coalesce(nullif(v_enr->>'image_url', ''), v_norm->>'image_url',
        CASE WHEN jsonb_array_length(v_images) > 0 THEN v_images->>0 ELSE NULL END,
        v_meta->>'image_url');
      v_image_attribution := nullif(v_enr->>'image_attribution', '');
      v_image_hash := nullif(v_enr->>'image_hash', '');
      v_excerpt := coalesce(v_norm->>'excerpt', v_meta->>'excerpt');
      v_published := coalesce(
        nullif(v_norm->>'published_at','')::TIMESTAMPTZ,
        nullif(v_dates->>'start','')::TIMESTAMPTZ,
        nullif(v_meta->>'published_at','')::TIMESTAMPTZ, now());
      v_source_id := coalesce(nullif(v_norm->>'source_id','')::UUID, nullif(v_meta->>'source_id','')::UUID);
      v_quality_status := nullif(v_enr->>'quality_status', '');
      v_relevance := nullif(v_enr->>'relevance_score', '')::NUMERIC;
      v_quality_after := nullif(v_enr->>'quality_score_after', '')::NUMERIC;
      v_quality_before := nullif(v_enr->>'quality_score_before', '')::NUMERIC;
      v_sentiment := nullif(v_enr->>'sentiment', '');
      v_pipeline_ver := nullif(v_enr->>'quality_pipeline_version', '');
      v_blocked_reasons := CASE WHEN jsonb_typeof(v_enr->'auto_publish_blocked_reasons') = 'array'
        THEN ARRAY(SELECT jsonb_array_elements_text(v_enr->'auto_publish_blocked_reasons')) ELSE NULL END;
      v_country_ids := coalesce(
        CASE WHEN jsonb_typeof(v_enr->'country_ids') = 'array'
          THEN ARRAY(SELECT (jsonb_array_elements_text(v_enr->'country_ids'))::UUID) END,
        CASE WHEN jsonb_typeof(v_norm->'country_ids') = 'array'
          THEN ARRAY(SELECT (jsonb_array_elements_text(v_norm->'country_ids'))::UUID) END,
        '{}'::UUID[]);
      v_city_ids := coalesce(
        CASE WHEN jsonb_typeof(v_enr->'city_ids') = 'array'
          THEN ARRAY(SELECT (jsonb_array_elements_text(v_enr->'city_ids'))::UUID) END,
        CASE WHEN jsonb_typeof(v_norm->'city_ids') = 'array'
          THEN ARRAY(SELECT (jsonb_array_elements_text(v_norm->'city_ids'))::UUID) END,
        '{}'::UUID[]);
      v_review_items := v_enr->'quality_resolved_links'->'review';

      IF v_title IS NULL OR v_source_id IS NULL THEN
        UPDATE public.ingestion_staging SET disposition = 'rejected',
          error_message = 'missing title or source_id', processed_at = now() WHERE id = v_row.id;
        v_skipped := v_skipped + 1; CONTINUE;
      END IF;

      v_fp := public.news_compute_fingerprint(v_title, v_published, v_source_id, v_url);
      v_existing_id := NULL;
      IF v_fp IS NOT NULL THEN SELECT id INTO v_existing_id FROM public.news_articles WHERE fingerprint = v_fp LIMIT 1; END IF;
      IF v_existing_id IS NULL AND v_url IS NOT NULL THEN
        SELECT id INTO v_existing_id FROM public.news_articles WHERE url = v_url LIMIT 1; END IF;

      IF v_existing_id IS NULL THEN
        INSERT INTO public.news_articles (
          source_id, title, content, excerpt, url, image_url, image_attribution, image_hash, author,
          published_at, category, tags, country_ids, city_ids,
          fingerprint, content_hash, ingestion_run_id, ingestion_staging_id,
          slug, publisher_name, first_seen_at, last_seen_at, seen_count,
          quality_status, relevance_score, quality_score, quality_score_before,
          sentiment, quality_decision, quality_pipeline_version,
          last_quality_run_at, auto_publish_blocked_reasons
        ) VALUES (
          v_source_id, v_title, v_content,
          left(coalesce(v_excerpt, v_content), 500),
          coalesce(v_url, 'staging://' || v_row.id::TEXT), v_image, v_image_attribution, v_image_hash,
          coalesce(v_norm->>'author', v_meta->>'author'), v_published,
          coalesce(nullif(v_norm->>'category',''), 'general'),
          coalesce(ARRAY(SELECT jsonb_array_elements_text(v_norm->'tags')), '{}'::TEXT[]),
          v_country_ids, v_city_ids, v_fp,
          encode(extensions.digest(convert_to(coalesce(v_content, v_title, ''), 'UTF8'), 'sha256'), 'hex'),
          p_pipeline_run_id, v_row.id,
          coalesce(nullif(v_norm->>'slug',''),
            trim(both '-' from substr(regexp_replace(lower(v_title), '[^a-z0-9]+', '-', 'g'), 1, 240))
              || '-' || substr(coalesce(v_fp, gen_random_uuid()::TEXT), 1, 8)),
          coalesce(nullif(v_norm->>'publisher_name',''), v_row.source_name),
          now(), now(), 1,
          v_quality_status, v_relevance, v_quality_after, v_quality_before,
          v_sentiment, v_enr->'quality_decision', v_pipeline_ver,
          CASE WHEN v_quality_status IS NOT NULL THEN now() ELSE NULL END,
          v_blocked_reasons
        ) RETURNING id INTO v_target_id;
        v_inserted := v_inserted + 1; v_action := 'inserted';
      ELSE
        UPDATE public.news_articles SET
          title = coalesce(v_title, title),
          content = coalesce(nullif(v_content,''), content),
          excerpt = coalesce(nullif(v_excerpt,''), excerpt),
          image_url = coalesce(v_image, image_url),
          image_attribution = coalesce(v_image_attribution, image_attribution),
          image_hash = coalesce(v_image_hash, image_hash),
          author = coalesce(v_norm->>'author', v_meta->>'author', author),
          published_at = LEAST(published_at, v_published),
          last_seen_at = now(), seen_count = coalesce(seen_count,1) + 1,
          fingerprint = coalesce(fingerprint, v_fp),
          content_hash = coalesce(content_hash, encode(extensions.digest(convert_to(coalesce(v_content, v_title, ''), 'UTF8'), 'sha256'), 'hex')),
          country_ids = ARRAY(SELECT DISTINCT unnest(coalesce(country_ids,'{}'::UUID[]) || v_country_ids)),
          city_ids    = ARRAY(SELECT DISTINCT unnest(coalesce(city_ids,'{}'::UUID[])    || v_city_ids)),
          quality_status = coalesce(v_quality_status, quality_status),
          relevance_score = coalesce(v_relevance, relevance_score),
          quality_score = coalesce(v_quality_after, quality_score),
          quality_score_before = coalesce(v_quality_before, quality_score_before),
          sentiment = coalesce(v_sentiment, sentiment),
          quality_decision = coalesce(v_enr->'quality_decision', quality_decision),
          quality_pipeline_version = coalesce(v_pipeline_ver, quality_pipeline_version),
          last_quality_run_at = CASE WHEN v_quality_status IS NOT NULL THEN now() ELSE last_quality_run_at END,
          auto_publish_blocked_reasons = coalesce(v_blocked_reasons, auto_publish_blocked_reasons),
          updated_at = now()
        WHERE id = v_existing_id RETURNING id INTO v_target_id;
        v_updated := v_updated + 1; v_action := 'updated';
      END IF;

      IF array_length(v_country_ids, 1) > 0 THEN
        INSERT INTO public.news_article_countries (article_id, country_id)
        SELECT v_target_id, cid FROM unnest(v_country_ids) AS cid
        ON CONFLICT (article_id, country_id) DO NOTHING;
      END IF;
      IF array_length(v_city_ids, 1) > 0 THEN
        INSERT INTO public.news_article_cities (article_id, city_id)
        SELECT v_target_id, cid FROM unnest(v_city_ids) AS cid
        ON CONFLICT (article_id, city_id) DO NOTHING;
      END IF;

      IF jsonb_typeof(v_review_items) = 'array' AND jsonb_array_length(v_review_items) > 0 THEN
        INSERT INTO public.entity_link_review
          (article_id, entity_type, candidate_name, score, context_snippet)
        SELECT v_target_id, COALESCE(item->>'type', 'country'),
               item->>'name', (item->>'score')::NUMERIC, item->>'reason'
          FROM jsonb_array_elements(v_review_items) AS item
         WHERE item->>'name' IS NOT NULL;
      END IF;

      UPDATE public.ingestion_staging
        SET disposition = v_action, target_record_id = v_target_id, processed_at = now() WHERE id = v_row.id;

      v_details := v_details || jsonb_build_object(
        'staging_id', v_row.id, 'article_id', v_target_id, 'action', v_action,
        'fingerprint', v_fp, 'quality_status', v_quality_status,
        'image_hash_set', v_image_hash IS NOT NULL,
        'countries_linked', array_length(v_country_ids, 1),
        'cities_linked', array_length(v_city_ids, 1),
        'entity_review_items', CASE WHEN jsonb_typeof(v_review_items) = 'array' THEN jsonb_array_length(v_review_items) ELSE 0 END);
    EXCEPTION WHEN OTHERS THEN
      v_errors := v_errors + 1;
      UPDATE public.ingestion_staging SET disposition = 'error', error_message = SQLERRM, processed_at = now() WHERE id = v_row.id;
    END;
  END LOOP;
  RETURN QUERY SELECT v_inserted, v_updated, v_skipped, v_errors, v_details;
END; $$;


ALTER FUNCTION "public"."news_commit_staging_batch"("p_job_id" "uuid", "p_pipeline_run_id" "uuid", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."news_compute_fingerprint"("p_title" "text", "p_published_at" timestamp with time zone, "p_source_id" "uuid", "p_url" "text" DEFAULT NULL::"text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE v_norm_title TEXT; v_day TEXT; v_basis TEXT;
BEGIN
  v_norm_title := lower(coalesce(p_title, ''));
  v_norm_title := regexp_replace(v_norm_title, '[^a-z0-9]+', ' ', 'g');
  v_norm_title := regexp_replace(v_norm_title, '\s+', ' ', 'g');
  v_norm_title := trim(v_norm_title);
  v_norm_title := left(v_norm_title, 200);
  v_day := to_char(coalesce(p_published_at, now()), 'YYYY-MM-DD');
  IF length(v_norm_title) >= 8 AND p_source_id IS NOT NULL THEN
    v_basis := v_norm_title || '|' || v_day || '|' || p_source_id::TEXT;
  ELSIF p_url IS NOT NULL THEN
    v_basis := 'url|' || lower(trim(p_url));
  ELSE
    RETURN NULL;
  END IF;
  RETURN encode(extensions.digest(v_basis::bytea, 'sha256'), 'hex');
END;
$$;


ALTER FUNCTION "public"."news_compute_fingerprint"("p_title" "text", "p_published_at" timestamp with time zone, "p_source_id" "uuid", "p_url" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."news_source_record_outcome"("p_source_id" "uuid", "p_success" boolean, "p_articles_count" integer DEFAULT 0, "p_error" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_failures INT; v_backoff_minutes INT; v_pause BOOLEAN := false; v_pause_reason TEXT := NULL;
BEGIN
  IF p_success THEN
    UPDATE public.news_sources
       SET consecutive_failures = 0, backoff_until = NULL,
           last_successful_fetch = now(), last_fetched_at = now(),
           last_error = NULL, status = 'active',
           articles_fetched = coalesce(articles_fetched,0) + p_articles_count,
           avg_articles_per_fetch = (coalesce(avg_articles_per_fetch,0) * 0.8) + (p_articles_count * 0.2),
           reliability_score = LEAST(1.0, coalesce(reliability_score,1.0) + 0.05),
           updated_at = now()
     WHERE id = p_source_id;
  ELSE
    SELECT consecutive_failures INTO v_failures FROM public.news_sources WHERE id = p_source_id;
    v_failures := coalesce(v_failures, 0) + 1;
    v_backoff_minutes := LEAST(1440, 5 * power(2, GREATEST(0, v_failures - 1))::INT);
    IF v_failures >= 8 THEN
      v_pause := true;
      v_pause_reason := format('auto-paused after %s consecutive failures: %s', v_failures, left(coalesce(p_error,''), 200));
    END IF;
    UPDATE public.news_sources
       SET consecutive_failures = v_failures,
           backoff_until = now() + (v_backoff_minutes || ' minutes')::INTERVAL,
           last_fetched_at = now(),
           last_error = left(coalesce(p_error,'unknown error'), 1000),
           status = CASE WHEN v_pause THEN 'paused' ELSE 'error' END,
           auto_paused = CASE WHEN v_pause THEN true ELSE auto_paused END,
           auto_paused_reason = CASE WHEN v_pause THEN v_pause_reason ELSE auto_paused_reason END,
           reliability_score = GREATEST(0.0, coalesce(reliability_score,1.0) - 0.1),
           updated_at = now()
     WHERE id = p_source_id;
  END IF;
END;
$$;


ALTER FUNCTION "public"."news_source_record_outcome"("p_source_id" "uuid", "p_success" boolean, "p_articles_count" integer, "p_error" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."news_sources_eligible"("p_limit" integer DEFAULT 50) RETURNS TABLE("id" "uuid", "name" "text", "url" "text", "source_type" "text", "category" "text", "fetch_frequency" integer, "last_fetched_at" timestamp with time zone, "keywords" "text"[])
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  SELECT s.id, s.name, s.url, s.source_type, s.category,
         s.fetch_frequency, s.last_fetched_at, s.keywords
    FROM public.news_sources s
   WHERE s.is_active = true
     AND s.auto_paused = false
     AND (s.backoff_until IS NULL OR s.backoff_until <= now())
     AND (s.last_fetched_at IS NULL
          OR s.last_fetched_at < now() - (coalesce(s.fetch_frequency,60) || ' minutes')::INTERVAL)
   ORDER BY s.reliability_score DESC NULLS LAST, s.last_fetched_at ASC NULLS FIRST
   LIMIT p_limit;
$$;


