CREATE OR REPLACE FUNCTION "public"."normalize_address"("a" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE PARALLEL SAFE
    SET "search_path" TO 'public', 'extensions'
    AS $$
  WITH x AS (
    SELECT lower(extensions.unaccent(coalesce(a,''))) AS s
  ),
  -- expand the most common ambiguous abbreviations BEFORE collapsing punctuation
  e AS (
    SELECT regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(
      regexp_replace(s, '\bavenue\b',     'ave', 'g'),
                       '\bstreet\b',      'st',  'g'),
                       '\bsaint\b',       'st',  'g'),
                       '\bboulevard\b',   'blvd','g'),
                       '\bdrive\b',       'dr',  'g'),
                       '\broad\b',        'rd',  'g'),
                       '\blane\b',        'ln',  'g'),
                       '\bcourt\b',       'ct',  'g'),
                       '\bplace\b',       'pl',  'g'),
                       '\bsquare\b',      'sq',  'g'),
                       '\bterrace\b',     'ter', 'g'),
                       '\bhighway\b',     'hwy', 'g'),
                       '\bparkway\b',     'pkwy','g'),
                       '\bnorth\b',       'n',   'g'),
                       '\bsouth\b',       's',   'g'),
                       '\beast\b',        'e',   'g') AS s
    FROM x
  ),
  e2 AS (
    SELECT regexp_replace(s, '\bwest\b', 'w', 'g') AS s FROM e
  )
  SELECT btrim(regexp_replace(s, '[^a-z0-9]+', ' ', 'g')) FROM e2;
$$;


ALTER FUNCTION "public"."normalize_address"("a" "text") OWNER TO "postgres";


