CREATE OR REPLACE FUNCTION "public"."notify_alert_webhooks"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_integration alert_integrations;
  v_severity_order int;
  v_min_order int;
BEGIN
  -- Severity order: info=1, warn=2, error=3
  v_severity_order := CASE NEW.severity
    WHEN 'info' THEN 1
    WHEN 'warn' THEN 2
    WHEN 'error' THEN 3
    ELSE 0
  END;

  FOR v_integration IN
    SELECT * FROM alert_integrations WHERE enabled = true
  LOOP
    v_min_order := CASE v_integration.min_severity
      WHEN 'info' THEN 1
      WHEN 'warn' THEN 2
      WHEN 'error' THEN 3
      ELSE 0
    END;
    IF v_severity_order < v_min_order THEN CONTINUE; END IF;

    -- Fire-and-forget HTTP POST via pg_net
    BEGIN
      PERFORM net.http_post(
        url := v_integration.webhook_url,
        headers := '{"Content-Type": "application/json"}'::jsonb,
        body := jsonb_build_object(
          'text',
          format('[%s] %s (%s): %s',
            upper(NEW.severity),
            NEW.alert_kind,
            COALESCE(NEW.source_slug, '-'),
            NEW.detail::text
          )
        )
      );
      UPDATE alert_integrations
      SET last_triggered_at = now(), total_sent = total_sent + 1, last_error = NULL
      WHERE id = v_integration.id;
    EXCEPTION WHEN OTHERS THEN
      UPDATE alert_integrations
      SET last_error = SQLERRM
      WHERE id = v_integration.id;
    END;
  END LOOP;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_alert_webhooks"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."notify_enrichment_pipeline"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pgmq'
    AS $$
DECLARE
  enrichment_managed_cols TEXT[] := ARRAY[
    'quality_score', 'needs_attention', 'duplicate_of_id', 'enrichment_status',
    'city_id', 'country_id', 'geo_linked_at', 'updated_at'
  ];
  changed JSONB := '[]'::JSONB;
  col TEXT;
BEGIN
  -- For UPDATEs: compute which columns changed, excluding enrichment-managed ones
  IF TG_OP = 'UPDATE' THEN
    -- Build array of changed column names using per-column comparison
    SELECT jsonb_agg(c.column_name)
    INTO changed
    FROM information_schema.columns c
    WHERE c.table_schema = TG_TABLE_SCHEMA
      AND c.table_name = TG_TABLE_NAME
      AND c.column_name != ALL(enrichment_managed_cols)
      AND to_jsonb(NEW) ->> c.column_name IS DISTINCT FROM to_jsonb(OLD) ->> c.column_name;

    -- If only enrichment-managed columns changed, skip to prevent loops
    IF changed IS NULL OR changed = '[]'::JSONB THEN
      RETURN NEW;
    END IF;
  END IF;

  -- Send message to pgmq enrichment queue
  PERFORM pgmq.send('enrichment_queue', jsonb_build_object(
    'entity_type', TG_TABLE_NAME,
    'entity_id', NEW.id,
    'action', TG_OP,
    'changed_columns', CASE WHEN TG_OP = 'UPDATE' THEN changed ELSE NULL END,
    'enqueued_at', now()
  ));

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_enrichment_pipeline"() OWNER TO "postgres";


