CREATE OR REPLACE FUNCTION "public"."optimize_auth_uid_in_policy"("p_schema_name" "text", "p_table_name" "text", "p_policy_name" "text") RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
DECLARE
  v_policy record;
  v_original_def text;
  v_optimized_def text;
BEGIN
  -- Get the policy details
  SELECT 
    p.cmd,
    COALESCE(p.qual::text, '') as using_qual,
    COALESCE(p.with_check::text, '') as check_qual,
    p.roles[1] as role_name
  INTO v_policy
  FROM 
    pg_policies p
  WHERE 
    p.schemaname = p_schema_name
    AND p.tablename = p_table_name
    AND p.policyname = p_policy_name;
    
  IF NOT FOUND THEN
    RETURN format('-- Policy %I not found on table %I.%I', p_policy_name, p_schema_name, p_table_name);
  END IF;
  
  -- Store original definition
  IF v_policy.cmd IN ('SELECT', 'DELETE') THEN
    v_original_def := format('CREATE POLICY %I ON %I.%I FOR %s TO %I USING (%s);',
                            p_policy_name, p_schema_name, p_table_name, 
                            v_policy.cmd, v_policy.role_name, v_policy.using_qual);
  ELSIF v_policy.cmd = 'INSERT' THEN
    v_original_def := format('CREATE POLICY %I ON %I.%I FOR %s TO %I WITH CHECK (%s);',
                            p_policy_name, p_schema_name, p_table_name, 
                            v_policy.cmd, v_policy.role_name, v_policy.check_qual);
  ELSIF v_policy.cmd = 'UPDATE' THEN
    v_original_def := format('CREATE POLICY %I ON %I.%I FOR %s TO %I USING (%s) WITH CHECK (%s);',
                            p_policy_name, p_schema_name, p_table_name, 
                            v_policy.cmd, v_policy.role_name, v_policy.using_qual, v_policy.check_qual);
  ELSIF v_policy.cmd = 'ALL' THEN
    v_original_def := format('CREATE POLICY %I ON %I.%I FOR %s TO %I USING (%s) WITH CHECK (%s);',
                            p_policy_name, p_schema_name, p_table_name, 
                            v_policy.cmd, v_policy.role_name, v_policy.using_qual, v_policy.check_qual);
  END IF;
  
  -- Create optimized definition
  v_optimized_def := v_original_def;
  
  -- Replace auth.uid() with (select auth.uid())
  v_optimized_def := regexp_replace(v_optimized_def, 'auth\.uid\(\)', '(select auth.uid())', 'g');
  
  -- Only return if there was an actual change
  IF v_original_def = v_optimized_def THEN
    RETURN format('-- Policy %I on table %I.%I does not need optimization', 
                 p_policy_name, p_schema_name, p_table_name);
  END IF;
  
  RETURN format('-- Optimizing policy %I on table %I.%I\n\n-- Original policy:\n%s\n\n-- Optimized policy:\nDROP POLICY IF EXISTS %I ON %I.%I;\n%s',
               p_policy_name, p_schema_name, p_table_name,
               v_original_def,
               p_policy_name, p_schema_name, p_table_name,
               v_optimized_def);
END;
$$;


ALTER FUNCTION "public"."optimize_auth_uid_in_policy"("p_schema_name" "text", "p_table_name" "text", "p_policy_name" "text") OWNER TO "postgres";


