CREATE OR REPLACE FUNCTION "public"."personalized_semantic_search"("p_query_vec" "extensions"."vector", "p_bias_vec" "extensions"."vector" DEFAULT NULL::"extensions"."vector", "p_bias_weight" real DEFAULT 0.3, "p_content_types" "text"[] DEFAULT NULL::"text"[], "p_limit" integer DEFAULT 100) RETURNS TABLE("content_type" "text", "content_id" "uuid", "score" real, "metadata" "jsonb")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE v_combined extensions.vector(1024);
BEGIN
  IF p_bias_vec IS NOT NULL THEN
    v_combined := ((1.0 - p_bias_weight) * p_query_vec + p_bias_weight * p_bias_vec);
  ELSE
    v_combined := p_query_vec;
  END IF;
  RETURN QUERY
  SELECT ce.content_type, ce.content_id,
         (1.0 - (ce.embedding <=> v_combined))::real,
         ce.metadata
  FROM content_embeddings ce
  WHERE (p_content_types IS NULL OR ce.content_type = ANY(p_content_types))
    AND ce.embedding IS NOT NULL
  ORDER BY ce.embedding <=> v_combined
  LIMIT p_limit;
END $$;


