CREATE OR REPLACE FUNCTION "public"."pipeline_health_snapshot"() RETURNS TABLE("target_table" "text", "total" bigint, "pending" bigint, "rejected" bigint, "review_pending" bigint, "stuck_normalize" bigint, "stuck_validate" bigint, "stuck_dedup" bigint, "stuck_commit" bigint, "review_stale" bigint)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
  SELECT
    coalesce(s.target_table, 'unknown')::text                                      AS target_table,
    count(*)::bigint                                                               AS total,
    count(*) FILTER (WHERE s.disposition   = 'pending')::bigint                    AS pending,
    count(*) FILTER (WHERE s.disposition   = 'rejected')::bigint                   AS rejected,
    count(*) FILTER (WHERE s.review_status = 'pending_review')::bigint             AS review_pending,
    count(*) FILTER (WHERE p.stuck_reason  = 'stuck_at_normalize')::bigint         AS stuck_normalize,
    count(*) FILTER (WHERE p.stuck_reason  = 'stuck_at_validate')::bigint          AS stuck_validate,
    count(*) FILTER (WHERE p.stuck_reason  = 'stuck_at_dedup')::bigint             AS stuck_dedup,
    count(*) FILTER (WHERE p.stuck_reason  = 'stuck_at_commit')::bigint            AS stuck_commit,
    count(*) FILTER (WHERE p.stuck_reason  = 'review_stale')::bigint               AS review_stale
  FROM public.ingestion_staging s
  LEFT JOIN public.pipeline_stuck_items p ON p.id = s.id
  WHERE s.target_table IS NOT NULL
  GROUP BY 1
  ORDER BY total DESC;
$$;


ALTER FUNCTION "public"."pipeline_health_snapshot"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."pipeline_runs_update_updated_at"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  NEW.updated_at = now();
  IF NEW.status IN ('completed', 'failed', 'cancelled') AND OLD.status NOT IN ('completed', 'failed', 'cancelled') THEN
    NEW.completed_at = now();
    IF NEW.started_at IS NOT NULL THEN
      NEW.duration_ms = EXTRACT(EPOCH FROM (now() - NEW.started_at))::INT * 1000;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."pipeline_runs_update_updated_at"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."position_first_letter"("s" "text") RETURNS integer
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  m text;
BEGIN
  IF s IS NULL OR s = '' THEN RETURN 0; END IF;
  -- regexp_match returns match; use regexp_instr-like via position of pattern
  -- Postgres lacks regexp_instr in older versions; emulate:
  FOR i IN 1..length(s) LOOP
    IF substring(s FROM i FOR 1) ~ '[[:alpha:]]' THEN
      RETURN i;
    END IF;
  END LOOP;
  RETURN 0;
END $$;


ALTER FUNCTION "public"."position_first_letter"("s" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."push_doc_expiry_candidates"() RETURNS TABLE("document_id" "uuid", "user_id" "uuid", "doc_type" "text", "title" "text", "days_out" integer, "expiry_date" "date")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT d.id, d.user_id, d.doc_type, d.title,
         (d.expiry_date - current_date)::int AS days_out,
         d.expiry_date
  FROM public.trip_documents d
  WHERE d.expiry_date IS NOT NULL
    AND (d.expiry_date - current_date) IN (30, 7)
    AND NOT EXISTS (
      SELECT 1 FROM public.push_sent s
      WHERE s.user_id = d.user_id
        AND s.kind = 'doc_expiry'
        AND s.ref_id = d.id
        AND s.day_bucket = current_date
    );
$$;


