CREATE OR REPLACE FUNCTION "public"."record_dedup_decision"("p_entity_type" "text", "p_staging_id" "uuid", "p_pipeline_run_id" "uuid", "p_match_id" "uuid", "p_match_method" "text", "p_confidence" numeric, "p_decision" "text", "p_action" "text", "p_rules" "jsonb", "p_decided_by" "text" DEFAULT 'pipeline-deduplicate'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
