BEGIN
  INSERT INTO scraper_dedupe_decisions(
    entity_type, entity_a_id, entity_b_id, staging_id, pipeline_run_id,
    match_method, confidence, decision, action, rules_fired, decided_by
  ) VALUES (
    p_entity_type, p_staging_id, p_match_id, p_staging_id, p_pipeline_run_id,
    coalesce(p_match_method, 'none'), coalesce(p_confidence, 0)::float8,
    p_decision, coalesce(p_action, 'no_match'),
    coalesce(p_rules, '{}'::jsonb), p_decided_by
  ) RETURNING id INTO v_id;
  RETURN v_id;
