CREATE OR REPLACE FUNCTION "public"."record_fix_proposed"("p_run_id" "uuid", "p_pr_url" "text", "p_commit_sha" "text", "p_files" "text"[], "p_summary" "text", "p_confidence" "text", "p_risks" "text", "p_actor_kind" "text" DEFAULT 'runner'::"text") RETURNS "public"."feedback_routine_runs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_run feedback_routine_runs%ROWTYPE;
BEGIN
  IF NOT (has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role])
          OR auth.role() = 'service_role') THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  IF p_confidence IS NOT NULL AND p_confidence NOT IN ('low','medium','high') THEN
    RAISE EXCEPTION 'invalid_confidence';
  END IF;
  UPDATE feedback_routine_runs
     SET status='fix_proposed',
         pr_url=COALESCE(p_pr_url, pr_url),
         commit_sha=COALESCE(p_commit_sha, commit_sha),
         files_changed=COALESCE(p_files, files_changed),
         fix_summary=COALESCE(p_summary, fix_summary),
         confidence=COALESCE(p_confidence, confidence),
         risks=COALESCE(p_risks, risks),
         finished_at=COALESCE(finished_at, now())
   WHERE id = p_run_id RETURNING * INTO v_run;
  IF NOT FOUND THEN RAISE EXCEPTION 'run_not_found' USING ERRCODE = 'P0002'; END IF;
  PERFORM _fb_log_event(v_run.story_id, 'fix_proposed',
    jsonb_build_object('pr_url', v_run.pr_url, 'commit_sha', v_run.commit_sha,
      'files_changed', v_run.files_changed, 'fix_summary', v_run.fix_summary,
      'confidence', v_run.confidence, 'risks', v_run.risks),
    p_actor_kind, v_run.id);
  RETURN v_run;
END;
$$;


ALTER FUNCTION "public"."record_fix_proposed"("p_run_id" "uuid", "p_pr_url" "text", "p_commit_sha" "text", "p_files" "text"[], "p_summary" "text", "p_confidence" "text", "p_risks" "text", "p_actor_kind" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_redirect_click"("p_redirect_id" "uuid", "p_path" "text", "p_query" "text" DEFAULT NULL::"text", "p_referer" "text" DEFAULT NULL::"text", "p_user_agent" "text" DEFAULT NULL::"text", "p_country" "text" DEFAULT NULL::"text", "p_ip_hash" "text" DEFAULT NULL::"text", "p_status" integer DEFAULT 301) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Increment click count
  UPDATE redirects SET click_count = click_count + 1 WHERE id = p_redirect_id;
  
  -- Insert event
  INSERT INTO redirect_events (redirect_id, path, query, referer, user_agent, country, ip_hash, status)
  VALUES (p_redirect_id, p_path, p_query, p_referer, p_user_agent, p_country, p_ip_hash, p_status);
END;
$$;


