CREATE TABLE IF NOT EXISTS "public"."feedback_retest_runs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "routine_run_id" "uuid" NOT NULL,
    "status" "text" DEFAULT 'queued'::"text" NOT NULL,
    "kind" "text" NOT NULL,
    "runner" "text" NOT NULL,
    "external_ref" "text",
    "result" "jsonb",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "finished_at" timestamp with time zone,
    CONSTRAINT "feedback_retest_runs_kind_check" CHECK (("kind" = ANY (ARRAY['typecheck'::"text", 'lint'::"text", 'unit'::"text", 'e2e'::"text", 'targeted'::"text"]))),
    CONSTRAINT "feedback_retest_runs_runner_check" CHECK (("runner" = ANY (ARRAY['mock'::"text", 'github_actions'::"text", 'webhook'::"text", 'local'::"text"]))),
    CONSTRAINT "feedback_retest_runs_status_check" CHECK (("status" = ANY (ARRAY['queued'::"text", 'running'::"text", 'passed'::"text", 'failed'::"text", 'error'::"text"])))
);


ALTER TABLE "public"."feedback_retest_runs" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_retest_result"("p_retest_id" "uuid", "p_status" "text", "p_result" "jsonb" DEFAULT '{}'::"jsonb", "p_external_ref" "text" DEFAULT NULL::"text", "p_actor_kind" "text" DEFAULT 'runner'::"text") RETURNS "public"."feedback_retest_runs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_retest feedback_retest_runs%ROWTYPE; v_run feedback_routine_runs%ROWTYPE;
BEGIN
  IF NOT (has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role])
          OR auth.role() = 'service_role') THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  IF p_status NOT IN ('queued','running','passed','failed','error') THEN RAISE EXCEPTION 'invalid_status'; END IF;
  UPDATE feedback_retest_runs
     SET status=p_status, result=COALESCE(p_result, result),
         external_ref=COALESCE(p_external_ref, external_ref),
         finished_at=CASE WHEN p_status IN ('passed','failed','error')
                          THEN COALESCE(finished_at, now()) ELSE finished_at END
   WHERE id = p_retest_id RETURNING * INTO v_retest;
  IF NOT FOUND THEN RAISE EXCEPTION 'retest_not_found'; END IF;
  SELECT * INTO v_run FROM feedback_routine_runs WHERE id = v_retest.routine_run_id;
  PERFORM _fb_log_event(v_run.story_id, 'retest_finished',
    jsonb_build_object('status', p_status, 'kind', v_retest.kind, 'result', p_result),
    p_actor_kind, v_run.id, v_retest.id);
  RETURN v_retest;
END;
$$;


ALTER FUNCTION "public"."record_retest_result"("p_retest_id" "uuid", "p_status" "text", "p_result" "jsonb", "p_external_ref" "text", "p_actor_kind" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_routine_progress"("p_run_id" "uuid", "p_status" "text", "p_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_external_ref" "text" DEFAULT NULL::"text", "p_actor_kind" "text" DEFAULT 'runner'::"text") RETURNS "public"."feedback_routine_runs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_run feedback_routine_runs%ROWTYPE;
BEGIN
  IF NOT (has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role])
          OR auth.role() = 'service_role') THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  IF p_status NOT IN ('queued','dispatched','in_progress','fix_proposed','failed','cancelled') THEN
    RAISE EXCEPTION 'invalid_status: %', p_status;
  END IF;
  SELECT * INTO v_run FROM feedback_routine_runs WHERE id = p_run_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'run_not_found' USING ERRCODE = 'P0002'; END IF;
  IF v_run.status IN ('failed','cancelled') AND p_status <> v_run.status THEN
    RAISE EXCEPTION 'terminal_state: %', v_run.status;
  END IF;
  IF v_run.status = 'fix_proposed' AND p_status NOT IN ('fix_proposed','failed','cancelled') THEN
    RAISE EXCEPTION 'illegal_transition: % -> %', v_run.status, p_status;
  END IF;
  UPDATE feedback_routine_runs
     SET status = p_status,
         external_ref = COALESCE(p_external_ref, external_ref),
         finished_at = CASE WHEN p_status IN ('fix_proposed','failed','cancelled')
                            THEN COALESCE(finished_at, now()) ELSE finished_at END,
         error = CASE WHEN p_status = 'failed' THEN COALESCE(p_payload->>'error', error) ELSE error END
   WHERE id = p_run_id RETURNING * INTO v_run;
  PERFORM _fb_log_event(v_run.story_id,
    CASE p_status WHEN 'failed' THEN 'routine_failed'
                  WHEN 'cancelled' THEN 'routine_cancelled'
                  ELSE 'routine_progress' END,
    p_payload || jsonb_build_object('status', p_status, 'external_ref', p_external_ref),
    p_actor_kind, v_run.id);
  RETURN v_run;
END;
$$;


ALTER FUNCTION "public"."record_routine_progress"("p_run_id" "uuid", "p_status" "text", "p_payload" "jsonb", "p_external_ref" "text", "p_actor_kind" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."recount_unified_tag_usage"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  WITH tag_usage AS (
    SELECT slug, count(*)::int AS n FROM (
      SELECT unnest(tags) AS slug FROM venues WHERE tags IS NOT NULL
      UNION ALL SELECT unnest(tags) AS slug FROM news_articles WHERE tags IS NOT NULL
      UNION ALL SELECT unnest(tags) AS slug FROM personalities WHERE tags IS NOT NULL
    ) all_tags WHERE slug IS NOT NULL AND slug <> ''
    GROUP BY slug
  )
  UPDATE unified_tags t SET usage_count = coalesce(tu.n, 0), updated_at = now()
    FROM tag_usage tu WHERE t.slug = tu.slug;

  UPDATE unified_tags SET usage_count = 0
   WHERE slug NOT IN (
     SELECT DISTINCT slug FROM (
       SELECT unnest(tags) AS slug FROM venues
       UNION SELECT unnest(tags) FROM news_articles
       UNION SELECT unnest(tags) FROM personalities
     ) used WHERE slug IS NOT NULL
   ) AND coalesce(usage_count, 0) <> 0;
END;
$$;


ALTER FUNCTION "public"."recount_unified_tag_usage"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."refresh_dashboard_stats"() RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
BEGIN
  -- Only refresh if the materialized view exists
  IF EXISTS (
    SELECT 1 FROM pg_matviews 
    WHERE schemaname = 'public' 
    AND matviewname = 'dashboard_stats'
  ) THEN
    REFRESH MATERIALIZED VIEW public.dashboard_stats;
  END IF;
END;
$$;


