CREATE OR REPLACE FUNCTION "public"."refresh_source_coverage"() RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE public.source_coverage_targets t
  SET actual_count = sub.cnt,
      success_ratio = CASE WHEN t.expected_count IS NULL OR t.expected_count = 0 THEN NULL
                           ELSE LEAST(1.0, sub.cnt::numeric / t.expected_count) END,
      updated_at = now()
  FROM (
    SELECT vs.source_slug, v.city_id, v.accommodation_type, count(*)::int AS cnt
    FROM public.venues v JOIN public.venue_sources vs ON vs.venue_id = v.id
    WHERE v.duplicate_of_id IS NULL
    GROUP BY vs.source_slug, v.city_id, v.accommodation_type
  ) sub
  WHERE t.source_slug = sub.source_slug AND t.city_id = sub.city_id
    AND coalesce(t.accommodation_type,'') = coalesce(sub.accommodation_type,'');
END; $$;


ALTER FUNCTION "public"."refresh_source_coverage"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."refresh_source_reliability"() RETURNS integer
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_rows INT := 0;
BEGIN
  WITH quality AS (
    SELECT source_name AS source_slug, entity_type, n, score_p50, score_p25
    FROM public.pipeline_quality_distribution
  ),
  coverage AS (
    SELECT source_slug, AVG(coalesce(success_ratio, 0))::numeric AS coverage_ratio
    FROM public.coverage_gaps GROUP BY source_slug
  ),
  events AS (
    SELECT
      s.source_name AS source_slug, s.entity_type,
      COUNT(*) FILTER (WHERE e.stage='validate' AND e.new_status='rejected')::numeric
        / NULLIF(COUNT(*) FILTER (WHERE e.stage='validate'), 0) AS rejection_rate,
      COUNT(*) FILTER (WHERE e.stage='source' AND e.new_status='failed')::numeric
        / NULLIF(COUNT(*) FILTER (WHERE e.stage='source'), 0) AS block_rate
    FROM public.ingestion_events e
    JOIN public.ingestion_staging s ON s.id = e.staging_id
    WHERE e.created_at > now() - interval '30 days'
      AND s.source_name IS NOT NULL AND s.entity_type IS NOT NULL
    GROUP BY s.source_name, s.entity_type
  ),
  rolled AS (
    SELECT q.source_slug, q.entity_type, q.n AS sample_size,
           q.score_p50 AS quality_p50, q.score_p25 AS quality_p25,
           coalesce(c.coverage_ratio, 0.5) AS coverage_ratio,
           coalesce(e.rejection_rate, 0)   AS rejection_rate,
           coalesce(e.block_rate, 0)       AS block_rate
    FROM quality q
    LEFT JOIN coverage c ON c.source_slug = q.source_slug
    LEFT JOIN events   e ON e.source_slug = q.source_slug AND e.entity_type = q.entity_type
  )
  INSERT INTO public.source_reliability AS sr (
    source_slug, entity_type, weight,
    quality_p50, quality_p25, coverage_ratio, rejection_rate, block_rate,
    sample_size, computed_at
  )
  SELECT source_slug, entity_type,
    CASE WHEN sample_size < 50 THEN NULL
         ELSE GREATEST(0.05,
                0.50 * coalesce(quality_p50, 0)/100.0
              + 0.25 * coverage_ratio
              + 0.25 * (1 - rejection_rate)
              - GREATEST(0, block_rate - 0.20) * 0.50
         )::numeric(4,3)
    END,
    quality_p50, quality_p25, coverage_ratio::numeric(4,3),
    rejection_rate::numeric(4,3), block_rate::numeric(4,3),
    sample_size, now()
  FROM rolled
  ON CONFLICT (source_slug, entity_type) DO UPDATE SET
    weight=EXCLUDED.weight, quality_p50=EXCLUDED.quality_p50, quality_p25=EXCLUDED.quality_p25,
    coverage_ratio=EXCLUDED.coverage_ratio, rejection_rate=EXCLUDED.rejection_rate,
    block_rate=EXCLUDED.block_rate, sample_size=EXCLUDED.sample_size, computed_at=EXCLUDED.computed_at;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  RETURN v_rows;
END;
$$;


ALTER FUNCTION "public"."refresh_source_reliability"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."register_circuit_breaker"("p_api_name" "text", "p_threshold" integer DEFAULT 5, "p_reset_seconds" integer DEFAULT 120) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_id uuid;
BEGIN
  INSERT INTO api_circuit_breakers(api_name, state, threshold, reset_timeout_seconds)
  VALUES (p_api_name, 'closed', p_threshold, p_reset_seconds)
  ON CONFLICT (api_name) DO UPDATE
    SET threshold = EXCLUDED.threshold,
        reset_timeout_seconds = EXCLUDED.reset_timeout_seconds,
        updated_at = now()
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."register_circuit_breaker"("p_api_name" "text", "p_threshold" integer, "p_reset_seconds" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reject_group_join_request"("request_id" "uuid") RETURNS "public"."group_join_requests"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  req public.group_join_requests;
BEGIN
  SELECT * INTO req FROM public.group_join_requests WHERE id = request_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Join request not found';
  END IF;
  IF req.status <> 'pending' THEN
    RAISE EXCEPTION 'Join request is not pending (status=%)', req.status;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.group_memberships gm
    WHERE gm.group_id = req.group_id
      AND gm.user_id = auth.uid()
      AND gm.role IN ('admin', 'moderator')
  ) THEN
    RAISE EXCEPTION 'Not authorized to reject requests for this group';
  END IF;

  UPDATE public.group_join_requests
    SET status = 'rejected', decided_by = auth.uid(), decided_at = now()
    WHERE id = request_id
    RETURNING * INTO req;

  RETURN req;
END;
$$;


ALTER FUNCTION "public"."reject_group_join_request"("request_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."remove_story_members"("p_story_id" "uuid", "p_submission_ids" "uuid"[]) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count integer;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  DELETE FROM feedback_story_members
  WHERE story_id = p_story_id
    AND submission_id = ANY(p_submission_ids);
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


