CREATE OR REPLACE FUNCTION "public"."remove_tag_from_category"("p_tag_id" "uuid", "p_category_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_was_primary BOOLEAN;
  v_new_primary_cat_id UUID;
BEGIN
  -- Check if we're removing the primary
  SELECT is_primary INTO v_was_primary
  FROM tag_category_assignments
  WHERE tag_id = p_tag_id AND category_id = p_category_id;

  -- Delete the assignment
  DELETE FROM tag_category_assignments
  WHERE tag_id = p_tag_id AND category_id = p_category_id;

  -- If we removed the primary, promote the next one
  IF v_was_primary THEN
    SELECT tca.category_id INTO v_new_primary_cat_id
    FROM tag_category_assignments tca
    JOIN tag_categories tc ON tc.id = tca.category_id
    WHERE tca.tag_id = p_tag_id
    ORDER BY tc.sort_order
    LIMIT 1;

    IF v_new_primary_cat_id IS NOT NULL THEN
      UPDATE tag_category_assignments
      SET is_primary = true
      WHERE tag_id = p_tag_id AND category_id = v_new_primary_cat_id;

      -- Update legacy columns
      UPDATE unified_tags
      SET category_id = v_new_primary_cat_id,
          category = (SELECT name FROM tag_categories WHERE id = v_new_primary_cat_id)
      WHERE id = p_tag_id;
    END IF;
  END IF;
END;
$$;


ALTER FUNCTION "public"."remove_tag_from_category"("p_tag_id" "uuid", "p_category_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."replay_rejected_staging"("p_error_substring" "text", "p_target_table" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 100) RETURNS TABLE("staging_id" "uuid", "previous_error" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE
  r RECORD;
BEGIN
  FOR r IN
    SELECT x.id, x.error_message FROM public.ingestion_staging x
    WHERE x.disposition = 'rejected'
      AND x.error_message IS NOT NULL
      AND x.error_message ILIKE '%' || p_error_substring || '%'
      AND (p_target_table IS NULL OR x.target_table = p_target_table)
    ORDER BY x.updated_at ASC
    LIMIT p_limit
    FOR UPDATE SKIP LOCKED
  LOOP
    UPDATE public.ingestion_staging SET
      disposition   = 'pending',
      error_message = null,
      updated_at    = now()
    WHERE id = r.id;

    INSERT INTO public.ingestion_events (staging_id, stage, old_status, new_status, actor, payload)
    VALUES (r.id, 'replay', 'rejected', 'pending', 'replay_rejected_staging',
            jsonb_build_object('previous_error', r.error_message));

    staging_id := r.id; previous_error := r.error_message;
    RETURN NEXT;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."replay_rejected_staging"("p_error_substring" "text", "p_target_table" "text", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_city_and_country"("p_city_name" "text", "p_country_name" "text") RETURNS TABLE("resolved_city_id" "uuid", "resolved_city_name" "text", "resolved_country_id" "uuid", "resolved_country_name" "text", "city_found" boolean, "country_found" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_country_id UUID;
  v_country_name TEXT;
  v_city_id UUID;
  v_city_name TEXT;
BEGIN
  -- 1. Resolve country (exact name, then code)
  SELECT c.id, c.name INTO v_country_id, v_country_name
  FROM countries c
  WHERE lower(c.name) = lower(p_country_name)
  LIMIT 1;

  IF v_country_id IS NULL AND length(p_country_name) <= 3 THEN
    SELECT c.id, c.name INTO v_country_id, v_country_name
    FROM countries c
    WHERE lower(c.code) = lower(p_country_name)
    LIMIT 1;
  END IF;

  -- 2. Resolve city (exact match, prefer matching country)
  IF p_city_name IS NOT NULL AND p_city_name != '' THEN
    -- Try exact match with country disambiguation
    IF v_country_id IS NOT NULL THEN
      SELECT ci.id, ci.name INTO v_city_id, v_city_name
      FROM cities ci
      WHERE lower(ci.name) = lower(p_city_name)
        AND ci.country_id = v_country_id
      LIMIT 1;
    END IF;

    -- Fallback: any city with that name (prefer highest population)
    IF v_city_id IS NULL THEN
      SELECT ci.id, ci.name INTO v_city_id, v_city_name
      FROM cities ci
      WHERE lower(ci.name) = lower(p_city_name)
      ORDER BY ci.population DESC NULLS LAST
      LIMIT 1;
    END IF;

    -- Fallback: city_aliases
    IF v_city_id IS NULL THEN
      SELECT ci.id, ci.name INTO v_city_id, v_city_name
      FROM city_aliases ca
      JOIN cities ci ON ci.id = ca.city_id
      WHERE lower(ca.alias) = lower(p_city_name)
      LIMIT 1;
    END IF;
  END IF;

  RETURN QUERY SELECT v_city_id, v_city_name, v_country_id, v_country_name,
    (v_city_id IS NOT NULL), (v_country_id IS NOT NULL);
END;
$$;


ALTER FUNCTION "public"."resolve_city_and_country"("p_city_name" "text", "p_country_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_currency_for_country"("p_country_code" "text") RETURNS TABLE("currency_code" "text", "currency_symbol" "text")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
  SELECT c2.code, c2.symbol
  FROM public.countries c
  JOIN public.currencies c2 ON c2.code = c.currency
  WHERE c.code = upper(p_country_code)
  LIMIT 1;
$$;


ALTER FUNCTION "public"."resolve_currency_for_country"("p_country_code" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_field_conflict"("p_variants" "jsonb", "p_entity_type" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_scored jsonb;
  v_best   jsonb;
BEGIN
  IF p_variants IS NULL OR jsonb_array_length(p_variants) = 0 THEN
    RETURN jsonb_build_object('resolved_value', NULL, 'resolved_source', NULL, 'scored_variants', '[]'::jsonb);
  END IF;

  WITH variants AS (
    SELECT v->>'source' AS source, v->'value' AS value,
           coalesce((v->>'recency_days')::numeric, 0) AS recency_days
    FROM jsonb_array_elements(p_variants) v
  ),
  weighted AS (
    SELECT v.source, v.value, v.recency_days,
           coalesce(sr.weight, 0.5) AS weight,
           LEAST(1.0, length(coalesce(v.value::text,'')) / 200.0) AS len_norm,
           exp(-v.recency_days / 30.0) AS recency_norm
    FROM variants v
    LEFT JOIN public.source_reliability sr
      ON sr.source_slug = v.source AND sr.entity_type = p_entity_type
  ),
  scored AS (
    SELECT source, value, weight, len_norm, recency_norm,
      CASE
        WHEN value IS NULL OR value = 'null'::jsonb OR value::text IN ('""','""""') THEN 0
        ELSE weight * (0.5 + 0.3 * len_norm + 0.2 * recency_norm)
      END AS score
    FROM weighted
  )
  SELECT jsonb_agg(
    jsonb_build_object(
      'source', source, 'value', value,
      'weight', round(weight::numeric, 3),
      'score',  round(score::numeric, 3)
    ) ORDER BY score DESC
  ) INTO v_scored
  FROM scored;

  SELECT jsonb_build_object(
    'resolved_value',  variant->'value',
    'resolved_source', variant->>'source',
    'scored_variants', v_scored
  )
  INTO v_best
  FROM jsonb_array_elements(v_scored) variant
  WHERE (variant->>'score')::numeric > 0
  ORDER BY (variant->>'score')::numeric DESC
  LIMIT 1;

  RETURN coalesce(
    v_best,
    jsonb_build_object('resolved_value', NULL, 'resolved_source', NULL, 'scored_variants', v_scored)
  );
END;
$$;


ALTER FUNCTION "public"."resolve_field_conflict"("p_variants" "jsonb", "p_entity_type" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."resolve_field_conflict"("p_variants" "jsonb", "p_entity_type" "text") IS 'Multi-source field conflict resolver. Returns highest-scoring variant via source_reliability.weight × length × recency.';



CREATE OR REPLACE FUNCTION "public"."resolve_geo_merge_candidate"("p_staging_id" "uuid", "p_decision" "text", "p_actor" "text" DEFAULT 'admin-review'::"text") RETURNS TABLE("entity_id" "uuid", "entity_type" "text", "action" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE v_stage RECORD; v_is_city BOOLEAN; v_result RECORD;
BEGIN
  IF p_decision NOT IN ('merge','not_duplicate') THEN RAISE EXCEPTION 'invalid_decision: %', p_decision; END IF;
  SELECT * INTO v_stage FROM public.ingestion_staging WHERE id = p_staging_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'staging_item_not_found: %', p_staging_id; END IF;
  IF v_stage.target_table NOT IN ('cities','countries') THEN RAISE EXCEPTION 'not_a_geo_staging_item: target=%', v_stage.target_table; END IF;
  IF v_stage.dedup_status <> 'merge_candidate' THEN RAISE EXCEPTION 'not_a_merge_candidate: dedup_status=%', v_stage.dedup_status; END IF;
  v_is_city := (v_stage.target_table = 'cities');
  IF p_decision = 'merge' THEN
    UPDATE public.ingestion_staging SET dedup_status='duplicate', review_status='approved', disposition='pending', updated_at=now() WHERE id = p_staging_id;
  ELSE
    UPDATE public.ingestion_staging SET dedup_status='unique', dedup_match_id=NULL, dedup_match_score=0, review_status='approved', disposition='pending', updated_at=now() WHERE id = p_staging_id;
  END IF;
  UPDATE public.review_queue SET status='resolved', resolution=p_decision, resolved_at=now(), resolved_by_label=p_actor
  WHERE entity_type='ingestion_staging' AND entity_id=p_staging_id AND status='pending';
  UPDATE public.scraper_dedupe_decisions SET decision=p_decision, decided_by=p_actor,
    action = CASE WHEN p_decision='merge' THEN 'admin_merge' ELSE 'admin_keep_separate' END
  WHERE entity_a_id = p_staging_id;
  IF v_is_city THEN
    SELECT * INTO v_result FROM public.commit_city_staging_item(p_staging_id, p_actor);
    entity_id := v_result.city_id; entity_type := 'city';
  ELSE
    SELECT * INTO v_result FROM public.commit_country_staging_item(p_staging_id, p_actor);
    entity_id := v_result.country_id; entity_type := 'country';
  END IF;
  action := v_result.action;
  INSERT INTO public.ingestion_events (staging_id, city_id, country_id, stage, new_status, actor, payload)
  VALUES (p_staging_id,
    CASE WHEN v_is_city THEN entity_id ELSE NULL END,
    CASE WHEN NOT v_is_city THEN entity_id ELSE NULL END,
    'review_resolve', p_decision, p_actor,
    jsonb_build_object('decision', p_decision, 'result_action', action));
  RETURN NEXT;
END; $$;


ALTER FUNCTION "public"."resolve_geo_merge_candidate"("p_staging_id" "uuid", "p_decision" "text", "p_actor" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_path_redirect"("p_path" "text") RETURNS TABLE("id" "uuid", "source_path" "text", "match_kind" "public"."redirect_match_kind", "target" "text", "status_code" integer, "preserve_query" boolean, "query_mode" "public"."redirect_query_mode", "query_override" "jsonb", "utm_defaults" "jsonb", "click_limit" integer, "click_count" integer)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  -- Try exact match first
  SELECT
    r.id, r.source_path, r.match_kind, r.target, r.status_code,
    r.preserve_query, r.query_mode, r.query_override, r.utm_defaults,
    r.click_limit, r.click_count
  FROM redirects r
  WHERE r.type = 'PATH'
    AND r.match_kind = 'EXACT'
    AND r.source_path = p_path
    AND r.is_enabled = true
    AND (r.start_at IS NULL OR r.start_at <= now())
    AND (r.end_at IS NULL OR r.end_at > now())
    AND (r.click_limit IS NULL OR r.click_count < r.click_limit)
  LIMIT 1;
$$;


ALTER FUNCTION "public"."resolve_path_redirect"("p_path" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_short_redirect"("p_slug" "text") RETURNS TABLE("id" "uuid", "slug" "text", "target" "text", "status_code" integer, "preserve_query" boolean, "query_mode" "public"."redirect_query_mode", "query_override" "jsonb", "utm_defaults" "jsonb", "click_limit" integer, "click_count" integer)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    r.id, r.slug, r.target, r.status_code,
    r.preserve_query, r.query_mode, r.query_override, r.utm_defaults,
    r.click_limit, r.click_count
  FROM redirects r
  WHERE r.type = 'SHORT'
    AND r.slug = p_slug
    AND r.is_enabled = true
    AND (r.start_at IS NULL OR r.start_at <= now())
    AND (r.end_at IS NULL OR r.end_at > now())
    AND (r.click_limit IS NULL OR r.click_count < r.click_limit)
  LIMIT 1;
$$;


ALTER FUNCTION "public"."resolve_short_redirect"("p_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_story"("p_story_id" "uuid", "p_close_items" boolean DEFAULT false) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_closed integer := 0;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  UPDATE feedback_stories
     SET status = 'resolved',
         resolved_at = now()
   WHERE id = p_story_id;

  IF p_close_items THEN
    UPDATE community_submissions cs
       SET feedback_status = 'done',
           resolution = COALESCE(cs.resolution, 'fixed'),
           resolved_at = COALESCE(cs.resolved_at, now())
      FROM feedback_story_members m
     WHERE m.story_id = p_story_id
       AND cs.id = m.submission_id
       AND cs.feedback_status <> 'done';
    GET DIAGNOSTICS v_closed = ROW_COUNT;
  END IF;

  RETURN v_closed;
END;
$$;


ALTER FUNCTION "public"."resolve_story"("p_story_id" "uuid", "p_close_items" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_tag"("input_slug" "text") RETURNS TABLE("tag_id" "uuid", "tag_name" "text", "tag_slug" "text", "is_redirect" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
BEGIN
  -- 1. Direct match on active tag
  RETURN QUERY
  SELECT ut.id, ut.name, ut.slug, FALSE
  FROM unified_tags ut
  WHERE ut.slug = input_slug AND ut.status = 'active'
  LIMIT 1;
  IF FOUND THEN RETURN; END IF;

  -- 2. Merged tag -> redirect to canonical
  RETURN QUERY
  SELECT canonical.id, canonical.name, canonical.slug, TRUE
  FROM unified_tags ut
  JOIN unified_tags canonical ON ut.merged_into_id = canonical.id
  WHERE ut.slug = input_slug AND ut.status = 'merged'
    AND canonical.status = 'active'
  LIMIT 1;
  IF FOUND THEN RETURN; END IF;

  -- 3. Alias lookup
  RETURN QUERY
  SELECT ut.id, ut.name, ut.slug, TRUE
  FROM tag_aliases ta
  JOIN unified_tags ut ON ta.canonical_tag_id = ut.id
  WHERE ta.alias_slug = input_slug AND ut.status = 'active'
  LIMIT 1;
  IF FOUND THEN RETURN; END IF;

  -- 4. Fuzzy match via trigram similarity (pg_trgm in extensions schema)
  RETURN QUERY
  SELECT ut.id, ut.name, ut.slug, TRUE
  FROM unified_tags ut
  WHERE ut.status = 'active'
    AND extensions.similarity(LOWER(ut.name), REPLACE(input_slug, '-', ' ')) > 0.6
  ORDER BY extensions.similarity(LOWER(ut.name), REPLACE(input_slug, '-', ' ')) DESC
  LIMIT 1;
END;
$$;


ALTER FUNCTION "public"."resolve_tag"("input_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_tag_slug"("p_slug" "text") RETURNS TABLE("id" "uuid", "slug" "text", "redirected" boolean, "original_slug" "text")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
  WITH direct AS (
    SELECT t.id, t.slug, FALSE AS redirected, p_slug AS original_slug
    FROM public.unified_tags t
    WHERE t.slug = p_slug AND t.status = 'active'
    LIMIT 1
  ),
  redirected AS (
    SELECT t.id, t.slug, TRUE AS redirected, p_slug AS original_slug
    FROM public.tag_slug_redirects r
    JOIN public.unified_tags t ON t.id = r.tag_id AND t.status = 'active'
    WHERE r.old_slug = p_slug
    LIMIT 1
  )
  SELECT * FROM direct
  UNION ALL
  SELECT * FROM redirected
  WHERE NOT EXISTS (SELECT 1 FROM direct);
$$;


ALTER FUNCTION "public"."resolve_tag_slug"("p_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_trip_geo_review"("p_queue_id" "uuid", "p_city_id" "uuid", "p_country_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_trip_id UUID;
  v_country UUID;
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM public.user_roles
    WHERE user_id = auth.uid() AND role = 'admin'
  ) THEN
    RAISE EXCEPTION 'not authorized';
  END IF;

  SELECT trip_id INTO v_trip_id
  FROM public.trip_geo_review_queue
  WHERE id = p_queue_id AND status = 'pending';

  IF v_trip_id IS NULL THEN
    RAISE EXCEPTION 'queue entry not found or already resolved';
  END IF;

  IF p_country_id IS NULL AND p_city_id IS NOT NULL THEN
    SELECT country_id INTO v_country FROM public.cities WHERE id = p_city_id;
  ELSE
    v_country := p_country_id;
  END IF;

  UPDATE public.trips
  SET primary_city_id = p_city_id,
      primary_country_id = v_country
  WHERE id = v_trip_id;

  UPDATE public.trip_geo_review_queue
  SET status = 'resolved',
      resolved_city_id = p_city_id,
      resolved_country_id = v_country,
      resolved_by = auth.uid(),
      resolved_at = now()
  WHERE id = p_queue_id;
END;
$$;


ALTER FUNCTION "public"."resolve_trip_geo_review"("p_queue_id" "uuid", "p_city_id" "uuid", "p_country_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."retry_enrichment"("p_entity_type" "text", "p_entity_id" "uuid", "p_steps" "text"[] DEFAULT NULL::"text"[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_current_status JSONB; v_failed_steps TEXT[]; v_step TEXT;
BEGIN
  IF NOT has_role_jwt('admin'::app_role) THEN RAISE EXCEPTION 'unauthorized' USING ERRCODE='42501'; END IF;
  IF p_entity_type NOT IN ('venues','events','personalities','news_articles') THEN
    RAISE EXCEPTION 'Invalid entity_type: %', p_entity_type;
  END IF;
  EXECUTE format('SELECT enrichment_status FROM %I WHERE id = $1', p_entity_type) INTO v_current_status USING p_entity_id;
  IF v_current_status IS NULL THEN v_current_status := '{}'::JSONB; END IF;
  IF p_steps IS NOT NULL THEN v_failed_steps := p_steps;
  ELSE SELECT array_agg(key) INTO v_failed_steps FROM jsonb_each_text(v_current_status) WHERE value = 'failed'; END IF;
  IF v_failed_steps IS NULL OR array_length(v_failed_steps, 1) IS NULL THEN
    RETURN jsonb_build_object('status','no_failed_steps','entity_type',p_entity_type,'entity_id',p_entity_id);
  END IF;
  FOREACH v_step IN ARRAY v_failed_steps LOOP
    v_current_status := jsonb_set(v_current_status, ARRAY[v_step], '"pending"'::JSONB);
  END LOOP;
  EXECUTE format('UPDATE %I SET enrichment_status = $1 WHERE id = $2', p_entity_type) USING v_current_status, p_entity_id;
  PERFORM pgmq.send('enrichment_queue', jsonb_build_object('entity_type', p_entity_type,
    'entity_id', p_entity_id, 'action', 'RETRY', 'retry_steps', to_jsonb(v_failed_steps)));
  INSERT INTO enrichment_log (entity_type, entity_id, step, status, error_message)
  VALUES (p_entity_type, p_entity_id, 'retry', 'done', 'Manual retry for steps: ' || array_to_string(v_failed_steps, ', '));
  RETURN jsonb_build_object('status','retried','entity_type',p_entity_type,'entity_id',p_entity_id,'steps',to_jsonb(v_failed_steps));
END;
$_$;


ALTER FUNCTION "public"."retry_enrichment"("p_entity_type" "text", "p_entity_id" "uuid", "p_steps" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."revert_content_change"("p_change_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_change RECORD;
  v_allowed_tables TEXT[] := ARRAY[
    'venues','events','personalities','news_articles',
    'cities','countries','unified_tags','marketplace_listings',
    'community_groups','hotels','queer_villages'
  ];
  v_sql TEXT;
  v_value TEXT;
BEGIN
  SELECT * INTO v_change FROM public.content_changes
    WHERE id = p_change_id AND status = 'applied'
    FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Change % not found or not applied', p_change_id;
  END IF;

  IF NOT v_change.content_type = ANY(v_allowed_tables) THEN
    RAISE EXCEPTION 'Invalid content_type: %', v_change.content_type;
  END IF;

  IF v_change.change_type = 'flag' THEN
    UPDATE public.content_changes
    SET status = 'reverted', reverted_at = now()
    WHERE id = p_change_id;
    RETURN TRUE;
  END IF;

  v_value := v_change.old_value #>> '{}';

  v_sql := format(
    'UPDATE %I SET %I = $1 WHERE id = $2',
    v_change.content_type,
    v_change.field_name
  );

  EXECUTE v_sql USING v_value, v_change.content_id;

  UPDATE public.content_changes
  SET status = 'reverted', reverted_at = now()
  WHERE id = p_change_id;

  RETURN TRUE;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'revert_content_change failed for %: %', p_change_id, SQLERRM;
  RETURN FALSE;
END;
$_$;


ALTER FUNCTION "public"."revert_content_change"("p_change_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rollback_tag_change"("p_log_id" bigint) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_log     tag_change_log%ROWTYPE;
  v_actor   TEXT := COALESCE(current_setting('app.actor', true), 'admin:rollback');
  v_before  JSONB;
BEGIN
  SELECT * INTO v_log FROM tag_change_log WHERE id = p_log_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'log entry % not found', p_log_id;
  END IF;
  v_before := v_log.before_data;
  IF v_before IS NULL THEN
    RAISE EXCEPTION 'log entry % has no before_data; cannot rollback', p_log_id;
  END IF;
  PERFORM set_config('app.actor', v_actor, true);
  IF v_log.action_type = 'update' THEN
    UPDATE unified_tags SET
      name              = COALESCE((v_before->>'name'), name),
      slug              = COALESCE((v_before->>'slug'), slug),
      description       = (v_before->>'description'),
      short_description = (v_before->>'short_description'),
      long_description  = (v_before->>'long_description'),
      image_url         = (v_before->>'image_url'),
      verification_status = (v_before->>'verification_status'),
      is_sensitive      = COALESCE((v_before->>'is_sensitive')::BOOLEAN, FALSE),
      human_reviewed    = COALESCE((v_before->>'human_reviewed')::BOOLEAN, FALSE)
    WHERE id = v_log.tag_id;
  ELSIF v_log.action_type = 'delete' THEN
    INSERT INTO unified_tags SELECT * FROM jsonb_populate_record(NULL::unified_tags, v_before);
  END IF;
  INSERT INTO tag_change_log(tag_id, action_type, before_data, after_data, actor, reason)
    VALUES (v_log.tag_id, 'rollback', v_log.after_data, v_log.before_data, v_actor, 'rollback of #' || p_log_id);
  RETURN jsonb_build_object('rolled_back', p_log_id, 'tag_id', v_log.tag_id);
END $$;


ALTER FUNCTION "public"."rollback_tag_change"("p_log_id" bigint) OWNER TO "postgres";


