CREATE OR REPLACE FUNCTION "public"."sanitize_event_website_field"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  blocked_domains TEXT[] := ARRAY[
    'gaytravel4u.com',
    'gaytravel4u.de',
    'spartacus.gayguide.travel'
  ];
  domain TEXT;
BEGIN
  IF NEW.website IS NOT NULL AND NEW.website <> '' THEN
    FOREACH domain IN ARRAY blocked_domains LOOP
      IF NEW.website ILIKE '%' || domain || '%' THEN
        RAISE NOTICE 'Blocked scraper source URL in events.website: %', NEW.website;
        NEW.website := NULL;
        EXIT;
      END IF;
    END LOOP;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sanitize_event_website_field"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sanitize_website_field"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  blocked_domains TEXT[] := ARRAY[
    'wikipedia.org',
    'wikidata.org',
    'wikimedia.org',
    'gaytravel4u.com',
    'gaytravel4u.de',
    'spartacus.gayguide.travel',
    'tripadvisor.com',
    'tripadvisor.es',
    'tripadvisor.de',
    'tripadvisor.co.uk',
    'tripadvisor.fr',
    'tripadvisor.it',
    'eventbrite.com',
    'eventbrite.co.uk',
    'eventbrite.de',
    'yelp.com',
    'foursquare.com',
    'google.com/maps',
    'goo.gl/maps',
    'maps.google.com'
  ];
  domain TEXT;
  website_val TEXT;
BEGIN
  -- Determine which column to check based on TG_TABLE_NAME
  IF TG_TABLE_NAME = 'personalities' THEN
    website_val := NEW.website_url;
  ELSE
    website_val := NEW.website;
  END IF;

  -- If website value is set, check against blocked domains
  IF website_val IS NOT NULL AND website_val != '' THEN
    FOREACH domain IN ARRAY blocked_domains LOOP
      IF website_val ILIKE '%' || domain || '%' THEN
        -- Silently null out the scraper URL instead of raising an error
        IF TG_TABLE_NAME = 'personalities' THEN
          NEW.website_url := NULL;
        ELSE
          NEW.website := NULL;
        END IF;
        RAISE NOTICE 'Blocked scraper source URL in %.%: %', TG_TABLE_NAME,
          CASE WHEN TG_TABLE_NAME = 'personalities' THEN 'website_url' ELSE 'website' END,
          website_val;
        EXIT; -- Stop checking once we found a match
      END IF;
    END LOOP;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sanitize_website_field"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."sanitize_website_field"() IS 'Prevents scraper/aggregator source URLs from being stored in website fields. Silently nullifies URLs from known scraper sources (Wikipedia, TripAdvisor, Eventbrite, etc.). The blocked_domains array should be updated when new scraper sources are added.';



CREATE OR REPLACE FUNCTION "public"."scan_table_duplicates"("p_entity_type" "text", "p_threshold" numeric DEFAULT 0.7, "p_limit" integer DEFAULT 200) RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    SET "statement_timeout" TO '300s'
    AS $$
DECLARE v_found INT := 0; v_scanned INT := 0; v_rec RECORD; v_match RECORD;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role,'moderator'::app_role]) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE='42501'; END IF;
  DELETE FROM scraper_dedupe_decisions WHERE entity_type=p_entity_type AND decision='pending';
  IF p_entity_type='venues' THEN
    FOR v_rec IN SELECT id, name, latitude, longitude, category FROM venues
      WHERE latitude IS NOT NULL AND longitude IS NOT NULL ORDER BY created_at DESC LIMIT p_limit
    LOOP
      v_scanned := v_scanned+1;
      FOR v_match IN SELECT venue_id, venue_name, combined_score, name_similarity, geo_distance_m
        FROM find_venue_duplicates(v_rec.name, v_rec.latitude, v_rec.longitude, v_rec.category, p_threshold)
        WHERE venue_id != v_rec.id ORDER BY combined_score DESC LIMIT 1
      LOOP
        IF NOT EXISTS (SELECT 1 FROM scraper_dedupe_decisions WHERE entity_type='venues'
          AND ((entity_a_id=v_rec.id AND entity_b_id=v_match.venue_id) OR (entity_a_id=v_match.venue_id AND entity_b_id=v_rec.id))) THEN
          INSERT INTO scraper_dedupe_decisions (entity_type, entity_a_id, entity_b_id, match_method, confidence, decision)
          VALUES ('venues', v_rec.id, v_match.venue_id, 'trigram+geo', v_match.combined_score, 'pending');
          v_found := v_found+1;
        END IF;
      END LOOP;
    END LOOP;
  ELSIF p_entity_type='events' THEN
    FOR v_rec IN SELECT id, title, start_date, city FROM events WHERE start_date IS NOT NULL ORDER BY created_at DESC LIMIT p_limit
    LOOP
      v_scanned := v_scanned+1;
      FOR v_match IN SELECT event_id, event_title, combined_score
        FROM find_event_duplicates(v_rec.title, v_rec.start_date, v_rec.city)
        WHERE event_id != v_rec.id ORDER BY combined_score DESC LIMIT 1
      LOOP
        IF NOT EXISTS (SELECT 1 FROM scraper_dedupe_decisions WHERE entity_type='events'
          AND ((entity_a_id=v_rec.id AND entity_b_id=v_match.event_id) OR (entity_a_id=v_match.event_id AND entity_b_id=v_rec.id))) THEN
          INSERT INTO scraper_dedupe_decisions (entity_type, entity_a_id, entity_b_id, match_method, confidence, decision)
          VALUES ('events', v_rec.id, v_match.event_id, 'trigram+date+city', v_match.combined_score, 'pending');
          v_found := v_found+1;
        END IF;
      END LOOP;
    END LOOP;
  ELSIF p_entity_type='personalities' THEN
    FOR v_rec IN SELECT id, name FROM personalities ORDER BY created_at DESC LIMIT p_limit
    LOOP
      v_scanned := v_scanned+1;
      FOR v_match IN SELECT personality_id, personality_name, name_similarity
        FROM find_personality_duplicates(v_rec.name, p_threshold)
        WHERE personality_id != v_rec.id ORDER BY name_similarity DESC LIMIT 1
      LOOP
        IF NOT EXISTS (SELECT 1 FROM scraper_dedupe_decisions WHERE entity_type='personalities'
          AND ((entity_a_id=v_rec.id AND entity_b_id=v_match.personality_id) OR (entity_a_id=v_match.personality_id AND entity_b_id=v_rec.id))) THEN
          INSERT INTO scraper_dedupe_decisions (entity_type, entity_a_id, entity_b_id, match_method, confidence, decision)
          VALUES ('personalities', v_rec.id, v_match.personality_id, 'trigram_name', v_match.name_similarity, 'pending');
          v_found := v_found+1;
        END IF;
      END LOOP;
    END LOOP;
  ELSIF p_entity_type='news_articles' THEN
    FOR v_rec IN SELECT id, title, source_id, published_at FROM news_articles
      WHERE title IS NOT NULL AND title != '' ORDER BY created_at DESC LIMIT p_limit
    LOOP
      v_scanned := v_scanned+1;
      FOR v_match IN SELECT article_id, article_title, combined_score
        FROM find_news_duplicates(v_rec.title, v_rec.source_id, v_rec.published_at, p_threshold)
        WHERE article_id != v_rec.id ORDER BY combined_score DESC LIMIT 1
      LOOP
        IF NOT EXISTS (SELECT 1 FROM scraper_dedupe_decisions WHERE entity_type='news_articles'
          AND ((entity_a_id=v_rec.id AND entity_b_id=v_match.article_id) OR (entity_a_id=v_match.article_id AND entity_b_id=v_rec.id))) THEN
          INSERT INTO scraper_dedupe_decisions (entity_type, entity_a_id, entity_b_id, match_method, confidence, decision)
          VALUES ('news_articles', v_rec.id, v_match.article_id, 'trigram_title', v_match.combined_score, 'pending');
          v_found := v_found+1;
        END IF;
      END LOOP;
    END LOOP;
  ELSIF p_entity_type='cities' THEN
    FOR v_rec IN SELECT id, name, country_id, latitude, longitude FROM cities ORDER BY created_at DESC LIMIT p_limit
    LOOP
      v_scanned := v_scanned+1;
      FOR v_match IN SELECT city_id, city_name, combined_score
        FROM find_city_duplicates(v_rec.name, v_rec.country_id, v_rec.latitude, v_rec.longitude, p_threshold)
        WHERE city_id != v_rec.id ORDER BY combined_score DESC LIMIT 1
      LOOP
        IF NOT EXISTS (SELECT 1 FROM scraper_dedupe_decisions WHERE entity_type='cities'
          AND ((entity_a_id=v_rec.id AND entity_b_id=v_match.city_id) OR (entity_a_id=v_match.city_id AND entity_b_id=v_rec.id))) THEN
          INSERT INTO scraper_dedupe_decisions (entity_type, entity_a_id, entity_b_id, match_method, confidence, decision)
          VALUES ('cities', v_rec.id, v_match.city_id, 'trigram+country+geo', v_match.combined_score, 'pending');
          v_found := v_found+1;
        END IF;
      END LOOP;
    END LOOP;
  ELSE RETURN json_build_object('error', 'Unsupported entity_type: ' || p_entity_type); END IF;
  RETURN json_build_object('entity_type',p_entity_type,'scanned',v_scanned,'duplicates_found',v_found,'threshold',p_threshold);
END;
$$;


ALTER FUNCTION "public"."scan_table_duplicates"("p_entity_type" "text", "p_threshold" numeric, "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."scan_table_duplicates"("p_entity_type" "text", "p_threshold" numeric DEFAULT 0.7, "p_limit" integer DEFAULT 500, "p_offset" integer DEFAULT 0) RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    SET "statement_timeout" TO '120s'
    AS $$
DECLARE v_found INT := 0; v_scanned INT := 0; v_total INT := 0; v_rec RECORD; v_match RECORD;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role,'moderator'::app_role]) THEN
    RAISE EXCEPTION 'unauthorized' USING ERRCODE='42501'; END IF;
  IF p_offset=0 THEN
    DELETE FROM scraper_dedupe_decisions WHERE entity_type=p_entity_type AND decision='pending';
  END IF;
  IF p_entity_type='venues' THEN
    SELECT count(*) INTO v_total FROM venues WHERE latitude IS NOT NULL AND longitude IS NOT NULL;
    FOR v_rec IN SELECT id, name, latitude, longitude, category FROM venues
      WHERE latitude IS NOT NULL AND longitude IS NOT NULL ORDER BY created_at DESC LIMIT p_limit OFFSET p_offset
    LOOP
      v_scanned := v_scanned+1;
      FOR v_match IN SELECT venue_id, venue_name, combined_score, name_similarity, geo_distance_m
        FROM find_venue_duplicates(v_rec.name, v_rec.latitude, v_rec.longitude, v_rec.category, p_threshold)
        WHERE venue_id != v_rec.id ORDER BY combined_score DESC LIMIT 1
      LOOP
        IF NOT EXISTS (SELECT 1 FROM scraper_dedupe_decisions WHERE entity_type='venues'
          AND ((entity_a_id=v_rec.id AND entity_b_id=v_match.venue_id) OR (entity_a_id=v_match.venue_id AND entity_b_id=v_rec.id))) THEN
          INSERT INTO scraper_dedupe_decisions (entity_type, entity_a_id, entity_b_id, match_method, confidence, decision)
          VALUES ('venues', v_rec.id, v_match.venue_id, 'trigram+geo', v_match.combined_score, 'pending');
          v_found := v_found+1;
        END IF;
      END LOOP;
    END LOOP;
  ELSIF p_entity_type='events' THEN
    SELECT count(*) INTO v_total FROM events WHERE start_date IS NOT NULL;
    FOR v_rec IN SELECT id, title, start_date, city FROM events WHERE start_date IS NOT NULL
      ORDER BY created_at DESC LIMIT p_limit OFFSET p_offset
    LOOP
      v_scanned := v_scanned+1;
      FOR v_match IN SELECT event_id, event_title, combined_score
        FROM find_event_duplicates(v_rec.title, v_rec.start_date, v_rec.city)
        WHERE event_id != v_rec.id ORDER BY combined_score DESC LIMIT 1
      LOOP
        IF NOT EXISTS (SELECT 1 FROM scraper_dedupe_decisions WHERE entity_type='events'
          AND ((entity_a_id=v_rec.id AND entity_b_id=v_match.event_id) OR (entity_a_id=v_match.event_id AND entity_b_id=v_rec.id))) THEN
          INSERT INTO scraper_dedupe_decisions (entity_type, entity_a_id, entity_b_id, match_method, confidence, decision)
          VALUES ('events', v_rec.id, v_match.event_id, 'trigram+date+city', v_match.combined_score, 'pending');
          v_found := v_found+1;
        END IF;
      END LOOP;
    END LOOP;
  ELSIF p_entity_type='personalities' THEN
    SELECT count(*) INTO v_total FROM personalities;
    FOR v_rec IN SELECT id, name FROM personalities ORDER BY created_at DESC LIMIT p_limit OFFSET p_offset
    LOOP
      v_scanned := v_scanned+1;
      FOR v_match IN SELECT personality_id, personality_name, name_similarity
        FROM find_personality_duplicates(v_rec.name, p_threshold)
        WHERE personality_id != v_rec.id ORDER BY name_similarity DESC LIMIT 1
      LOOP
        IF NOT EXISTS (SELECT 1 FROM scraper_dedupe_decisions WHERE entity_type='personalities'
          AND ((entity_a_id=v_rec.id AND entity_b_id=v_match.personality_id) OR (entity_a_id=v_match.personality_id AND entity_b_id=v_rec.id))) THEN
          INSERT INTO scraper_dedupe_decisions (entity_type, entity_a_id, entity_b_id, match_method, confidence, decision)
          VALUES ('personalities', v_rec.id, v_match.personality_id, 'trigram_name', v_match.name_similarity, 'pending');
          v_found := v_found+1;
        END IF;
      END LOOP;
    END LOOP;
  ELSIF p_entity_type='news_articles' THEN
    SELECT count(*) INTO v_total FROM news_articles WHERE title IS NOT NULL AND title != '';
    FOR v_rec IN SELECT id, title, source_id, published_at FROM news_articles
      WHERE title IS NOT NULL AND title != '' ORDER BY created_at DESC LIMIT p_limit OFFSET p_offset
    LOOP
      v_scanned := v_scanned+1;
      FOR v_match IN SELECT article_id, article_title, combined_score
        FROM find_news_duplicates(v_rec.title, v_rec.source_id, v_rec.published_at, p_threshold)
        WHERE article_id != v_rec.id ORDER BY combined_score DESC LIMIT 1
      LOOP
        IF NOT EXISTS (SELECT 1 FROM scraper_dedupe_decisions WHERE entity_type='news_articles'
          AND ((entity_a_id=v_rec.id AND entity_b_id=v_match.article_id) OR (entity_a_id=v_match.article_id AND entity_b_id=v_rec.id))) THEN
          INSERT INTO scraper_dedupe_decisions (entity_type, entity_a_id, entity_b_id, match_method, confidence, decision)
          VALUES ('news_articles', v_rec.id, v_match.article_id, 'trigram_title', v_match.combined_score, 'pending');
          v_found := v_found+1;
        END IF;
      END LOOP;
    END LOOP;
  ELSIF p_entity_type='cities' THEN
    SELECT count(*) INTO v_total FROM cities;
    FOR v_rec IN SELECT id, name, country_id, latitude, longitude FROM cities ORDER BY created_at DESC LIMIT p_limit OFFSET p_offset
    LOOP
      v_scanned := v_scanned+1;
      FOR v_match IN SELECT city_id, city_name, combined_score
        FROM find_city_duplicates(v_rec.name, v_rec.country_id, v_rec.latitude, v_rec.longitude, p_threshold)
        WHERE city_id != v_rec.id ORDER BY combined_score DESC LIMIT 1
      LOOP
        IF NOT EXISTS (SELECT 1 FROM scraper_dedupe_decisions WHERE entity_type='cities'
          AND ((entity_a_id=v_rec.id AND entity_b_id=v_match.city_id) OR (entity_a_id=v_match.city_id AND entity_b_id=v_rec.id))) THEN
          INSERT INTO scraper_dedupe_decisions (entity_type, entity_a_id, entity_b_id, match_method, confidence, decision)
          VALUES ('cities', v_rec.id, v_match.city_id, 'trigram+country+geo', v_match.combined_score, 'pending');
          v_found := v_found+1;
        END IF;
      END LOOP;
    END LOOP;
  ELSE RETURN json_build_object('error', 'Unsupported entity_type: ' || p_entity_type); END IF;
  RETURN json_build_object('entity_type',p_entity_type,'scanned',v_scanned,'duplicates_found',v_found,
    'threshold',p_threshold,'offset',p_offset,'total',v_total,'has_more',(p_offset+v_scanned)<v_total);
END;
$$;


ALTER FUNCTION "public"."scan_table_duplicates"("p_entity_type" "text", "p_threshold" numeric, "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


