    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE scraper_snapshots
  SET archived_at = now(),
      r2_key = p_r2_key,
      content = NULL,
      content_gz = NULL
  WHERE id = p_id AND archived_at IS NULL;
END;
$$;


