CREATE OR REPLACE FUNCTION "public"."search_cities"("q" "text", "max_results" integer DEFAULT 8) RETURNS TABLE("id" "uuid", "name" "text", "timezone" "text", "country_id" "uuid", "country_name" "text", "country_code" "text")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'extensions'
    AS $$
  with needle as (
    select extensions.unaccent(lower(coalesce(q, ''))) as n
  )
  select c.id,
         c.name,
         c.timezone,
         co.id   as country_id,
         co.name as country_name,
         co.code as country_code
  from public.cities c
  join public.countries co on co.id = c.country_id,
       needle
  where length(needle.n) >= 2
    and (
      extensions.unaccent(lower(c.name)) like needle.n || '%'
      or extensions.unaccent(lower(c.name)) like '%' || needle.n || '%'
    )
  order by
    (extensions.unaccent(lower(c.name)) like needle.n || '%') desc,
    c.name asc
  limit greatest(1, least(coalesce(max_results, 8), 50));
$$;


ALTER FUNCTION "public"."search_cities"("q" "text", "max_results" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."search_events"("p_city" "text" DEFAULT NULL::"text", "p_event_type" "text" DEFAULT NULL::"text", "p_start" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_end" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_tags" "text"[] DEFAULT NULL::"text"[], "p_accessibility_attributes" "text"[] DEFAULT NULL::"text"[], "p_target_groups" "text"[] DEFAULT NULL::"text"[], "p_search" "text" DEFAULT NULL::"text", "p_include_past" boolean DEFAULT false, "p_limit" integer DEFAULT 24, "p_offset" integer DEFAULT 0) RETURNS TABLE("total" bigint, "event" "jsonb")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  WITH filtered AS (
    SELECT e.*
    FROM public.events e
    WHERE e.status = 'active'
      AND (
        CASE
          WHEN p_include_past THEN e.start_date <= now()
          ELSE COALESCE(e.end_date, e.start_date) >= now()
        END
      )
      AND (
        p_city IS NULL
        OR public.immutable_unaccent(lower(e.city))
           ILIKE '%' || public.immutable_unaccent(lower(p_city)) || '%'
      )
      AND (p_event_type IS NULL OR e.event_type = p_event_type)
      AND (p_end   IS NULL OR e.start_date                       <= p_end)
      AND (p_start IS NULL OR COALESCE(e.end_date, e.start_date) >= p_start)
      AND (p_accessibility_attributes IS NULL OR e.accessibility_attributes && p_accessibility_attributes)
      AND (p_target_groups IS NULL OR e.target_groups && p_target_groups)
      AND (
        p_search IS NULL
        OR e.title ILIKE '%' || p_search || '%'
        OR e.description ILIKE '%' || p_search || '%'
      )
  ),
  counted AS (SELECT count(*)::BIGINT AS total FROM filtered),
  paged AS (
    SELECT f.*
    FROM filtered f
    ORDER BY f.featured DESC,
             CASE WHEN p_include_past THEN f.start_date END DESC,
             CASE WHEN NOT p_include_past THEN f.start_date END ASC
    LIMIT  GREATEST(COALESCE(p_limit, 24), 1)
    OFFSET GREATEST(COALESCE(p_offset, 0), 0)
  )
  SELECT
    (SELECT total FROM counted) AS total,
    to_jsonb(p) || jsonb_build_object(
      'venues',
      CASE WHEN v.id IS NULL THEN NULL ELSE jsonb_build_object(
        'id',      v.id,
        'name',    v.name,
        'address', v.address,
        'city',    v.city,
        'state',   v.state,
        'country', v.country,
        'phone',   v.phone,
        'website', v.website,
        'email',   v.email
      ) END
    ) AS event
  FROM paged p
  LEFT JOIN public.venues v ON v.id = p.venue_id;
$$;


ALTER FUNCTION "public"."search_events"("p_city" "text", "p_event_type" "text", "p_start" timestamp with time zone, "p_end" timestamp with time zone, "p_tags" "text"[], "p_accessibility_attributes" "text"[], "p_target_groups" "text"[], "p_search" "text", "p_include_past" boolean, "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."search_tags_with_aliases"("q" "text", "p_limit" integer DEFAULT 20) RETURNS TABLE("id" "uuid", "name" "text", "slug" "text", "short_description" "text", "image_url" "text", "is_sensitive" boolean, "verification_status" "text", "match_via" "text", "match_score" real)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
WITH q_norm AS (SELECT lower(trim(q)) AS qn),
canonical AS (
  SELECT t.id, t.name, t.slug, t.short_description, t.image_url, t.is_sensitive, t.verification_status,
         'canonical'::text AS match_via,
         GREATEST(similarity(lower(t.name), (SELECT qn FROM q_norm)),
                  similarity(lower(t.slug), (SELECT qn FROM q_norm)))::real AS match_score
  FROM unified_tags t
  WHERE t.status='active'
    AND (lower(t.name) % (SELECT qn FROM q_norm)
         OR lower(t.slug) % (SELECT qn FROM q_norm)
         OR lower(t.name) ILIKE '%' || (SELECT qn FROM q_norm) || '%'
         OR lower(t.slug) ILIKE '%' || (SELECT qn FROM q_norm) || '%')
),
via_alias AS (
  SELECT t.id, t.name, t.slug, t.short_description, t.image_url, t.is_sensitive, t.verification_status,
         'alias'::text AS match_via,
         similarity(lower(a.alias_name), (SELECT qn FROM q_norm))::real AS match_score
  FROM tag_aliases a
  JOIN unified_tags t ON t.id = a.canonical_tag_id
  WHERE t.status='active'
    AND (lower(a.alias_name) % (SELECT qn FROM q_norm)
         OR lower(a.alias_name) ILIKE '%' || (SELECT qn FROM q_norm) || '%')
),
combined AS (SELECT * FROM canonical UNION ALL SELECT * FROM via_alias)
SELECT DISTINCT ON (id)
  id, name, slug, short_description, image_url, is_sensitive, verification_status, match_via, match_score
FROM combined
ORDER BY id, match_score DESC NULLS LAST
LIMIT p_limit;
$$;


ALTER FUNCTION "public"."search_tags_with_aliases"("q" "text", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."secure_passkey_access"("p_user_id" "uuid", "p_operation" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  -- Enhanced rate limiting for passkey operations
  IF NOT public.basic_rate_limit(
    'passkey_ops_' || p_user_id::TEXT, 
    5  -- Max 5 passkey operations per hour
  ) THEN
    PERFORM public.log_enhanced_security_event(
      'PASSKEY_RATE_LIMIT_EXCEEDED',
      p_user_id,
      jsonb_build_object(
        'operation', p_operation,
        'timestamp', NOW()
      ),
      'high'
    );
    RETURN FALSE;
  END IF;
  
  -- Log passkey access
  PERFORM public.log_enhanced_security_event(
    'PASSKEY_DATA_ACCESS',
    p_user_id,
    jsonb_build_object(
      'operation', p_operation,
      'timestamp', NOW()
    ),
    'medium'
  );
  
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."secure_passkey_access"("p_user_id" "uuid", "p_operation" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."set_publisher_name"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $_$
DECLARE
  domain TEXT;
  api_source BOOLEAN;
BEGIN
  -- Only act when publisher_name is null and url is present
  IF NEW.publisher_name IS NOT NULL OR NEW.url IS NULL THEN
    RETURN NEW;
  END IF;

  -- Check if this is from an API aggregator source
  SELECT EXISTS(
    SELECT 1 FROM news_sources 
    WHERE id = NEW.source_id 
    AND name IN ('NewsAPI.org', 'NewsData.io', 'GNews.io', 'TheNewsAPI.com', 'Google News LGBT Rights')
  ) INTO api_source;

  -- Only derive publisher for API sources; RSS sources use their own name
  IF NOT api_source THEN
    RETURN NEW;
  END IF;

  -- Extract domain from URL
  domain := REGEXP_REPLACE(NEW.url, '^https?://(www\.)?', '');
  domain := REGEXP_REPLACE(domain, '/.*$', '');

  -- Map known domains
  NEW.publisher_name := CASE
    WHEN domain ILIKE '%nytimes.com' THEN 'New York Times'
    WHEN domain ILIKE '%washingtonpost.com' THEN 'Washington Post'
    WHEN domain ILIKE '%theguardian.com' THEN 'The Guardian'
    WHEN domain ILIKE '%bbc.com' OR domain ILIKE '%bbc.co.uk' THEN 'BBC'
    WHEN domain ILIKE '%cnn.com' THEN 'CNN'
    WHEN domain ILIKE '%nbcnews.com' THEN 'NBC News'
    WHEN domain ILIKE '%abcnews.go.com' THEN 'ABC News'
    WHEN domain ILIKE '%cbsnews.com' THEN 'CBS News'
    WHEN domain ILIKE '%reuters.com' THEN 'Reuters'
    WHEN domain ILIKE '%apnews.com' THEN 'AP News'
    WHEN domain ILIKE '%huffpost.com' THEN 'HuffPost'
    WHEN domain ILIKE '%advocate.com' THEN 'The Advocate'
    WHEN domain ILIKE '%pinknews.co.uk' OR domain ILIKE '%thepinknews.com' THEN 'Pink News'
    WHEN domain ILIKE '%lgbtqnation.com' THEN 'LGBTQ Nation'
    WHEN domain ILIKE '%queerty.com' THEN 'Queerty'
    WHEN domain ILIKE '%outsports.com' THEN 'Outsports'
    WHEN domain ILIKE '%out.com' THEN 'Out Magazine'
    WHEN domain ILIKE '%them.us' THEN 'Them'
    WHEN domain ILIKE '%washingtonblade.com' THEN 'Washington Blade'
    WHEN domain ILIKE '%latimes.com' THEN 'LA Times'
    WHEN domain ILIKE '%npr.org' THEN 'NPR'
    WHEN domain ILIKE '%politico.com' THEN 'Politico'
    WHEN domain ILIKE '%axios.com' THEN 'Axios'
    WHEN domain ILIKE '%forbes.com' THEN 'Forbes'
    WHEN domain ILIKE '%newsweek.com' THEN 'Newsweek'
    WHEN domain ILIKE '%yahoo.com' THEN 'Yahoo News'
    WHEN domain ILIKE '%reddit.com' THEN 'Reddit'
    WHEN domain ILIKE '%19thnews.org' THEN 'The 19th'
    WHEN domain ILIKE '%metroweekly.com' THEN 'Metro Weekly'
    WHEN domain ILIKE '%foxnews.com' THEN 'Fox News'
    WHEN domain ILIKE '%dailycaller.com' THEN 'Daily Caller'
    WHEN domain ILIKE '%dailykos.com' THEN 'Daily Kos'
    WHEN domain ILIKE '%pennlive.com' THEN 'PennLive'
    WHEN domain ILIKE '%salon.com' THEN 'Salon'
    WHEN domain ILIKE '%slate.com' THEN 'Slate'
    WHEN domain ILIKE '%vox.com' THEN 'Vox'
    WHEN domain ILIKE '%theatlantic.com' THEN 'The Atlantic'
    WHEN domain ILIKE '%rollingstone.com' THEN 'Rolling Stone'
    WHEN domain ILIKE '%variety.com' THEN 'Variety'
    WHEN domain ILIKE '%espn.com' THEN 'ESPN'
    WHEN domain ILIKE '%people.com' THEN 'People'
    WHEN domain ILIKE '%usatoday.com' THEN 'USA Today'
    WHEN domain ILIKE '%sfgate.com' THEN 'SFGate'
    WHEN domain ILIKE '%independent.co.uk' THEN 'The Independent'
    WHEN domain ILIKE '%aljazeera.com' THEN 'Al Jazeera'
    WHEN domain ILIKE '%pbs.org' THEN 'PBS'
    WHEN domain ILIKE '%bloomberg.com' THEN 'Bloomberg'
    WHEN domain ILIKE '%wired.com' THEN 'Wired'
    WHEN domain ILIKE '%thedailybeast.com' THEN 'The Daily Beast'
    WHEN domain ILIKE '%erininthemorning.com' THEN 'Erin in the Morning'
    ELSE INITCAP(REPLACE(REPLACE(SPLIT_PART(domain, '.', 1), '-', ' '), '_', ' '))
  END;

  RETURN NEW;
END;
$_$;


ALTER FUNCTION "public"."set_publisher_name"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."set_story_narrative"("p_story_id" "uuid", "p_brief_title" "text", "p_narrative" "text", "p_mark_edited" boolean DEFAULT true) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  UPDATE feedback_stories
     SET brief_title = COALESCE(p_brief_title, brief_title),
         narrative   = COALESCE(p_narrative, narrative),
         narrative_edited = CASE WHEN p_mark_edited THEN true ELSE narrative_edited END
   WHERE id = p_story_id;
END;
$$;


