    AS $$
  SELECT jsonb_build_object(
    'id', id, 'name', name, 'display_name', display_name, 'version', version,
    'nodes', nodes, 'edges', edges, 'default_context', default_context,
    'max_concurrency', max_concurrency, 'timeout_seconds', timeout_seconds,
    'snapshotted_at', now()
  ) FROM pipeline_definitions WHERE id = p_pipeline_id;
$$;


