CREATE OR REPLACE FUNCTION "public"."snapshot_pipeline_version"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only snapshot if a version bump occurred or this is a fresh insert
  IF TG_OP = 'UPDATE' AND NEW.version = OLD.version THEN
    RETURN NEW;
  END IF;

  INSERT INTO pipeline_definition_versions (
    pipeline_id, version, name, display_name, description,
    nodes, edges, schedule, default_context, saved_by
  ) VALUES (
    NEW.id, NEW.version, NEW.name, NEW.display_name, NEW.description,
    NEW.nodes, NEW.edges, NEW.schedule, COALESCE(NEW.default_context, '{}'::jsonb),
    auth.uid()
  )
  ON CONFLICT (pipeline_id, version) DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."snapshot_pipeline_version"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."stage_event_for_commit"("p_source_type" "text", "p_source_name" "text", "p_source_entity_id" "text", "p_raw" "jsonb", "p_normalized" "jsonb" DEFAULT NULL::"jsonb", "p_source_url" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE
  v_id UUID;
  v_hash TEXT := encode(extensions.digest(coalesce(p_raw::text,''), 'sha256'), 'hex');
  v_norm JSONB := coalesce(p_normalized, p_raw);
BEGIN
  -- Idempotency: skip if already staged with same hash
  SELECT id INTO v_id FROM public.ingestion_staging
  WHERE source_type = p_source_type
    AND source_entity_id = p_source_entity_id
    AND payload_hash = v_hash
  LIMIT 1;
  IF v_id IS NOT NULL THEN RETURN v_id; END IF;

  INSERT INTO public.ingestion_staging (
    source_type, source_name, target_table, entity_type,
    raw_data, normalized_data,
    source_entity_id, payload_hash,
    ai_validation_status, dedup_status, disposition, review_status
  ) VALUES (
    p_source_type, coalesce(p_source_name, p_source_type), 'events', 'event',
    p_raw, v_norm,
    p_source_entity_id, v_hash,
    'pending', 'pending', 'pending', 'auto'
  ) RETURNING id INTO v_id;

  INSERT INTO public.ingestion_events (staging_id, stage, new_status, actor, payload)
  VALUES (v_id, 'stage', 'pending', 'api-importer',
          jsonb_build_object('source_type', p_source_type, 'source_entity_id', p_source_entity_id,
                             'source_url', p_source_url, 'target_table', 'events'));

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."stage_event_for_commit"("p_source_type" "text", "p_source_name" "text", "p_source_entity_id" "text", "p_raw" "jsonb", "p_normalized" "jsonb", "p_source_url" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."start_retest"("p_run_id" "uuid", "p_kind" "text", "p_runner" "text" DEFAULT 'mock'::"text") RETURNS "public"."feedback_retest_runs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_run feedback_routine_runs%ROWTYPE; v_retest feedback_retest_runs%ROWTYPE;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  IF p_kind NOT IN ('typecheck','lint','unit','e2e','targeted') THEN RAISE EXCEPTION 'invalid_kind'; END IF;
  IF p_runner NOT IN ('mock','github_actions','webhook','local') THEN RAISE EXCEPTION 'invalid_runner'; END IF;
  SELECT * INTO v_run FROM feedback_routine_runs WHERE id = p_run_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'run_not_found'; END IF;
  IF v_run.status NOT IN ('fix_proposed','in_progress') THEN
    RAISE EXCEPTION 'cannot_retest_in_status: %', v_run.status;
  END IF;
  INSERT INTO feedback_retest_runs (routine_run_id, kind, runner, status, created_by)
  VALUES (p_run_id, p_kind, p_runner, 'queued', auth.uid())
  RETURNING * INTO v_retest;
  PERFORM _fb_log_event(v_run.story_id, 'retest_started',
    jsonb_build_object('kind', p_kind, 'runner', p_runner, 'retest_id', v_retest.id),
    'user', v_run.id, v_retest.id);
  RETURN v_retest;
END;
$$;


ALTER FUNCTION "public"."start_retest"("p_run_id" "uuid", "p_kind" "text", "p_runner" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."story_member_divergence"("p_story_id" "uuid") RETURNS TABLE("status_diff" integer, "priority_diff" integer, "assignee_diff" integer)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH story AS (
    SELECT status, priority, assignee_id FROM feedback_stories WHERE id = p_story_id
  ),
  members AS (
    SELECT cs.feedback_status, cs.priority, cs.assignee_id
      FROM feedback_story_members m
      JOIN community_submissions cs ON cs.id = m.submission_id
     WHERE m.story_id = p_story_id
  )
  SELECT
    COUNT(*) FILTER (
      WHERE m.feedback_status <> CASE (SELECT status FROM story)
        WHEN 'planned' THEN 'planned'
        WHEN 'in_progress' THEN 'in_progress'
        WHEN 'resolved' THEN 'done'
        WHEN 'archived' THEN 'done'
        ELSE m.feedback_status
      END
    )::integer AS status_diff,
    COUNT(*) FILTER (WHERE m.priority <> (SELECT priority FROM story))::integer AS priority_diff,
    COUNT(*) FILTER (
      WHERE m.assignee_id IS DISTINCT FROM (SELECT assignee_id FROM story)
    )::integer AS assignee_diff
  FROM members m;
$$;


ALTER FUNCTION "public"."story_member_divergence"("p_story_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."suggest_story_from_ids"("p_submission_ids" "uuid"[]) RETURNS TABLE("proposed_title" "text", "member_ids" "uuid"[], "avg_similarity" real)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_eligible uuid[];
  v_avg real;
  v_title text;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  IF array_length(p_submission_ids, 1) IS NULL THEN
    RAISE EXCEPTION 'submission_ids must not be empty';
  END IF;

  SELECT array_agg(cs.id ORDER BY cs.id) INTO v_eligible
    FROM community_submissions cs
   WHERE cs.id = ANY(p_submission_ids)
     AND cs.content_type IN ('feedback','api_error')
     AND cs.duplicate_of IS NULL
     AND cs.is_spam = false
     AND NOT EXISTS (
       SELECT 1 FROM feedback_story_members m
         JOIN feedback_stories s ON s.id = m.story_id
        WHERE m.submission_id = cs.id
          AND s.status NOT IN ('resolved','archived')
     );

  IF v_eligible IS NULL OR array_length(v_eligible, 1) < 2 THEN
    proposed_title := NULL;
    member_ids := COALESCE(v_eligible, ARRAY[]::uuid[]);
    avg_similarity := 0;
    RETURN NEXT;
    RETURN;
  END IF;

  WITH pairs AS (
    SELECT
      GREATEST(
        0.4 * COALESCE(similarity(a.data->>'title', b.data->>'title'), 0)
        + 0.6 * COALESCE(1 - (a.embedding <=> b.embedding), 0),
        0.0
      )::real AS score
    FROM community_submissions a
    JOIN community_submissions b
      ON a.id < b.id
     AND a.id = ANY(v_eligible)
     AND b.id = ANY(v_eligible)
  )
  SELECT avg(score) INTO v_avg FROM pairs;

  SELECT cs.data->>'title' INTO v_title
    FROM community_submissions cs
   WHERE cs.id = ANY(v_eligible)
   ORDER BY cs.submitted_at ASC
   LIMIT 1;

  proposed_title := COALESCE(v_title, 'Related feedback cluster');
  member_ids := v_eligible;
  avg_similarity := COALESCE(v_avg, 0);
  RETURN NEXT;
END;
$$;


ALTER FUNCTION "public"."suggest_story_from_ids"("p_submission_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_tag_category_assignment"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- When category_id changes, update the primary assignment
  IF NEW.category_id IS DISTINCT FROM OLD.category_id AND NEW.category_id IS NOT NULL THEN
    -- Remove old primary
    UPDATE tag_category_assignments
    SET is_primary = false
    WHERE tag_id = NEW.id AND is_primary = true;
    
    -- Upsert new primary
    INSERT INTO tag_category_assignments (tag_id, category_id, is_primary)
    VALUES (NEW.id, NEW.category_id, true)
    ON CONFLICT (tag_id, category_id) 
    DO UPDATE SET is_primary = true;
    
    -- Sync text column
    NEW.category := (SELECT name FROM tag_categories WHERE id = NEW.category_id);
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_tag_category_assignment"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tag_hygiene_report"() RETURNS TABLE("issue_type" "text", "issue_count" bigint, "sample_items" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
  -- Orphaned tags (active but no category)
  SELECT 'orphaned_no_category'::TEXT, COUNT(*), 
    STRING_AGG(name, ', ' ORDER BY name) 
  FROM unified_tags WHERE status = 'active' AND category_id IS NULL
  
  UNION ALL
  
  -- Tags with no junction table entry
  SELECT 'missing_junction_entry'::TEXT, COUNT(*),
    STRING_AGG(ut.name, ', ' ORDER BY ut.name)
  FROM unified_tags ut
  LEFT JOIN tag_category_assignments tca ON tca.tag_id = ut.id
  WHERE ut.status = 'active' AND tca.id IS NULL
  
  UNION ALL
  
  -- Tags in Miscellaneous (should be further classified)
  SELECT 'miscellaneous_active'::TEXT, COUNT(*),
    LEFT(STRING_AGG(name, ', ' ORDER BY name), 200)
  FROM unified_tags WHERE status = 'active' AND category = 'Miscellaneous'
  
  UNION ALL
  
  -- Near-duplicate pairs (similarity > 0.8)
  SELECT 'near_duplicates'::TEXT, COUNT(*),
    LEFT(STRING_AGG(a.name || ' <-> ' || b.name, '; '), 200)
  FROM unified_tags a
  JOIN unified_tags b ON a.id < b.id
  WHERE a.status = 'active' AND b.status = 'active'
    AND extensions.similarity(LOWER(a.name), LOWER(b.name)) > 0.8
  
  UNION ALL
  
  -- Tags with out-of-sync text category vs FK
  SELECT 'category_out_of_sync'::TEXT, COUNT(*),
    LEFT(STRING_AGG(ut.name || ' (text=' || COALESCE(ut.category, 'NULL') || ', fk=' || COALESCE(tc.name, 'NULL') || ')', '; '), 200)
  FROM unified_tags ut
  LEFT JOIN tag_categories tc ON ut.category_id = tc.id
  WHERE ut.status = 'active' AND ut.category IS DISTINCT FROM tc.name;
$$;


ALTER FUNCTION "public"."tag_hygiene_report"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tags_missing_descriptions"("p_limit" integer) RETURNS TABLE("id" "uuid", "name" "text", "slug" "text", "human_reviewed" boolean)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  SELECT id, name, slug, human_reviewed
  FROM unified_tags
  WHERE status='active'
    AND human_reviewed IS NOT TRUE
    AND (short_description IS NULL OR long_description IS NULL)
  ORDER BY random()
  LIMIT p_limit;
$$;


