CREATE OR REPLACE FUNCTION "public"."tags_missing_embeddings"("p_limit" integer DEFAULT 1000) RETURNS TABLE("id" "uuid", "name" "text", "slug" "text", "short_description" "text", "updated_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT t.id, t.name, t.slug, t.short_description, t.updated_at
  FROM unified_tags t
  LEFT JOIN tag_embeddings e ON e.tag_id = t.id
  WHERE t.status='active' AND e.tag_id IS NULL
  ORDER BY t.updated_at DESC
  LIMIT p_limit;
$$;


