CREATE OR REPLACE FUNCTION "public"."track_event_secure"("p_session_id" "text", "p_event_type" "text", "p_entity_type" "text", "p_entity_id" "text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE v_uid uuid := auth.uid(); v_id uuid;
BEGIN
  IF p_event_type NOT IN ('click','view','save','favorite','book','attend','dismiss') THEN
    RAISE EXCEPTION 'bad event_type';
  END IF;
  IF p_entity_type NOT IN ('venue','event','city','country','personality','news','tag','marketplace','queer_village') THEN
    RAISE EXCEPTION 'bad entity_type';
  END IF;
  IF length(coalesce(p_session_id,'')) > 64 OR length(p_entity_id) > 64 THEN
    RAISE EXCEPTION 'field too long';
  END IF;

  INSERT INTO user_events(user_id, session_id, event_type, entity_type, entity_id, metadata)
  VALUES (v_uid, p_session_id, p_event_type, p_entity_type, p_entity_id, p_metadata)
  RETURNING id INTO v_id;
  RETURN v_id;
END $$;


