    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO public.trip_members (trip_id, user_id, role, accepted_at)
  VALUES (NEW.id, NEW.owner_id, 'owner', now())
  ON CONFLICT (trip_id, user_id) DO NOTHING;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trip_auto_add_owner"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trip_auto_generate_days"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.start_date IS NOT NULL AND NEW.end_date IS NOT NULL
     AND NEW.start_date <= NEW.end_date
     AND (OLD IS NULL OR OLD.start_date IS DISTINCT FROM NEW.start_date OR OLD.end_date IS DISTINCT FROM NEW.end_date)
  THEN
    DELETE FROM public.trip_days
    WHERE trip_id = NEW.id
      AND date NOT BETWEEN NEW.start_date AND NEW.end_date;

    INSERT INTO public.trip_days (trip_id, date, sort_order)
    SELECT NEW.id, d::date, (ROW_NUMBER() OVER (ORDER BY d))::int - 1
    FROM generate_series(NEW.start_date, NEW.end_date, '1 day'::interval) AS d
    ON CONFLICT (trip_id, date) DO NOTHING;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trip_auto_generate_days"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trip_places_backfill_geo"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
BEGIN
  IF NEW.country_id IS NULL OR NEW.city_id IS NULL THEN
    IF NEW.venue_id IS NOT NULL THEN
      SELECT COALESCE(NEW.country_id, v.country_id),
             COALESCE(NEW.city_id, v.city_id)
        INTO NEW.country_id, NEW.city_id
        FROM venues v WHERE v.id = NEW.venue_id;
    ELSIF NEW.event_id IS NOT NULL THEN
      SELECT COALESCE(NEW.country_id, e.country_id),
             COALESCE(NEW.city_id, e.city_id)
        INTO NEW.country_id, NEW.city_id
        FROM events e WHERE e.id = NEW.event_id;
    ELSIF NEW.hotel_id IS NOT NULL THEN
      SELECT COALESCE(NEW.country_id, h.country_id),
             COALESCE(NEW.city_id, h.city_id)
        INTO NEW.country_id, NEW.city_id
        FROM hotels h WHERE h.id = NEW.hotel_id;
    END IF;
  END IF;
  RETURN NEW;
END $$;


ALTER FUNCTION "public"."trip_places_backfill_geo"() OWNER TO "postgres";


