ALTER FUNCTION "public"."trip_update_timestamp"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trips_denorm_geo"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.primary_city_id IS NOT NULL
     AND (OLD IS NULL OR NEW.primary_city_id IS DISTINCT FROM OLD.primary_city_id) THEN
    SELECT c.name, c.timezone, c.country_id
      INTO NEW.primary_city_name, NEW.timezone, NEW.primary_country_id
    FROM public.cities c
    WHERE c.id = NEW.primary_city_id;
  END IF;

  IF NEW.primary_country_id IS NOT NULL
     AND (OLD IS NULL OR NEW.primary_country_id IS DISTINCT FROM OLD.primary_country_id
          OR NEW.primary_country_code IS NULL) THEN
    SELECT code INTO NEW.primary_country_code
    FROM public.countries
    WHERE id = NEW.primary_country_id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trips_denorm_geo"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."unarchive_story"("p_story_id" "uuid") RETURNS "public"."feedback_stories"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_story feedback_stories%ROWTYPE;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  UPDATE feedback_stories
     SET archived_at=NULL, archived_by=NULL, archive_reason=NULL,
         status = CASE WHEN status='archived' THEN 'open' ELSE status END
   WHERE id = p_story_id RETURNING * INTO v_story;
  IF NOT FOUND THEN RAISE EXCEPTION 'story_not_found' USING ERRCODE = 'P0002'; END IF;
  PERFORM _fb_log_event(p_story_id, 'unarchived', '{}'::jsonb);
  RETURN v_story;
END;
$$;


ALTER FUNCTION "public"."unarchive_story"("p_story_id" "uuid") OWNER TO "postgres";


