CREATE OR REPLACE FUNCTION "public"."upsert_api_error"("p_fingerprint" "text", "p_data" "jsonb", "p_source" "text" DEFAULT 'unknown'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id uuid;
BEGIN
  -- Try to bump existing row with same fingerprint
  UPDATE community_submissions
  SET occurrence_count = occurrence_count + 1,
      last_seen_at = now(),
      data = jsonb_set(
        data,
        '{last_occurrence}',
        p_data
      )
  WHERE fingerprint = p_fingerprint
    AND content_type = 'api_error'
  RETURNING id INTO v_id;

  IF v_id IS NOT NULL THEN
    RETURN v_id;
  END IF;

  -- Insert new row
  INSERT INTO community_submissions (
    content_type, data, fingerprint, occurrence_count, last_seen_at, feedback_status
  ) VALUES (
    'api_error', p_data, p_fingerprint, 1, now(), 'new'
  )
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."upsert_api_error"("p_fingerprint" "text", "p_data" "jsonb", "p_source" "text") OWNER TO "postgres";


