CREATE OR REPLACE FUNCTION "public"."validate_content_security"("content_text" "text", "content_type" "text" DEFAULT 'general'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
DECLARE
  result jsonb;
  security_score integer := 100;
  errors text[] := '{}';
BEGIN
  IF content_text ~* '<script|javascript:|on\w+=' THEN
    security_score := security_score - 50;
    errors := array_append(errors, 'Potentially malicious script detected'); END IF;
  IF content_text ~* '(union|select|insert|update|delete|drop)\s' THEN
    security_score := security_score - 30;
    errors := array_append(errors, 'Potentially malicious SQL detected'); END IF;
  IF length(content_text) > 10000 THEN
    security_score := security_score - 20;
    errors := array_append(errors, 'Content exceeds maximum length'); END IF;
  result := jsonb_build_object(
    'is_valid', array_length(errors, 1) IS NULL,
    'errors', errors,
    'security_level',
      CASE WHEN security_score >= 80 THEN 'low'
           WHEN security_score >= 50 THEN 'medium'
           ELSE 'high' END,
    'strength_score', security_score);
  RETURN result;
END;
$$;


ALTER FUNCTION "public"."validate_content_security"("content_text" "text", "content_type" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_file_upload"("file_name" "text", "file_size" integer, "mime_type" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $_$
DECLARE
  result jsonb;
  errors text[] := '{}';
  max_size integer := 10 * 1024 * 1024;
  allowed_types text[] := ARRAY[
    'image/jpeg','image/png','image/gif','image/webp',
    'video/mp4','video/webm','audio/mpeg','audio/wav'];
BEGIN
  IF file_size > max_size THEN
    errors := array_append(errors, 'File size exceeds 10MB limit'); END IF;
  IF NOT (mime_type = ANY(allowed_types)) THEN
    errors := array_append(errors, 'File type not allowed'); END IF;
  IF file_name ~* '\.(exe|bat|cmd|scr|pif|com|jar|zip|rar)$' THEN
    errors := array_append(errors, 'File extension not allowed'); END IF;
  result := jsonb_build_object(
    'is_valid', array_length(errors, 1) IS NULL,
    'errors', errors,
    'file_info', jsonb_build_object('name', file_name, 'size', file_size, 'type', mime_type));
  RETURN result;
END;
$_$;


ALTER FUNCTION "public"."validate_file_upload"("file_name" "text", "file_size" integer, "mime_type" "text") OWNER TO "postgres";


