CREATE OR REPLACE FUNCTION "public"."validate_password_enhanced"("password_text" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
DECLARE
  result jsonb;
  strength_score integer := 0;
  errors text[] := '{}';
BEGIN
  IF length(password_text) >= 8 THEN strength_score := strength_score + 25;
  ELSE errors := array_append(errors, 'Password must be at least 8 characters'); END IF;
  IF password_text ~ '[A-Z]' THEN strength_score := strength_score + 20;
  ELSE errors := array_append(errors, 'Password must contain uppercase letters'); END IF;
  IF password_text ~ '[a-z]' THEN strength_score := strength_score + 20;
  ELSE errors := array_append(errors, 'Password must contain lowercase letters'); END IF;
  IF password_text ~ '[0-9]' THEN strength_score := strength_score + 20;
  ELSE errors := array_append(errors, 'Password must contain numbers'); END IF;
  IF password_text ~ '[^A-Za-z0-9]' THEN strength_score := strength_score + 15;
  ELSE errors := array_append(errors, 'Password must contain special characters'); END IF;
  result := jsonb_build_object(
    'is_valid', strength_score >= 85,
    'errors', errors,
    'strength_score', strength_score,
    'strength_level',
      CASE WHEN strength_score >= 85 THEN 'strong'
           WHEN strength_score >= 60 THEN 'medium'
           ELSE 'weak' END);
  RETURN result;
END;
$$;


ALTER FUNCTION "public"."validate_password_enhanced"("password_text" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_privacy_settings"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  -- Ensure privacy_settings is properly structured with secure defaults
  IF NEW.privacy_settings IS NULL OR NEW.privacy_settings = '{}'::jsonb THEN
    NEW.privacy_settings := jsonb_build_object(
      'profile_visibility', false,
      'location_public', false,
      'pronouns_public', false,
      'contact_public', false,
      'interests_public', false,
      'sexual_orientation_public', false,
      'gender_identity_public', false,
      'bio_public', true,
      'phone_public', false,
      'emergency_contact_public', false,
      'relationship_status_public', false,
      'income_range_public', false,
      'political_views_public', false,
      'religious_beliefs_public', false
    );
  END IF;
  
  -- Log privacy setting changes for audit
  IF TG_OP = 'UPDATE' AND OLD.privacy_settings IS DISTINCT FROM NEW.privacy_settings THEN
    PERFORM public.log_enhanced_security_event(
      'PRIVACY_SETTINGS_UPDATED',
      NEW.user_id,
      jsonb_build_object(
        'old_settings', OLD.privacy_settings,
        'new_settings', NEW.privacy_settings,
        'timestamp', NOW()
      ),
      'medium'
    );
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_privacy_settings"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_profile_access"("requesting_user_id" "uuid", "profile_user_id" "uuid", "access_type" "text" DEFAULT 'read'::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  -- Owner always has access
  IF requesting_user_id = profile_user_id THEN
    RETURN TRUE;
  END IF;
  
  -- For non-owners, only allow basic read access to public profiles
  IF access_type = 'read' THEN
    RETURN EXISTS (
      SELECT 1 FROM public.profiles 
      WHERE user_id = profile_user_id 
      AND COALESCE((privacy_settings->>'profile_visibility')::boolean, false) = true
    );
  END IF;
  
  -- All other access denied
  RETURN FALSE;
END;
$$;


ALTER FUNCTION "public"."validate_profile_access"("requesting_user_id" "uuid", "profile_user_id" "uuid", "access_type" "text") OWNER TO "postgres";


