CREATE OR REPLACE FUNCTION "public"."verify_story"("p_story_id" "uuid", "p_outcome" "text", "p_note" "text" DEFAULT NULL::"text") RETURNS "public"."feedback_stories"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_story feedback_stories%ROWTYPE; v_kind text;
BEGIN
  IF NOT has_any_role_jwt(ARRAY['admin'::app_role, 'moderator'::app_role]) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  IF p_outcome NOT IN ('resolved','reopen','needs_followup') THEN RAISE EXCEPTION 'invalid_outcome'; END IF;
  IF p_outcome = 'resolved' THEN
    UPDATE feedback_stories SET status='resolved', resolved_at=COALESCE(resolved_at, now())
     WHERE id = p_story_id RETURNING * INTO v_story;
    v_kind := 'verified';
  ELSIF p_outcome = 'reopen' THEN
    UPDATE feedback_stories
       SET status='in_progress', resolved_at=NULL, archived_at=NULL,
           archived_by=NULL, archive_reason=NULL
     WHERE id = p_story_id RETURNING * INTO v_story;
    v_kind := 'reopened';
  ELSE
    UPDATE feedback_stories
       SET needs_followup_reason = COALESCE(p_note, needs_followup_reason)
     WHERE id = p_story_id RETURNING * INTO v_story;
    v_kind := 'needs_followup';
  END IF;
  IF NOT FOUND THEN RAISE EXCEPTION 'story_not_found' USING ERRCODE = 'P0002'; END IF;
  PERFORM _fb_log_event(p_story_id, v_kind,
    jsonb_build_object('outcome', p_outcome, 'note', p_note));
  RETURN v_story;
END;
$$;


ALTER FUNCTION "public"."verify_story"("p_story_id" "uuid", "p_outcome" "text", "p_note" "text") OWNER TO "postgres";


