    CONSTRAINT "events_slug_format_chk" CHECK ((("slug" IS NULL) OR ("slug" ~ '^[a-z0-9][a-z0-9-]*[a-z0-9]$'::"text") OR ("slug" ~ '^[a-z0-9]$'::"text"))),
    CONSTRAINT "events_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'cancelled'::"text", 'postponed'::"text", 'completed'::"text"])))
);


