COMMENT ON COLUMN "public"."events"."content_language" IS 'ISO 639-1 code of the language the human-authored fields (title, description) are written in. NULL = unknown, UI falls back to client detection.';



CREATE OR REPLACE VIEW "public"."cities_admin" WITH ("security_invoker"='true') AS
 SELECT "c"."id",
    "c"."name",
    "c"."country_id",
    "c"."region_name",
    "c"."population",
    "c"."latitude",
    "c"."longitude",
    "c"."timezone",
    "c"."is_capital",
    "c"."is_major_city",
    "c"."major_airport_code",
    "c"."created_at",
    "c"."updated_at",
    "co"."name" AS "country_name",
    COALESCE("co"."lgbt_legal_status",
        CASE
            WHEN ("co"."lgbti_same_sex_unions" IS NULL) THEN NULL::"text"
            WHEN ("left"("co"."lgbti_same_sex_unions", 1) = '{'::"text") THEN (("co"."lgbti_same_sex_unions")::"jsonb" ->> 'summary'::"text")
            ELSE "co"."lgbti_same_sex_unions"
        END) AS "lgbt_legal_status",
    COALESCE("co"."lgbt_rights_status",
        CASE
            WHEN ("co"."equality_score" >= 80) THEN 'High protections'::"text"
            WHEN ("co"."equality_score" >= 60) THEN 'Moderate protections'::"text"
            WHEN ("co"."equality_score" >= 40) THEN 'Limited protections'::"text"
            WHEN ("co"."equality_score" >= 20) THEN 'Restricted'::"text"
            WHEN ("co"."equality_score" IS NOT NULL) THEN 'Hostile'::"text"
            ELSE NULL::"text"
        END) AS "lgbt_rights_status",
    "co"."equality_score",
    "co"."continent_id",
    COALESCE("v"."venue_count", (0)::bigint) AS "venue_count",
    COALESCE("e"."event_count", (0)::bigint) AS "event_count"
   FROM ((("public"."cities" "c"
     LEFT JOIN "public"."countries" "co" ON (("co"."id" = "c"."country_id")))
     LEFT JOIN ( SELECT "venues"."city_id",
            "count"(*) AS "venue_count"
           FROM "public"."venues"
          WHERE ("venues"."city_id" IS NOT NULL)
          GROUP BY "venues"."city_id") "v" ON (("v"."city_id" = "c"."id")))
     LEFT JOIN ( SELECT "events"."city_id",
            "count"(*) AS "event_count"
           FROM "public"."events"
          WHERE ("events"."city_id" IS NOT NULL)
          GROUP BY "events"."city_id") "e" ON (("e"."city_id" = "c"."id")));


ALTER VIEW "public"."cities_admin" OWNER TO "postgres";


COMMENT ON VIEW "public"."cities_admin" IS 'Read-only flat view of cities with joined country LGBT data and venue/event counts. Used by the admin Cities CMS page (AdminCities.tsx). security_invoker preserves RLS from cities/countries.';



