CREATE OR REPLACE VIEW "public"."city_ingest_stats" WITH ("security_invoker"='true') AS
 SELECT "date_trunc"('day'::"text", "created_at") AS "day",
    "source_type" AS "source",
    "count"(*) AS "staged",
    "count"(*) FILTER (WHERE ("ai_validation_status" = 'approved'::"text")) AS "validated",
    "count"(*) FILTER (WHERE ("dedup_status" = 'unique'::"text")) AS "unique_items",
    "count"(*) FILTER (WHERE ("dedup_status" = 'duplicate'::"text")) AS "duplicates",
    "count"(*) FILTER (WHERE ("dedup_status" = 'merge_candidate'::"text")) AS "merge_candidates",
    "count"(*) FILTER (WHERE ("disposition" = ANY (ARRAY['inserted'::"text", 'updated'::"text"]))) AS "committed",
    "count"(*) FILTER (WHERE ("disposition" = 'rejected'::"text")) AS "rejected",
    "count"(*) FILTER (WHERE ("review_status" = 'pending_review'::"text")) AS "pending_review"
   FROM "public"."ingestion_staging"
  WHERE ("target_table" = 'cities'::"text")
  GROUP BY ("date_trunc"('day'::"text", "created_at")), "source_type";


