    "city_id" "uuid",
    "entity_type" "text" DEFAULT 'venue'::"text" NOT NULL,
    "accommodation_type" "text",
    "expected_count" integer,
    "actual_count" integer DEFAULT 0 NOT NULL,
    "last_run_at" timestamp with time zone,
    "last_success_at" timestamp with time zone,
    "success_ratio" numeric(4,3),
    "is_enabled" boolean DEFAULT true NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "public"."source_coverage_targets" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."coverage_gaps" WITH ("security_invoker"='true') AS
 SELECT "t"."source_slug",
    "c"."name" AS "city",
    "t"."accommodation_type",
    "t"."expected_count",
    "t"."actual_count",
    "t"."success_ratio",
    "t"."last_run_at",
        CASE
            WHEN ("t"."last_run_at" IS NULL) THEN 'never_run'::"text"
            WHEN ("t"."last_run_at" < ("now"() - '14 days'::interval)) THEN 'stale'::"text"
            WHEN (COALESCE("t"."success_ratio", (0)::numeric) < 0.4) THEN 'under_target'::"text"
            WHEN (COALESCE("t"."success_ratio", (0)::numeric) < 0.7) THEN 'partial'::"text"
            ELSE 'ok'::"text"
        END AS "gap_kind"
   FROM ("public"."source_coverage_targets" "t"
     LEFT JOIN "public"."cities" "c" ON (("c"."id" = "t"."city_id")))
  WHERE "t"."is_enabled"
  ORDER BY COALESCE("t"."success_ratio", (0)::numeric), "t"."last_run_at" NULLS FIRST;


ALTER VIEW "public"."coverage_gaps" OWNER TO "postgres";


