CREATE OR REPLACE VIEW "public"."dedup_precision" WITH ("security_invoker"='true') AS
 SELECT "rpc_match_type",
    ("count"(*))::integer AS "decisions",
    ("count"(*) FILTER (WHERE ("human_decision" = 'confirmed_duplicate'::"text")))::integer AS "confirmed",
    ("count"(*) FILTER (WHERE ("human_decision" = 'not_duplicate'::"text")))::integer AS "rejected",
    ("count"(*) FILTER (WHERE ("human_decision" = 'merge'::"text")))::integer AS "merged",
    "round"((("count"(*) FILTER (WHERE ("human_decision" = ANY (ARRAY['confirmed_duplicate'::"text", 'merge'::"text"]))))::numeric / (NULLIF("count"(*), 0))::numeric), 3) AS "precision",
    "round"("avg"("rpc_score"), 3) AS "avg_rpc_score",
    "round"("avg"("rpc_score") FILTER (WHERE ("human_decision" = 'not_duplicate'::"text")), 3) AS "avg_score_when_wrong",
    "max"("created_at") AS "last_decision"
   FROM "public"."dedup_decisions_feedback"
  WHERE ("rpc_match_type" IS NOT NULL)
  GROUP BY "rpc_match_type"
  ORDER BY (("count"(*))::integer) DESC;


ALTER VIEW "public"."dedup_precision" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."dlq_summary" WITH ("security_invoker"='true') AS
