CREATE OR REPLACE VIEW "public"."geo_merge_candidates" WITH ("security_invoker"='true') AS
 SELECT "s"."id" AS "staging_id",
    "s"."target_table",
    "s"."entity_type",
    "s"."source_type" AS "source",
    "s"."source_entity_id",
    ("s"."normalized_data" ->> 'name'::"text") AS "proposed_name",
    ("s"."normalized_data" ->> 'code'::"text") AS "proposed_code",
    ((("s"."normalized_data" -> 'location'::"text") ->> 'lat'::"text"))::numeric AS "proposed_lat",
    ((("s"."normalized_data" -> 'location'::"text") ->> 'lng'::"text"))::numeric AS "proposed_lng",
    (("s"."normalized_data" -> 'location'::"text") ->> 'country'::"text") AS "proposed_country_name",
    (("s"."normalized_data" -> 'location'::"text") ->> 'country_code'::"text") AS "proposed_country_code",
    "s"."dedup_match_id" AS "match_id",
    "s"."dedup_match_score" AS "match_score",
    "s"."dedup_details",
    "s"."created_at",
        CASE
            WHEN ("s"."target_table" = 'cities'::"text") THEN "mc"."name"
            ELSE NULL::"text"
        END AS "match_name",
        CASE
            WHEN ("s"."target_table" = 'cities'::"text") THEN "mc"."latitude"
            ELSE NULL::numeric
        END AS "match_lat",
        CASE
            WHEN ("s"."target_table" = 'cities'::"text") THEN "mc"."longitude"
            ELSE NULL::numeric
        END AS "match_lng",
        CASE
            WHEN ("s"."target_table" = 'countries'::"text") THEN "mco"."name"
            ELSE NULL::"text"
        END AS "match_country_name",
        CASE
            WHEN ("s"."target_table" = 'countries'::"text") THEN "mco"."code"
            ELSE NULL::"text"
        END AS "match_country_code"
   FROM (("public"."ingestion_staging" "s"
     LEFT JOIN "public"."cities" "mc" ON ((("s"."target_table" = 'cities'::"text") AND ("mc"."id" = "s"."dedup_match_id"))))
     LEFT JOIN "public"."countries" "mco" ON ((("s"."target_table" = 'countries'::"text") AND ("mco"."id" = "s"."dedup_match_id"))))
  WHERE (("s"."target_table" = ANY (ARRAY['cities'::"text", 'countries'::"text"])) AND ("s"."dedup_status" = 'merge_candidate'::"text") AND ("s"."review_status" = 'pending_review'::"text") AND ("s"."disposition" = 'pending'::"text"));


ALTER VIEW "public"."geo_merge_candidates" OWNER TO "postgres";


