CREATE OR REPLACE VIEW "public"."hotel_ingest_stats" WITH ("security_invoker"='true') AS
 SELECT "date_trunc"('day'::"text", "created_at") AS "day",
    "source_type" AS "source",
    COALESCE(("normalized_data" ->> 'accommodation_type'::"text"), 'unknown'::"text") AS "accommodation_type",
    "count"(*) AS "staged",
    "count"(*) FILTER (WHERE ("ai_validation_status" = 'approved'::"text")) AS "validated",
    "count"(*) FILTER (WHERE ("dedup_status" = 'unique'::"text")) AS "unique_items",
    "count"(*) FILTER (WHERE ("dedup_status" = 'duplicate'::"text")) AS "duplicates",
    "count"(*) FILTER (WHERE ("disposition" = ANY (ARRAY['inserted'::"text", 'committed'::"text"]))) AS "committed",
    "count"(*) FILTER (WHERE ("disposition" = 'rejected'::"text")) AS "rejected",
    "count"(*) FILTER (WHERE ("review_status" = 'pending_review'::"text")) AS "pending_review"
   FROM "public"."ingestion_staging" "s"
  WHERE (("target_table" = 'venues'::"text") AND (COALESCE(("normalized_data" ->> 'accommodation_type'::"text"), ''::"text") <> ''::"text"))
  GROUP BY ("date_trunc"('day'::"text", "created_at")), "source_type", COALESCE(("normalized_data" ->> 'accommodation_type'::"text"), 'unknown'::"text");


ALTER VIEW "public"."hotel_ingest_stats" OWNER TO "postgres";


