CREATE OR REPLACE VIEW "public"."inbox_orphan_count_v" WITH ("security_invoker"='on') AS
 SELECT "user_id",
    ("count"(*))::integer AS "orphan_count"
   FROM "public"."reservations"
  WHERE (("trip_id" IS NULL) AND ("status" <> ALL (ARRAY['cancelled'::"text", 'completed'::"text"])))
  GROUP BY "user_id";


ALTER VIEW "public"."inbox_orphan_count_v" OWNER TO "postgres";


COMMENT ON VIEW "public"."inbox_orphan_count_v" IS 'Per-user count of orphan (unattached, open) reservations. Drives the Inbox badge in the header.';



