CREATE OR REPLACE VIEW "public"."news_image_duplicates" WITH ("security_invoker"='on') AS
 WITH "groups" AS (
         SELECT "news_articles"."image_hash",
            "count"(*) AS "n",
            "array_agg"("news_articles"."id" ORDER BY "news_articles"."published_at") AS "article_ids",
            "array_agg"("news_articles"."title" ORDER BY "news_articles"."published_at") AS "titles",
            "array_agg"("news_articles"."published_at" ORDER BY "news_articles"."published_at") AS "published_dates",
            "array_agg"("news_articles"."source_id" ORDER BY "news_articles"."published_at") AS "source_ids"
           FROM "public"."news_articles"
          WHERE ("news_articles"."image_hash" IS NOT NULL)
          GROUP BY "news_articles"."image_hash"
         HAVING ("count"(*) > 1)
        )
 SELECT "image_hash",
    "n",
    "article_ids",
    "titles",
    "published_dates",
    "source_ids"
   FROM "groups"
  ORDER BY "n" DESC, "image_hash";


ALTER VIEW "public"."news_image_duplicates" OWNER TO "postgres";


COMMENT ON VIEW "public"."news_image_duplicates" IS 'Groups of news_articles sharing the same image_hash. Same image on multiple articles is often (but not always) a duplicate — admin reviews each group.';



CREATE OR REPLACE VIEW "public"."news_quality_health" WITH ("security_invoker"='on') AS
 SELECT "count"(*) FILTER (WHERE ("quality_status" = 'passed'::"text")) AS "passed",
    "count"(*) FILTER (WHERE ("quality_status" = 'review'::"text")) AS "review",
    "count"(*) FILTER (WHERE ("quality_status" = 'rejected'::"text")) AS "rejected",
    "count"(*) FILTER (WHERE ("quality_status" = 'pending'::"text")) AS "pending",
    "count"(*) FILTER (WHERE ("quality_status" IS NULL)) AS "legacy_unprocessed",
    "count"(*) AS "total",
    "avg"("relevance_score") FILTER (WHERE ("relevance_score" IS NOT NULL)) AS "avg_relevance",
    "avg"("quality_score") FILTER (WHERE ("quality_score" IS NOT NULL)) AS "avg_quality_after",
    "avg"((("quality_score")::numeric - "quality_score_before")) FILTER (WHERE (("quality_score" IS NOT NULL) AND ("quality_score_before" IS NOT NULL))) AS "avg_quality_delta",
    "max"("last_quality_run_at") AS "last_run_at"
   FROM "public"."news_articles";


ALTER VIEW "public"."news_quality_health" OWNER TO "postgres";


