CREATE OR REPLACE VIEW "public"."news_quality_source_health" WITH ("security_invoker"='on') AS
 SELECT "v"."id" AS "source_id",
    "v"."name" AS "source_name",
    "count"("a".*) AS "total",
    "count"(*) FILTER (WHERE ("a"."quality_status" = 'passed'::"text")) AS "passed",
    "count"(*) FILTER (WHERE ("a"."quality_status" = 'review'::"text")) AS "review",
    "count"(*) FILTER (WHERE ("a"."quality_status" = 'rejected'::"text")) AS "rejected",
    "count"(*) FILTER (WHERE ("a"."quality_status" IS NULL)) AS "legacy",
    "avg"("a"."quality_score") FILTER (WHERE ("a"."quality_score" IS NOT NULL)) AS "avg_quality",
    "avg"("a"."relevance_score") FILTER (WHERE ("a"."relevance_score" IS NOT NULL)) AS "avg_relevance",
        CASE
            WHEN ("count"(*) FILTER (WHERE ("a"."quality_status" IS NOT NULL)) > 0) THEN (("count"(*) FILTER (WHERE ("a"."quality_status" = 'rejected'::"text")))::numeric / ("count"(*) FILTER (WHERE ("a"."quality_status" IS NOT NULL)))::numeric)
            ELSE NULL::numeric
        END AS "reject_rate",
    "max"("a"."last_quality_run_at") AS "last_run_at"
   FROM ("public"."venues" "v"
     JOIN "public"."news_articles" "a" ON (("a"."source_id" = "v"."id")))
  GROUP BY "v"."id", "v"."name"
 HAVING ("count"(*) > 0);


ALTER VIEW "public"."news_quality_source_health" OWNER TO "postgres";


COMMENT ON VIEW "public"."news_quality_source_health" IS 'Per-source quality breakdown for the admin Quality Review tab.';



