CREATE OR REPLACE VIEW "public"."personality_data_health" WITH ("security_invoker"='true') AS
 SELECT ( SELECT "count"(*) AS "count"
           FROM "public"."personalities") AS "total",
    ( SELECT "count"(*) AS "count"
           FROM "public"."personalities"
          WHERE ("personalities"."verification_status" = 'verified'::"text")) AS "verified",
    ( SELECT "count"(*) AS "count"
           FROM "public"."personalities"
          WHERE ("personalities"."verification_status" = 'pending'::"text")) AS "pending_verification",
    ( SELECT "count"(*) AS "count"
           FROM "public"."personalities"
          WHERE ("personalities"."visibility" = 'public'::"text")) AS "public_rows",
    ( SELECT "count"(*) AS "count"
           FROM "public"."personalities"
          WHERE ("personalities"."visibility" = 'draft'::"text")) AS "draft_rows",
    ( SELECT "count"(*) AS "count"
           FROM "public"."personalities"
          WHERE ("personalities"."duplicate_of_id" IS NOT NULL)) AS "known_duplicates",
    ( SELECT "count"(*) AS "count"
           FROM "public"."personalities"
          WHERE "personalities"."needs_attention") AS "needs_attention",
    ( SELECT "count"(*) AS "count"
           FROM "public"."personalities"
          WHERE (("personalities"."image_url" IS NULL) OR ("personalities"."image_url" = ''::"text"))) AS "missing_image",
    ( SELECT "count"(*) AS "count"
           FROM "public"."personalities"
          WHERE (("personalities"."description" IS NULL) OR ("personalities"."description" = ''::"text"))) AS "missing_description",
    ( SELECT "count"(*) AS "count"
           FROM "public"."personalities"
          WHERE (("personalities"."lgbti_connection" IS NULL) OR ("personalities"."lgbti_connection" = ''::"text"))) AS "missing_lgbti",
    ( SELECT "count"(*) AS "count"
           FROM "public"."personalities"
          WHERE (("personalities"."wikidata_qid" IS NULL) OR ("personalities"."wikidata_qid" = ''::"text"))) AS "missing_qid",
    ( SELECT ("avg"("personalities"."quality_score"))::integer AS "avg"
           FROM "public"."personalities"
          WHERE ("personalities"."quality_score" IS NOT NULL)) AS "avg_quality",
    ( SELECT "count"(*) AS "count"
           FROM "public"."review_queue"
          WHERE (("review_queue"."entity_type" = 'personality'::"text") AND ("review_queue"."status" = 'pending'::"text"))) AS "open_reviews";


