CREATE OR REPLACE VIEW "public"."pipeline_error_summary" WITH ("security_invoker"='true') AS
 SELECT "function_name",
    "severity",
    "count"(*) FILTER (WHERE ("created_at" > ("now"() - '01:00:00'::interval))) AS "last_1h",
    "count"(*) FILTER (WHERE ("created_at" > ("now"() - '24:00:00'::interval))) AS "last_24h",
    "count"(*) FILTER (WHERE ("created_at" > ("now"() - '7 days'::interval))) AS "last_7d",
    "max"("created_at") AS "last_seen_at"
   FROM "public"."pipeline_errors"
  GROUP BY "function_name", "severity";


