CREATE OR REPLACE VIEW "public"."pipeline_quality_daily" WITH ("security_invoker"='true') AS
 SELECT ("date_trunc"('day'::"text", "created_at"))::"date" AS "day",
    "entity_type",
    "source_name",
    ("count"(*))::integer AS "n",
    "percentile_cont"((0.50)::double precision) WITHIN GROUP (ORDER BY (((("enriched_data" ->> 'quality_score'::"text"))::numeric)::double precision)) AS "score_p50",
    "avg"((("enriched_data" ->> 'quality_score'::"text"))::numeric) AS "score_avg"
   FROM "public"."ingestion_staging"
  WHERE (("enrichment_status" = 'completed'::"text") AND ("enriched_data" ? 'quality_score'::"text") AND ("created_at" > ("now"() - '90 days'::interval)))
  GROUP BY (("date_trunc"('day'::"text", "created_at"))::"date"), "entity_type", "source_name"
  ORDER BY (("date_trunc"('day'::"text", "created_at"))::"date") DESC, "entity_type", "source_name";


ALTER VIEW "public"."pipeline_quality_daily" OWNER TO "postgres";


COMMENT ON VIEW "public"."pipeline_quality_daily" IS '90-day daily median/mean quality scores per (entity_type, source_name). Chart-friendly.';



CREATE OR REPLACE VIEW "public"."pipeline_quality_distribution" WITH ("security_invoker"='true') AS
 SELECT "entity_type",
    "source_name",
    ("count"(*))::integer AS "n",
    "min"((("enriched_data" ->> 'quality_score'::"text"))::numeric) AS "score_min",
    "percentile_cont"((0.25)::double precision) WITHIN GROUP (ORDER BY (((("enriched_data" ->> 'quality_score'::"text"))::numeric)::double precision)) AS "score_p25",
    "percentile_cont"((0.50)::double precision) WITHIN GROUP (ORDER BY (((("enriched_data" ->> 'quality_score'::"text"))::numeric)::double precision)) AS "score_p50",
    "percentile_cont"((0.75)::double precision) WITHIN GROUP (ORDER BY (((("enriched_data" ->> 'quality_score'::"text"))::numeric)::double precision)) AS "score_p75",
    "max"((("enriched_data" ->> 'quality_score'::"text"))::numeric) AS "score_max",
    "avg"((("enriched_data" ->> 'quality_score'::"text"))::numeric) AS "score_avg"
   FROM "public"."ingestion_staging"
  WHERE (("enrichment_status" = 'completed'::"text") AND ("enriched_data" ? 'quality_score'::"text") AND ("created_at" > ("now"() - '30 days'::interval)))
  GROUP BY "entity_type", "source_name"
  ORDER BY "entity_type", "source_name";


ALTER VIEW "public"."pipeline_quality_distribution" OWNER TO "postgres";


COMMENT ON VIEW "public"."pipeline_quality_distribution" IS 'Rolling 30-day quality-score distribution per (entity_type, source_name). Read by /admin/pipelines to spot per-source regressions.';



