CREATE OR REPLACE VIEW "public"."pipeline_stuck_items" WITH ("security_invoker"='true') AS
 SELECT "id",
    "target_table",
    "source_type",
    "source_name",
    "disposition",
    "ai_validation_status",
    "dedup_status",
    "review_status",
    "error_message",
    "created_at",
    "updated_at",
    (EXTRACT(epoch FROM ("now"() - "updated_at")))::integer AS "stale_seconds",
        CASE
            WHEN (("disposition" = 'pending'::"text") AND ("ai_validation_status" = 'pending'::"text") AND ("normalized_data" IS NULL) AND (("now"() - "updated_at") > '00:10:00'::interval)) THEN 'stuck_at_normalize'::"text"
            WHEN (("normalized_data" IS NOT NULL) AND ("ai_validation_status" = 'pending'::"text") AND (("now"() - "updated_at") > '00:10:00'::interval)) THEN 'stuck_at_validate'::"text"
            WHEN (("ai_validation_status" = 'approved'::"text") AND ("dedup_status" = 'pending'::"text") AND (("now"() - "updated_at") > '00:10:00'::interval)) THEN 'stuck_at_dedup'::"text"
            WHEN (("review_status" = 'pending_review'::"text") AND (("now"() - "updated_at") > '24:00:00'::interval)) THEN 'review_stale'::"text"
            WHEN (("disposition" = 'pending'::"text") AND ("ai_validation_status" = 'approved'::"text") AND ("dedup_status" = ANY (ARRAY['unique'::"text", 'duplicate'::"text", 'merge_candidate'::"text"])) AND ("review_status" = 'approved'::"text") AND (("now"() - "updated_at") > '00:10:00'::interval)) THEN 'stuck_at_commit'::"text"
            WHEN (("disposition" = 'rejected'::"text") AND ("error_message" IS NOT NULL)) THEN 'rejected_with_error'::"text"
            ELSE 'other'::"text"
        END AS "stuck_reason"
   FROM "public"."ingestion_staging" "s"
  WHERE (("disposition" = ANY (ARRAY['pending'::"text", 'approved'::"text", 'rejected'::"text"])) AND ("target_table" IS NOT NULL));


ALTER VIEW "public"."pipeline_stuck_items" OWNER TO "postgres";


