    "romance_style" "text",
    "physical_affection_preference" "text",
    "sexual_frequency_preference" "text",
    "communication_about_sex" "text",
    "jealousy_comfort_level" "text",
    "sexual_exploration_openness" "text",
    "user_mode" "public"."user_mode" DEFAULT 'exploration'::"public"."user_mode",
    "is_online" boolean DEFAULT false,
    "last_seen_at" timestamp with time zone DEFAULT "now"(),
    "avatar_config" "jsonb",
    "phone_encrypted" "text",
    "emergency_contact_phone_encrypted" "text",
    "sexual_orientation_encrypted" "text",
    "gender_identity_encrypted" "text",
    "relationship_status_encrypted" "text",
    "income_range_encrypted" "text",
    "political_views_encrypted" "text",
    "religious_beliefs_encrypted" "text",
    "photos_visibility" "text" DEFAULT 'private'::"text",
    "avatar_type" "text",
    "mailbox_address" "text",
    "physical_attributes" "jsonb" DEFAULT '{}'::"jsonb",
    "lifestyle" "jsonb" DEFAULT '{}'::"jsonb",
    "dating_profile" "jsonb" DEFAULT '{}'::"jsonb",
    "identity_details" "jsonb" DEFAULT '{}'::"jsonb",
    "moderation_status" "text" DEFAULT 'approved'::"text" NOT NULL,
    "email" "text",
    CONSTRAINT "profiles_avatar_type_check" CHECK (("avatar_type" = ANY (ARRAY['upload'::"text", 'builder'::"text", 'gravatar'::"text"]))),
    CONSTRAINT "profiles_bdsm_role_check" CHECK (("bdsm_role" = ANY (ARRAY['dominant'::"text", 'submissive'::"text", 'switch'::"text", 'top'::"text", 'bottom'::"text", 'versatile'::"text", 'not_interested'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_chosen_family_status_check" CHECK (("chosen_family_status" = ANY (ARRAY['have_chosen_family'::"text", 'building_chosen_family'::"text", 'looking_for_chosen_family'::"text", 'not_interested'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_communication_about_sex_check" CHECK (("communication_about_sex" = ANY (ARRAY['very_open'::"text", 'open_with_partners'::"text", 'private'::"text", 'uncomfortable'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_current_relationship_status_check" CHECK (("current_relationship_status" = ANY (ARRAY['single'::"text", 'taken'::"text", 'its_complicated'::"text", 'open_to_explore'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_disability_status_check" CHECK (("disability_status" = ANY (ARRAY['yes'::"text", 'no'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_family_acceptance_level_check" CHECK (("family_acceptance_level" = ANY (ARRAY['very_supportive'::"text", 'supportive'::"text", 'neutral'::"text", 'unsupportive'::"text", 'very_unsupportive'::"text", 'no_contact'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_financial_situation_check" CHECK (("financial_situation" = ANY (ARRAY['financially_stable'::"text", 'getting_by'::"text", 'struggling'::"text", 'in_crisis'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_housing_situation_check" CHECK (("housing_situation" = ANY (ARRAY['stable_housing'::"text", 'temporary_housing'::"text", 'looking_for_housing'::"text", 'housing_insecure'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_immigration_status_check" CHECK (("immigration_status" = ANY (ARRAY['citizen'::"text", 'permanent_resident'::"text", 'temporary_resident'::"text", 'undocumented'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_jealousy_comfort_level_check" CHECK (("jealousy_comfort_level" = ANY (ARRAY['very_comfortable'::"text", 'somewhat_comfortable'::"text", 'gets_jealous'::"text", 'very_jealous'::"text", 'depends'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_kink_experience_level_check" CHECK (("kink_experience_level" = ANY (ARRAY['none'::"text", 'curious'::"text", 'beginner'::"text", 'intermediate'::"text", 'advanced'::"text", 'expert'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_mailbox_address_format" CHECK (("mailbox_address" ~ '^[a-z0-9][a-z0-9.\-]{1,28}[a-z0-9]$'::"text")),
    CONSTRAINT "profiles_mental_health_openness_check" CHECK (("mental_health_openness" = ANY (ARRAY['very_open'::"text", 'somewhat_open'::"text", 'private'::"text", 'prefer_not_to_discuss'::"text"]))),
    CONSTRAINT "profiles_moderation_status_check" CHECK (("moderation_status" = ANY (ARRAY['approved'::"text", 'suspended'::"text", 'banned'::"text"]))),
    CONSTRAINT "profiles_neurodivergent_status_check" CHECK (("neurodivergent_status" = ANY (ARRAY['yes'::"text", 'no'::"text", 'self_diagnosed'::"text", 'questioning'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_photos_visibility_check" CHECK (("photos_visibility" = ANY (ARRAY['private'::"text", 'friends'::"text", 'public'::"text"]))),
    CONSTRAINT "profiles_physical_affection_preference_check" CHECK (("physical_affection_preference" = ANY (ARRAY['very_affectionate'::"text", 'moderately_affectionate'::"text", 'minimal_affection'::"text", 'touch_averse'::"text", 'depends_on_relationship'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_relationship_style_check" CHECK (("relationship_style" = ANY (ARRAY['monogamous'::"text", 'polyamorous'::"text", 'relationship_anarchist'::"text", 'open_relationship'::"text", 'swinging'::"text", 'exploring'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_romance_style_check" CHECK (("romance_style" = ANY (ARRAY['very_romantic'::"text", 'somewhat_romantic'::"text", 'practical'::"text", 'anti_romantic'::"text", 'depends_on_partner'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_sexual_exploration_openness_check" CHECK (("sexual_exploration_openness" = ANY (ARRAY['very_open'::"text", 'somewhat_open'::"text", 'selective'::"text", 'not_interested'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_sexual_frequency_preference_check" CHECK (("sexual_frequency_preference" = ANY (ARRAY['multiple_times_daily'::"text", 'daily'::"text", 'few_times_week'::"text", 'weekly'::"text", 'few_times_month'::"text", 'monthly'::"text", 'rarely'::"text", 'asexual'::"text", 'depends'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "profiles_sexual_health_status_check" CHECK (("sexual_health_status" = ANY (ARRAY['recently_tested_clean'::"text", 'regularly_tested'::"text", 'prefer_not_to_discuss'::"text", 'will_discuss_privately'::"text"]))),
    CONSTRAINT "profiles_workplace_safety_check" CHECK (("workplace_safety" = ANY (ARRAY['completely_out'::"text", 'partially_out'::"text", 'not_out'::"text", 'unsafe_to_be_out'::"text", 'not_applicable'::"text", 'prefer_not_to_say'::"text"]))),
    CONSTRAINT "valid_phone_format" CHECK ((("phone" IS NULL) OR ("phone" ~* '^\+?[1-9]\d{1,14}$'::"text"))),
    CONSTRAINT "valid_website_format" CHECK ((("website" IS NULL) OR ("website" ~* '^https?://[^\s/$.?#].[^\s]*$'::"text")))
);

