CREATE OR REPLACE VIEW "public"."public_profiles" WITH ("security_invoker"='on') AS
 SELECT "user_id",
    "display_name",
    "avatar_url",
        CASE
            WHEN (COALESCE((("privacy_settings" ->> 'bio_public'::"text"))::boolean, false) OR ("user_id" = "auth"."uid"()) OR "public"."has_role"(( SELECT "auth"."uid"() AS "uid"), 'admin'::"public"."app_role")) THEN "bio"
            ELSE NULL::"text"
        END AS "bio",
        CASE
            WHEN (COALESCE((("privacy_settings" ->> 'pronouns_public'::"text"))::boolean, false) OR ("user_id" = "auth"."uid"()) OR "public"."has_role"(( SELECT "auth"."uid"() AS "uid"), 'admin'::"public"."app_role")) THEN "pronouns"
            ELSE NULL::"text"
        END AS "pronouns",
        CASE
            WHEN (COALESCE((("privacy_settings" ->> 'gender_identity_public'::"text"))::boolean, false) OR ("user_id" = "auth"."uid"()) OR "public"."has_role"(( SELECT "auth"."uid"() AS "uid"), 'admin'::"public"."app_role")) THEN "gender_identity"
            ELSE NULL::"text"
        END AS "gender_identity",
        CASE
            WHEN (COALESCE((("privacy_settings" ->> 'sexual_orientation_public'::"text"))::boolean, false) OR ("user_id" = "auth"."uid"()) OR "public"."has_role"(( SELECT "auth"."uid"() AS "uid"), 'admin'::"public"."app_role")) THEN "sexual_orientation"
            ELSE NULL::"text"
        END AS "sexual_orientation",
        CASE
            WHEN (COALESCE((("privacy_settings" ->> 'location_public'::"text"))::boolean, false) OR ("user_id" = "auth"."uid"()) OR "public"."has_role"(( SELECT "auth"."uid"() AS "uid"), 'admin'::"public"."app_role")) THEN "location"
            ELSE NULL::"text"
        END AS "location",
    "social_links"
   FROM "public"."profiles" "p";


ALTER VIEW "public"."public_profiles" OWNER TO "postgres";


