CREATE TABLE IF NOT EXISTS "public"."redirects" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "type" "public"."redirect_type" DEFAULT 'SHORT'::"public"."redirect_type" NOT NULL,
    "slug" "text",
    "source_path" "text",
    "match_kind" "public"."redirect_match_kind" DEFAULT 'EXACT'::"public"."redirect_match_kind" NOT NULL,
    "target" "text" NOT NULL,
    "status_code" integer DEFAULT 301 NOT NULL,
    "is_enabled" boolean DEFAULT true NOT NULL,
    "start_at" timestamp with time zone,
    "end_at" timestamp with time zone,
    "preserve_query" boolean DEFAULT true NOT NULL,
    "query_mode" "public"."redirect_query_mode" DEFAULT 'PRESERVE'::"public"."redirect_query_mode" NOT NULL,
    "query_override" "jsonb",
    "utm_defaults" "jsonb",
    "click_limit" integer,
    "click_count" integer DEFAULT 0 NOT NULL,
    "notes" "text",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "no_reserved_slugs" CHECK ((("slug" IS NULL) OR ("slug" <> ALL (ARRAY['admin'::"text", 'api'::"text", 'go'::"text", 'auth'::"text", 'login'::"text", 'signup'::"text", 'sitemap'::"text", 'robots'::"text", 'favicon'::"text", 'manifest'::"text", 'sw'::"text", 'index'::"text", 'health'::"text", 'status'::"text", 'null'::"text", 'undefined'::"text", 'test'::"text", 'www'::"text", 'mail'::"text", 'ftp'::"text", 'cdn'::"text", 'assets'::"text", 'static'::"text", 'public'::"text"])))),
    CONSTRAINT "redirects_click_limit_check" CHECK ((("click_limit" IS NULL) OR ("click_limit" > 0))),
    CONSTRAINT "redirects_status_code_check" CHECK (("status_code" = ANY (ARRAY[301, 302, 307, 308]))),
    CONSTRAINT "slug_format" CHECK ((("slug" IS NULL) OR ("slug" ~ '^[a-z0-9]([a-z0-9-]*[a-z0-9])?$'::"text"))),
    CONSTRAINT "slug_length" CHECK ((("slug" IS NULL) OR (("length"("slug") >= 3) AND ("length"("slug") <= 64)))),
    CONSTRAINT "slug_required_for_short" CHECK ((("type" <> 'SHORT'::"public"."redirect_type") OR (("slug" IS NOT NULL) AND ("slug" <> ''::"text")))),
    CONSTRAINT "source_path_required_for_path" CHECK ((("type" <> 'PATH'::"public"."redirect_type") OR (("source_path" IS NOT NULL) AND ("source_path" <> ''::"text"))))
);


ALTER TABLE "public"."redirects" OWNER TO "postgres";


