    "status" "text" NOT NULL,
    "started_at" timestamp with time zone DEFAULT "now"(),
    "finished_at" timestamp with time zone,
    "pages_fetched" integer DEFAULT 0,
    "entities_parsed" integer DEFAULT 0,
    "entities_inserted" integer DEFAULT 0,
    "entities_updated" integer DEFAULT 0,
    "entities_deduped" integer DEFAULT 0,
    "blocked_by_robots" integer DEFAULT 0,
    "failed_requests" integer DEFAULT 0,
    "errors" "jsonb" DEFAULT '[]'::"jsonb",
    "coverage_geo" integer DEFAULT 0,
    "coverage_phone" integer DEFAULT 0,
    "coverage_website" integer DEFAULT 0,
    "coverage_images" integer DEFAULT 0,
    "coverage_tags" integer DEFAULT 0,
    "coverage_address" integer DEFAULT 0,
    "coverage_description" integer DEFAULT 0,
    CONSTRAINT "scraper_ingest_runs_status_check" CHECK (("status" = ANY (ARRAY['running'::"text", 'completed'::"text", 'failed'::"text", 'partial'::"text"])))
);


ALTER TABLE "public"."scraper_ingest_runs" OWNER TO "postgres";


COMMENT ON COLUMN "public"."scraper_ingest_runs"."coverage_geo" IS 'Count of entities in this run that had non-null lat AND lng after normalization';



COMMENT ON COLUMN "public"."scraper_ingest_runs"."coverage_phone" IS 'Count of entities with a non-null phone (applies to venue/stay only)';



CREATE OR REPLACE VIEW "public"."scraper_ingest_coverage" WITH ("security_invoker"='on') AS
 SELECT "source_name",
    "entity_type",
    "started_at",
    "entities_parsed",
        CASE
            WHEN ("entities_parsed" > 0) THEN "round"(((100.0 * ("coverage_geo")::numeric) / ("entities_parsed")::numeric), 1)
            ELSE NULL::numeric
        END AS "pct_geo",
        CASE
            WHEN ("entities_parsed" > 0) THEN "round"(((100.0 * ("coverage_phone")::numeric) / ("entities_parsed")::numeric), 1)
            ELSE NULL::numeric
        END AS "pct_phone",
        CASE
            WHEN ("entities_parsed" > 0) THEN "round"(((100.0 * ("coverage_website")::numeric) / ("entities_parsed")::numeric), 1)
            ELSE NULL::numeric
        END AS "pct_website",
        CASE
            WHEN ("entities_parsed" > 0) THEN "round"(((100.0 * ("coverage_images")::numeric) / ("entities_parsed")::numeric), 1)
            ELSE NULL::numeric
        END AS "pct_images",
        CASE
            WHEN ("entities_parsed" > 0) THEN "round"(((100.0 * ("coverage_tags")::numeric) / ("entities_parsed")::numeric), 1)
            ELSE NULL::numeric
        END AS "pct_tags",
        CASE
            WHEN ("entities_parsed" > 0) THEN "round"(((100.0 * ("coverage_address")::numeric) / ("entities_parsed")::numeric), 1)
            ELSE NULL::numeric
        END AS "pct_address",
        CASE
            WHEN ("entities_parsed" > 0) THEN "round"(((100.0 * ("coverage_description")::numeric) / ("entities_parsed")::numeric), 1)
            ELSE NULL::numeric
        END AS "pct_description"
   FROM "public"."scraper_ingest_runs"
  WHERE ("status" = ANY (ARRAY['completed'::"text", 'partial'::"text"]))
  ORDER BY "started_at" DESC;


ALTER VIEW "public"."scraper_ingest_coverage" OWNER TO "postgres";


