COMMENT ON COLUMN "public"."scraper_snapshots"."content_gz" IS 'gzip-compressed snapshot body. Decompress in app layer. Canonical after migration 004.';



COMMENT ON COLUMN "public"."scraper_snapshots"."content_encoding" IS 'Compression scheme: gzip for new rows, NULL for pre-migration rows stored in content TEXT.';



CREATE OR REPLACE VIEW "public"."scraper_snapshots_archive_candidates" WITH ("security_invoker"='true') AS
 SELECT "id",
    "source_name",
    "url",
    "content_type",
    "content_hash",
    "fetched_at",
    "octet_length"("content_gz") AS "gz_bytes"
   FROM "public"."scraper_snapshots"
  WHERE (("archived_at" IS NULL) AND ("fetched_at" < ("now"() - '30 days'::interval)) AND ("content_gz" IS NOT NULL))
  ORDER BY "fetched_at"
 LIMIT 1000;


ALTER VIEW "public"."scraper_snapshots_archive_candidates" OWNER TO "postgres";


