CREATE TABLE IF NOT EXISTS "public"."source_reliability" (
    "source_slug" "text" NOT NULL,
    "entity_type" "text" NOT NULL,
    "weight" numeric(4,3),
    "quality_p50" numeric(5,2),
    "quality_p25" numeric(5,2),
    "coverage_ratio" numeric(4,3),
    "rejection_rate" numeric(4,3),
    "block_rate" numeric(4,3),
    "sample_size" integer DEFAULT 0 NOT NULL,
    "computed_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "public"."source_reliability" OWNER TO "postgres";


COMMENT ON TABLE "public"."source_reliability" IS 'Per-source reliability rollup. Refreshed hourly by refresh_source_reliability(). weight in [0,1] feeds review-gate downranking and conflict-resolver voting.';



CREATE OR REPLACE VIEW "public"."source_reliability_current" WITH ("security_invoker"='true') AS
 SELECT "source_slug",
    "entity_type",
    "weight",
    "quality_p50",
    "coverage_ratio",
    "rejection_rate",
    "block_rate",
    "sample_size",
    "computed_at",
        CASE
            WHEN ("weight" IS NULL) THEN 'insufficient_data'::"text"
            WHEN ("weight" >= 0.75) THEN 'reliable'::"text"
            WHEN ("weight" >= 0.50) THEN 'acceptable'::"text"
            WHEN ("weight" >= 0.25) THEN 'degraded'::"text"
            ELSE 'unreliable'::"text"
        END AS "tier"
   FROM "public"."source_reliability"
  ORDER BY "weight" DESC NULLS LAST, "source_slug", "entity_type";


ALTER VIEW "public"."source_reliability_current" OWNER TO "postgres";


