CREATE OR REPLACE VIEW "public"."tag_usage_summary" WITH ("security_invoker"='true') AS
 SELECT "ut"."id",
    "ut"."name",
    "ut"."slug",
    "ut"."category",
    "ut"."usage_count",
    "count"(
        CASE
            WHEN ("uta"."entity_type" = 'event'::"text") THEN 1
            ELSE NULL::integer
        END) AS "event_count",
    "count"(
        CASE
            WHEN ("uta"."entity_type" = 'venue'::"text") THEN 1
            ELSE NULL::integer
        END) AS "venue_count",
    "count"(
        CASE
            WHEN ("uta"."entity_type" = 'marketplace_listing'::"text") THEN 1
            ELSE NULL::integer
        END) AS "marketplace_count",
    "count"(
        CASE
            WHEN ("uta"."entity_type" = 'content'::"text") THEN 1
            ELSE NULL::integer
        END) AS "content_count",
    "count"(
        CASE
            WHEN ("uta"."entity_type" = 'news_article'::"text") THEN 1
            ELSE NULL::integer
        END) AS "news_count",
    "count"(
        CASE
            WHEN ("uta"."entity_type" = 'community_post'::"text") THEN 1
            ELSE NULL::integer
        END) AS "post_count",
    "count"(
        CASE
            WHEN ("uta"."entity_type" = 'community_group'::"text") THEN 1
            ELSE NULL::integer
        END) AS "group_count"
   FROM ("public"."unified_tags" "ut"
     LEFT JOIN "public"."unified_tag_assignments" "uta" ON (("ut"."id" = "uta"."tag_id")))
  GROUP BY "ut"."id", "ut"."name", "ut"."slug", "ut"."category", "ut"."usage_count"
  ORDER BY "ut"."usage_count" DESC;


ALTER VIEW "public"."tag_usage_summary" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."tags_with_categories" WITH ("security_invoker"='true') AS
 SELECT "id",
    "name",
    "slug",
    "description",
    "image_url",
    "usage_count",
    "category",
    "created_at",
    "updated_at",
    "category_id",
    "wikipedia_url",
    "status",
    "merged_into_id",
    "deprecated_at",
    "deprecation_reason",
    COALESCE(( SELECT "jsonb_agg"("jsonb_build_object"('id', "tc"."id", 'name', "tc"."name", 'slug', "tc"."slug", 'level', "tc"."level", 'parent_id', "tc"."parent_id", 'parent_name', "pc"."name", 'is_primary', "tca"."is_primary") ORDER BY "tca"."is_primary" DESC, "tc"."level") AS "jsonb_agg"
           FROM (("public"."tag_category_assignments" "tca"
             JOIN "public"."tag_categories" "tc" ON (("tc"."id" = "tca"."category_id")))
             LEFT JOIN "public"."tag_categories" "pc" ON (("pc"."id" = "tc"."parent_id")))
          WHERE ("tca"."tag_id" = "ut"."id")), '[]'::"jsonb") AS "categories"
   FROM "public"."unified_tags" "ut";


ALTER VIEW "public"."tags_with_categories" OWNER TO "postgres";


