CREATE OR REPLACE VIEW "public"."user_submission_reputation" WITH ("security_invoker"='true') AS
 SELECT "cs"."submitted_by" AS "user_id",
    ("count"(*) FILTER (WHERE (("a"."field" = 'status'::"text") AND (("a"."new_value")::"text" = ANY (ARRAY['"approved"'::"text", '"promoted"'::"text"])))))::integer AS "approved",
    ("count"(*) FILTER (WHERE (("a"."field" = 'status'::"text") AND (("a"."new_value")::"text" = ANY (ARRAY['"rejected"'::"text", '"spam"'::"text"])))))::integer AS "rejected",
    "max"("a"."at") AS "last_review_at"
   FROM ("public"."community_submissions" "cs"
     LEFT JOIN "public"."community_submissions_audit" "a" ON (("a"."submission_id" = "cs"."id")))
  WHERE ("cs"."submitted_by" IS NOT NULL)
  GROUP BY "cs"."submitted_by";


ALTER VIEW "public"."user_submission_reputation" OWNER TO "postgres";


COMMENT ON VIEW "public"."user_submission_reputation" IS 'M9.2 — per-user approved/rejected counts. AdminSubmissions queries this for the Submitter column.';



