CREATE OR REPLACE VIEW "public"."v_api_error_daily" WITH ("security_invoker"='true') AS
 SELECT "cs"."id" AS "submission_id",
    "cs"."fingerprint",
    ("date_trunc"('day'::"text", "a"."at"))::"date" AS "day",
    ("count"(*))::integer AS "n"
   FROM ("public"."community_submissions" "cs"
     JOIN "public"."community_submissions_audit" "a" ON (("a"."submission_id" = "cs"."id")))
  WHERE (("cs"."content_type" = 'api_error'::"text") AND ("a"."at" >= ("now"() - '30 days'::interval)))
  GROUP BY "cs"."id", "cs"."fingerprint", (("date_trunc"('day'::"text", "a"."at"))::"date");


ALTER VIEW "public"."v_api_error_daily" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_feedback_analytics_daily" WITH ("security_invoker"='true') AS
 SELECT ("date_trunc"('day'::"text", "submitted_at"))::"date" AS "day",
    "content_type",
    "feedback_status",
    ("data" ->> 'category'::"text") AS "category",
    "priority",
    ("count"(*))::integer AS "n"
   FROM "public"."community_submissions"
  WHERE (("submitted_at" >= ("now"() - '180 days'::interval)) AND ("is_spam" = false))
  GROUP BY (("date_trunc"('day'::"text", "submitted_at"))::"date"), "content_type", "feedback_status", ("data" ->> 'category'::"text"), "priority";


ALTER VIEW "public"."v_feedback_analytics_daily" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_popular_entities" WITH ("security_invoker"='true') AS
 SELECT 'venue'::"text" AS "content_type",
    ("venues"."id")::"text" AS "content_id",
    ((COALESCE(("venues"."quality_score")::integer, 0) +
        CASE
            WHEN "venues"."featured" THEN 20
            ELSE 0
        END))::real AS "score"
   FROM "public"."venues"
UNION ALL
 SELECT 'event'::"text" AS "content_type",
    ("events"."id")::"text" AS "content_id",
    (((
        CASE
            WHEN "events"."featured" THEN 20
            ELSE 0
        END)::numeric + GREATEST((0)::numeric, ((30)::numeric - (EXTRACT(epoch FROM ("events"."start_date" - "now"())) / 86400.0)))))::real AS "score"
   FROM "public"."events"
  WHERE ("events"."start_date" > ("now"() - '1 day'::interval))
UNION ALL
 SELECT 'city'::"text" AS "content_type",
    ("cities"."id")::"text" AS "content_id",
    (10)::real AS "score"
   FROM "public"."cities"
UNION ALL
 SELECT 'personality'::"text" AS "content_type",
    ("personalities"."id")::"text" AS "content_id",
    (5)::real AS "score"
   FROM "public"."personalities";


ALTER VIEW "public"."v_popular_entities" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_top_queries" WITH ("security_invoker"='true') AS
 SELECT "query_normalized",
    "count"(*) AS "n",
    ("avg"("n_results"))::integer AS "avg_results",
    ("avg"("took_ms"))::integer AS "avg_ms",
    "max"("created_at") AS "last_seen"
   FROM "public"."search_queries"
  WHERE ("created_at" > ("now"() - '7 days'::interval))
  GROUP BY "query_normalized"
  ORDER BY ("count"(*)) DESC;


ALTER VIEW "public"."v_top_queries" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_zero_hit_queries" WITH ("security_invoker"='true') AS
 SELECT "query_normalized",
    "count"(*) AS "n",
    "max"("created_at") AS "last_seen"
   FROM "public"."search_queries"
  WHERE (("n_results" = 0) AND ("created_at" > ("now"() - '30 days'::interval)))
  GROUP BY "query_normalized"
 HAVING ("count"(*) >= 2)
  ORDER BY ("count"(*)) DESC;


ALTER VIEW "public"."v_zero_hit_queries" OWNER TO "postgres";


