CREATE OR REPLACE VIEW "public"."venue_checkin_stats" WITH ("security_invoker"='on') AS
 SELECT "venue_id",
    ("count"(*))::integer AS "total_checkins",
    ("count"(DISTINCT "date"("created_at")))::integer AS "days_with_checkins",
    "max"("created_at") AS "last_checkin",
        CASE
            WHEN ("count"(*) = 0) THEN 'none'::"text"
            WHEN ("count"(*) <= 3) THEN 'low'::"text"
            WHEN ("count"(*) <= 10) THEN 'medium'::"text"
            WHEN ("count"(*) <= 25) THEN 'high'::"text"
            ELSE 'very_high'::"text"
        END AS "activity_level"
   FROM "public"."venue_checkins"
  GROUP BY "venue_id";


