ALTER TABLE "public"."webhook_deliveries" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."workflow_definitions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "name" "text" NOT NULL,
    "display_name" "text",
    "description" "text",
    "edge_function" "text" NOT NULL,
    "queue_name" "text" NOT NULL,
    "default_payload" "jsonb" DEFAULT '{}'::"jsonb",
    "schedule" "text",
    "max_retries" integer DEFAULT 3,
    "retry_backoff_base" integer DEFAULT 30,
    "max_concurrency" integer DEFAULT 1,
    "timeout_seconds" integer DEFAULT 150,
    "is_enabled" boolean DEFAULT true,
    "priority" integer DEFAULT 5,
    "tags" "text"[] DEFAULT '{}'::"text"[],
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"()
);


ALTER TABLE "public"."workflow_definitions" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."workflow_runs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "definition_id" "uuid",
    "workflow_name" "text" NOT NULL,
    "queue_name" "text" NOT NULL,
    "pgmq_msg_id" bigint,
    "status" "text" DEFAULT 'queued'::"text" NOT NULL,
    "attempt" integer DEFAULT 1,
    "max_attempts" integer DEFAULT 3,
    "input_payload" "jsonb" DEFAULT '{}'::"jsonb",
    "output_result" "jsonb",
    "error_message" "text",
    "error_details" "jsonb",
    "progress_pct" integer DEFAULT 0,
    "items_total" integer DEFAULT 0,
    "items_processed" integer DEFAULT 0,
    "items_succeeded" integer DEFAULT 0,
    "items_failed" integer DEFAULT 0,
    "queued_at" timestamp with time zone DEFAULT "now"(),
    "started_at" timestamp with time zone,
    "completed_at" timestamp with time zone,
    "duration_ms" integer,
    "next_retry_at" timestamp with time zone,
    "triggered_by" "text" DEFAULT 'cron'::"text",
    "idempotency_key" "text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "workflow_runs_progress_pct_check" CHECK ((("progress_pct" >= 0) AND ("progress_pct" <= 100))),
    CONSTRAINT "workflow_runs_status_check" CHECK (("status" = ANY (ARRAY['queued'::"text", 'running'::"text", 'completed'::"text", 'failed'::"text", 'dead_letter'::"text", 'cancelled'::"text"]))),
    CONSTRAINT "workflow_runs_triggered_by_check" CHECK (("triggered_by" = ANY (ARRAY['cron'::"text", 'webhook'::"text", 'admin'::"text", 'api'::"text", 'system'::"text"])))
);


ALTER TABLE "public"."workflow_runs" OWNER TO "postgres";


